kbd_scancode_lut         = $0F90
;   notes:
;     Value = defMON internal key code stored to kbd_decoded_key (KEY_NONE = no binding, e.g. modifier keys filtered). So scancode Y = ((7 - row) * 8) + col, with row 7 occupying scancodes 56..63 (Y=63 = row 7 col 0 = RUN/STOP key in the C64 matrix), and row 0 occupying scancodes 0..7. The trailing bytes at splash_status_template_data are a separate data table — see that region's role.
;
;     Decoded key map by scancode (Y), keyed by the C64 keymatrix row/col:
;
;      Scancode | C64 matrix    | kbd_scancode_lut value | Decoded as
;      ---------+---------------+------------------------+--------------------
;      0        | row 0 col 0   | $6F                    | INSTDEL
;      1        | row 0 col 1   | $B5                    | RETURN
;      2        | row 0 col 2   | $B3                    | CRSRLR
;      3        | row 0 col 3   | $B1                    | F7
;      4        | row 0 col 4   | $B7                    | F1
;      5        | row 0 col 5   | $6A                    | F3
;      6        | row 0 col 6   | $92                    | F5
;      7        | row 0 col 7   | $84                    | CRSRUD
;      8        | row 1 col 7   | $FF                    | LSHIFT (filtered)
;      9        | row 1 col 6   | $05                    | E
;      10       | row 1 col 5   | $13                    | S
;      11       | row 1 col 4   | $1A                    | Z (see super-cmd note)
;      12       | row 1 col 3   | $34                    | "4"
;      13       | row 1 col 2   | $01                    | A
;      14       | row 1 col 1   | $17                    | W
;      15       | row 1 col 0   | $33                    | "3"
;      ...      | (rows 2-6)    |                        |
;      57       | row 7 col 6   | $11                    | Q (see super-cmd note)
;      58       | row 7 col 5   | $FF                    | CBM (filtered)
;      60       | row 7 col 3   | $32                    | SPACE
;      62       | row 7 col 1   | $1F                    | LEFTARROW
;      63       | row 7 col 0   | $31                    | RUN/STOP
splash_status_template_data = $0FA2
kbd_page_band_end        = $0FFF

