; ── SONG RAM — ARRANGERS, PATTERN BANK, sidTAB ($1800-$71FF) ───────────
song_position_arrays_lo  = $1800
;   notes:
;     +$0F stride per entry.
;
;     NOT the saved-file body.
sidtab_row_lo_byte1      = $1801
sidtab_jp_slot_1804      = $1804
;   notes: Tunes occasionally author JP-source bytes at sub-byte offsets within the sidtab_row_lo-sidtab_jp_pointer_page_end JP-target table. The static image carries a $00 here, but a loaded song may overlay it with a JP source.
sidtab_jp_slot_1807      = $1807
;   notes: Two more entries continuing the same $0F per-row stride as sidtab_jp_slot_1809.
sidtab_jp_slot_1809      = $1809
;   notes: The bytes advance by $0F per entry — sidTAB row-pointer low bytes on the $0F-byte per-row stride.
sidtab_jp_target_row24   = $1824
;   notes: JP-target slot for sidtab row $24.
load_decoder_dest_floor_below = $1825
load_decoder_dest_floor  = $1826
sidtab_jp_pointer_page_end = $18FF
;   notes: End-of-page marker.
song_position_arrays_hi  = $1900
sidtab_row_hi_byte1      = $1901
sidtab_decoder_buffer_end = $19FF
;   notes: pat_base_lo begins at pat_base_lo.
pat_base_lo              = $1A00
;   notes: Entries alternate $00/$80 — patterns are packed two per 256-byte page on a 128-byte stride, so an even pat_num maps to offset $00 within its page and an odd one to $80.
pat_base_hi              = $1A80
;   notes: High bytes repeat in pairs (one page holds two patterns) and increment once per page — the companion of pat_base_lo's $00/$80 low-byte alternation.
pat_base_hi_end          = $1AFF
;   notes: Boundary marker — arranger_v0_sid1 begins the V0 arranger.
arranger_v0_sid1         = $1B00
;   notes: When V0 entry has bit 7 set (typically $FF), it's a JUMP COMMAND, NOT a pattern reference: the jump target row is read from V1's arranger at the same song-position (arranger_v1_sid1,Y), and the repeat count is read from V2's (arranger_v2_sid1,Y). So V2 = 'number of jumps to take before falling through'; V2 = 0 = infinite loop. Target and count live in V1 and V2 arrangers at the same row Y, not in the V0 arranger itself.
arranger_v0_sid1_byte1   = $1B01
arranger_v1_sid1         = $1C00
;   notes: Dual-purpose: on rows where V0 == $FF the V1 entry at the same row is the JUMP TARGET row index instead of V1's pattern number. See arranger_v0_sid1 for the jump-command shape.
arranger_v2_sid1         = $1D00
;   notes: Dual-purpose: on rows where V0 == $FF the V2 entry is the jump-command repeat count ($00 = infinite). See arranger_v0_sid1.
dl_per_step_counters     = $1E00
;   notes: $00..$7F = hold this row for that many frames; $80..$FF = STop (freeze + gate-off, bmi in cascade dispatches to bmi-fall-through that skips the row-refetch). Implicitly written by the LOAD-time secondary pass and by sidTAB-editor save. Reference tune slot 7 freeze = dl_per_step_counters[7] = $80.
dl_per_step_counters_byte1 = $1E01
pattern_bank             = $1F00
;   notes:
;     Each pattern = 128 B = 32 steps × 4 bytes (flag, slot_a, slot_b, note); GATE_N (flag bit 4) must be set for a note to actually play.
;
;     Player IRQ reads from here every frame. Patterns are addressed via
;     pat_base_lo/hi tables at pat_base_lo/pat_base_hi — pat_num N lives at
;     (pat_base_hi,N) << 8 | (pat_base_lo,N).
;
;     Default-stride layout (most factory tunes use $80 stride):
;     pat$00 = pattern_bank, pat$01 = pat01_default_base, pat$02 = pat02_default_base, pat$03 = pat03_default_base_sid2_v3, pat$04 = pat04_default_base_sid2_v4,
;     pat$05 = pat05_default_base_sid2_v5,... Stride is per-tune via pat_base_lo/pat_base_hi tables; do not assume
;     linear $80 in synthesised tunes. See pat01_default_base/pat02_default_base/pat03_default_base_sid2_v3/pat04_default_base_sid2_v4/pat05_default_base_sid2_v5 for
;     boundary markers.
pattern_bank_v0_step0_slot_a = $1F01
;   notes: slot_a is the sidcall starting-row index applied when flag bit 6 (GATE_A) is set.
pattern_bank_v0_step0_slot_b = $1F02
pattern_bank_v0_step0_note = $1F03
;   notes: Player IRQ reads this once per frame and zeros it if the corresponding flag's GATE_N bit (bit 4) is clear. Bare chromatic-row key in seqED writes here (pattern_bank + voice*4 + 3).
pattern_bank_v1_step0_flag = $1F04
;   notes: flag bits: 7=ALT pattern-end, 6=GATE_A, 5=GATE_B, 4=GATE_N (must be set for the note to play), 3-0=duration nibble. Cells continue at +4-byte stride per voice, then +12-byte stride per step within a pattern.
