; ──────────────────────────────────────────────────────────────────────
; $0826  post_load_init_decoder
; ──────────────────────────────────────────────────────────────────────
; Post-LOAD init and decoder entry point.
;
;   callers:             1 code sites: $76DB
;
;   NOT just a state-reset.
;
;   Called via JMP post_load_init_decoder from disk_menu_return_handler after KERNAL LOAD returns. Resets
;   editor state vars (cursor_state_cluster-step_cursor, seqlist_col_cursor, seqlist_row_counter) then runs the byte-stream
;   decoder that transforms file body at sidtab_row_lo..super_cmd_staged into LIVE form:
;    - regenerates pitch LUT sidtab_row_lo-sidtab_decoder_buffer_end (+$0F stride; see pitch_lut_generator_inner_loop loop)
;    - populates pat_base_lo/hi at pat_base_lo/pat_base_hi
;    - populates arrangers V0/V1/V2 at arranger_v0_sid1/arranger_v1_sid1/arranger_v2_sid1
;    - populates LIVE pattern bank starting at pattern_bank
;    - writes across $A0-$BF (player tables / self-mod scratch)
post_load_init_decoder .block
                           lda  #PLAYBACK_OFF    ; $0826
                           sta  playback_state    ; $0828
                           jsr  super_init_full    ; $082B
                           ldx  #$05    ; $082E
                           lda  #SID_VIEW_2    ; $0830
l_1:                       sta  cursor_state_cluster,x    ; $0832
                           dex    ; $0835
                           bpl  l_1    ; $0836  $05 walked back 1 and had bit 7 clear?
                           sta  sid_chip_view    ; $0838
                           jsr  sid2_chipview_voice_mute_apply    ; $083B
                           lda  #SID_VIEW_1    ; $083E
                           sta  sid_chip_view    ; $0840
                           jsr  sid2_chipview_voice_mute_apply    ; $0843
                           jsr  secondary_disk_data_reader    ; $0846
                           lda  #$30    ; $0849
                           sta  octave_offset    ; $084B
                           lda  #$01    ; $084E
                           sta  ui_mode_prev    ; $0850
                           jsr  mode_transition_wrapper    ; $0853
                           lda  #$01    ; $0856
                           sta  ui_state_716e    ; $0858
                           lda  #$05    ; $085B
                           sta  voice_selector    ; $085D
                           lda  #$08    ; $0860
                           sta  page_offset    ; $0862
                           lda  #$FF    ; $0865
                           sta  page_pair_counter    ; $0867
                           lda  #$19    ; $086A
                           sta  step_cursor    ; $086C
                           lda  #$01    ; $086F
                           sta  seqlist_col_cursor    ; $0871
                           lda  #$00    ; $0874
                           sta  seqed_col_cursor    ; $0876
                           lda  #$00    ; $0879
                           sta  sidtab_scroll    ; $087B
                           sta  chip_view_cursor_y    ; $087E
                           lda  #$06    ; $0881
                           sta  chip_view_cursor_x    ; $0883
                           lda  #$08    ; $0886
                           sta  seqlist_cursor_aux1    ; $0888
                           lda  #DIGIT_PHASE_HIGH    ; $088B
                           sta  digit_phase    ; $088D
                           lda  #$00    ; $0890
                           jsr  border_set_a    ; $0892
                           sta  VIC_BORDER    ; $0895
                           sta  VIC_SP2_X.VIC_BG0    ; $0898
                           jsr  vic_sprite_init    ; $089B
                           ldx  #$F2    ; $089E
                           ldy  #$0F    ; $08A0
                           lda  #$08    ; $08A2
                           jsr  statusline_print_zstring    ; $08A4
                           inc  editor_busy_wait_counter    ; $08A7
.bend

; ──────────────────────────────────────────────────────────────────────
; $08AA  editor_frame_barrier
; ──────────────────────────────────────────────────────────────────────
; Per-frame editor body entry — busy-wait barrier.
;
;   callers:             2 code sites: $08AC, $09F5 main_loop_close
;   inputs:              editor_frame_barrier = self-modify counter (immediate operand of LDA at editor_frame_barrier)
;
;   The 'frame top' of defMON's editor loop. Spins on a self-modifying
;   `lda #$XX; beq` whose immediate is bumped by post_load_startup each
;   pass through the editor loop tail at main_loop_zero_counters — that
;   INC is what releases the spin and lets one frame's worth of editor
;   work run.
;
;   Once unblocked, the body does (in order):
;    - border-colour + super-cmd repaint (VIC_BORDER := ui_mode_range_bound;
;      statusline_tick; green-border tint when super_cmd_extra is set);
;    - frame-timer ratchet (increments ui_mode_range_bound, ANDs $0F;
;      when the bottom 4 bits land on 0 or 4, bumps the sub-frame counter);
;    - ui_mode fan-out (seqED arm INCs editor_row_delta, seqLIST arm INCs
;      editor_col_delta, both merge to the frame-work tail);
;    - frame-work tail (editor_frame_work_tail): unconditional playhead
;      follow-cursor + two patchable LDA-#$01/BEQ gates around the chip-view
;      status repaint and seqLIST status painter; in seqLIST mode also runs
;      the arranger advance super_cmd_page_commit;
;    - main_loop_zero_counters wipes the per-frame counters;
;    - main_loop (kbd_scan + mode dispatch — the 'input half');
;    - main_loop_close JMPs back to editor_frame_barrier.
;
;   The "main_loop" label is the *input-scan* half of the same loop, not a
;   distinct entry — control flows
;   editor_frame_barrier → frame work → main_loop_zero_counters → main_loop
;   → main_loop_close → editor_frame_barrier, all one circular flow.
;
;   Internal labels:
;    editor_frame_work_tail   converged per-frame work tail (entered from
;                             the three mode arms; runs the playhead update
;                             and the two patched gates).
;    main_loop_zero_counters  counter-zero block before the input half.
;                             Reached by fall-through, a patched LDA skip,
;                             or a JMP from editor_frame_jmp_padding.
editor_frame_barrier .block
                           lda  #$00    ; $08AA  ; ← editor_busy_wait_counter
                           beq  editor_frame_barrier    ; $08AC  editor_busy_wait_counter was zero?
                           lda  border_color_state_a    ; $08AE
                           sta  VIC_BORDER    ; $08B1
                           jsr  statusline_tick    ; $08B4
                           lda  super_cmd_extra    ; $08B7
                           beq  l_1    ; $08BA  super_cmd_extra was zero?
                           lda  #$05    ; $08BC
                           jsr  border_set_a    ; $08BE
l_1:                       lda  cursor_redraw_flag    ; $08C1
                           inc  cursor_redraw_flag    ; $08C4
                           and  #$0F    ; $08C7
                           beq  l_2    ; $08C9  (cursor_redraw_flag & $0F) was zero?
                           cmp  #$04    ; $08CB
                           bne  l_3    ; $08CD  (cursor_redraw_flag & $0F) was not $04?
l_2:                       inc  editor_other_delta    ; $08CF
l_3:                       lda  ui_mode_range_bound    ; $08D2
                           cmp  #UI_MODE_SEQED    ; $08D5
                           bne  editor_frame_work_tail.l_2    ; $08D7  ui_mode_range_bound was not UI_MODE_SEQED?
                           lda  #$00    ; $08D9  ; ← editor_other_delta
                           beq  editor_frame_work_tail    ; $08DB  editor_other_delta was zero?
                           lda  ui_mode    ; $08DD
                           cmp  #UI_MODE_SEQED    ; $08E0
                           bne  l_4    ; $08E2  ui_mode was not UI_MODE_SEQED?
                           inc  editor_row_delta    ; $08E4
                           jmp  editor_frame_work_tail    ; $08E7
l_4:                       cmp  #UI_MODE_SEQLIST    ; $08EA
                           bne  editor_frame_work_tail    ; $08EC  ui_mode was not UI_MODE_SEQLIST?
                           inc  editor_col_delta    ; $08EE
.bend

; ──────────────────────────────────────────────────────────────────────
; $08F1  editor_frame_work_tail
; ──────────────────────────────────────────────────────────────────────
; Converged per-frame work tail inside editor_frame_barrier.
;
;   callers:             3 code sites: $08DB, $08E7, $08EC
;
;   Branched to from the three mode arms of editor_frame_barrier. Unconditionally runs the playhead-follows-cursor update, then runs the filter cutoff status repaint and seqLIST status painter each gated by their own patchable enable flag. In seqLIST mode (ui_mode_range_bound = UI_MODE_SEQLIST) it also advances the arranger page via super_cmd_page_commit. Internal label of editor_frame_barrier's body.
editor_frame_work_tail .block
                           jsr  playhead_follows_cursor    ; $08F1
                           lda  #$01    ; $08F4  ; ← editor_row_delta
                           beq  l_1    ; $08F6  editor_row_delta was zero?
                           jsr  filter_cutoff_status_paint    ; $08F8
l_1:                       lda  #$01    ; $08FB  ; ← editor_col_delta
                           beq  l_2    ; $08FD  editor_col_delta was zero?
                           jsr  seqLIST_status_painter    ; $08FF
l_2:                       lda  ui_mode_range_bound    ; $0902
                           cmp  #UI_MODE_SEQLIST    ; $0905
                           bne  main_loop_zero_counters    ; $0907  ui_mode_range_bound was not UI_MODE_SEQLIST?
                           lda  editor_other_delta    ; $0909
                           beq  l_3    ; $090C  editor_other_delta was zero?
                           inc  editor_aux_counter    ; $090E
l_3:                       lda  #$01    ; $0911  ; ← editor_aux_counter
.bend

; ──────────────────────────────────────────────────────────────────────
; $0913  editor_frame_supercmd_check
; ──────────────────────────────────────────────────────────────────────
; Super-cmd page-commit check inside editor_frame_barrier.
;
;   code edges:          fall-through from $0911 editor_frame_work_tail_3 (2 bytes earlier)
;   apparent (from data): $7184 in sub_frame_phase, $7195 in sub_frame_phase, $719F in sub_frame_phase, $7769 in disk_subtitle_template
;
;   Reached by fall-through from editor_frame_work_tail A←$01: →main_loop_zero_counters when zero (never taken — A=$01) / call super_cmd_page_commit (super-cmd page-commit when staged) / jump main_loop_zero_counters (counter-zero block). Not a separate function — see editor_frame_barrier.
editor_frame_supercmd_check .block
                           beq  main_loop_zero_counters    ; $0913  editor_aux_counter was zero?
                           jsr  super_cmd_page_commit    ; $0915
                           jmp  main_loop_zero_counters    ; $0918
.bend

; ──────────────────────────────────────────────────────────────────────
; $091B  main_loop_zero_counters
; ──────────────────────────────────────────────────────────────────────
; Per-frame counter-zero block inside editor_frame_barrier.
;
;   callers:             3 code sites: $0907, $0913 editor_frame_supercmd_check, $0918
;
;   Reached either by fall-through from the editor_frame_work_tail mode-2 arm, editor_frame_supercmd_check patched-read skip, or editor_frame_jmp_padding jmp. Zeroes editor_frame_barrier / editor_row_delta / editor_col_delta / editor_frame_work_tail / editor_frame_barrier so the next iteration starts with cleared deltas. Internal label of editor_frame_barrier's body.
main_loop_zero_counters .block
                           lda  #$00    ; $091B
                           sta  editor_busy_wait_counter    ; $091D
                           sta  editor_row_delta    ; $0920
                           sta  editor_col_delta    ; $0923
                           sta  editor_aux_counter    ; $0926
                           sta  editor_other_delta    ; $0929
.bend

; ──────────────────────────────────────────────────────────────────────
; $092C  main_loop
; ──────────────────────────────────────────────────────────────────────
; Main editor loop top.
;
;   inputs:              ui_mode, kbd_modifiers/kbd_decoded_key (kbd modifiers + decoded key)
;   outputs:             Loops forever; modal handlers RTS back here.
;
;   code edges:          fall-through from $0929 in main_loop_zero_counters (3 bytes earlier)
main_loop .block
                           jsr  kbd_scan    ; $092C
.bend

; ──────────────────────────────────────────────────────────────────────
; $092F  main_loop_postscan
; ──────────────────────────────────────────────────────────────────────
; Main loop entry point past the call kbd_scan.
;
;   code edges:          fall-through from $092C main_loop (3 bytes earlier)
;
;   The instruction at main_loop_postscan (compare =$FF) acts on the decoded keycode in A returned by kbd_scan; control then flows to modifier_extract → mode_dispatch.
main_loop_postscan .block
                           cmp  #$FF    ; $092F
                           beq  mode_dispatch.l_5    ; $0931  kbd_scan->A was $FF?
                           jsr  global_pre_dispatch    ; $0933
                           jsr  super_cmd_dispatch    ; $0936
.bend

; ──────────────────────────────────────────────────────────────────────
; $0939  mode_dispatch
; ──────────────────────────────────────────────────────────────────────
; Mode dispatch.
;
;   inputs:              ui_mode: UI_MODE_SEQED = seqED, UI_MODE_SEQLIST = seqLIST, UI_MODE_SIDTAB = sidTAB, UI_MODE_DISK = secondary_disk_mode
;
;   code edges:          fall-through from $0936 in main_loop_postscan (3 bytes earlier)
;
;   Reads ui_mode and dispatches to the per-mode handler: UI_MODE_DISK →
;   secondary_disk_mode_handler, $01 → seqED_handler, $02 → seqLIST_handler,
;   $04 → sidTAB_handler.
;
;   Only reached when a key was pressed. The main loop polls the keyboard
;   first and short-circuits straight to the loop tail at main_loop_postscan
;   when nothing is in the decode buffer.
;
;   ui_mode = UI_MODE_DISK is NOT the visible disk menu (that suspends mode_dispatch entirely).
;   $20 is reachable only via CTRL+/ from sidTAB; see secondary_disk_mode_handler.
mode_dispatch .block
                           lda  ui_mode    ; $0939
; ─── switch (ui_mode) — 4 cases ───
;     case UI_MODE_DISK           → $0940
;     case UI_MODE_SEQED          → $094A
;     case UI_MODE_SEQLIST        → $0954
;     case UI_MODE_SIDTAB         → $095E
;     default                   → $0964
                           cmp  #UI_MODE_DISK    ; $093C
                           bne  l_1    ; $093E  ui_mode was not UI_MODE_DISK?
                           jsr  secondary_disk_mode_handler    ; $0940
                           jmp  main_loop_tail    ; $0943
l_1:                       cmp  #UI_MODE_SEQED    ; $0946
                           bne  l_2    ; $0948  ui_mode was not UI_MODE_SEQED?
                           jsr  seqED_handler    ; $094A
                           jmp  main_loop_tail    ; $094D
l_2:                       cmp  #UI_MODE_SEQLIST    ; $0950
                           bne  l_3    ; $0952  ui_mode was not UI_MODE_SEQLIST?
                           jsr  seqLIST_handler    ; $0954
                           jmp  main_loop_tail    ; $0957
l_3:                       cmp  #UI_MODE_SIDTAB    ; $095A
                           bne  l_4    ; $095C  ui_mode was not UI_MODE_SIDTAB?
                           jsr  sidTAB_handler    ; $095E
                           jmp  main_loop_tail    ; $0961
l_4:                       jmp  main_loop_tail    ; $0964
l_5:                       lda  digit_phase    ; $0967
                           beq  main_loop_tail    ; $096A  digit_phase was DIGIT_PHASE_HIGH?
                           lda  kbd_modifiers    ; $096C
                           bne  main_loop_tail    ; $096F  kbd_modifiers was non-zero?
                           lda  #DIGIT_PHASE_HIGH    ; $0971
                           sta  digit_phase    ; $0973
.bend

; ──────────────────────────────────────────────────────────────────────
; $0976  main_loop_tail
; ──────────────────────────────────────────────────────────────────────
; Main editor loop post-dispatch tail.
;
;   callers:             mode_dispatch (mode_dispatch arms, JMP not JSR), main_loop_postscan BEQ shortcut → mode_dispatch fall-through
;   inputs:              kbd_modifiers, kbd_decoded_key, ui_mode, page_offset (per-key dispatch index), voice_selector_lut_v0+ (voice-stop tables per modifier nibble)
;   outputs:             digit_phase cleared when no modifier; super_cmd_flags := $01 when no modifier; voice_selector updated when seqED + matching voice-stop; ui_mode_range_bound (repaint flag) := $04 on voice change
;   registers clobbered: A, X, Y
;
;   Joined from every mode_dispatch arm and from the no-key shortcut at main_loop_postscan. Resets digit_phase when no modifier is held, arms super_cmd_flags := $01 when no modifier is held, and in seqED (ui_mode = $01) walks the per-key voice-selector lookup tables (voice_selector_lut_v0 .. voice_selector_lut_v4) to advance voice_selector when the key matches that voice's chord slot.
;
;   The decoded-key fan-out dispatches on five modifier slots (KEY_NONE / SHIFT-only / CTRL-only / CBM-only / CTRL+CBM) and indexes into the matching voice-stop table at stride $03. On match: voice_selector := table value and ui_mode_range_bound := UI_MODE_SIDTAB (cursor repaint). On miss: short-circuit straight to the next frame at main_loop_close. Fires once per main-loop iteration.
main_loop_tail .block
                           lda  kbd_modifiers    ; $0976
                           bne  l_1    ; $0979  kbd_modifiers was non-zero?
                           lda  #SUPERCMD_S_DIG1    ; $097B
                           sta  super_cmd_flags    ; $097D
l_1:                       lda  ui_mode    ; $0980
                           cmp  #UI_MODE_SEQED    ; $0983
                           bne  main_loop_close    ; $0985  ui_mode was not UI_MODE_SEQED?
                           ldx  super_cmd_state_71cf    ; $0987
                           lda  kbd_decoded_key    ; $098A
                           cmp  #KEY_CRSRUD    ; $098D
                           beq  l_2    ; $098F  kbd_decoded_key was KEY_CRSRUD?
                           lda  kbd_modifiers    ; $0991
                           bne  l_3    ; $0994  kbd_modifiers was non-zero?
l_2:                       lda  voice_selector_lut_v0,x    ; $0996
                           cmp  voice_selector    ; $0999
                           bne  l_8    ; $099C  voice_selector_lut_v0,X was not voice_selector?
                           jmp  main_loop_close    ; $099E
l_3:                       cmp  #KBD_MOD_CBM    ; $09A1
                           bne  l_4    ; $09A3  kbd_modifiers was not KBD_MOD_CBM?
                           lda  voice_selector_lut_v1,x    ; $09A5
                           cmp  voice_selector    ; $09A8
                           bne  l_8    ; $09AB  voice_selector_lut_v1,X was not voice_selector?
                           jmp  main_loop_close    ; $09AD
l_4:                       cmp  #KBD_MOD_SHIFT    ; $09B0
                           bne  l_5    ; $09B2  kbd_modifiers was not KBD_MOD_SHIFT?
                           lda  voice_selector_lut_v2,x    ; $09B4
                           cmp  voice_selector    ; $09B7
                           bne  l_8    ; $09BA  voice_selector_lut_v2,X was not voice_selector?
                           jmp  main_loop_close    ; $09BC
l_5:                       cmp  #$30    ; $09BF
                           bne  l_6    ; $09C1  kbd_modifiers was not $30?
                           inc  main_loop_tail + $56    ; $09C3
                           lda  #$04    ; $09C6
                           sta  cursor_redraw_flag    ; $09C8
                           lda  #$FF    ; $09CB
                           and  #$07    ; $09CD
                           clc    ; $09CF
                           adc  voice_selector_lut_v4,x    ; $09D0
                           cmp  voice_selector    ; $09D3
                           bne  l_8    ; $09D6  A was not voice_selector?
                           jmp  main_loop_close    ; $09D8
l_6:                       cmp  #$24    ; $09DB
                           bne  l_7    ; $09DD  kbd_modifiers was not $24?
                           lda  voice_selector_lut_v3,x    ; $09DF
                           cmp  voice_selector    ; $09E2
                           bne  l_8    ; $09E5  voice_selector_lut_v3,X was not voice_selector?
                           jmp  main_loop_close    ; $09E7
l_7:                       jmp  main_loop_close    ; $09EA
l_8:                       sta  voice_selector    ; $09ED
                           lda  #$04    ; $09F0
                           sta  cursor_redraw_flag    ; $09F2
.bend

; ──────────────────────────────────────────────────────────────────────
; $09F5  main_loop_close
; ──────────────────────────────────────────────────────────────────────
; Main editor loop close: jump editor_frame_barrier.
;
;   callers:             8 in-band JMPs from main_loop_tail+; the closure point of every main-loop iteration.
;   inputs:              (none — terminal jump)
;   outputs:             PC := editor_frame_barrier (per-frame busy-wait barrier)
;
;   Branched to from main_loop_tail (no-voice-match), the seqED voice-walk fall-throughs (main_loop_tail), and the explicit →main_loop_close when nonzero at main_loop_tail when ui_mode != UI_MODE_SEQED.
main_loop_close .block
                           jmp  editor_frame_barrier    ; $09F5
        .byte $EA, $EA, $EA, $EA, $EA, $EA, $EA, $EA, $55, $55, $55    ; $09F8
        .fill 21, $AA    ; $0A03-$0A17
        .byte $55, $55, $55, $AA, $AA, $AA    ; $0A18
        .fill 33, $00    ; $0A1E-$0A3E
.bend

; ──────────────────────────────────────────────────────────────────────
; $0A3F  vic_cia_quiesce
; ──────────────────────────────────────────────────────────────────────
; VIC + CIA quiesce.
;
;   callers:             cold_boot_origin (cold-boot entry, 3rd instruction); save_ui_entry (disk_menu open paint)
;   registers clobbered: A
;
;   Mask CIA1/CIA2 IRQs, clear sprite-enable + raster-IRQ bookkeeping, point break/IRQ vectors (VEC_CBINV_LO-VEC_NMINV_HI) at cold_boot_origin (cold-boot entry), set $01=#$37 (default banking, KERNAL ROM in).
;
;   Defensive 'silence everything' helper run before any code that wants
;   clean control of the CPU. The cold-boot caller uses it to escape any
;   state the C64's BASIC/KERNAL reset left behind; the disk-menu caller
;   uses it to suspend the editor's IRQ machine while the nested
;   disk_menu_input_loop UI loop owns the screen.
;
;   Internal label (NOT a separate entry):
;    vic_cia_quiesce_body  fall-through after the IRQ mask: writes $7F to
;    both CIA ICRs, zeros VIC_IRQ_MASK, patches IRQ/BRK vectors
;    (BRK → CPU_DDR, IRQ → cold_boot_origin), zeros sprite-enable
;    VIC_SPRITE_ENABLE, ORs $08 into VIC_CR1 (text mode +
;    screen-on bit), ACKs pending IRQs (ASL VIC_IRQ_STATUS; BIT
;    CIA1_ICR/CIA2_ICR), then `LDA #$37; STA $01` (KERNAL banking).
;
;   defMON has no BASIC stub; cold start lands directly at
;   cold_boot_origin, whose first three bytes (LDX #$FF; TXS; SEI) are
;   the unambiguous "real code, not a `1 SYS` header" tell.
vic_cia_quiesce .block
                           sei    ; $0A3F
                           lda  #$7F    ; $0A40
.bend

; ──────────────────────────────────────────────────────────────────────
; $0A42  vic_cia_quiesce_body
; ──────────────────────────────────────────────────────────────────────
; Fall-through label inside vic_cia_quiesce VIC+CIA quiesce.
;
;   code edges:          fall-through from $0A40 in vic_cia_quiesce (2 bytes earlier)
;   apparent (from data): $B9FD in seqED_arm_dispatch_lut
;
;   vic_cia_quiesce sets up IRQ-off + A←$7F; vic_cia_quiesce_body executes the actual quiesce sequence (CIA1/CIA2 ICR mask, VIC raster-IRQ disable, IRQ/break vector patch, sprite-enable clear, default banking). Reached only as fall-through. Not a separate function — see vic_cia_quiesce.
vic_cia_quiesce_body .block
                           sta  CIA1_ICR    ; $0A42  ; CIA1_ICR := disable TA/TB/TOD/SP/FLAG
                           sta  CIA2_ICR    ; $0A45
                           lda  #$00    ; $0A48
                           sta  VIC_IRQ_MASK    ; $0A4A  ; VIC_IRQ_MASK := enable none
                           lda  #$00    ; $0A4D
                           sta  VEC_NMINV_LO    ; $0A4F
                           sta  VEC_CBINV_LO    ; $0A52
                           lda  #$08    ; $0A55
                           sta  VEC_NMINV_HI    ; $0A57
                           sta  VEC_CBINV_HI    ; $0A5A
                           lda  #$00    ; $0A5D
                           sta  VIC_SP2_X.VIC_SPRITE_ENABLE    ; $0A5F  ; VIC_SPRITE_ENABLE := sprites on: none
                           lda  VIC_CR1    ; $0A62
                           ora  #$08    ; $0A65
                           sta  VIC_CR1    ; $0A67
                           asl  VIC_SP2_X.VIC_IRQ_STATUS    ; $0A6A
                           bit  CIA1_ICR    ; $0A6D
                           bit  CIA2_ICR    ; $0A70
                           lda  #$37    ; $0A73
                           sta  CPU_PORT    ; $0A75
                           rts    ; $0A77
.bend

; ──────────────────────────────────────────────────────────────────────
; $0A78  irq_banking_setup
; ──────────────────────────────────────────────────────────────────────
; IRQ/banking setup called by disk_menu_return_handler in the LOAD chain.
;
;   callers:             4 code sites: $7423 save_ui_entry, $7455, $76D8, $7880
;   registers clobbered: A
;
;   IRQ-off; CIA timer setup; $01=#$35 banks KERNAL ROM OUT (exposes RAM-under-I/O at ram_under_io-ram_under_io_end for the decoder); NMI vector → nmi_irq_entry; return.
;
;   Without this, the decoder at decoder_emit_byte_inc+/would be inaccessible — its bytes are obscured by KERNAL ROM under default banking.
irq_banking_setup .block
                           lda  #$7F    ; $0A78
                           sta  CIA1_ICR    ; $0A7A  ; CIA1_ICR := disable TA/TB/TOD/SP/FLAG
                           sta  CIA2_ICR    ; $0A7D
                           lda  #$35    ; $0A80
                           sta  CPU_PORT    ; $0A82
                           lda  #$ED    ; $0A84
                           sta  VEC_NMI_LO    ; $0A86
                           lda  #$0A    ; $0A89
                           sta  VEC_NMI_HI    ; $0A8B
                           lda  #$8B    ; $0A8E
                           sta  VEC_IRQ_LO    ; $0A90
                           lda  #$0B    ; $0A93
                           sta  VEC_IRQ_HI    ; $0A95
                           lda  cia2_timer_lo    ; $0A98
                           sta  CIA2_TA_LO    ; $0A9B
                           lda  cia2_timer_hi    ; $0A9E
                           sta  CIA2_TA_HI    ; $0AA1
                           asl  VIC_SP2_X.VIC_IRQ_STATUS    ; $0AA4
                           bit  CIA1_ICR    ; $0AA7
                           bit  CIA2_ICR    ; $0AAA
                           jsr  raster_wait    ; $0AAD
                           lda  #$FF    ; $0AB0
l_1:                       cmp  VIC_RASTER    ; $0AB2
                           bne  l_1    ; $0AB5  $FF was not VIC_RASTER?
                           lda  #$11    ; $0AB7
                           sta  CIA2_CRA    ; $0AB9  ; CIA2_CRA := start TA, continuous, force load, count φ2, TOD 60Hz
                           lda  #$81    ; $0ABC
                           sta  CIA2_ICR    ; $0ABE  ; CIA2_ICR := enable TA
                           lda  #$01    ; $0AC1
                           sta  VIC_IRQ_MASK    ; $0AC3  ; VIC_IRQ_MASK := enable raster
                           lda  VIC_CR1    ; $0AC6
                           and  #$7F    ; $0AC9
                           sta  VIC_CR1    ; $0ACB
                           lda  #$FB    ; $0ACE
.bend

; ──────────────────────────────────────────────────────────────────────
; $0AD0  raster_irq_trigger_setter
; ──────────────────────────────────────────────────────────────────────
; Raster-IRQ trigger line + VIC bank setter.
;
;   inputs:              A = raster line at which the editor's split-screen / mode-aware repaint should fire.
;   outputs:             VIC_RASTER = A; CIA2_PRA = $C7.
;   registers clobbered: A
;
;   code edges:          fall-through from $0ACE in irq_banking_setup_1 (2 bytes earlier)
;
;   Latches the caller's A into VIC_RASTER (the raster-compare line), then writes
;   CIA2_PRA = $C7 = %11000111: bits 6-7 set the serial-bus CLK/DATA lines as
;   outputs (idle high), bit 2 (TXD) high, bits 0-1 = %11 select VIC bank 0
;   (the bottom 16 KiB of address space, which holds the default screen RAM at
;   screen_ram). Re-asserting both on every mode entry defends against the
;   disk-menu's nested input loop having repointed VIC bank during directory I/O.
raster_irq_trigger_setter .block
                           sta  VIC_RASTER    ; $0AD0
                           lda  #$C7    ; $0AD3
                           sta  CIA2_PRA    ; $0AD5
                           rts    ; $0AD8
.bend

; ──────────────────────────────────────────────────────────────────────
; $0AD9  nmi_sid2_silence_count
; ──────────────────────────────────────────────────────────────────────
; Start of the secondary boot-init helper band (boot_init_band-boot_init_band_end, ~200 bytes).
;
;   callers:             2 code sites: $0AF8, $0B88 nmi_post_player_tail_3
;
;   Fired once at boot from the chain rooted at post_load_init_decoder / the main `jump post_load_init_decoder` after LOAD (disk_menu_return_handler chain). Mostly screen-init, IRQ vector install, ZP setup.
nmi_sid2_silence_count .block
                           lda  #$00    ; $0AD9
                           beq  nmi_sid2_silence_cont.l_1    ; $0ADB  boot_init_band_$1 was zero?
.bend

; ──────────────────────────────────────────────────────────────────────
; $0ADD  nmi_sid2_silence_branch
; ──────────────────────────────────────────────────────────────────────
; Post-NMI branch inside nmi_irq_entry's exit fragment: when stereo+SID#2 is active the player-tail conditionally branches here to fire the SID#2 silence-latch update at sid2_chipview_voice_mute_apply before restoring border + return-from-IRQ.
;
;   code edges:          fall-through from $0ADB in nmi_sid2_silence_count (2 bytes earlier)
nmi_sid2_silence_branch .block
                           dec  nmi_sid2_silence_count + $01    ; $0ADD
.bend

; ──────────────────────────────────────────────────────────────────────
; $0AE0  nmi_sid2_silence_cont
; ──────────────────────────────────────────────────────────────────────
; Continuation of the nmi_sid2_silence_branch post-NMI branch — fall-through into nmi_irq_entry's restore-A/X/Y + return-from-IRQ tail.
;
;   code edges:          fall-through from $0ADD nmi_sid2_silence_branch (3 bytes earlier)
nmi_sid2_silence_cont .block
                           jsr  sid2_chipview_voice_mute_apply    ; $0AE0
l_1:                       lda  #$00    ; $0AE3  ; ← (SMC operand at $0AE4, no name)
                           ldx  #$00    ; $0AE5  ; ← (SMC operand at $0AE6, no name)
                           ldy  #$00    ; $0AE7  ; ← (SMC operand at $0AE8, no name)
                           bit  CIA2_ICR    ; $0AE9
                           rti    ; $0AEC
.bend

; ──────────────────────────────────────────────────────────────────────
; $0AED  nmi_irq_entry
; ──────────────────────────────────────────────────────────────────────
; NMI/raster-IRQ entry — gated player-tick driver.
;
;   inputs:              playback_state (immediate at LDA #$XX) — non-zero = play tick enabled, zero = no-op exit
;   outputs:             When playing: SID#1/SID#2 registers written via player_play/player_sound_update/sid2_subframe_entry/sid2_subframe_forced_variant; sub_frame_phase/sub_frame_count ratcheted; editor_row_delta / editor_col_delta arranger-row counters INCed.
;   registers clobbered: A, X, Y
;
;   Saves A/X/Y to self-modify storage (nmi_sid2_silence_cont); read playback_state (immediate-operand load — playback_state IS the playback state flag); beq → exit tail at boot_init_band if playback off; else fall through to the player body at nmi_irq_entry which calls player_sound_update (sub-frame SID update), conditionally sid2_subframe_forced_variant (SID#2 sub-frame), the nmi_subframe_call_site site for call player_play (player_play full tick), conditional sid2_subframe_entry (SID#2 player_play), then to the nmi_post_player_tail post-player tail (border restore + arranger ratchet at sub_frame_phase/sub_frame_count + optional IEC encode at iec_clk_pulse + jump boot_init_band exit).
;
;   Self-modifying-gate trick: playback_state is *both* the player-state flag AND
;   the immediate operand of the LDA at nmi_irq_entry. `stop_playback` (stop_playback)
;   writes $00 there; `play_from_*` writes non-zero. The NMI then either
;   falls into the player body or short-circuits to RTI, with no
;   conditional branch beyond the BEQ at nmi_irq_entry.
;
;   Internal labels (sub-labels of nmi_irq_entry):
;    boot_init_band exit tail: BIT CIA2_ICR (clear CIA2 IRQ flag), restore regs,
;    RTI via nmi_sid2_silence_cont (the $40 byte that ends the exit fragment).
;    nmi_irq_entry playing branch: red border (VIC_BORDER=$02), then JSR player_sound_update,
;    optional sid2_subframe_forced_variant, JMP nmi_post_player_tail.
;    nmi_irq_entry alt path (when playback_state self-modify counter hits a phase) —
;    decides whether this NMI handles a sub-frame or a full
;    tick based on nmi_irq_entry (also a self-modify counter byte).
;    nmi_subframe_call_site call site: JSR player_play (player_play full per-frame tick).
;    nmi_post_player_tail post-player tail: restore border from ui_mode_range_bound; advance
;    sub_frame_phase ratchet (wraps at sub_frame_count → 0); shared-arranger / IEC
;    / counter bookkeeping; JMP boot_init_band.
;
;   The IRQ source is a raster IRQ via CIA-1 Timer-A at ~42 Hz
;   (23546 cycles), not a true NMI from the restore-key.
nmi_irq_entry .block
                           sta  nmi_sid2_silence_cont + $04    ; $0AED
                           stx  nmi_sid2_silence_cont + $06    ; $0AF0
                           sty  nmi_sid2_silence_cont + $08    ; $0AF3
                           lda  #$00    ; $0AF6  ; ← playback_state
                           beq  nmi_sid2_silence_count    ; $0AF8  playback_state was PLAYBACK_OFF?
                           lda  #$02    ; $0AFA  ; ← nmi_playback_gate_smc
                           sta  VIC_BORDER    ; $0AFC
                           lda  sub_frame_phase    ; $0AFF
                           beq  l_2    ; $0B02  sub_frame_phase was zero?
                           jsr  player_sound_update    ; $0B04
                           lda  stereo_enable    ; $0B07
                           beq  l_1    ; $0B0A  stereo_enable was STEREO_OFF?
                           lda  #$0B    ; $0B0C
                           sta  VIC_BORDER    ; $0B0E
                           jsr  sid2_subframe_forced_variant    ; $0B11
l_1:                       jmp  nmi_post_player_tail    ; $0B14
l_2:                       lda  #$00    ; $0B17  ; ← sid2_stereo_sync_byte
                           bpl  l_4    ; $0B19  sid2_stereo_sync_byte had bit 7 clear?
                           inc  sid2_stereo_sync_byte    ; $0B1B
                           jmp  nmi_post_player_tail    ; $0B1E
l_3:                       dec  sid2_stereo_sync_byte    ; $0B21
l_4:                       lda  #$00    ; $0B24  ; ← (SMC operand at $0B25, no name)
                           beq  l_5    ; $0B26  nmi_irq_entry_$38 was zero?
                           dec  playback_state + $2E    ; $0B28
                           jmp  nmi_subframe_call_site    ; $0B2B
l_5:                       lda  #$0C    ; $0B2E
                           sta  CIA2_PRB    ; $0B30
.bend

; ──────────────────────────────────────────────────────────────────────
; $0B33  nmi_subframe_call_site
; ──────────────────────────────────────────────────────────────────────
; Sub-frame player-tick call site inside nmi_irq_entry.
;
;   callers:             1 code sites: $0B2B
;
;   call player_play (full per-frame player_play) → conditional call sid2_subframe_entry (SID#2 player_play when stereo_enable stereo flag set). Reached from nmi_irq_entry jmp.
nmi_subframe_call_site .block
                           jsr  player_play    ; $0B33
                           lda  stereo_enable    ; $0B36
                           beq  l_1    ; $0B39  stereo_enable was STEREO_OFF?
                           lda  playback_state + $16    ; $0B3B
                           sta  VIC_BORDER    ; $0B3E
                           jsr  sid2_subframe_entry    ; $0B41
l_1:                       lda  #$04    ; $0B44
                           sta  CIA2_PRB    ; $0B46
                           lda  sid2_stereo_sync_byte    ; $0B49
                           beq  nmi_post_player_tail    ; $0B4C  sid2_stereo_sync_byte was zero?
                           bpl  nmi_irq_entry.l_3    ; $0B4E  sid2_stereo_sync_byte had bit 7 clear?
.bend

; ──────────────────────────────────────────────────────────────────────
; $0B50  nmi_post_player_tail
; ──────────────────────────────────────────────────────────────────────
; Post-player tail inside nmi_irq_entry.
;
;   callers:             3 code sites: $0B14 nmi_irq_entry_1, $0B1E, $0B4C
;
;   Reached from nmi_irq_entry jump and nmi_subframe_call_site beq.
nmi_post_player_tail .block
;     read ui_mode_range_bound → write VIC_BORDER (restore border).
                           lda  border_color_state_a    ; $0B50
                           sta  VIC_BORDER    ; $0B53
;     read sub_frame_phase / A+=SUB_FRAME_1X (advance arranger ratchet) / compare sub_frame_count → write sub_frame_phase (wrap to 0 at target).
                           lda  sub_frame_phase    ; $0B56
                           clc    ; $0B59
                           adc  #$01    ; $0B5A
                           cmp  sub_frame_count    ; $0B5C
                           bne  l_1    ; $0B5F  A was not sub_frame_count?
;     read current_arranger_row / compare =$FF → →nmi_post_player_tail when zero.
                           lda  #$00    ; $0B61
l_1:                       sta  sub_frame_phase    ; $0B63
                           lda  current_arranger_row    ; $0B66
                           cmp  #$FF    ; $0B69  ; ← (SMC operand at $0B6A, no name)
                           beq  l_2    ; $0B6B  current_arranger_row was $FF?
;     X←v0_row_timer / →skip when positive.
                           ldx  v0_row_timer    ; $0B6D
                           bpl  l_2    ; $0B70  v0_row_timer had bit 7 clear?
;     write nmi_post_player_tail / call iec_clk_pulse (IEC encode emit).
                           sta  nmi_post_player_tail + $1A    ; $0B72
                           jsr  iec_clk_pulse    ; $0B75
                           inc  editor_col_delta    ; $0B78
l_2:                       lda  ui_state_716e    ; $0B7B
                           beq  l_3    ; $0B7E  ui_state_716e was zero?
                           lda  v0_row_timer    ; $0B80
                           bne  l_3    ; $0B83  v0_row_timer was non-zero?
                           inc  editor_row_delta    ; $0B85
l_3:                       jmp  nmi_sid2_silence_count    ; $0B88
.bend

; ──────────────────────────────────────────────────────────────────────
; $0B8B  raster_irq_entry
; ──────────────────────────────────────────────────────────────────────
; Raster-IRQ entry: services the VIC raster interrupt.
;
;   inputs:              A, X, Y
;   registers clobbered: A, X, Y
;
;   Saves A/X/Y into self-mod restore slots, bumps a frame counter, calls iec_recv_primitive_a, restores A/X/Y, acknowledges the VIC raster-IRQ latch, and RTIs. Reached only via the IRQ vector, so seeded explicitly (see SEED_LANDMARKS) rather than statically.
raster_irq_entry .block
                           sta  raster_irq_entry + $10    ; $0B8B
                           stx  raster_irq_entry + $12    ; $0B8E
                           sty  raster_irq_entry + $14    ; $0B91
                           inc  editor_busy_wait_counter    ; $0B94
                           jsr  iec_recv_primitive_a    ; $0B97
                           lda  #$00    ; $0B9A  ; ← (SMC operand at $0B9B, no name)
                           ldx  #$00    ; $0B9C  ; ← (SMC operand at $0B9D, no name)
                           ldy  #$00    ; $0B9E  ; ← (SMC operand at $0B9F, no name)
                           asl  VIC_SP2_X.VIC_IRQ_STATUS    ; $0BA0
.bend

; ──────────────────────────────────────────────────────────────────────
; $0BA3  boot_init_band_end
; ──────────────────────────────────────────────────────────────────────
; End of the secondary boot-init helper band (boot_init_band-boot_init_band_end).
;
;   code edges:          fall-through from $0BA0 in raster_irq_entry (3 bytes earlier)
;
;   Boundary marker.
boot_init_band_end .block
                           rti    ; $0BA3
.bend

; ──────────────────────────────────────────────────────────────────────
; $0BA4  jsr_with_ram_helper
; ──────────────────────────────────────────────────────────────────────
; jsr-with-RAM-banked-in helper.
;
;   callers:             5 sites in the disk-band LOAD chain: disk_menu_return_handler, save_overwrite_body, save_overwrite_body, disk_menu_ui_band_end (all part of disk_menu_return_handler load_tune + post-LOAD secondary-pass dispatch). Lets callers invoke the RAM-with-I/O LOAD-decoder without exposing the bank-swap dance.
;   inputs:              X = target addr lo, Y = target addr hi.
;   registers clobbered: A, X, Y
;
;   Caller passes (X = target lo, Y = target hi); jsr_with_ram_helper self-mods the call operand at jsr_with_ram_helper, raises IRQ-off, saves $01 banking byte, sets $01=#$30 (RAM visible at ram_under_io-ram_under_io_end, KERNAL/CHARGEN/I/O all banked out), JSRs the target, restores $01, IRQ-on, return.
;
;   Self-modifying-JSR trick: the JSR operand bytes are *storage* — overwritten
;   by the entry STX/STY pair before each invocation. The pre-patch sentinel
;   value happens to point at kbd_page_band_end, but the runtime never executes
;   that target.
;
;   $01 = #$30 banks out KERNAL ROM + BASIC ROM + I/O simultaneously,
;   making RAM at paint_page_smc_af_aa_c8-harness_coverage_end / ram_under_io-ram_under_io_end / seqLIST_status_painter-VEC_IRQ_HI visible. defMON
;   uses this to access its post-LOAD decoder code that lives in
;   RAM-under-I/O at the RAM-with-I/O decoder band (decoder_block_helper / secondary_song_position_transform / secondary_pat_base_init / secondary_pattern_marker etc.).
jsr_with_ram_helper .block
                           stx  jsr_with_ram_helper + $0F    ; $0BA4
                           sty  jsr_with_ram_helper + $10    ; $0BA7
                           sei    ; $0BAA
                           lda  CPU_PORT    ; $0BAB
                           pha    ; $0BAD
                           lda  #$30    ; $0BAE
                           sta  CPU_PORT    ; $0BB0
; ──── SMC-patched JSR (4 catalogued targets) ────
;   Patched at: $0BA4, $0BA7
;   Banking trampoline (jsr_with_ram_helper) — the caller supplies the
;   target in (X = low byte, Y = high byte), which the helper stores into
;   this JSR operand before banking RAM in over the I/O area and calling.
;   All 5 call sites are in the disk load/save path and pass an immediate
;   target, so the dispatch set is statically complete: the four
;   RAM-under-I/O routines below.
;   Targets:
;     $CEB2  decoder_load_setup                [load ($76D5, $7731)]
;     $CE81  save_prep_orchestrator            [save ($771F)]
;     $D02C  save_encode_orchestrator          [save ($783A)]
;     $D92A  ram_screen_repaint                [post-load screen ($7856)]
                           jsr  kbd_page_band_end    ; $0BB2
                           pla    ; $0BB5
                           sta  CPU_PORT    ; $0BB6
                           cli    ; $0BB8
                           rts    ; $0BB9
.bend

; ──────────────────────────────────────────────────────────────────────
; $0BBA  mode_transition_wrapper
; ──────────────────────────────────────────────────────────────────────
; Mode-transition wrapper.
;
;   callers:             post_load_init_decoder (cold-boot enter-seqED) + 13 mode-switch sites across seqED (seqED_CRSRUD_bare_arm), seqLIST (seqED_sidcall_arm/seqED_cursor_wrap), sidTAB (sidtab_cascade_nomod_entry/sidtab_cascade_nomod_clrhome_arm/sidtab_cascade_cbm_leftarrow_arm/post_write_paint_tail), disk band (shift_x_disk_menu_chord/seqlist_step_row_smc/seqLIST_handler), and the disk-menu paint loop (save_ui_entry).
;   inputs:              A = new ui_mode (UI_MODE_SEQED = seqED, UI_MODE_SEQLIST = seqLIST, UI_MODE_SIDTAB = sidTAB; any other = generic 'mode 4' tail)
;   outputs:             ui_mode = new mode; ui_mode_prev = prev mode (saved before swap); ui_mode_range_bound = $04 (cursor-redraw flag); JMP super_cmd_state_init (editor repaint)
;   registers clobbered: A, X
;
;   Save current ui_mode + super-cmd state, switch to new mode (A on stack), restore that mode's super-cmd state, then dispatch to mode-specific post-switch fixup. Body shape (high level):
;    - save outgoing mode's super-cmd state via super_cmd_state_save (parks
;      it in super_cmd_save_table+slot);
;    - commit the new mode into ui_mode and load its super-cmd state from
;      the same per-mode slot table via super_cmd_state_load;
;    - recolour the border (green when super_cmd_extra is set, default
;      otherwise);
;    - dispatch on the new mode: each arm flips ui_mode_range_bound to its
;      mode-mirror state byte and primes the NMI entry, then jumps to the
;      shared tail mode_transition_wrapper_tail (sets ui_mode_range_bound=UI_MODE_SIDTAB
;      and jumps super_cmd_state_init for the editor repaint).
;   super_cmd_state_save / super_cmd_state_load are the per-mode save/restore
;   primitives; ui_mode_to_slot_idx is the shared mode → slot-index
;   ($0/$1/$2) computer that both use.
;
;   Internal labels (NOT separate functions — sub-labels of mode_transition_wrapper):
;    mode_transition_color_arm border-color + counter-bump arm. BEQ skip-to-mode_transition_color_arm with
;    A=$00 (clear border) or LDA #$05 + JSR border_set_a (red). Then
;    per-new-mode dispatch (CMP ui_mode cascade): seqED/seqLIST
;    → INC editor_row_delta + INC editor_col_delta arranger row-changed counters,
;    set ui_mode_range_bound mode-mirror = UI_MODE_SEQED, nmi_irq_entry = UI_MODE_SEQLIST, JMP mode_transition_wrapper_tail tail.
;    mode_transition_wrapper_tail common tail. STA ui_mode_range_bound = UI_MODE_SIDTAB (cursor repaint flag); JMP
;    super_cmd_state_init (editor repaint dispatch).
mode_transition_wrapper .block
                           pha    ; $0BBA
                           lda  ui_mode    ; $0BBB
                           sta  ui_mode_prev    ; $0BBE
                           jsr  super_cmd_state_save    ; $0BC1
                           pla    ; $0BC4
                           sta  ui_mode    ; $0BC5
                           jsr  super_cmd_state_load    ; $0BC8
                           lda  #$00    ; $0BCB
                           ldx  super_cmd_extra    ; $0BCD
.bend

; ──────────────────────────────────────────────────────────────────────
; $0BD0  mode_transition_color_arm
; ──────────────────────────────────────────────────────────────────────
; Border-color + counter-bump arm inside mode_transition_wrapper.
;
;   code edges:          fall-through from $0BCD in mode_transition_wrapper (3 bytes earlier)
;
;   →skip-to-$0 when zeroBD4 + call border_set_a to recolour the border per super-cmd state; then per-new-mode dispatch bumps editor_row_delta/editor_col_delta arranger row counters and sets ui_mode_range_bound mode-mirror. Not a separate function — see mode_transition_wrapper.
mode_transition_color_arm .block
                           beq  l_1    ; $0BD0  super_cmd_extra was zero?
                           lda  #$05    ; $0BD2
l_1:                       jsr  border_set_a    ; $0BD4
                           lda  ui_mode    ; $0BD7
                           cmp  #UI_MODE_SEQED    ; $0BDA
                           beq  l_2    ; $0BDC  ui_mode was UI_MODE_SEQED?
                           cmp  #UI_MODE_SEQLIST    ; $0BDE
                           bne  l_3    ; $0BE0  ui_mode was not UI_MODE_SEQLIST?
l_2:                       inc  editor_row_delta    ; $0BE2
                           inc  editor_col_delta    ; $0BE5
                           lda  #UI_MODE_SEQED    ; $0BE8
                           sta  ui_mode_range_bound    ; $0BEA
                           lda  #$02    ; $0BED
                           sta  nmi_playback_gate_smc    ; $0BEF
                           jmp  mode_transition_wrapper_tail    ; $0BF2
l_3:                       cmp  #UI_MODE_SIDTAB    ; $0BF5
                           bne  mode_transition_wrapper_tail    ; $0BF7  ui_mode was not UI_MODE_SIDTAB?
                           inc  editor_aux_counter    ; $0BF9
                           lda  #UI_MODE_SEQLIST    ; $0BFC
                           sta  ui_mode_range_bound    ; $0BFE
                           lda  #$03    ; $0C01
                           sta  nmi_playback_gate_smc    ; $0C03
                           jmp  mode_transition_wrapper_tail    ; $0C06
.bend

; ──────────────────────────────────────────────────────────────────────
; $0C09  mode_transition_wrapper_tail
; ──────────────────────────────────────────────────────────────────────
; Common tail of mode_transition_wrapper.
;
;   callers:             3 code sites: $0BF2, $0BF7, $0C06
;
;   write ui_mode_range_bound := UI_MODE_SIDTAB (cursor-redraw flag); jump super_cmd_state_init (editor repaint). Reached from mode_transition_wrapper + mode_transition_color_arm (seqED/seqLIST arm fall-through) + mode_transition_color_arm path. Not a separate function — see mode_transition_wrapper.
mode_transition_wrapper_tail .block
                           lda  #$04    ; $0C09
                           sta  cursor_redraw_flag    ; $0C0B
                           jmp  super_cmd_state_init    ; $0C0E
.bend

; ──────────────────────────────────────────────────────────────────────
; $0C11  super_cmd_state_save
; ──────────────────────────────────────────────────────────────────────
; Super-cmd state save to per-mode slot.
;
;   callers:             mode_transition_wrapper (mode-transition wrapper mode_transition_wrapper — save outgoing mode's state before swap)
;   inputs:              A = current ui_mode (UI_MODE_SEQED/UI_MODE_SEQLIST/UI_MODE_SIDTAB); supercmd_flag_mask..super_arg_slot_z = current super-cmd state
;   outputs:             super_cmd_save_table+slot..super_cmd_save_table_anchor+slot = saved 6-byte state for that mode
;   registers clobbered: A, X
;
;   super_cmd_save_table+X, super_cmd_save_slot_b+X, super_cmd_save_slot_c+X,
;         super_cmd_save_slot_d+X, super_cmd_save_slot_e+X, super_cmd_save_table_end+X.
;     - return.
;
;   The save/restore pair super_cmd_state_save/super_cmd_state_load lets defMON preserve each mode's
;   super-command context across mode switches. When the user CTRL+TAB-
;   equivalents between seqED ↔ sidTAB ↔ seqLIST, the active mode's
;   super-cmd flags (e.g. CTRL+RETURN chain, paste-buffer state) are
;   parked in super_cmd_save_table+ tables and restored when that mode is re-entered.
;   Six bytes × three slots = 18 bytes total at super_cmd_save_table..super_cmd_save_table_anchor.
super_cmd_state_save .block
;     call ui_mode_to_slot_idx (A=ui_mode → X=slot index $00/UI_MODE_SEQED/UI_MODE_SEQLIST).
                           jsr  ui_mode_to_slot_idx    ; $0C11
                           lda  super_cmd_extra    ; $0C14
;     store supercmd_flag_mask..super_arg_slot_z (6 super-cmd state bytes) into slot tables: super_cmd_save_table+X, super_cmd_save_slot_b+X, super_cmd_save_slot_c+X, super_cmd_save_slot_d+X, super_cmd_save_slot_e+X, super_cmd_save_table_end+X.
                           sta  super_cmd_save_table,x    ; $0C17
                           lda  super_arg_slot_r    ; $0C1A
                           sta  super_cmd_save_slot_b,x    ; $0C1D
                           lda  super_arg_slot_q    ; $0C20
                           sta  super_cmd_save_slot_c,x    ; $0C23
                           lda  super_arg_slot_swr_hi    ; $0C26
                           sta  super_cmd_save_slot_d,x    ; $0C29
                           lda  super_arg_slot_w    ; $0C2C
                           sta  super_cmd_save_slot_e,x    ; $0C2F
                           lda  super_arg_slot_z    ; $0C32
                           sta  super_cmd_save_table_end,x    ; $0C35
;     return.
                           rts    ; $0C38
.bend

; ──────────────────────────────────────────────────────────────────────
; $0C39  super_cmd_state_load
; ──────────────────────────────────────────────────────────────────────
; Super-cmd state load from per-mode slot.
;
;   callers:             mode_transition_wrapper (mode-transition wrapper mode_transition_wrapper — restore incoming mode's state after swap)
;   inputs:              A = new ui_mode (UI_MODE_SEQED/UI_MODE_SEQLIST/UI_MODE_SIDTAB); super_cmd_save_table+slot..super_cmd_save_table_anchor+slot = previously-saved state
;   outputs:             supercmd_flag_mask..super_arg_slot_z = restored super-cmd state for the new mode
;   registers clobbered: A, X
;
;   Restores the six saved super-cmd state bytes for the new mode out of
;   the per-slot tables (super_cmd_save_table .. super_cmd_save_table_end) into
;   their live locations (supercmd_flag_mask .. super_arg_slot_z). The internal
;   super_cmd_load_fallthrough label is the continuation point after the first
;   byte restore — it's where the remaining 5 restores live, reached only by
;   fall-through (not a separate entry).
super_cmd_state_load .block
                           jsr  ui_mode_to_slot_idx    ; $0C39
                           lda  super_cmd_save_table,x    ; $0C3C
                           sta  super_cmd_extra    ; $0C3F
.bend

; ──────────────────────────────────────────────────────────────────────
; $0C42  super_cmd_load_fallthrough
; ──────────────────────────────────────────────────────────────────────
; Fall-through label inside super_cmd_state_load super-cmd state restore.
;
;   code edges:          fall-through from $0C3F in super_cmd_state_load (3 bytes earlier)
;   apparent (from data): $AE6E in seqED_header_color_template
;
;   super_cmd_state_load does the mode→slot resolution + first byte restore (supercmd_flag_mask from super_cmd_save_table+X). super_cmd_load_fallthrough then completes the remaining 5 byte restores into super_arg_slot_r..super_arg_slot_z:
;     - super_cmd_save_slot_b+X
;     - super_cmd_save_slot_c+X
;     - super_cmd_save_slot_d+X
;     - super_cmd_save_slot_e+X
;     - super_cmd_save_table_end+X
;
;   Not a separate function — see super_cmd_state_load.
super_cmd_load_fallthrough .block
                           lda  super_cmd_save_slot_b,x    ; $0C42
                           sta  super_arg_slot_r    ; $0C45
                           lda  super_cmd_save_slot_c,x    ; $0C48
                           sta  super_arg_slot_q    ; $0C4B
                           lda  super_cmd_save_slot_d,x    ; $0C4E
                           sta  super_arg_slot_swr_hi    ; $0C51
                           lda  super_cmd_save_slot_e,x    ; $0C54
                           sta  super_arg_slot_w    ; $0C57
                           lda  super_cmd_save_table_end,x    ; $0C5A
                           sta  super_arg_slot_z    ; $0C5D
                           rts    ; $0C60
.bend

; ──────────────────────────────────────────────────────────────────────
; $0C61  ui_mode_to_slot_idx
; ──────────────────────────────────────────────────────────────────────
; ui_mode → slot index.
;
;   callers:             super_cmd_state_save (save), super_cmd_state_load (restore)
;   inputs:              A = ui_mode (must be UI_MODE_SEQED / UI_MODE_SEQLIST / UI_MODE_SIDTAB)
;   outputs:             X = slot index ($00 / $01 / $02)
;   registers clobbered: X
;
;   A=UI_MODE_SEQED → X=$00, A=UI_MODE_SEQLIST → X=UI_MODE_SEQED, A=UI_MODE_SIDTAB → X=UI_MODE_SEQLIST. Used by super_cmd_state_save/super_cmd_state_load super-cmd save/restore. If A is none of those three, falls through to the infinite panic loop at panic_color_loop (increment VIC_BORDER / jump panic_color_loop — flashes border forever); the function relies on a should-never-happen contract that A is one of those three. ui_mode = UI_MODE_DISK (secondary-disk) is NEVER routed through here — mode_transition_wrapper's three-arm cascade ($BC2 / $BDE / $BF5) only feeds UI_MODE_SEQED/UI_MODE_SEQLIST/UI_MODE_SIDTAB into super_cmd_state_save/super_cmd_state_load.
ui_mode_to_slot_idx .block
                           cmp  #$01    ; $0C61
                           bne  l_1    ; $0C63  A was not $01?
                           ldx  #$00    ; $0C65
                           rts    ; $0C67
l_1:                       cmp  #$02    ; $0C68
                           bne  l_2    ; $0C6A  A was not $02?
                           ldx  #$01    ; $0C6C
                           rts    ; $0C6E
l_2:                       cmp  #$04    ; $0C6F
                           bne  panic_color_loop    ; $0C71  A was not $04?
                           ldx  #$02    ; $0C73
                           rts    ; $0C75
.bend

; ──────────────────────────────────────────────────────────────────────
; $0C76  panic_color_loop
; ──────────────────────────────────────────────────────────────────────
; Panic loop: increment VIC_BORDER; jump panic_color_loop.
;
;   callers:             2 code sites: $0C71, $0C79
;   inputs:              (none — terminal loop)
;   registers clobbered: none (preserves A/X/Y)
;
;   Reached only via ui_mode_to_slot_idx fall-through when ui_mode is not UI_MODE_SEQED / UI_MODE_SEQLIST / UI_MODE_SIDTAB — a should-never-happen panic. Three border-color INCs per iteration produce a fast colour-cycle on screen until reset. Only reference is the panic_color_loop JMP panic_color_loop self-jump — no external entry points. The cold-boot path always passes A=UI_MODE_SEQED through ui_mode_to_slot_idx's first arm, so this panic is unreachable from a clean boot.
panic_color_loop .block
                           inc  VIC_BORDER    ; $0C76
                           jmp  panic_color_loop    ; $0C79
        .byte $60    ; $0C7C
        .fill 18, $00    ; $0C7D-$0C8E
.bend

; ──────────────────────────────────────────────────────────────────────
; $0C8F  sid_silence_and_reinit
; ──────────────────────────────────────────────────────────────────────
; sid_silence_and_reinit.
;
;   callers:             save_ui_entry (disk-menu screen init, after stop_playback); global_pre_dispatch_statusline_epilogue, supercmd_cbm_shift_fallthrough, supercmd_cbm_shift_fallthrough (3 super-cmd handlers in the CTRL+R super-cmd band — speed-change + tune-init paths that also silence the voices first).
;   inputs:              stereo_enable = stereo_enable (controls SID#2 mirror)
;   outputs:             SID_V1_FREQ_LO-SID_FILTER_RES (and sid2_base_default-save_encoder_jp_chain_walker if stereo) = 0 except SID_VOL_FILTER=$0F, save_encoder_jp_chain_walker=$0F if stereo, SID_V1_CTRL/B/2=$08 voice-CTRL test-bit, save_encoder_jp_chain_walker/B/2=$08 if stereo.
;   registers clobbered: A, X, Y
;
;   Set master volume to $0F (full open), zero all 24 SID#1 registers SID_V1_FREQ_LO-SID_FILTER_RES (descending X=$11..STEREO_OFF, also writing to SID#2 sid2_base_default,X when stereo_enable stereo flag is set), then raise the TEST bit ($08) on each voice's CTRL register (SID_V1_CTRL/SID_V2_CTRL/SID_V3_CTRL plus the SID#2 mirrors at save_encoder_jp_chain_walker when stereo). The TEST bit holds each oscillator in reset/silence — the voice is muted but ready to start cleanly on the next GATE event.
;
;   Distinct from player_init_body which zeros SID regs but does
;   NOT set the TEST bit and does NOT touch SID#2. sid_silence_and_reinit is the
;   'silence audibly + leave running with TEST asserted' helper used
;   when the UI mode transition wants to immediately silence the SID
;   without resetting the player state machine.
sid_silence_and_reinit .block
                           lda  #$0F    ; $0C8F
                           sta  SID_VOL_FILTER    ; $0C91  ; SID_VOL_FILTER := vol=15
                           ldx  #$11    ; $0C94
                           lda  #$00    ; $0C96
l_1:                       sta  load_decoder_pat_base_walk.SID_V1_FREQ_LO,x    ; $0C98
                           ldy  stereo_enable    ; $0C9B
                           beq  l_2    ; $0C9E  stereo_enable was STEREO_OFF?
                           sta  sid2_base_default,x    ; $0CA0
l_2:                       dex    ; $0CA3
                           bpl  l_1    ; $0CA4  $11 walked back 1 and had bit 7 clear?
                           lda  #$08    ; $0CA6
                           sta  SID_V1_CTRL    ; $0CA8  ; SID_V1_CTRL := wave off TEST
                           sta  load_decoder_pat_base_walk.SID_V2_CTRL    ; $0CAB
                           sta  SID_V3_CTRL    ; $0CAE
                           ldy  stereo_enable    ; $0CB1
                           beq  l_3    ; $0CB4  stereo_enable was STEREO_OFF?
                           sta  sid2_alias_d504    ; $0CB6
                           sta  save_encoder_jp_chain_walker.sid2_alias_d50b    ; $0CB9
                           sta  save_encoder_jp_chain_walker.decoder_state_d512    ; $0CBC
                           lda  #$0F    ; $0CBF
                           sta  sid2_master_volume    ; $0CC1  ; sid2_master_volume := vol=15
l_3:                       rts    ; $0CC4
.bend

; ──────────────────────────────────────────────────────────────────────
; $0CC5  stop_playback
; ──────────────────────────────────────────────────────────────────────
; stop_playback.
;
;   callers:             cold_boot_prelude_midbyte (cold-boot init); save_ui_entry (disk-menu open paint); super-command stop arms.
;   registers clobbered: A
;
;   Zero playback_state (player tick-enable flag) and CIA2_PRB (CIA2 user-port byte = ScannerBoy sync output).
stop_playback .block
                           lda  #PLAYBACK_OFF    ; $0CC5
                           sta  playback_state    ; $0CC7
                           lda  #$00    ; $0CCA
                           sta  CIA2_PRB    ; $0CCC
                           rts    ; $0CCF
.bend

; ──────────────────────────────────────────────────────────────────────
; $0CD0  border_set_a
; ──────────────────────────────────────────────────────────────────────
; Border-color set + state mirror.
;
;   callers:             post_load_startup (cold-boot, A=$00 → black border); mode_transition_color_arm (mode-transition super-cmd recolour, A=$00 or $05); other UI handlers via mode_transition_wrapper tail.
;   inputs:              A = palette index ($00 = black, $05 = green, etc.)
;   registers clobbered: none (preserves A/X/Y)
;
;   Stores A into ui_mode_range_bound (UI state byte for 'current border color') and VIC_BORDER (VIC border).
;
;   Companion routine at border_set_b follows the same shape against ui_mode_range_bound (a second mirrored state byte) — paired with border_set_a for two-state UI feedback (e.g. play vs edit indicator).
border_set_a .block
                           sta  border_color_state_a    ; $0CD0
                           sta  VIC_BORDER    ; $0CD3
                           rts    ; $0CD6
.bend

; ──────────────────────────────────────────────────────────────────────
; $0CD7  border_set_b
; ──────────────────────────────────────────────────────────────────────
; Border-color set + state mirror — companion to border_set_a with a second slot at ui_mode_range_bound.
;
;   callers:             6 code sites: $B679, $C24E, $C256, $E48C, $E4CA, $E529
;   inputs:              A = palette index.
;   registers clobbered: none (preserves A/X/Y)
;
;   Body: write ui_mode_range_bound / write VIC_BORDER / return. Both routines write the SAME border register (VIC_BORDER); they differ only in which state-mirror byte they update — border_set_a owns ui_mode_range_bound, border_set_b owns ui_mode_range_bound — letting callers track two parallel visual-feedback states (e.g. play indicator + super-cmd indicator) without trampling each other's saved value.
border_set_b .block
                           sta  border_color_state_b    ; $0CD7
                           sta  VIC_BORDER    ; $0CDA
                           rts    ; $0CDD
.bend

; ──────────────────────────────────────────────────────────────────────
; $0CDE  screen_row_addr_resolver
; ──────────────────────────────────────────────────────────────────────
; Screen-row address resolver.
;
;   callers:             vic_sprite_init_internal (seqED ui_mode paint), super_cmd_page_commit (sidTAB paint band).
;   inputs:              Y = screen row index (0..24)
;   outputs:             $02/$03 = screen_ram + Y*40 (screen RAM row base)
;   registers clobbered: A
;
;   Y = row index ($00..$18) → $02/$03 := screen RAM address of that row's left edge. Used by the editor paint code for write ($02),Y indirect glyph writes.
;
;   Companion data regions screen_row_addr_lo / screen_row_addr_hi hold the 25-entry screen row LUT (8-bit Y indexes into the C64 25-line text screen).
screen_row_addr_resolver .block
                           lda  screen_row_addr_lo,y    ; $0CDE
                           sta  zp_ptr1_lo    ; $0CE1
                           lda  screen_row_addr_hi,y    ; $0CE3
                           sta  zp_ptr1_hi    ; $0CE6
                           rts    ; $0CE8
.bend

; ──────────────────────────────────────────────────────────────────────
; $0CE9  playhead_follows_cursor
; ──────────────────────────────────────────────────────────────────────
; Per-frame playhead-follows-cursor helper.
;
;   callers:             editor_frame_work_tail (editor frame body, unconditional JSR each iteration)
;   inputs:              playback_state (player playing flag), current_arranger_row / sid2_voice_record_v2 (V0 arranger row indices), sid_chip_view, ui_mode_mirror (prev arranger row mirror), digit_phase (cursor-follow flag), v0_row_timer (gate byte), v0_freq_lookup_smc (sub-position within pattern)
;   outputs:             ui_mode_mirror (updated arranger row mirror), step_cursor, page_pair_counter, editor_row_delta/editor_col_delta (per-voice row-changed flags), screen via seqLIST_step_auto_advance repaint
;   registers clobbered: A, X, Y
;
;   Called once per editor main-loop iteration from editor_frame_work_tail. If playback_state (player tick-enable) is zero, beq to early-exit at speedadj_block_header (return). Otherwise: reads arranger row index current_arranger_row (or sid2_voice_record_v2 for SID#2 view per sid_chip_view); decrement X; if it has changed since last frame (ui_mode_mirror mirror), update ui_mode_mirror and increment editor_col_delta (V1 row-changed flag); then walks digit_phase (a step-cursor-follow flag) + v0_row_timer; conditionally fires call seqLIST_step_auto_advance to repaint plus updates step_cursor + page_pair_counter + bumps editor_row_delta (V0 row-changed flag).
;
;   Fires once per main-loop iteration. Mostly no-ops via the BEQ speedadj_block_header
;   fast-exit when playback_state=PLAYBACK_OFF (no playback). The bulk of the body runs
;   only when playback is active — the cursor visibly follows the
;   player's arranger walk during playback.
playhead_follows_cursor .block
                           lda  playback_state    ; $0CE9
                           beq  l_5    ; $0CEC  playback_state was PLAYBACK_OFF?
                           ldx  current_arranger_row    ; $0CEE
                           lda  sid_chip_view    ; $0CF1
                           beq  l_1    ; $0CF4  sid_chip_view was SID_VIEW_1?
                           ldx  sid2_frame_state_slot    ; $0CF6
l_1:                       dex    ; $0CF9
                           cpx  ui_mode_mirror    ; $0CFA
                           beq  l_2    ; $0CFD
                           lda  v0_row_timer    ; $0CFF
                           bpl  l_2    ; $0D02  v0_row_timer had bit 7 clear?
                           stx  ui_mode_mirror    ; $0D04
                           inc  editor_col_delta    ; $0D07
l_2:                       lda  ui_state_716e    ; $0D0A
                           beq  l_5    ; $0D0D  ui_state_716e was zero?
                           lda  v0_row_timer    ; $0D0F
                           bne  l_5    ; $0D12  v0_row_timer was non-zero?
                           jsr  seqLIST_step_auto_advance    ; $0D14
                           ldx  current_arranger_row    ; $0D17
                           lda  sid_chip_view    ; $0D1A
                           beq  l_3    ; $0D1D  sid_chip_view was SID_VIEW_1?
                           ldx  sid2_frame_state_slot    ; $0D1F
l_3:                       dex    ; $0D22
                           lda  v0_freq_lookup_smc    ; $0D23
                           and  #$7F    ; $0D26
                           lsr  a    ; $0D28
                           lsr  a    ; $0D29
                           sec    ; $0D2A
                           sbc  #SPEEDADJ_PRESET_BOUND    ; $0D2B
                           bcs  l_4    ; $0D2D  preset index ≥ SPEEDADJ_PRESET_BOUND (4-preset table bounds check)
                           dex    ; $0D2F
                           and  #$1F    ; $0D30
l_4:                       sta  step_cursor    ; $0D32
                           stx  page_pair_counter    ; $0D35
                           inc  editor_row_delta    ; $0D38
l_5:                       rts    ; $0D3B
.bend

; ──────────────────────────────────────────────────────────────────────
; $0D3C  speedadj_bump_up
; ──────────────────────────────────────────────────────────────────────
; Speed-adjust sub-arm: bump Timer-A reload UP.
;
;   callers:             2 code sites: $828C speedadj_cbm_f1_bumpup, $8295 speedadj_cbm_f3_bumpup_inv
;
;   Adds A (the modifier-encoded amount A=$01 or A=$80) to the current Timer-A reload, propagating carry to cia2_timer_hi. Dispatched via speedadj_cbm_f1_bumpup (CBM+F1, A=$01) and speedadj_cbm_f3_bumpup_inv (CBM+F3, A=$80) — see speedadj_block_header sub-arm map.
speedadj_bump_up .block
                           clc    ; $0D3C
                           adc  cia2_timer_lo    ; $0D3D
                           sta  cia2_timer_lo    ; $0D40
                           bcc  speedadj_writeback_tail    ; $0D43
                           inc  cia2_timer_hi    ; $0D45
                           jmp  speedadj_writeback_tail    ; $0D48
.bend

; ──────────────────────────────────────────────────────────────────────
; $0D4B  speedadj_bump_down
; ──────────────────────────────────────────────────────────────────────
; Speed-adjust sub-arm: bump Timer-A reload DOWN.
;
;   callers:             2 code sites: $82B3 speedadj_cbmshift_f1_bumpdown, $82BC speedadj_cbmshift_f3_bumpdown_inv
;
;   Subtracts the modifier-encoded amount (A=$01 or A=$80, self-modded into the SBC operand) from cia2_timer_lo, borrowing into cia2_timer_hi when needed. Dispatched via speedadj_cbmshift_f1_bumpdown (CBM+SHIFT+F1, A=$01) and speedadj_cbmshift_f3_bumpdown_inv (CBM+SHIFT+F3, A=$80) — see speedadj_block_header sub-arm map.
speedadj_bump_down .block
                           sta  speedadj_bump_down + $08    ; $0D4B
                           lda  cia2_timer_lo    ; $0D4E
                           sec    ; $0D51
                           sbc  #$FF    ; $0D52  ; ← (SMC operand at $0D53, no name)
                           sta  cia2_timer_lo    ; $0D54
                           bcs  speedadj_writeback_tail    ; $0D57  (cia2_timer_lo − $FF) shifted-out bit was 1?
                           dec  cia2_timer_hi    ; $0D59
                           jmp  speedadj_writeback_tail    ; $0D5C
.bend

; ──────────────────────────────────────────────────────────────────────
; $0D5F  speedadj_shift_left
; ──────────────────────────────────────────────────────────────────────
; Speed-adjust sub-arm: shift Timer-A reload LEFT (×2).
;
;   callers:             1 code sites: $82A3 speedadj_cbm_f7_shiftleft
;
;   set-carry + rotate cia2_timer_lo left + rotate cia2_timer_hi left + jump speedadj_writeback_tail. Doubles the reload. Dispatched via speedadj_cbm_f7_shiftleft (CBM+F7) — see speedadj_block_header sub-arm map.
speedadj_shift_left .block
                           sec    ; $0D5F
l_1:                       rol  cia2_timer_lo    ; $0D60
                           rol  cia2_timer_hi    ; $0D63
                           jmp  speedadj_writeback_tail    ; $0D66
.bend

; ──────────────────────────────────────────────────────────────────────
; $0D69  speedadj_shift_right
; ──────────────────────────────────────────────────────────────────────
; Speed-adjust sub-arm: shift Timer-A reload RIGHT (÷2 with floor at cold_boot_origin).
;
;   callers:             1 code sites: $82CA speedadj_cbmshift_f7_shiftright
;
;   shift cia2_timer_hi right / rotate cia2_timer_lo right; compare cia2_timer_hi with #$08; →speedadj_shift_left when no-carry (re-shift) — clamps the floor by re-doubling if hi < $08. Dispatched via speedadj_cbmshift_f7_shiftright (CBM+SHIFT+F7) — see speedadj_block_header sub-arm map.
speedadj_shift_right .block
                           lsr  cia2_timer_hi    ; $0D69
                           ror  cia2_timer_lo    ; $0D6C
                           lda  cia2_timer_hi    ; $0D6F
                           cmp  #$08    ; $0D72
                           bcc  speedadj_shift_left.l_1    ; $0D74  cia2_timer_hi was below $08?
                           jmp  speedadj_writeback_tail    ; $0D76
.bend

; ──────────────────────────────────────────────────────────────────────
; $0D79  speedadj_preset_loader
; ──────────────────────────────────────────────────────────────────────
; Speed-preset loader.
;
;   callers:             4 sites in CTRL+R super-cmd speed-preset arms: shift_x_disk_menu_chord (X=$01 → preset 0, ~50 Hz PAL VBL), shift_x_disk_menu_chord (X=$02 → preset 1, ~100 Hz), shift_x_disk_menu_chord (X=$04 → preset 2, ~200 Hz), shift_x_disk_menu_chord (X=$08 → preset 3, ~400 Hz / 8-sub-frame). Plus 1 internal call from speedadj_preset_loader (post-adjust write-back chain).
;   inputs:              X = sub_frame_count (SUB_FRAME_1X/SUB_FRAME_2X/SUB_FRAME_4X/SUB_FRAME_8X = preset index 0/1/2/3).
;   outputs:             cia2_timer_lo/cia2_timer_hi = preset Timer-A reload; sub_frame_count = X; sub_frame_phase = $00.
;   registers clobbered: A, X, Y
;
;   Caller passes X = sub_frame_count (SUB_FRAME_1X..SUB_FRAME_8X — number of NMIs per main tick). speedadj_preset_loader converts X to a 0-based preset index via A←X / lsr-loop (counts trailing zero bits), looks up Timer-A reload pair from speedadj_preset_timer_lo_lut (lo) / speedadj_preset_timer_hi_lut (hi), stores into cia2_timer_lo/cia2_timer_hi, raster-syncs on VIC_RASTER, sets X→sub_frame_count, clears sub_frame_phase (sub_frame phase counter), falls into speedadj_writeback_tail for the write-back.
;
;   Preset values from disasm at speedadj_preset_timer_lo_lut (lo) + speedadj_preset_timer_hi_lut (hi):
;    preset 0 (X=$01): cia2_timer_lo=$C7 cia2_timer_hi=$4C (19655 cycles ≈ PAL VBL, ~50 Hz)
;    preset 1 (X=$02): cia2_timer_lo=$63 cia2_timer_hi=$26 (9827 cycles ≈ 100 Hz)
;    preset 2 (X=$04): cia2_timer_lo=$31 cia2_timer_hi=$13 → v1_cascade_slot_triple = 4913 cycles ≈ 200 Hz
;    preset 3 (X=SUB_FRAME_8X): cia2_timer_lo=$98 cia2_timer_hi=$09 → main_loop_tail = 2456 cycles × sub_frame_count=8 = 19648 cycles
;    ≈ 50 Hz main / 400 Hz sub-frame (the high-resolution sub-frame preset).
;
;   The raster-sync wait at speedadj_preset_loader (LDY #$F9; CPY VIC_RASTER; BNE wait)
;   ensures the new Timer-A value takes effect on a clean raster boundary,
;   avoiding a partial-tick glitch.
;
;   The TXA / LSR-loop at speedadj_preset_loader counts the trailing zeros of X to
;   produce the preset index — works because X is constrained to one of
;   $01/$02/$04/$08 by the caller.
speedadj_preset_loader .block
                           ldy  #$FF    ; $0D79
                           txa    ; $0D7B
l_1:                       iny    ; $0D7C
                           lsr  a    ; $0D7D
                           bcc  l_1    ; $0D7E
                           lda  speedadj_preset_timer_lo_lut,y    ; $0D80
                           sta  cia2_timer_lo    ; $0D83
                           lda  speedadj_preset_timer_hi_lut,y    ; $0D86
                           sta  cia2_timer_hi    ; $0D89
                           ldy  #$F9    ; $0D8C
l_2:                       cpy  VIC_RASTER    ; $0D8E
                           bne  l_2    ; $0D91  $F9 was not VIC_RASTER?
                           iny    ; $0D93
l_3:                       cpy  VIC_RASTER    ; $0D94
                           bne  l_3    ; $0D97  ($F9 + 1) was not VIC_RASTER?
                           stx  sub_frame_count    ; $0D99
                           lda  #$00    ; $0D9C
                           sta  sub_frame_phase    ; $0D9E
                           jmp  speedadj_writeback_tail    ; $0DA1
        .byte $C7, $63, $31, $98, $4C, $26, $13, $09    ; $0DA4
.bend

; ──────────────────────────────────────────────────────────────────────
; $0DAC  speedadj_writeback_tail
; ──────────────────────────────────────────────────────────────────────
; Timer-A write-back tail (shared by all 6 speed-adjust super-cmd arms).
;
;   callers:             7 internal sites in speedadj_block_header-speedadj_ldy_smc speed-adjust block: speedadj_bump_up (INC carry-clear from speedadj_bump_up), speedadj_bump_up (post-INC fall-through), speedadj_bump_down (DEC carry-set from speedadj_bump_down), speedadj_bump_down (post-DEC fall-through), speedadj_shift_left (post-ROL ×2), speedadj_shift_right (post-LSR /2 with clamp), speedadj_preset_loader (post-preset write from speedadj_preset_loader).
;   inputs:              cia2_timer_lo / cia2_timer_hi = new Timer-A reload.
;   outputs:             CIA2_TA_LO / CIA2_TA_HI = Timer-A registers; status line repainted.
;   registers clobbered: A, X, Y
;
;   Installs the new Timer-A reload into the CIA registers, then repaints the status line with the current Timer-A value as hex digits.
speedadj_writeback_tail .block
                           lda  cia2_timer_lo    ; $0DAC
                           sta  CIA2_TA_LO    ; $0DAF
                           lda  cia2_timer_hi    ; $0DB2
                           sta  CIA2_TA_HI    ; $0DB5
                           jsr  statusline_clear    ; $0DB8
;     $14 = 'T' (Timer status-line column glyph)
                           lda  #$14    ; $0DBB
                           jsr  statusline_print_char    ; $0DBD
;     $20 = space (separator)
                           lda  #$20    ; $0DC0
                           jsr  statusline_print_char    ; $0DC2
;     $24 = '$' (hex marker)
                           lda  #$24    ; $0DC5
                           jsr  statusline_print_char    ; $0DC7
                           ldx  cia2_timer_hi    ; $0DCA
                           jsr  statusline_print_hex_byte    ; $0DCD
                           ldx  cia2_timer_lo    ; $0DD0
                           jmp  statusline_print_hex_byte    ; $0DD3
.bend

; ──────────────────────────────────────────────────────────────────────
; $0DD6  speedadj_subframe_up
; ──────────────────────────────────────────────────────────────────────
; Sub-frame-count bump UP.
;
;   callers:             speedadj_cbm_f5_subframe_up (CBM+F5 arm in the CBM+F-key parser cascade).
;   inputs:              X
;   outputs:             sub_frame_count = clamp(prev + 1, 1, 8); status line repainted via speedadj_status_repaint.
;   registers clobbered: A, X, Y
;
;   Reads sub_frame_count; if it's already SUB_FRAME_8X, beq to speedadj_status_repaint (status repaint, no-op). Else increment sub_frame_count and fall through to speedadj_status_repaint. Pairs with speedadj_subframe_down (bump DOWN); both adjust the sub-frame divider within [1, 8]. Adjusting sub_frame_count alone (without changing cia2_timer_lo/cia2_timer_hi Timer-A reload) re-divides the per-tune main-tick rate. Use speedadj_preset_loader to load a full preset (Timer-A + sub_frame_count).
speedadj_subframe_up .block
                           lda  sub_frame_count    ; $0DD6
                           cmp  #SUB_FRAME_8X    ; $0DD9
                           beq  speedadj_status_repaint    ; $0DDB  sub_frame_count was SUB_FRAME_8X?
                           inc  sub_frame_count    ; $0DDD
                           jmp  speedadj_status_repaint    ; $0DE0
.bend

; ──────────────────────────────────────────────────────────────────────
; $0DE3  speedadj_subframe_down
; ──────────────────────────────────────────────────────────────────────
; Sub-frame-count bump DOWN.
;
;   callers:             speedadj_cbmshift_f5_subframe_dn (CBM+SHIFT+F5 arm in the CBM+F-key parser cascade).
;   inputs:              X
;   outputs:             sub_frame_count = clamp(prev - 1, 1, 8); status line repainted via speedadj_status_repaint.
;   registers clobbered: A, X, Y
;
;   Reads sub_frame_count; if it's already SUB_FRAME_1X, beq to speedadj_status_repaint (no-op). Else decrement sub_frame_count and fall through to speedadj_status_repaint. Companion to speedadj_subframe_up (bump UP).
speedadj_subframe_down .block
                           lda  sub_frame_count    ; $0DE3
                           cmp  #SUB_FRAME_1X    ; $0DE6
                           beq  speedadj_status_repaint    ; $0DE8  sub_frame_count was SUB_FRAME_1X?
                           dec  sub_frame_count    ; $0DEA
.bend

; ──────────────────────────────────────────────────────────────────────
; $0DED  speedadj_status_repaint
; ──────────────────────────────────────────────────────────────────────
; Speed-adjust status-line repaint.
;
;   callers:             speedadj_subframe_up (post-clamp/INC), speedadj_subframe_down (post-clamp/DEC), speedadj_subframe_up (post-INC fall-through), speedadj_subframe_down (post-DEC fall-through). External: speedadj_subframe_up JMP.
;   inputs:              sub_frame_count = current sub_frame_count (1..8).
;   outputs:             status line shows 'SUB N' style indicator.
;   registers clobbered: A, X, Y
;
;   Tail shared by speedadj_subframe_up / speedadj_subframe_down and their fall-throughs at speedadj_subframe_up / speedadj_subframe_down. Sequence:
;     - call statusline_clear (status-line clear).
;     - walk a 7-byte literal prefix at kbd_scan_modifier_operand_bytes (X=$06..$00 →loop when positive), printing each via print_char_to_statusline (status-line glyph print).
;     - X ← sub_frame_count / read hex_digit_lo_lut,X (sub-frame screen-code digit LUT) / jump print_char_to_statusline to print the current sub_frame_count value.
;
;   kbd_scan_modifier_operand_bytes..paint_ui_selection_cell is a 7-byte status-line prefix data segment (printed right-to-left via the X=6..0 BPL loop).
speedadj_status_repaint .block
                           jsr  statusline_clear    ; $0DED
                           ldx  #$06    ; $0DF0
l_1:                       lda  kbd_scan_modifier_operand_bytes,x    ; $0DF2
                           jsr  statusline_print_char    ; $0DF5
                           dex    ; $0DF8
                           bpl  l_1    ; $0DF9  statusline_print_char->X walked back 1 and had bit 7 clear?
                           ldx  sub_frame_count    ; $0DFB
                           lda  hex_digit_lo_lut,x    ; $0DFE
                           jmp  statusline_print_char    ; $0E01
        .byte $2F, $31, $20, $04, $10, $13    ; $0E04
.bend

; ──────────────────────────────────────────────────────────────────────
; $0E0A  paint_ui_selection_cell
; ──────────────────────────────────────────────────────────────────────
; Paint UI selection cell.
;
;   callers:             12 sites across the field-writer band, the cursor-highlight helpers, and scroll-redraw.
;   inputs:              A = selected flag ($00 = unselected → glyph $D1 / color $00; non-zero → glyph $A0 / color $02); X = color-RAM row index (used in seqED/seqLIST path, 4-cell stride); Y = screen-RAM offset within SCREEN_RAM_SIDTAB_GLYPH+ (used in sidTAB/disk path).
;   outputs:             A
;   registers clobbered: A
;
;   Mode-aware: in seqED ($01) / seqLIST ($02), paint 4 color-RAM cells at COLOR_RAM+x..psid_export_template+x; in sidTAB / disk modes, paint one screen-RAM glyph at SCREEN_RAM_SIDTAB_GLYPH+y. INCs boot_init_band (paint-count instrumentation byte) on entry.
;
;   The fork at paint_ui_selection_cell (CMP #$01 / CMP #$02) routes to the 4-color-cell
;   painter; everything else (notably ui_mode UI_MODE_SIDTAB = sidTAB, UI_MODE_DISK =
;   secondary-disk) takes the 1-screen-glyph painter. The two paths are
;   deliberately *different geometries*, not a stride choice — seqED uses
;   horizontal 4-cell row highlights, sidTAB/disk uses single-glyph cursor.
paint_ui_selection_cell .block
                           pha    ; $0E0A
                           inc  nmi_sid2_silence_count + $01    ; $0E0B
                           lda  ui_mode    ; $0E0E
                           cmp  #UI_MODE_SEQED    ; $0E11
                           beq  paint_selection_glyph_write.l_1    ; $0E13  ui_mode was UI_MODE_SEQED?
                           cmp  #UI_MODE_SEQLIST    ; $0E15
                           beq  paint_selection_glyph_write.l_1    ; $0E17  ui_mode was UI_MODE_SEQLIST?
                           pla    ; $0E19
                           beq  l_1    ; $0E1A  A was zero?
                           lda  #$A0    ; $0E1C
                           jmp  paint_selection_glyph_write    ; $0E1E
l_1:                       lda  #$D1    ; $0E21
.bend

; ──────────────────────────────────────────────────────────────────────
; $0E23  paint_selection_glyph_write
; ──────────────────────────────────────────────────────────────────────
; Shared screen-RAM glyph write inside paint_ui_selection_cell's sidTAB/disk arm: write SCREEN_RAM_SIDTAB_GLYPH,Y / return.
;
;   callers:             1 code sites: $0E1E
;
;   Reached either from paint_ui_selection_cell (jmp, after A=$A0 selected-glyph load) or as fall-through from paint_ui_selection_cell (A=$D1 unselected glyph). Not a separate function — see paint_ui_selection_cell.
paint_selection_glyph_write .block
                           sta  SCREEN_RAM_SIDTAB_GLYPH,y    ; $0E23
                           rts    ; $0E26
l_1:                       pla    ; $0E27
                           beq  l_2    ; $0E28  A was zero?
                           lda  #$02    ; $0E2A
l_2:                       sta  COLOR_RAM,x    ; $0E2C
                           sta  COLOR_RAM + $01,x    ; $0E2F
                           sta  COLOR_RAM + $02,x    ; $0E32
                           sta  COLOR_RAM + $03,x    ; $0E35
                           rts    ; $0E38
        .byte $00, $00, $00, $00, $00, $00, $00, $00, $00, $00, $00, $00, $00, $02    ; $0E39
.bend

; ──────────────────────────────────────────────────────────────────────
; $0E47  kbd_scan
; ──────────────────────────────────────────────────────────────────────
; Keyboard scan + decoded-key dispatch.
;
;   callers:             9 sites: main_loop (editor main_loop input scan) + 8 disk-band loops (disk_menu_close_tail, dir_entry_inner_loop, disk_confirm_prompt_loop, disk_menu_kbd_scan, disk_menu_save_banner_dismiss, disk_menu_save_banner_dismiss, disk_menu_ui_band_end, filename_prompt_paint) — each disk-menu input-wait body calls kbd_scan to poll for the user's next key.
;   inputs:              CIA1_PRA/CIA1_PRB = CIA-1 keyboard matrix rows.
;   outputs:             kbd_matrix_mirror-kbd_matrix_mirror_end = matrix mirror (per-row bitmap); kbd_decoded_key = decoded key screen-code ($FF = no key); kbd_modifiers = modifier mask (via modifier_extract); kbd_voice_mute = voice-mute mask (via modifier_extract); kbd_debounce_counter = debounce countdown.
;   registers clobbered: A, X, Y
;
;   Walks all 8 CIA-1 keyboard matrix rows, writes the 8-byte mirror to
;   kbd_matrix_mirror..kbd_matrix_mirror_end, decodes the first pressed key
;   into kbd_decoded_key (scancode → screen code via the kbd_scancode_lut
;   LUT), runs modifier_extract for the modifier mask, and debounces against
;   the previous-frame state.
;
;   Three notable sub-labels within the body:
;    kbd_scan_inner_continue   the hot scancode-walk inner-loop body — 64
;                              iterations per call, restarts here after an
;                              unbound-key skip.
;    kbd_scan_samekey_branch   same-key dispatch branch (auto-repeat path).
;    kbd_scan_samemod_branch   same-modifier dispatch branch (debounce
;                              countdown; commits auto-repeat at zero via
;                              retry_counter_reload).
;
;   Debounce reload is 12 frames (Y=$0C → kbd_debounce_counter).
kbd_scan .block
                           lda  #$00    ; $0E47
                           sta  CIA1_PRA    ; $0E49
l_1:                       lda  CIA1_PRB    ; $0E4C
                           cmp  CIA1_PRB    ; $0E4F
                           bne  l_1    ; $0E52  CIA1_PRB was not CIA1_PRB?
                           cmp  #$FF    ; $0E54
                           bne  l_3    ; $0E56  CIA1_PRB was not $FF?
l_2:                       lda  #$01    ; $0E58
                           sta  kbd_debounce_counter    ; $0E5A
                           lda  kbd_decoded_key    ; $0E5D
                           sta  kbd_decoded_key_prev    ; $0E60
                           lda  #$00    ; $0E63
                           sta  kbd_modifiers    ; $0E65
                           lda  #KEY_NONE    ; $0E68
                           sta  kbd_decoded_key    ; $0E6A
                           rts    ; $0E6D
l_3:                       lda  #$FF    ; $0E6E
                           sta  CIA1_PRA    ; $0E70
l_4:                       lda  CIA1_PRB    ; $0E73
                           cmp  CIA1_PRB    ; $0E76
                           bne  l_4    ; $0E79  CIA1_PRB was not CIA1_PRB?
                           cmp  #$FF    ; $0E7B
                           bne  l_2    ; $0E7D  CIA1_PRB was not $FF?
                           lda  kbd_decoded_key    ; $0E7F
                           sta  kbd_decoded_key_prev    ; $0E82
                           lda  kbd_modifiers    ; $0E85
                           sta  kbd_modifiers_prev    ; $0E88
                           ldx  #$07    ; $0E8B
                           lda  #$FE    ; $0E8D
                           sta  kbd_scan + $4C    ; $0E8F
l_5:                       lda  #$FE    ; $0E92  ; ← (SMC operand at $0E93, no name)
                           sta  CIA1_PRA    ; $0E94
l_6:                       lda  CIA1_PRB    ; $0E97
                           cmp  CIA1_PRB    ; $0E9A
                           bne  l_6    ; $0E9D  CIA1_PRB was not CIA1_PRB?
                           eor  #$FF    ; $0E9F
                           sta  kbd_matrix_mirror,x    ; $0EA1
                           sec    ; $0EA4
                           rol  kbd_scan + $4C    ; $0EA5
                           dex    ; $0EA8
                           bpl  l_5    ; $0EA9  $07 walked back 1 and had bit 7 clear?
                           ldx  #$00    ; $0EAB
                           stx  kbd_modifiers    ; $0EAD
                           stx  kbd_voice_mute    ; $0EB0
                           lda  #$FF    ; $0EB3
                           sta  CIA1_PRA    ; $0EB5
l_7:                       lda  CIA1_PRB    ; $0EB8
                           cmp  CIA1_PRB    ; $0EBB
                           bne  l_7    ; $0EBE  CIA1_PRB was not CIA1_PRB?
                           cmp  #$FF    ; $0EC0
                           bne  l_2    ; $0EC2  CIA1_PRB was not $FF?
                           lda  #$00    ; $0EC4
                           sta  kbd_scan + $89    ; $0EC6
                           ldy  #$3F    ; $0EC9
l_8:                       cpy  #$FF    ; $0ECB
                           beq  kbd_scan_inner_continue.l_1    ; $0ECD  ($3F − 1) was $FF?
                           ldx  #$FF    ; $0ECF  ; ← (SMC operand at $0ED0, no name)
                           lda  kbd_matrix_mirror,x    ; $0ED1
                           inc  kbd_scan + $89    ; $0ED4
                           ldx  #$07    ; $0ED7
l_9:                       ror  a    ; $0ED9
                           bcs  kbd_scan_inner_continue.l_2    ; $0EDA
.bend

; ──────────────────────────────────────────────────────────────────────
; $0EDC  kbd_scan_inner_continue
; ──────────────────────────────────────────────────────────────────────
; Per-row inner-scan continuation inside kbd_scan.
;
;   callers:             1 code sites: $0EF7
;
;   decrement Y re-entry from kbd_scan_inner_continue jump after a kbd_scancode_lut,Y scancode-LUT miss. Hot inner loop while any key is held. Internal label of kbd_scan.
kbd_scan_inner_continue .block
                           dey    ; $0EDC
                           dex    ; $0EDD
                           bpl  kbd_scan.l_9    ; $0EDE  $07 walked back 1 and had bit 7 clear?
                           bmi  kbd_scan.l_8    ; $0EE0  $07 walked back 1 and had bit 7 set?
l_1:                       jsr  modifier_extract    ; $0EE2
                           lda  #KEY_NONE    ; $0EE5
                           sta  kbd_decoded_key    ; $0EE7
                           rts    ; $0EEA
l_2:                       sta  kbd_scan_inner_continue + $1A    ; $0EEB
                           lda  kbd_scancode_lut,y    ; $0EEE
                           cmp  #$FF    ; $0EF1
                           bne  l_3    ; $0EF3  kbd_scancode_lut,Y was not $FF?
                           lda  #KEY_NONE    ; $0EF5  ; ← (SMC operand at $0EF6, no name)
                           jmp  kbd_scan_inner_continue    ; $0EF7
l_3:                       sta  kbd_decoded_key    ; $0EFA
                           jsr  modifier_extract    ; $0EFD
                           lda  kbd_decoded_key    ; $0F00
                           cmp  kbd_decoded_key_prev    ; $0F03
.bend

; ──────────────────────────────────────────────────────────────────────
; $0F06  kbd_scan_samekey_branch
; ──────────────────────────────────────────────────────────────────────
; Same-key dispatch branch inside kbd_scan (→kbd_scan_samemod_branch when nonzero → key-changed reset).
;
;   code edges:          fall-through from $0F03 in kbd_scan_inner_continue_3 (3 bytes earlier)
;   apparent (from data): $7765 in disk_subtitle_template
;
;   Reached once per debounce check. Internal label of kbd_scan.
kbd_scan_samekey_branch .block
                           bne  kbd_scan_samemod_branch.l_2    ; $0F06  kbd_decoded_key was not kbd_decoded_key_prev?
                           ldy  kbd_modifiers_prev    ; $0F08
                           cpy  kbd_modifiers    ; $0F0B
.bend

; ──────────────────────────────────────────────────────────────────────
; $0F0E  kbd_scan_samemod_branch
; ──────────────────────────────────────────────────────────────────────
; Same-modifier dispatch branch inside kbd_scan (→retry_counter_reload when nonzero → mods-changed reset).
;
;   code edges:          fall-through from $0F0B in kbd_scan_samekey_branch (3 bytes earlier)
;   apparent (from data): $167C in pitch_lut_band_padding, $7775 in disk_subtitle_template
;
;   Reached when the held-key bytes match but the modifier mask may have flipped. Internal label of kbd_scan.
kbd_scan_samemod_branch .block
                           bne  retry_counter_reload.l_1    ; $0F0E  kbd_modifiers_prev was not kbd_modifiers?
l_1:                       dec  kbd_debounce_counter    ; $0F10
                           beq  retry_counter_reload    ; $0F13  (kbd_debounce_counter − 1) was zero?
                           lda  #$FF    ; $0F15
                           rts    ; $0F17
l_2:                       ldy  #$0C    ; $0F18
                           sty  kbd_debounce_counter    ; $0F1A
                           rts    ; $0F1D
.bend

; ──────────────────────────────────────────────────────────────────────
; $0F1E  retry_counter_reload
; ──────────────────────────────────────────────────────────────────────
; 3-instruction helper: Y←$02 / Y→kbd_debounce_counter / return.
;
;   callers:             kbd_scan_samemod_branch BEQ (only).
;   registers clobbered: Y
;
;   Resets the keyboard-state retry counter at kbd_debounce_counter to 2. Reached by →retry_counter_reload when zero from kbd_scan_samemod_branch (the retry-budget-exhausted branch of kbd_dead_trampoline's dead path).
retry_counter_reload .block
                           ldy  #$02    ; $0F1E
                           sty  kbd_debounce_counter    ; $0F20
                           rts    ; $0F23
l_1:                       cmp  #KEY_CRSRLR    ; $0F24
                           beq  kbd_scan_samemod_branch.l_1    ; $0F26  kbd_decoded_key was KEY_CRSRLR?
                           cmp  #KEY_CRSRUD    ; $0F28
                           beq  kbd_scan_samemod_branch.l_1    ; $0F2A  kbd_decoded_key was KEY_CRSRUD?
                           lda  #$FF    ; $0F2C
                           sta  kbd_debounce_counter    ; $0F2E
                           rts    ; $0F31
.bend

; ──────────────────────────────────────────────────────────────────────
; $0F32  modifier_extract
; ──────────────────────────────────────────────────────────────────────
; Modifier extractor.
;
;   callers:             2 code sites: $0EE2 kbd_scan_inner_continue_1, $0EFD
;   outputs:             kbd_modifiers = KBD_MOD_CTRL CTRL | KBD_MOD_SHIFT SHIFT | KBD_MOD_CBM CBM; kbd_voice_mute = voice-mute toggles
;   registers clobbered: A
;
;   Builds kbd_modifiers (mod byte) and kbd_voice_mute (voice-mute) from matrix mirror at kbd_matrix_mirror..kbd_matrix_mirror_end.
modifier_extract .block
                           lda  kbd_matrix_mirror + $06    ; $0F32
                           and  #$80    ; $0F35
                           beq  l_1    ; $0F37  (paint_selection_glyph_write_$1C & $80) was zero?
                           lda  kbd_modifiers    ; $0F39
                           ora  #$10    ; $0F3C
                           sta  kbd_modifiers    ; $0F3E
l_1:                       lda  kbd_matrix_row1    ; $0F41
                           and  #$10    ; $0F44
                           ora  kbd_modifiers    ; $0F46
                           sta  kbd_modifiers    ; $0F49
                           lda  kbd_matrix_mirror    ; $0F4C
                           and  #$04    ; $0F4F
                           ora  kbd_modifiers    ; $0F51
                           sta  kbd_modifiers    ; $0F54
                           lda  kbd_matrix_mirror    ; $0F57
                           and  #$20    ; $0F5A
                           ora  kbd_modifiers    ; $0F5C
                           sta  kbd_modifiers    ; $0F5F
                           lda  kbd_matrix_mirror + $02    ; $0F62
                           and  #$20    ; $0F65
                           beq  l_2    ; $0F67  (paint_selection_glyph_write_$18 & $20) was zero?
                           lda  kbd_voice_mute    ; $0F69
                           ora  #$01    ; $0F6C
                           sta  kbd_voice_mute    ; $0F6E
l_2:                       lda  kbd_matrix_row1    ; $0F71
                           and  #$04    ; $0F74
                           beq  l_3    ; $0F76  (kbd_matrix_row1 & $04) was zero?
                           lda  kbd_voice_mute    ; $0F78
                           ora  #$02    ; $0F7B
                           sta  kbd_voice_mute    ; $0F7D
l_3:                       lda  kbd_matrix_row1    ; $0F80
                           and  #$20    ; $0F83
                           beq  l_4    ; $0F85  (kbd_matrix_row1 & $20) was zero?
                           lda  kbd_voice_mute    ; $0F87
                           ora  #$04    ; $0F8A
                           sta  kbd_voice_mute    ; $0F8C
l_4:                       rts    ; $0F8F
        .byte $6F, $B5, $B3, $B1, $B7, $6A, $92, $84, $FF, $05, $13, $1A, $34, $01, $17, $33    ; $0F90
        .byte $18, $14, $06, $03, $36, $04, $12, $35, $16, $15, $08, $02, $38, $07, $19, $37    ; $0FA0
        .byte $0E, $0F, $0B, $0D, $30, $0A, $09, $39, $2C, $1D, $FE, $2E, $3D, $0C, $10, $2D    ; $0FB0
        .byte $2F, $1E, $FE, $FF, $88, $FE, $00, $3A, $93, $11, $FF, $20, $32, $FF, $1F, $31    ; $0FC0
        .fill 34, $00    ; $0FD0-$0FF1
        .byte $32, $30, $32, $30, $31, $30, $30, $38, $32, $32, $30, $31, $34, $33    ; $0FF2
.bend

; ──────────────────────────────────────────────────────────────────────
; $1000  player_init
; ──────────────────────────────────────────────────────────────────────
; player_init.
;
;   callers:             2 code sites: $7878, $8194
;   inputs:              A
;   registers clobbered: A, X, Y
;
;   A=tune index; call once after LOAD to bootstrap player state.
player_init .block
                           jmp  player_init_body    ; $1000
.bend

; ──────────────────────────────────────────────────────────────────────
; $1003  player_play
; ──────────────────────────────────────────────────────────────────────
; player_play.
;
;   callers:             2 code sites: $0B33 nmi_subframe_call_site, $81CA
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Call every frame from IRQ to advance playback.
player_play .block
                           jmp  player_play_body    ; $1003
.bend

; ──────────────────────────────────────────────────────────────────────
; $1006  player_sound_update
; ──────────────────────────────────────────────────────────────────────
; player_sound_update.
;
;   callers:             1 code sites: $0B04
;   registers clobbered: A, X, Y
;
;   Sub-frame SID write update (per ScannerBoy / CIA2_PRB sync model).
;
;   The sub-frame path patches the in-line sentinel at subframe_sentinel_opcode
;   to $60 (RTS opcode, which also happens to read as a positive byte for the
;   BPL gate at row_advance_gate). With that gate disabled, calling
;   player_play_body pushes the current row's SID register block without
;   advancing pattern rows or the slide oscillator. The sentinel is restored
;   before tailing into the sidTAB cascade at sidtab_cascade_entry, so
;   sidTAB-driven envelopes still tick at sub-frame rate. This dual-purpose
;   $60 trick is what keeps the sub-frame path divergent from the full-frame
;   entry at player_play.
player_sound_update .block
                           lda  subframe_sentinel_opcode    ; $1006
                           pha    ; $1009
                           lda  #$60    ; $100A
                           sta  subframe_sentinel_opcode    ; $100C
                           jsr  player_play_body    ; $100F
                           pla    ; $1012
                           sta  subframe_sentinel_opcode    ; $1013
.bend

; ──────────────────────────────────────────────────────────────────────
; $1016  player_sound_update_jmp_tail
; ──────────────────────────────────────────────────────────────────────
; Final instruction of player_sound_update — `jump sidtab_cascade_entry` (3 bytes $4C $DF $12).
;
;   code edges:          fall-through from $1013 in player_sound_update (3 bytes earlier)
;
;   Unconditionally jumps to the sidTAB cascade tail after player_sound_update restores the subframe_sentinel_opcode sentinel, so the cascade ticks once per sub-frame NMI just like a main-tick NMI. This is why the cascade decrements every voice's step counter on every NMI.
player_sound_update_jmp_tail .block
                           jmp  sidtab_cascade_entry    ; $1016
        .byte $00, $00, $00, $00, $00, $00, $00, $01, $FE    ; $1019
.bend

; ──────────────────────────────────────────────────────────────────────
; $1022  player_play_body
; ──────────────────────────────────────────────────────────────────────
; main per-frame player tick.
;
;   callers:             2 code sites: $1003 player_play, $100F
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Falls through V0/V1/V2 SID-write band (player_play_body-filter_resonance_routing), SID#1 globals + filter slide (filter_resonance_routing-filter_cutoff_block_end), then the sentinel bpl at row_advance_gate gates the pattern-row advance phase (skipped when called via player_sound_update sub-frame path). Tail JMPs through the 6-step sidTAB cascade (sidtab_cascade_entry-v2_sc2_cascade_slot_triple) and the per-voice pitch oscillator (pitch_slide_oscillator-groove_song_position).
;
;   Pervasively self-modified. Every `lda #$00` immediate in the SID-write
;   band (player_play_body-filter_resonance_routing) is a patch slot whose operand byte serves as the
;   voice's working register, indexed by X = $00 (V0) / $31 (V1) / $62 (V2)
;   by callers like the sidTAB writer at sidtab_row_apply and the slide oscillator at
;   pitch_slide_oscillator. Reordering instructions in this band will break those reads —
;   the per-voice offsets are baked into the instruction layout.
;
;   SID-write band writes per voice:
;    V0 → SID_V1_FREQ_LO-SID_V1_SR (freq lo/hi, pulse lo/hi, control + EOR-gate, A/D, S/R)
;    V1 → SID_V2_FREQ_LO-SID_V2_SR
;    V2 → SID_V3_FREQ_LO-SID_V3_SR
;   plus globals at v2_sid_write_band..filter_cutoff_block_end:
;    SID_FC_LO filter cutoff lo (immediate; usually 0)
;    SID_FILTER_RES filter resonance/routing (from filter_resonance_routing)
;    SID_VOL_FILTER volume ($0F OR filter_volume_or_mode mode)
;    SID_FC_HI filter cutoff hi (driven by slide accumulator filter_cutoff_slide_accumulator..)
;
;   Pattern row advance (row_advance_gate-row_advance_band_end): decrements per-voice row timers
;   v0_row_timer / v1_row_timer / v2_row_timer; on underflow, advances the arranger ($1B/$1C/$1D
;   indexed by Y=current_arranger_row), refreshes pat_base pointers (v0_freq_lookup_smc/row_read_body_v1/row_read_body_v2),
;   copies row bytes into the SID-write patch slots, and bumps Y.
;
;   Tail JMP sidtab_cascade_entry runs the 6-step sidTAB cascade (V0/V1/V2 × sidcall1/2),
;   each step dec'ing its own step-counter (v0_sc1_counter/v1_sc1_counter/v2_sc1_counter/v0_sc2_counter/v1_sc2_counter/
;   v2_sc2_counter), then on underflow re-fetches a sidTAB row pointer via the
;   song_position_arrays (sidtab_row_lo/sidtab_row_hi — post-LOAD these hold the runtime
;   sidtab_data_base+X*$0F pointers secondary_song_position_transform wrote) and calls sidtab_row_apply to apply it.
player_play_body .block
                           ldx  #$00    ; $1022  ; ← pw_lo_patch_v0
                           lda  #$00    ; $1024  ; ← pw_hi_patch_v0
; ──── SMC-patched OPCODE — instruction TYPE changes at runtime ────
;   Patched at: $C5A6
;   STX can flip to: JMP
;   When patched, jumps to:
;     $1053  v1_sid_write_band             [skip V0 SID writes]
;   STX -> JMP: when voice 0's wave is off, the SID-write band entry is overwritten with a jump that skips V0's SID writes; restored to STX when the voice plays again.
l_1:                       stx  SID_V1_PW_LO    ; $1026
                           sta  load_decoder_pat_base_walk.SID_V1_PW_HI    ; $1029
                           ldx  #$00    ; $102C  ; ← slide_acc_commit_lo
                           lda  #$00    ; $102E  ; ← slide_acc_commit_hi
                           stx  load_decoder_pat_base_walk.SID_V1_FREQ_LO    ; $1030
                           sta  SID_V1_FREQ_HI    ; $1033
                           ldx  #$00    ; $1036  ; ← v0_sid_patch_a
                           ldy  #$00    ; $1038  ; ← v0_sid_patch_b
                           lda  #$00    ; $103A  ; ← v0_sid_patch_c
                           eor  #$00    ; $103C  ; ← v0_sid_patch_d
                           stx  load_decoder_pat_base_walk.SID_V1_SR    ; $103E
                           sty  SID_V1_AD    ; $1041
                           sta  SID_V1_CTRL    ; $1044
                           jmp  v1_sid_write_band    ; $1047
        .byte $00, $00, $00, $00, $00, $00, $01, $02, $FD    ; $104A
.bend

; ──────────────────────────────────────────────────────────────────────
; $1053  v1_sid_write_band
; ──────────────────────────────────────────────────────────────────────
; V1 SID-write band — voice-1 analog of player_play_body.
;
;   callers:             1 code sites: $1047
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Falls through from pw_hi_patch_v0 jmp at end of V0 band. Same shape as V0: stx/write pulse-width into SID_V2_PW_LO/SID_V2_PW_HI (v1_sid_write_band), freq lo/hi into SID_V2_FREQ_LO/SID_V2_FREQ_HI (v1_sid_write_band), then S/R into SID_V2_SR (v1_sid_write_band), A/D into SID_V2_AD (v1_sid_write_band), ctrl_main eor ctrl_eor into SID_V2_CTRL (v1_sid_write_band). Per-voice working record at voice_record_v1 (offsets voice_record_v1..v1_voice_record_pad = slide accumulator lo/hi/mode; v1_sid_write_band = SID-write patch slots indexed by X=$31). Tail JMPs to v2_sid_write_band (V2 SID-write band). Pulse-width pair at v1_sid_write_band = V0's pw_lo_patch_v0/pw_hi_patch_v0 offset by $31. Freq pair at v1_sid_write_band = V0's pw_hi_patch_v0 + $31. Self-modifying — operand bytes serve as per-voice working registers and must not be reordered. The X=$31 base offset is hard-coded into the slide oscillator (pitch_slide_oscillator) and into sidtab_row_apply dispatch.
v1_sid_write_band .block
                           ldx  #$00    ; $1053
                           lda  #$00    ; $1055
; ──── SMC-patched OPCODE — instruction TYPE changes at runtime ────
;   Patched at: $C5C8
;   STX can flip to: JMP
;   When patched, jumps to:
;     $1084  v2_sid_write_band             [skip V1 SID writes]
;   STX -> JMP: skips voice 1's SID writes when V1's wave is off.
l_1:                       stx  load_decoder_pat_base_walk.SID_V2_PW_LO    ; $1057
                           sta  SID_V2_PW_HI    ; $105A
                           ldx  #$00    ; $105D
                           lda  #$00    ; $105F
                           stx  load_decoder_pat_base_walk.SID_V2_FREQ_LO    ; $1061
                           sta  SID_V2_FREQ_HI    ; $1064
                           ldx  #$00    ; $1067
                           ldy  #$00    ; $1069
                           lda  #$00    ; $106B
                           eor  #$00    ; $106D
                           stx  SID_V2_SR    ; $106F
                           sty  SID_V2_AD    ; $1072
                           sta  load_decoder_pat_base_walk.SID_V2_CTRL    ; $1075
                           jmp  v2_sid_write_band    ; $1078
        .byte $00, $00, $00, $00, $00, $00, $02, $04, $FB    ; $107B
.bend

; ──────────────────────────────────────────────────────────────────────
; $1084  v2_sid_write_band
; ──────────────────────────────────────────────────────────────────────
; V2 SID-write band + SID#1 globals tail.
;
;   callers:             1 code sites: $1078
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   V2 analog of v1_sid_write_band: writes SID_V3_FREQ_LO..SID_V3_SR (freq/PW/ctrl/ADSR) from V2's per-voice working record (voice_record_v2, X=$62), then falls through into the shared SID#1 globals tail (filter resonance/routing patched from filter_resonance_routing; volume + filter mode from filter_volume_or_mode; the filter-cutoff slide accumulator). The volume ORA $0F at filter_volume_or_mode forces volume to $0F (max) and ORs in the high-nibble filter-mode bits, so defMON tunes can't quiet the volume below max via this path — per-voice volume comes from envelope S/R only.
v2_sid_write_band .block
                           ldx  #$00    ; $1084
                           lda  #$00    ; $1086
; ──── SMC-patched OPCODE — instruction TYPE changes at runtime ────
;   Patched at: $C5EA
;   STX can flip to: JMP
;   When patched, jumps to:
;     $10A9  sid1_globals_tail             [skip V2 SID writes]
;   STX -> JMP: skips voice 2's SID writes when V2's wave is off.
l_1:                       stx  load_decoder_pat_base_walk.SID_V3_PW_LO    ; $1088
                           sta  SID_V3_PW_HI    ; $108B
                           ldx  #$00    ; $108E
                           lda  #$00    ; $1090
                           stx  load_decoder_pat_base_walk.SID_V3_FREQ_LO    ; $1092
                           sta  load_decoder_pat_base_walk.SID_V3_FREQ_HI    ; $1095
                           ldx  #$00    ; $1098
                           ldy  #$00    ; $109A
                           lda  #$00    ; $109C
                           eor  #$00    ; $109E
                           stx  SID_V3_SR    ; $10A0
                           sty  load_decoder_pat_base_walk.SID_V3_AD    ; $10A3
                           sta  SID_V3_CTRL    ; $10A6
                           lda  #$00    ; $10A9  ; ← filter_resonance_routing
                           sta  load_decoder_pat_base_walk.SID_FILTER_RES    ; $10AB
                           lda  #$00    ; $10AE  ; ← filter_volume_or_mode
                           ora  #$0F    ; $10B0
                           sta  SID_VOL_FILTER    ; $10B2
.bend

; ──────────────────────────────────────────────────────────────────────
; $10B5  filter_cutoff_slide_accumulator
; ──────────────────────────────────────────────────────────────────────
; 16-bit signed accumulator integrating cutoff_hi per frame.
;
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   code edges:          fall-through from $10B2 in filter_volume_or_mode (3 bytes earlier)
;
;   Integrates a step into the 16-bit cutoff accumulator each frame. The step
;   operands at filter_cutoff_slide_accumulator / filter_cutoff_slide_acc_hi
;   are patched by sidtab_row_apply's ACID-column handler, and the ADC/SBC
;   opcode byte itself is patched between $69 (ADC) and $E9 (SBC) to flip
;   direction. Bit 7 of the ACID column byte selects mode: $00..$7F = absolute
;   set (lo cleared, accumulator armed to row_byte and ramps up), $80..$FF =
;   step + direction (magnitude = row_byte & $7F; opcode flips ADC ↔ SBC).
;
;   The output written to SID_FC_HI passes through an optional NOP/ASL at
;   filter_slide_output_opcode, patched once at startup by raster_sync_random
;   from V3-osc entropy: NOP ($EA) = passthrough, ASL ($0A) = doubles cutoff.
;   The companion threshold-reload immediate at
;   filter_cutoff_slide_threshold_reload pairs with that opcode ($02 in the
;   NOP path, $00 in the ASL path) so the saturation clamp lands at the same
;   audible range.
filter_cutoff_slide_accumulator .block
                           lda  #$00    ; $10B5  ; ← filter_cutoff_acc_lo
                           clc    ; $10B7
; ──── SMC-patched OPCODE — instruction TYPE changes at runtime ────
;   Patched at: $178F, $17A0
;   ADC can flip to: SBC
;   ADC <-> SBC: filter cutoff-slide direction (lo-byte step). $178F stores $69 (ADC, ramp up); $17A0 stores $E9 (SBC, ramp down). Bit 7 of the ACID-column byte selects the direction.
filter_cutoff_slide_adc_opcode_smc: adc  #$00    ; $10B8  ; ← filter_cutoff_slide_step_lo_smc
                           sta  filter_cutoff_acc_lo    ; $10BA
                           lda  #$00    ; $10BD  ; ← filter_cutoff_slide_acc_hi
; ──── SMC-patched OPCODE — instruction TYPE changes at runtime ────
;   Patched at: $1792, $17A3
;   ADC can flip to: SBC
;   ADC <-> SBC: hi-byte companion of $10B8, patched in the same pass ($1792 stores ADC, $17A3 stores SBC) so the 16-bit slide adds or subtracts consistently across both bytes.
filter_cutoff_slide_adc_opcode_smc2: adc  #$00    ; $10BF  ; ← filter_cutoff_slide_step_hi_smc
                           bpl  l_1    ; $10C1  ($00 + $00) had bit 7 clear?
                           lda  filter_cutoff_slide_threshold_reload    ; $10C3
l_1:                       sta  filter_cutoff_slide_acc_hi    ; $10C6
                           adc  #$00    ; $10C9  ; ← filter_cutoff_slide_saturation_step
                           bmi  l_2    ; $10CB  (A + $00) had bit 7 set?
                           cmp  #$02    ; $10CD  ; ← filter_cutoff_slide_threshold_reload
                           bcs  filter_slide_output_opcode    ; $10CF  A was $02 or above?
l_2:                       lda  filter_cutoff_slide_threshold_reload    ; $10D1
.bend

; ──────────────────────────────────────────────────────────────────────
; $10D4  filter_slide_output_opcode
; ──────────────────────────────────────────────────────────────────────
; single byte patched into the slide oscillator's output path between filter_slide_output_opcode write SID_FC_HI.
;
;   callers:             3 code sites: $10CF, $151D raster_sync_random_3, $81A8
;   values:
;     $0A = asl A (double; SID_FC_HI = saturated value <<1, max=$04)
;     $EA = no-op (pass-through; SID_FC_HI = saturated accumulator value, max=$02)
;
;   Set once by raster_sync_random at slide_dec_lut_lo based on V3-osc bit 0.
filter_slide_output_opcode .block
; ──── SMC-patched OPCODE — instruction TYPE changes at runtime ────
;   Patched at: $151D
;   ASL can flip to: NOP
;   ASL <-> NOP: filter cutoff output scaling (SID#1). $151D stores $EA (NOP, pass-through, max cutoff $02) or leaves $0A (ASL, doubles to max $04). Chosen at startup by raster_sync_random.
                           asl  a    ; $10D4
                           sta  SID_FC_HI    ; $10D5
.bend

; ──────────────────────────────────────────────────────────────────────
; $10D8  subframe_sentinel_opcode
; ──────────────────────────────────────────────────────────────────────
; Sub-frame sentinel — the OPCODE byte of the `lda #$FF; bpl row_advance_band_v0` instruction at subframe_sentinel_opcode.
;
;   callers:             3 code sites: $1006 player_sound_update, $100C, $1013
;   values:
;     $60 = RTS opcode (sub-frame entry: return early, skip row advance)
;     $A9 = LDA-imm opcode (main-tick entry: load $FF and run row advance)
;
;   Normally LDA-imm, making the instruction A←$FF → A=$FF (negative) → →not when positive taken → row advance runs. Patched to RTS by player_sound_update, which turns the instruction into an early-return — when the call player_play_body at player_sound_update flows into subframe_sentinel_opcode, the return bails out of player_play, skipping the row-advance band. player_sound_update restores the LDA-imm opcode. NOT a data byte; treating it as one (e.g. writing $FF to subframe_sentinel_opcode to 'force play mode') replaces the read opcode with an illegal jam opcode.
subframe_sentinel_opcode .block
; ──── SMC-patched OPCODE — instruction TYPE changes at runtime ────
;   Patched at: $100C, $1013
;   LDA can flip to: RTS
;   LDA -> RTS: sub-frame gate. player_sound_update writes $60 (RTS) at $100C to bail out of player_play before the row-advance band on a sub-frame tick, then restores $A9 (LDA-imm) at $1013.
                           lda  #$FF    ; $10D8  ; ← silence_or_endsong_flag
.bend

; ──────────────────────────────────────────────────────────────────────
; $10DA  row_advance_gate
; ──────────────────────────────────────────────────────────────────────
; →row_advance_band_v0 when positive instruction.
;
;   code edges:          fall-through from $10D8 subframe_sentinel_opcode (2 bytes earlier)
;
;   Together with subframe_sentinel_opcode sentinel byte forms the in-line `A←$FF; →row_advance_band_v0 when positive` that gates the entire pattern-row advance phase. Normally subframe_sentinel_opcode = $A9 (A←$FF opcode) → A=$FF → →not when positive taken → falls through to silence_or_song_advance silence/end-of-song handler then arranger walk; sub-frame entry (player_sound_update) patches subframe_sentinel_opcode to $60 (return opcode) so the call player_play_body path RTSes here instead of advancing rows.
row_advance_gate .block
                           bpl  row_advance_band_v0    ; $10DA  silence_or_endsong_flag had bit 7 clear?
.bend

; ──────────────────────────────────────────────────────────────────────
; $10DC  silence_or_song_advance
; ──────────────────────────────────────────────────────────────────────
; entry from →fall-through when positive at row_advance_gate.
;
;   code edges:          fall-through from $10DA row_advance_gate (2 bytes earlier)
;
;   A&=$0F masks the dur nibble from sentinel/silence flag in A; STAs the nibble into silence_or_endsong_flag (silence latch) and into all three voice row timers v0_row_timer/v1_row_timer/v2_row_timer (every voice fires the row-read on the same cadence after a song-position bump). Then Y←SILENCE_FLAG_EOS (will become $00 after the iny at arranger_load_pat_bases/$10E A) primes the arranger walk.
silence_or_song_advance .block
                           and  #$0F    ; $10DC
                           sta  silence_or_endsong_flag    ; $10DE
                           sta  v0_row_timer    ; $10E1
                           sta  v1_row_timer    ; $10E4
                           sta  v2_row_timer    ; $10E7
                           ldy  #$FF    ; $10EA  ; ← current_arranger_row
.bend

; ──────────────────────────────────────────────────────────────────────
; $10EC  arranger_advance_song
; ──────────────────────────────────────────────────────────────────────
; walks the song-position arrangers (arranger_v0_sid1/arranger_v1_sid1/arranger_v2_sid1) until landing on a non-FF V0 entry.
;
;   code edges:          fall-through from $10EA in silence_or_song_advance (2 bytes earlier)
;
;   Reads V0's arranger byte at the current row. Positive values are pattern numbers — pat_base pointers load from those and the song advances normally. Negative values (high bit set, typically $FF) are JUMP COMMANDs: target row comes from V1's arranger at the same index, repeat count from V2's. V2 == 0 means unconditional immediate jump (Y := V1[Y]); V2 != 0 arms a groove timer (groove_compare_slot := Y, groove_repeat_counter := V2) on first visit and decrements it on each re-visit, falling through past the FF row only when the timer underflows. See arranger_v0_sid1 for full FF-jump arranger semantics.
arranger_advance_song .block
                           ldx  arranger_v0_sid1,y    ; $10EC
                           bpl  arranger_load_pat_bases.l_1    ; $10EF  arranger_v0_sid1,Y had bit 7 clear?
                           lda  arranger_v2_sid1,y    ; $10F1
                           beq  arranger_fall_through    ; $10F4  arranger_v2_sid1,Y was zero?
                           cpy  groove_compare_slot    ; $10F6
                           beq  l_1    ; $10F9  $FF was groove_compare_slot?
                           sty  groove_compare_slot    ; $10FB
                           sta  groove_repeat_counter    ; $10FE
                           jmp  arranger_fall_through    ; $1101
l_1:                       dec  groove_repeat_counter    ; $1104
                           bne  arranger_fall_through    ; $1107  (groove_repeat_counter − 1) was non-zero?
                           lda  #$00    ; $1109
                           sta  groove_compare_slot    ; $110B
                           iny    ; $110E
                           jmp  arranger_load_pat_bases    ; $110F
.bend

; ──────────────────────────────────────────────────────────────────────
; $1112  arranger_fall_through
; ──────────────────────────────────────────────────────────────────────
; entry from groove-timer underflow at arranger_advance_song →not when nonzero taken, OR from the V2==0 immediate-jump path at arranger_advance_song →taken when zero.
;
;   callers:             3 code sites: $10F4, $1101, $1107
;
;   read arranger_v1_sid1,Y reads V1's arranger entry (the jump target row index), Y←A moves it into Y, then fall-through to arranger_load_pat_bases to refresh pat_base pointers.
arranger_fall_through .block
                           lda  arranger_v1_sid1,y    ; $1112
                           tay    ; $1115
.bend

; ──────────────────────────────────────────────────────────────────────
; $1116  arranger_load_pat_bases
; ──────────────────────────────────────────────────────────────────────
; given Y = new song-position row, load all three voices' pat_base lo/hi pointers from pat_base_lo/pat_base_hi indexed by V0/V1/V2's arranger entries.
;
;   callers:             1 code sites: $110F
;
;   Stores per-voice into the v0_freq_lookup_smc/v0_freq_lookup_smc_hi (V0), row_read_body_v1 (V1), row_read_body_v2 (V2) self-modifying lda-abs operands that the row-read body reads. increment Y + Y→current_arranger_row then advances the song-position cursor.
arranger_load_pat_bases .block
                           ldx  arranger_v0_sid1,y    ; $1116
l_1:                       lda  pat_base_lo,x    ; $1119
                           sta  v0_freq_lookup_smc    ; $111C
                           lda  pat_base_hi,x    ; $111F
                           sta  v0_freq_lookup_smc_hi    ; $1122
                           ldx  arranger_v1_sid1,y    ; $1125
                           lda  pat_base_lo,x    ; $1128
                           sta  player_state_120e    ; $112B
                           lda  pat_base_hi,x    ; $112E
                           sta  v0_player_state_120f    ; $1131
                           ldx  arranger_v2_sid1,y    ; $1134
                           lda  pat_base_lo,x    ; $1137
                           sta  v0_player_state_1296    ; $113A
                           lda  pat_base_hi,x    ; $113D
                           sta  v0_player_state_1297    ; $1140
                           iny    ; $1143
                           sty  current_arranger_row    ; $1144
.bend

; ──────────────────────────────────────────────────────────────────────
; $1147  row_advance_band_v0
; ──────────────────────────────────────────────────────────────────────
; voice-0 timer + pattern row-read dispatch.
;
;   callers:             1 code sites: $10DA row_advance_gate
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Per-frame V0 pattern-row gate. The row timer at v0_row_timer counts
;   down each main-tick NMI; when it underflows ($FF) this band reads
;   the next row from pat_base (via the self-modifying load at
;   v0_patch_operands_entry), copies row.flag into the sax-pair at
;   v0_row_dur_sax_smc, reloads v0_row_timer from the row's dur nibble,
;   and emits the row's side-effects (see "What this band DOES emit"
;   below). When the timer is still counting down, it just decrements
;   and jumps through to V1's band.
;
;   Cadence: this band runs ONLY on main-tick NMIs. Sub-frame NMIs reach
;   the player via player_sound_update, which patches subframe_sentinel_opcode to $60 (RTS opcode); the
;   row_advance_gate BPL row_advance_band_v0 gate is therefore unreachable on a sub-frame NMI —
;   the JSR player_play_body path RTSes back to player_sound_update's tail before row_advance_gate executes.
;
;   What this band DOES emit:
;    - sets sidcall row indices (v0_sc1_row_idx V0sc1, v0_sc2_row_idx V0sc2) via row_read_body_v0
;    - sets current_note (current_note_v0) + transpose buffer (v0_transpose_buffer)
;    - zeros V0 slide accumulator + mode (voice_record_v0/v0_slide_acc/slide_mode_v0)
;    - reloads V0 row timer (v0_row_timer) with the row's dur nibble
;
;   What this band does NOT emit:
;    - SID_V1_CTRL-SID_V1_SR (V0 ctrl/AD/SR) — these are emitted by player_play_body's
;    SID-write band reading the patched operand bytes at pw_hi_patch_v0/
;    pw_hi_patch_v0; the operand bytes are patched by sidtab_row_apply
;    when the cascade arm at sidtab_cascade_entry refetches.
;    - Pulse width (SID_V1_PW_LO/SID_V1_PW_HI) — patched at pw_lo_patch_v0/pw_hi_patch_v0 by sidtab_row_apply too.
;    - Any other env-program byte (PS, AF, TR, RE, FV, CP, ACID) — all
;    flow through sidtab_row_apply → operand-patch slots → player_play_body SID-write band.
;
;   Cascade-fire NMI offset (the per-sub-frame NMI on which sidtab_row_apply runs
;   for V0 sc1) is NOT necessarily NMI 0 of the main-tick group. The
;   cascade arm at sidtab_cascade_entry DECs its counter EVERY NMI (sub-frame and
;   main-tick); the refetch fires on whichever NMI the counter reaches
;   $00. So env-program byte changes for V0 can commit at any NMI 0..N-1
;   within a sub_frame_count=N main-tick group, depending on the running
;   DL byte sequence of the active sidTAB row.
row_advance_band_v0 .block
                           ldx  #$00    ; $1147
v0_row_ldy_smc:            ldy  #$FF    ; $1149  ; ← v0_row_timer
v0_row_advance_bmi:        bmi  row_read_body_v0    ; $114B  v0_row_timer had bit 7 set?
                           dec  v0_row_timer    ; $114D
;   step-idiom: source = v0_row_timer  (= $114A)
;               decremented 1× via DEX/DEY/DEC     ; final step @ $114D
;               test     = BPL "had bit 7 clear?"
                           bpl  row_advance_band_v1    ; $1150  v0_row_timer walked back 1 and had bit 7 clear?
.bend

; ──────────────────────────────────────────────────────────────────────
; $1152  v0_patch_operands_entry
; ──────────────────────────────────────────────────────────────────────
; patch path landing site inside row_advance_band_v0.
;
;   code edges:          fall-through from $1150 in v0_row_advance_bmi (2 bytes earlier)
;
;   Reached after timer dec at v0_row_timer underflows ($00 → $FF) and bpl at v0_row_timer fails. v0_patch_operands_entry copies pat_base lo/hi (v0_freq_lookup_smc/v0_freq_lookup_smc_hi) into the operand slots at row_read_body_v0/V0_gate_n_branch/v0_patch_operands_entry and asl-cascades the flag byte at v0_patch_operands_entry into the lda-#$FF immediates at row_read_body_v0 (= the GATE_A/B/N gates inside row_read_body_v0). v0_patch_to_v1_jmp JMPs to V1 (row_advance_band_v1) WITHOUT running row_read_body_v0 — the row read fires on the NEXT NMI when v0_row_ldy_smc reads v0_row_timer=$FF and v0_row_advance_bmi →branches when negative to row_read_body_v0.
v0_patch_operands_entry .block
                           lda  v0_freq_lookup_smc    ; $1152
                           sta  V0_gate_n_branch + $01    ; $1155
                           sta  row_read_body_v0 + $15    ; $1158
                           sta  v0_patch_operands_entry + $19    ; $115B
                           lda  v0_freq_lookup_smc_hi    ; $115E
                           sta  V0_gate_n_branch + $02    ; $1161
                           sta  row_read_body_v0 + $16    ; $1164
                           sta  v0_patch_operands_entry + $1A    ; $1167
                           lda  VEC_IRQ_HI    ; $116A
                           sta  v0_gate_n_tail + $0E    ; $116D
                           asl  a    ; $1170
                           sta  row_read_body_v0 + $03    ; $1171
                           asl  a    ; $1174
                           sta  row_read_body_v0 + $11    ; $1175
                           asl  a    ; $1178
                           sta  row_read_body_v0 + $1F    ; $1179
.bend

; ──────────────────────────────────────────────────────────────────────
; $117C  v0_patch_to_v1_jmp
; ──────────────────────────────────────────────────────────────────────
; `jump row_advance_band_v1` instruction at the tail of v0_patch_operands_entry-v0_patch_to_v1_jmp's patch path.
;
;   code edges:          fall-through from $1179 in v0_patch_operands_entry (3 bytes earlier)
;
;   Hands off to the V1 row-advance band (row_advance_band_v1) after patching row_read_body_v0's operand bytes for the NEXT NMI's row read. The current NMI does NOT execute row_read_body_v0; row read fires one NMI later when v0_row_timer=$FF triggers the v0_row_advance_bmi →branch when negative.
v0_patch_to_v1_jmp .block
                           jmp  row_advance_band_v1    ; $117C
.bend

; ──────────────────────────────────────────────────────────────────────
; $117F  row_read_body_v0
; ──────────────────────────────────────────────────────────────────────
; runs when V0's row timer hits $FF.
;
;   callers:             1 code sites: $114B v0_row_advance_bmi
;   inputs:              X
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Reads the 4-byte pattern row at (pat_base + Y*4) via three self-modifying lda-abs (row_read_body_v0/V0_gate_n_branch — each patched with pat_base from v0_freq_lookup_smc/v0_freq_lookup_smc_hi set by arranger_load_pat_bases). Y=$01 → step_byte_a → v0_sc1_row_idx (sidcall1 row index) + v0_sc1_counter (sidcall1 step counter = $00); Y=$02 → step_byte_b → v0_sc2_row_idx (sidcall2 row index) + v0_sc2_counter; Y=$03 → step_byte_n (NOTE) → v0_transpose_buffer (transpose buffer) + current_note_v0 (current_note) + zeros slide accumulator voice_record_v0/v0_slide_acc/slide_mode_v0. The →gate when positive at row_read_body_v0 skips the GATE_N branch when step_byte == $FF (no-op step).
;
;   Each of the three sub-bands (row_read_body_v0, row_read_body_v0, row_read_body_v0-v0_gate_n_tail)
;   follows the same `LDY #$01; LDA #$FF; BPL skip; LDA ($pat),y; STA target;
;   INY` shape. The `LDA #$FF` immediate operand at row_read_body_v0 is
;   PATCHED by the SAX undocumented opcode at SAX_v0_dur_nibble ($8F = SAX abs) plus
;   LDA #$0F → A=$0F masks the flag byte's low nibble (GATE_A bit 0, GATE_B
;   bit 1, GATE_N bit 4 ungate selectors) — only when the gate bit is set
;   will the next iteration's BPL fall through and actually read the step
;   byte. See V0_gate_n_branch for the GATE_N specifics.
row_read_body_v0 .block
                           ldy  #$01    ; $117F
                           lda  #$FF    ; $1181  ; ← (SMC operand at $1182, no name)
; ──── SMC-patched branch — static target is the unpatched default ────
;   Patched at: $D1B8
;   GATE branch (voice 0, sidcall-1). BPL offset set to $0A once at load by $D1B8; skips the sc1 row-index + counter latch when the sidcall-1 gate bit is clear.
                           bpl  l_1    ; $1183  row_read_body_v0_$3 had bit 7 clear?
                           lda  VEC_IRQ_HI,y    ; $1185
                           sta  v0_sc1_row_idx    ; $1188
                           stx  v0_sc1_counter    ; $118B
l_1:                       iny    ; $118E
                           lda  #$FF    ; $118F  ; ← (SMC operand at $1190, no name)
; ──── SMC-patched branch — static target is the unpatched default ────
;   Patched at: $D1BD
;   GATE branch (voice 0, sidcall-2). BPL offset set to $0A once at load by $D1BD; skips the sc2 row-index + counter latch when the sidcall-2 gate bit is clear.
                           bpl  l_2    ; $1191  row_read_body_v0_$11 had bit 7 clear?
                           lda  VEC_IRQ_HI,y    ; $1193
                           sta  v0_sc2_row_idx    ; $1196
                           stx  v0_sc2_counter    ; $1199
l_2:                       iny    ; $119C
                           lda  #$FF    ; $119D  ; ← (SMC operand at $119E, no name)
; ──── SMC-patched branch — static target is the unpatched default ────
;   Patched at: $D1C2
;   GATE branch (voice 0, note / GATE_N). BPL offset set to $13 once at load by $D1C2; skips the NOTE read + transpose/slide reset when the note gate bit is clear.
                           bpl  v0_gate_n_tail.l_1    ; $119F  row_read_body_v0_$1F had bit 7 clear?
.bend

; ──────────────────────────────────────────────────────────────────────
; $11A1  V0_gate_n_branch
; ──────────────────────────────────────────────────────────────────────
; body at V0_gate_n_branch-v0_gate_n_tail fires when GATE_N bit 4 is set in the row flag.
;
;   code edges:          fall-through from $119F in row_read_body_v0_2 (2 bytes earlier)
;
;   Reads the NOTE byte (the LDA operand is patched to point at pat_base + Y), latches it into both the per-voice transpose buffer (for sidTAB TR columns) and the pitch oscillator's current_note. Then zeros V0's slide accumulator lo/hi/mode in one pass (X is $00 at this point). The slide-mode reset is the critical bit — see pitch_slide_oscillator for why.
V0_gate_n_branch .block
                           lda  VEC_IRQ_HI,y    ; $11A1
                           sta  v0_transpose_buffer    ; $11A4
.bend

; ──────────────────────────────────────────────────────────────────────
; $11A7  v0_gate_n_tail
; ──────────────────────────────────────────────────────────────────────
; V0_gate_n_branch tail — write current_note_v0 (current_note write) + the three X→voice_record_v0/v0_slide_acc/slide_mode_v0 slide-accumulator zeros.
;
;   code edges:          fall-through from $11A4 in V0_gate_n_branch (3 bytes earlier)
;
;   Falls through to increment Y at v0_gate_n_tail and the →gate when positive at v0_gate_n_tail that checks the next flag bit.
v0_gate_n_tail .block
                           sta  current_note_v0    ; $11A7
                           stx  voice_record_v0    ; $11AA
                           stx  v0_slide_acc    ; $11AD
                           stx  slide_mode_v0    ; $11B0
l_1:                       iny    ; $11B3
v0_row_dur_sax_smc:        ldx  #SILENCE_FLAG_EOS    ; $11B4  ; ← (SMC operand at $11B5, no name)
                           bpl  V0_row_read_tail    ; $11B6  v0_gate_n_tail_$E had bit 7 clear?
                           stx  silence_or_endsong_flag    ; $11B8
                           bmi  row_advance_band_v1    ; $11BB  v0_gate_n_tail_$E had bit 7 set?
.bend

; ──────────────────────────────────────────────────────────────────────
; $11BD  V0_row_read_tail
; ──────────────────────────────────────────────────────────────────────
; after the 3 step-byte loops, advance pat_base by Y (= 4 bytes per row, plus any extra step bytes consumed).
;
;   callers:             1 code sites: $11B6
;
;   A←Y + clear-carry + A+=v0_freq_lookup_smc → write v0_freq_lookup_smc; →V0_row_read_tail when no-carry + increment v0_freq_lookup_smc_hi propagates carry to pat_base_hi. Then A←$0F + write A&X→v0_row_timer (undocumented opcode $8F = A & X → mem) lands flag.dur_nibble into the V0 row timer.
V0_row_read_tail .block
                           tya    ; $11BD
                           clc    ; $11BE
                           adc  v0_freq_lookup_smc    ; $11BF
                           sta  v0_freq_lookup_smc    ; $11C2
                           bcc  l_1    ; $11C5  v0_freq_lookup_smc no carry
                           inc  v0_freq_lookup_smc_hi    ; $11C7
l_1:                       lda  #$0F    ; $11CA
.bend

; ──────────────────────────────────────────────────────────────────────
; $11CC  SAX_v0_dur_nibble
; ──────────────────────────────────────────────────────────────────────
; undocumented opcode $8F ($write A&X→abs) at SAX_v0_dur_nibble.
;
;   code edges:          fall-through from $11CA V0_row_read_tail_1 (2 bytes earlier)
;
;   SAX v0_row_timer (undocumented NMOS opcode $8F, 3 bytes). Stores A & X to absolute address v0_row_timer. With A=$0F (from V0_row_read_tail) and X=row.flag_byte (set from the row's flag at v0_row_dur_sax_smc-v0_gate_n_tail), the result is flag & $0F = duration nibble — which becomes the next V0 row timer reload. V1 analog at row_read_body_v2_ldy_smc ($8F D2 11 → SAX v1_row_timer); V2 analog at row_advance_band_v2_ldy_smc ($8F 5A 12 → SAX v2_row_timer). Each lands the row's dur nibble into that voice's timer reload slot.
SAX_v0_dur_nibble .block
                           sax  v0_row_timer    ; $11CC
.bend

; ──────────────────────────────────────────────────────────────────────
; $11CF  row_advance_band_v1
; ──────────────────────────────────────────────────────────────────────
; voice-1 analog of row_advance_band_v0.
;
;   callers:             3 code sites: $1150, $117C v0_patch_to_v1_jmp, $11BB
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   X←$00 at entry, but row_read_body_v1's mirror-store at X→voice_record_v1/v1_voice_record_pad has shifted X to $31 by the time the band finishes (V1's slide accumulator sits at offset $31 from V0's voice_record_v0/v0_slide_acc/slide_mode_v0). Same shape as V0's row_advance_band_v0: →row_read_body_v1 when negative fires row read, decrement v1_row_timer + →row_advance_band_v2 when positive skips. Pattern row addresses come from row_read_body_v1 (set by arranger_load_pat_bases). On GATE_N fires, zeros voice_record_v1/v1_voice_record_pad. Per-NMI cadence + env-program emit timing: see row_advance_band_v0 notes. V1 mirrors V0's model — runs only on main-tick NMIs; does NOT emit V1 env-program bytes (SID_V2_CTRL/SID_V2_AD/SID_V2_SR), those flow through sidtab_row_apply → v1_sid_write_band operand slots → v1_sid_write_band V1 SID-write band. Cascade-fire NMI for V1 sc1 lives on the sidtab_cascade_v1_sc1 arm (V1 sc1 counter at v1_sc1_counter).
row_advance_band_v1 .block
                           ldx  #$00    ; $11CF
                           lda  #$FF    ; $11D1  ; ← v1_row_timer
                           bmi  row_read_body_v1    ; $11D3  v1_row_timer had bit 7 set?
                           dec  v1_row_timer    ; $11D5
;   step-idiom: source = v1_row_timer  (= $11D2)
;               decremented 1× via DEX/DEY/DEC     ; final step @ $11D5
;               test     = BPL "had bit 7 clear?"
                           bpl  row_advance_band_v2    ; $11D8  v1_row_timer walked back 1 and had bit 7 clear?
                           lda  player_state_120e    ; $11DA
                           sta  row_read_body_v1 + $23    ; $11DD
                           sta  row_read_body_v1 + $15    ; $11E0
                           sta  v1_row_timer + $21    ; $11E3
                           lda  v0_player_state_120f    ; $11E6
                           sta  row_read_body_v1 + $24    ; $11E9
                           sta  row_read_body_v1 + $16    ; $11EC
                           sta  v1_row_timer + $22    ; $11EF
                           lda  VEC_IRQ_HI    ; $11F2
                           sta  row_read_body_v1 + $36    ; $11F5
                           asl  a    ; $11F8
                           sta  row_read_body_v1 + $03    ; $11F9
                           asl  a    ; $11FC
                           sta  row_read_body_v1 + $11    ; $11FD
                           asl  a    ; $1200
                           sta  row_read_body_v1 + $1F    ; $1201
                           jmp  row_advance_band_v2    ; $1204
.bend

; ──────────────────────────────────────────────────────────────────────
; $1207  row_read_body_v1
; ──────────────────────────────────────────────────────────────────────
; V1 analog of row_read_body_v0.
;
;   callers:             1 code sites: $11D3
;   inputs:              X
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Reads 4-byte row at (pat_base_v1 + Y) via row_read_body_v1. Y=$01 → v1_sc1_row_idx (V1 sc1 row idx) + v1_sc1_counter (V1 sc1 counter); Y=$02 → v1_sc2_row_idx (V1 sc2 row idx) + v1_sc2_counter (V1 sc2 counter); Y=$03 → v1_cascade_slot_triple (V1 sc1 transpose mirror) + v1_sc2_cascade_slot_triple (V1 sc2 transpose mirror) + X→voice_record_v1/v1_voice_record_pad (V1 slide accumulator + mode reset). The mirror-store targets v1_cascade_slot_triple/v1_sc2_cascade_slot_triple are in the sidcall1/sidcall2 cascade rows rather than a per-voice 'transpose buffer' like V0's v0_transpose_buffer. V0_gate_n_branch/v0_gate_n_tail (V0 writes v0_transpose_buffer + current_note_v0) vs row_read_body_v1 (V1 writes v1_cascade_slot_triple + v1_sc2_cascade_slot_triple — both are sidcall row indexes, not the V1 current_note at v0_sc2_cascade_slot_triple). V1's current_note_v0-analog (current_note) lives at v0_sc2_cascade_slot_triple but isn't written from the row-read path; instead v1_sc1_row_idx = sidcall1 row index acts as the V1 'note' for the cascade dispatch.
row_read_body_v1 .block
                           ldy  #$01    ; $1207
                           lda  #$FF    ; $1209  ; ← (SMC operand at $120A, no name)
; ──── SMC-patched branch — static target is the unpatched default ────
;   Patched at: $D1C7
;   GATE branch (voice 1, sidcall-1). BPL offset set to $0A once at load by $D1C7; v1 analogue of $1183.
                           bpl  l_1    ; $120B  row_read_body_v1_$3 had bit 7 clear?
                           lda  VEC_IRQ_HI,y    ; $120D
                           sta  v1_sc1_row_idx    ; $1210
                           stx  v1_sc1_counter    ; $1213
l_1:                       iny    ; $1216
                           lda  #$FF    ; $1217  ; ← (SMC operand at $1218, no name)
; ──── SMC-patched branch — static target is the unpatched default ────
;   Patched at: $D1CC
;   GATE branch (voice 1, sidcall-2). BPL offset set to $0A once at load by $D1CC; v1 analogue of $1191.
                           bpl  l_2    ; $1219  row_read_body_v1_$11 had bit 7 clear?
                           lda  VEC_IRQ_HI,y    ; $121B
                           sta  v1_sc2_row_idx    ; $121E
                           stx  v1_sc2_counter    ; $1221
l_2:                       iny    ; $1224
                           lda  #$FF    ; $1225  ; ← (SMC operand at $1226, no name)
; ──── SMC-patched branch — static target is the unpatched default ────
;   Patched at: $D1D1
;   GATE branch (voice 1, note / GATE_N). BPL offset set to $13 once at load by $D1D1; v1 analogue of $119F.
                           bpl  l_3    ; $1227  row_read_body_v1_$1F had bit 7 clear?
                           lda  VEC_IRQ_HI,y    ; $1229
                           sta  v1_cascade_slot_triple + $02    ; $122C
                           sta  v1_sc2_cascade_slot_triple + $01    ; $122F
                           stx  voice_record_v1    ; $1232
                           stx  voice_record_v1.slide_acc_lo    ; $1235
                           stx  v1_voice_record_pad    ; $1238
l_3:                       iny    ; $123B
                           ldx  #SILENCE_FLAG_EOS    ; $123C  ; ← (SMC operand at $123D, no name)
                           bpl  l_4    ; $123E  row_read_body_v1_$36 had bit 7 clear?
                           stx  silence_or_endsong_flag    ; $1240
                           bmi  row_advance_band_v2    ; $1243  row_read_body_v1_$36 had bit 7 set?
l_4:                       tya    ; $1245
                           clc    ; $1246
                           adc  player_state_120e    ; $1247
                           sta  player_state_120e    ; $124A
                           bcc  l_5    ; $124D  player_state_120e no carry
                           inc  v0_player_state_120f    ; $124F
l_5:                       lda  #$0F    ; $1252
.bend

; ──────────────────────────────────────────────────────────────────────
; $1254  row_read_body_v2_ldy_smc
; ──────────────────────────────────────────────────────────────────────
; Undocumented opcode $8F (abs): stores A & X into voice 1's row-timer reload — the V1 analog of SAX_v0_dur_nibble (A=$0F, X=row flag, result = duration nibble).
;
;   code edges:          fall-through from $1252 row_read_body_v1_5 (2 bytes earlier)
;
;   Name retained from when the $8F opcode byte was read as an ldy operand; it is a standalone SAX instruction, not a patched operand slot.
row_read_body_v2_ldy_smc .block
                           sax  v1_row_timer    ; $1254
.bend

; ──────────────────────────────────────────────────────────────────────
; $1257  row_advance_band_v2
; ──────────────────────────────────────────────────────────────────────
; voice-2 analog of row_advance_band_v0/row_advance_band_v1.
;
;   callers:             3 code sites: $11D8, $1204, $1243
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Same shape; pat_base from row_read_body_v2; row timer at v2_row_timer; GATE_N branch at row_read_body_v2 writes v2_cascade_slot_triple/v2_sc2_cascade_slot_triple (V2 sc1/sc2 row index mirrors) + zeros voice_record_v2 (V2 slide accumulator/mode at offset $62 from V0's voice_record_v0). Per-NMI cadence + env-program emit timing: see row_advance_band_v0 notes. V2 mirrors V0's model — runs only on main-tick NMIs; does NOT emit V2 env-program bytes (SID_V3_CTRL/SID_V3_AD/SID_V3_SR), those flow through sidtab_row_apply → v2_sid_write_band operand slots → v2_sid_write_band V2 SID-write band. Cascade-fire NMI for V2 sc1 lives on the sidtab_cascade_v2_sc1 arm (V2 sc1 counter at v2_sc1_counter).
row_advance_band_v2 .block
                           ldx  #$00    ; $1257
                           lda  #$FF    ; $1259  ; ← v2_row_timer
                           bmi  row_read_body_v2    ; $125B  v2_row_timer had bit 7 set?
                           dec  v2_row_timer    ; $125D
;   step-idiom: source = v2_row_timer  (= $125A)
;               decremented 1× via DEX/DEY/DEC     ; final step @ $125D
;               test     = BPL "had bit 7 clear?"
                           bpl  sidtab_cascade_entry    ; $1260  v2_row_timer walked back 1 and had bit 7 clear?
                           lda  v0_player_state_1296    ; $1262
                           sta  row_read_body_v2 + $23    ; $1265
                           sta  row_read_body_v2 + $15    ; $1268
                           sta  v2_row_timer + $21    ; $126B
                           lda  v0_player_state_1297    ; $126E
                           sta  row_read_body_v2 + $24    ; $1271
                           sta  row_read_body_v2 + $16    ; $1274
                           sta  v2_row_timer + $22    ; $1277
                           lda  VEC_IRQ_HI    ; $127A
                           sta  row_read_body_v2 + $36    ; $127D
                           asl  a    ; $1280
                           sta  row_read_body_v2 + $03    ; $1281
                           asl  a    ; $1284
                           sta  row_read_body_v2 + $11    ; $1285
                           asl  a    ; $1288
                           sta  row_read_body_v2 + $1F    ; $1289
                           jmp  sidtab_cascade_entry    ; $128C
.bend

; ──────────────────────────────────────────────────────────────────────
; $128F  row_read_body_v2
; ──────────────────────────────────────────────────────────────────────
; V2 analog of row_read_body_v0/row_read_body_v1.
;
;   callers:             1 code sites: $125B
;   inputs:              X
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Reads 4-byte row at (pat_base_v2 + Y) via row_read_body_v2. Y=$01 → v2_sc1_row_idx + v2_sc1_counter (V2 sc1); Y=$02 → v2_sc2_row_idx + v2_sc2_counter (V2 sc2); Y=$03 → v2_cascade_slot_triple + v2_sc2_cascade_slot_triple (sidcall row index mirrors) + X→voice_record_v2 (V2 slide accumulator + mode reset).
row_read_body_v2 .block
                           ldy  #$01    ; $128F
                           lda  #$FF    ; $1291  ; ← (SMC operand at $1292, no name)
; ──── SMC-patched branch — static target is the unpatched default ────
;   Patched at: $D1D6
;   GATE branch (voice 2, sidcall-1). BPL offset set to $0A once at load by $D1D6; v2 analogue of $1183.
                           bpl  l_1    ; $1293  row_read_body_v2_$3 had bit 7 clear?
                           lda  VEC_IRQ_HI,y    ; $1295
                           sta  v2_sc1_row_idx    ; $1298
                           stx  v2_sc1_counter    ; $129B
l_1:                       iny    ; $129E
                           lda  #$FF    ; $129F  ; ← (SMC operand at $12A0, no name)
; ──── SMC-patched branch — static target is the unpatched default ────
;   Patched at: $D1DB
;   GATE branch (voice 2, sidcall-2). BPL offset set to $0A once at load by $D1DB; v2 analogue of $1191.
                           bpl  l_2    ; $12A1  row_read_body_v2_$11 had bit 7 clear?
                           lda  VEC_IRQ_HI,y    ; $12A3
                           sta  v2_sc2_row_idx    ; $12A6
                           stx  v2_sc2_counter    ; $12A9
l_2:                       iny    ; $12AC
                           lda  #$FF    ; $12AD  ; ← (SMC operand at $12AE, no name)
; ──── SMC-patched branch — static target is the unpatched default ────
;   Patched at: $D1E0
;   GATE branch (voice 2, note / GATE_N). BPL offset set to $13 once at load by $D1E0; v2 analogue of $119F.
                           bpl  l_3    ; $12AF  row_read_body_v2_$1F had bit 7 clear?
                           lda  VEC_IRQ_HI,y    ; $12B1
                           sta  v2_cascade_slot_triple + $02    ; $12B4
                           sta  v2_sc2_cascade_slot_triple + $01    ; $12B7
                           stx  voice_record_v2    ; $12BA
                           stx  voice_record_v2.slide_acc_lo    ; $12BD
                           stx  voice_record_v2.slide_mode    ; $12C0
l_3:                       iny    ; $12C3
                           ldx  #SILENCE_FLAG_EOS    ; $12C4  ; ← (SMC operand at $12C5, no name)
                           bpl  l_4    ; $12C6  row_read_body_v2_$36 had bit 7 clear?
                           stx  silence_or_endsong_flag    ; $12C8
                           bmi  sidtab_cascade_entry    ; $12CB  row_read_body_v2_$36 had bit 7 set?
l_4:                       tya    ; $12CD
                           clc    ; $12CE
                           adc  v0_player_state_1296    ; $12CF
                           sta  v0_player_state_1296    ; $12D2
                           bcc  l_5    ; $12D5  v0_player_state_1296 no carry
                           inc  v0_player_state_1297    ; $12D7
l_5:                       lda  #$0F    ; $12DA
.bend

; ──────────────────────────────────────────────────────────────────────
; $12DC  row_advance_band_v2_ldy_smc
; ──────────────────────────────────────────────────────────────────────
; Undocumented opcode $8F (abs): stores A & X into voice 2's row-timer reload — the V2 analog of SAX_v0_dur_nibble.
;
;   code edges:          fall-through from $12DA row_read_body_v2_5 (2 bytes earlier)
;
;   Name retained from when the $8F opcode byte was read as an ldy operand; it is a standalone SAX instruction.
row_advance_band_v2_ldy_smc .block
                           sax  v2_row_timer    ; $12DC
.bend

; ──────────────────────────────────────────────────────────────────────
; $12DF  sidtab_cascade_entry
; ──────────────────────────────────────────────────────────────────────
; start of the 6-step sidTAB cascade tail.
;
;   callers:             4 code sites: $1016 player_sound_update_jmp_tail, $1260, $128C, $12CB
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   jmp'd into from both player_play_body's main-tick body and from player_sound_update's sub-frame body (after player_sound_update patches subframe_sentinel_opcode to $60 and JSRs player_play_body).
;
;   The 6 cascade arms are:
;     - sidtab_cascade_entry    (V0 sc1)
;     - sidtab_cascade_v1_sc1   (V1 sc1)
;     - sidtab_cascade_v2_sc1   (V2 sc1)
;     - sidtab_cascade_v0_sc2   (V0 sc2)
;     - sidtab_cascade_v1_sc2   (V1 sc2)
;     - sidtab_cascade_v2_sc2   (V2 sc2)
;
;   Each arm does:
;     - A ← counter.
;     - →refetch when zero (sidtab_refetch_v0_sc1 / v1_sc1_refetch / etc.).
;     - →skip-to-next-arm when negative.
;     - else decrement counter + jmp to next arm.
;
;   counter == $00 → refetch path that calls sidtab_row_apply to apply the row, advances row index, sets counter from DL byte at dl_per_step_counters,Y.
;
;   The cascade ticks exactly once per NMI on every NMI — every arm
;   sidtab_cascade_entry/sidtab_cascade_v1_sc1/sidtab_cascade_v2_sc1/sidtab_cascade_v0_sc2/sidtab_cascade_v1_sc2/sidtab_cascade_v2_sc2 and the pitch oscillator pitch_slide_oscillator
;   fire +1 per NMI; row_advance_band_v0 (row advance) fires only on main-tick NMIs.
;
;   The arms group all-sc1 then all-sc2 (sidtab_cascade_entry V0 sc1 / sidtab_cascade_v1_sc1 V1 sc1 /
;   sidtab_cascade_v2_sc1 V2 sc1 / sidtab_cascade_v0_sc2 V0 sc2 / sidtab_cascade_v1_sc2 V1 sc2 / sidtab_cascade_v2_sc2 V2 sc2), each:
;   LDA #counter; BEQ refetch (sidtab_refetch_v0_sc1/v1_sc1_refetch/v2_cascade_slot_triple/v0_sc2_cascade_slot_triple/v1_sc2_cascade_slot_triple/v2_sc2_cascade_slot_triple);
;   BMI skip-to-next-arm; else DEC counter + JMP to next arm.
sidtab_cascade_entry .block
                           lda  #$FF    ; $12DF  ; ← v0_sc1_counter
                           beq  sidtab_refetch_v0_sc1    ; $12E1  v0_sc1_counter was zero?
                           bmi  sidtab_cascade_v1_sc1    ; $12E3  v0_sc1_counter had bit 7 set?
                           dec  v0_sc1_counter    ; $12E5
                           jmp  sidtab_cascade_v1_sc1    ; $12E8
        .byte $00, $00, $00    ; $12EB
.bend

; ──────────────────────────────────────────────────────────────────────
; $12EE  sidtab_refetch_v0_sc1
; ──────────────────────────────────────────────────────────────────────
; V0 sidcall1 row-refetch path.
;
;   callers:             1 code sites: $12E1
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Entered when v0_sc1_counter underflows. Reads the current row's hi byte from sidtab_row_hi; if non-zero it's the row's runtime ptr-hi (post-LOAD: usually $5F). If zero, the row is a JP marker — the cascade reads the redirect target from sidtab_row_lo,Y, re-loads Y from it, and re-reads sidtab_row_hi at the redirected row for the actual ptr-hi (see JP_redirect_reread). The new row's DL byte goes into v0_sc1_counter, the row index advances, and sidtab_row_apply applies the row. The JP redirect (sidtab_row_hi[Y] == 0) is how tunes hold a voice on a single sustain cascade indefinitely — a self-loop pair keeps the voice alive for the lifetime of a note.
sidtab_refetch_v0_sc1 .block
                           ldy  #$FF    ; $12EE  ; ← v0_sc1_row_idx
                           lda  song_position_arrays_hi,y    ; $12F0
                           bne  JP_redirect_reread.l_1    ; $12F3  song_position_arrays_hi,Y was non-zero?
                           lda  song_position_arrays_lo,y    ; $12F5
                           tay    ; $12F8
.bend

; ──────────────────────────────────────────────────────────────────────
; $12F9  JP_redirect_reread
; ──────────────────────────────────────────────────────────────────────
; read sidtab_row_hi,Y at JP_redirect_reread after the Y←A at sidtab_refetch_v0_sc1.
;
;   code edges:          fall-through from $12F8 in v0_sc1_row_idx (1 bytes earlier)
;
;   Executes only when sidtab_refetch_v0_sc1 →was when nonzero not taken (= first read of sidtab_row_hi was zero = JP marker). Re-reads sidtab_row_hi at the redirected row; that second read MUST be non-zero (= runtime ptr-hi, typically $5F). A double-zero would loop infinitely through JP_redirect_reread — defMON tunes never produce that on-disk shape.
JP_redirect_reread .block
                           lda  song_position_arrays_hi,y    ; $12F9
l_1:                       sta  zp_sidtab_row_hi    ; $12FC
                           lda  dl_per_step_counters,y    ; $12FE
                           sta  v0_sc1_counter    ; $1301
                           lda  song_position_arrays_lo,y    ; $1304
                           iny    ; $1307
                           sty  v0_sc1_row_idx    ; $1308
                           ldx  #$00    ; $130B
                           jsr  sidtab_row_apply    ; $130D
.bend

; ──────────────────────────────────────────────────────────────────────
; $1310  sidtab_cascade_v1_sc1
; ──────────────────────────────────────────────────────────────────────
; V1 sidcall1 cascade entry.
;
;   callers:             2 code sites: $12E3, $12E8
;
;   Same 6-instruction prologue as sidtab_cascade_entry (A←$FF + →refetch_v1_sc1 when zero + bmi to next cascade step). Counter v1_sc1_counter; row index v1_sc1_row_idx; refetch at v1_sc1_refetch; X=$31 (V1) at v1_cascade_slot_triple; call sidtab_row_apply at v1_cascade_slot_triple.
sidtab_cascade_v1_sc1 .block
                           lda  #$FF    ; $1310  ; ← v1_sc1_counter
                           beq  v1_sc1_refetch    ; $1312  v1_sc1_counter was zero?
                           bmi  sidtab_cascade_v2_sc1    ; $1314  v1_sc1_counter had bit 7 set?
                           dec  v1_sc1_counter    ; $1316
                           jmp  sidtab_cascade_v2_sc1    ; $1319
        .byte $00, $00, $00    ; $131C
v1_sc1_refetch:            ldy  #$FF    ; $131F  ; ← v1_sc1_row_idx
                           lda  song_position_arrays_hi,y    ; $1321
                           bne  l_1    ; $1324  song_position_arrays_hi,Y was non-zero?
                           lda  song_position_arrays_lo,y    ; $1326
                           tay    ; $1329
                           lda  song_position_arrays_hi,y    ; $132A
l_1:                       sta  zp_sidtab_row_hi    ; $132D
                           lda  dl_per_step_counters,y    ; $132F
                           sta  v1_sc1_counter    ; $1332
                           lda  song_position_arrays_lo,y    ; $1335
                           iny    ; $1338
                           sty  v1_sc1_row_idx    ; $1339
                           ldx  #$31    ; $133C
                           jsr  sidtab_row_apply    ; $133E
.bend

; ──────────────────────────────────────────────────────────────────────
; $1341  sidtab_cascade_v2_sc1
; ──────────────────────────────────────────────────────────────────────
; V2 sidcall1 cascade entry.
;
;   callers:             2 code sites: $1314, $1319
;
;   Counter v2_sc1_counter; row index v2_sc1_row_idx; refetch at v2_cascade_slot_triple; X=$62 (V2) at v2_cascade_slot_triple; call sidtab_row_apply at v2_cascade_slot_triple.
sidtab_cascade_v2_sc1 .block
                           lda  #$FF    ; $1341  ; ← v2_sc1_counter
                           beq  l_1    ; $1343  v2_sc1_counter was zero?
                           bmi  sidtab_cascade_v0_sc2    ; $1345  v2_sc1_counter had bit 7 set?
                           dec  v2_sc1_counter    ; $1347
                           jmp  sidtab_cascade_v0_sc2    ; $134A
        .byte $00, $00, $00    ; $134D
l_1:                       ldy  #$FF    ; $1350  ; ← v2_sc1_row_idx
                           lda  song_position_arrays_hi,y    ; $1352
                           bne  l_2    ; $1355  song_position_arrays_hi,Y was non-zero?
                           lda  song_position_arrays_lo,y    ; $1357
                           tay    ; $135A
                           lda  song_position_arrays_hi,y    ; $135B
l_2:                       sta  zp_sidtab_row_hi    ; $135E
                           lda  dl_per_step_counters,y    ; $1360
                           sta  v2_sc1_counter    ; $1363
                           lda  song_position_arrays_lo,y    ; $1366
                           iny    ; $1369
                           sty  v2_sc1_row_idx    ; $136A
                           ldx  #$62    ; $136D
                           jsr  sidtab_row_apply    ; $136F
.bend

; ──────────────────────────────────────────────────────────────────────
; $1372  sidtab_cascade_v0_sc2
; ──────────────────────────────────────────────────────────────────────
; V0 sidcall2 cascade entry.
;
;   callers:             2 code sites: $1345, $134A
;
;   Counter v0_sc2_counter; row index v0_sc2_row_idx; refetch at v0_sc2_cascade_slot_triple; X=$00 (V0) at v0_sc2_cascade_slot_triple; call sidtab_row_apply at v0_sc2_cascade_slot_triple.
sidtab_cascade_v0_sc2 .block
                           lda  #$FF    ; $1372  ; ← v0_sc2_counter
                           beq  l_1    ; $1374  v0_sc2_counter was zero?
                           bmi  sidtab_cascade_v1_sc2    ; $1376  v0_sc2_counter had bit 7 set?
                           dec  v0_sc2_counter    ; $1378
                           jmp  sidtab_cascade_v1_sc2    ; $137B
        .byte $00, $00, $00    ; $137E
l_1:                       ldy  #$FF    ; $1381  ; ← v0_sc2_row_idx
                           lda  song_position_arrays_hi,y    ; $1383
                           bne  l_2    ; $1386  song_position_arrays_hi,Y was non-zero?
                           lda  song_position_arrays_lo,y    ; $1388
                           tay    ; $138B
                           lda  song_position_arrays_hi,y    ; $138C
l_2:                       sta  zp_sidtab_row_hi    ; $138F
                           lda  dl_per_step_counters,y    ; $1391
                           sta  v0_sc2_counter    ; $1394
                           lda  song_position_arrays_lo,y    ; $1397
                           iny    ; $139A
                           sty  v0_sc2_row_idx    ; $139B
                           ldx  #$00    ; $139E
                           jsr  sidtab_row_apply    ; $13A0
.bend

; ──────────────────────────────────────────────────────────────────────
; $13A3  sidtab_cascade_v1_sc2
; ──────────────────────────────────────────────────────────────────────
; V1 sidcall2 cascade entry.
;
;   callers:             2 code sites: $1376, $137B
;
;   Counter v1_sc2_counter; row index v1_sc2_row_idx; refetch at v1_sc2_cascade_slot_triple; X=$31 (V1) at v1_sc2_cascade_slot_triple; call sidtab_row_apply at v1_sc2_cascade_slot_triple.
sidtab_cascade_v1_sc2 .block
                           lda  #$FF    ; $13A3  ; ← v1_sc2_counter
                           beq  l_1    ; $13A5  v1_sc2_counter was zero?
                           bmi  sidtab_cascade_v2_sc2    ; $13A7  v1_sc2_counter had bit 7 set?
                           dec  v1_sc2_counter    ; $13A9
                           jmp  sidtab_cascade_v2_sc2    ; $13AC
        .byte $00, $00, $00    ; $13AF
l_1:                       ldy  #$FF    ; $13B2  ; ← v1_sc2_row_idx
                           lda  song_position_arrays_hi,y    ; $13B4
                           bne  l_2    ; $13B7  song_position_arrays_hi,Y was non-zero?
                           lda  song_position_arrays_lo,y    ; $13B9
                           tay    ; $13BC
                           lda  song_position_arrays_hi,y    ; $13BD
l_2:                       sta  zp_sidtab_row_hi    ; $13C0
                           lda  dl_per_step_counters,y    ; $13C2
                           sta  v1_sc2_counter    ; $13C5
                           lda  song_position_arrays_lo,y    ; $13C8
                           iny    ; $13CB
                           sty  v1_sc2_row_idx    ; $13CC
                           ldx  #$31    ; $13CF
                           jsr  sidtab_row_apply    ; $13D1
.bend

; ──────────────────────────────────────────────────────────────────────
; $13D4  sidtab_cascade_v2_sc2
; ──────────────────────────────────────────────────────────────────────
; V2 sidcall2 cascade entry.
;
;   callers:             2 code sites: $13A7, $13AC
;
;   Counter v2_sc2_counter; row index v2_sc2_row_idx; refetch at v2_sc2_cascade_slot_triple; X=$62 (V2) at v2_sc2_cascade_slot_triple; call sidtab_row_apply at v2_sc2_cascade_slot_triple. Tail fall-through (or jump pitch_slide_oscillator) reaches the pitch oscillator.
sidtab_cascade_v2_sc2 .block
                           lda  #$FF    ; $13D4  ; ← v2_sc2_counter
                           beq  l_1    ; $13D6  v2_sc2_counter was zero?
                           bmi  pitch_slide_oscillator    ; $13D8  v2_sc2_counter had bit 7 set?
                           dec  v2_sc2_counter    ; $13DA
                           jmp  pitch_slide_oscillator    ; $13DD
        .byte $00, $00, $00    ; $13E0
l_1:                       ldy  #$FF    ; $13E3  ; ← v2_sc2_row_idx
                           lda  song_position_arrays_hi,y    ; $13E5
                           bne  l_2    ; $13E8  song_position_arrays_hi,Y was non-zero?
                           lda  song_position_arrays_lo,y    ; $13EA
                           tay    ; $13ED
                           lda  song_position_arrays_hi,y    ; $13EE
l_2:                       sta  zp_sidtab_row_hi    ; $13F1
                           lda  dl_per_step_counters,y    ; $13F3
                           sta  v2_sc2_counter    ; $13F6
                           lda  song_position_arrays_lo,y    ; $13F9
                           iny    ; $13FC
                           sty  v2_sc2_row_idx    ; $13FD
                           ldx  #$62    ; $1400
                           jsr  sidtab_row_apply    ; $1402
.bend

; ──────────────────────────────────────────────────────────────────────
; $1405  pitch_slide_oscillator
; ──────────────────────────────────────────────────────────────────────
; per-voice pitch slide + pulse-width modulation loop.
;
;   callers:             2 code sites: $13D8, $13DD
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Iterates X = $62, $31, $00 (V2, V1, V0). For each voice, dispatches on slide mode (slide_mode_v0,X):
;     - == 0     → simple note-pitch lookup (pitch_no_slide_path; freq = NOTE_PITCH[current_note_v0,X] + pitch_base_v0,X).
;     - $80..$FF → active slide (pitch_oscillator_voice_loop_body+; Y = slide_mode<<1 selects slide_inc/dec rate from slide_dec_lut_lo / pitch_lut_band / slide_dec_lut_hi / slide_inc_lut_hi).
;     - $01..$7F → portamento (pitch_portamento_path+; interval-interpolates current note → target via adjacent-semitone LUTs interval_lut_lo_a / interval_lut_lo_b / interval_lut_hi_a / interval_lut_hi_b).
;
;   Slide accumulator at voice_record_v0/v0_slide_acc,X is integrated then added to NOTE_PITCH[current_note_v0,X] to produce the final 16-bit freq, written to pw_hi_patch_v0,X.
;
;   PS (pulse-width sweep) at ps_sweep_entry-ps_sweep_tail is reached via jump from pitch_oscillator_voice_loop_body (active slide tail) and pitch_no_slide_path (no-slide tail). It uses ps_depth_v0,X as a signed depth+direction byte and BORROWS the pw_lo_patch_v0/pw_hi_patch_v0,X patch slots (= the PW operands the sidTAB writer at sidtab_row_apply also targets) as the working register. Bit 7 of ps_depth_v0,X picks direction:
;     - SET   → ADD path at ps_sweep_add_path_smc (`ANC #$7F` masks magnitude and clears C; A+=pulse_lo).
;     - CLEAR → SUB path at ps_sweep_sub_path (read pulse_lo; A-=ps_depth_v0,X — C-in is UNCONTROLLED, inherits prior adc at pitch_oscillator_voice_loop_body / pitch_no_slide_path).
;
;   On pulse_hi overflow (ps_sweep_hi_clamp clamp lo=$F8) or underflow (ps_sweep_lo_clamp clamp lo=$01) the direction bit flips via `A^=$80 / write ps_depth_v0,X` at ps_sweep_hi_clamp / ps_sweep_lo_clamp, producing a triangle PW sweep.
;
;   Tail loops via pitch_oscillator_loop_tail_smc →groove_song_position when negative — exits when X underflows after V0.
;
;   The 8 paired pitch tables in slide_dec_lut_lo-pitch_lut_band are accessed by multiple
;   labelled bases that ALIAS the same 576-byte backing region:
;
;    pitch_lut_band / slide_inc_lut_hi — slide increment per-frame (additive path)
;    slide_dec_lut_lo / slide_dec_lut_hi — slide decrement per-frame (subtractive path, signed)
;    note_pitch_lut_lo / note_pitch_lut_hi — note → target pitch (full-octave LUT)
;    interval_lut_lo_a / interval_lut_hi_a + interval_lut_lo_b / interval_lut_hi_b — adjacent-semitone interval (used at
;    pitch_portamento_path to compute portamento step size between current note
;    and target note)
;
;   Y indexes into these tables via Y = current_note_v0,X (current note) or
;   Y = slide_mode_v0,X asl (slide-mode pair). The LUT bytes themselves are dual-
;   purpose: slide_dec_lut_lo-pitch_oscillator_anc_smc_mirror is also live 6502 CODE in the player; the slide
;   LUT bases at slide_dec_lut_lo/pitch_lut_band read the same backing bytes through a
;   different abstract index.
;
;   Slide accumulator reset: the pattern-row advance band at V0_gate_n_branch-v0_gate_n_tail
;   (V0's GATE_N branch) unconditionally zeros voice_record_v0/v0_slide_acc/slide_mode_v0 every time
;   GATE_N fires on a step. Without this reset, a slide_mode set by sidTAB
;   AF column at some earlier row keeps integrating across subsequent
;   GATE_N events and the freq drifts catastrophically into oscillator-wrap
;   territory. V1 has the same reset in its V0_gate_n_branch-analog band; V2 likewise.
pitch_slide_oscillator .block
                           ldx  #$62    ; $1405
.bend

; ──────────────────────────────────────────────────────────────────────
; $1407  pitch_oscillator_voice_loop_body
; ──────────────────────────────────────────────────────────────────────
; Per-voice X-loop body inside pitch_slide_oscillator.
;
;   callers:             1 code sites: $14E8 pitch_oscillator_voice_loop_tail
;
;   Reached only by jump pitch_oscillator_voice_loop_tail (the X-loop continuation that closes each iteration of the V2→V1→V0 walk). Not a separate function — see pitch_slide_oscillator.
pitch_oscillator_voice_loop_body .block
;     read slide_mode_v0,X (slide mode byte).
                           lda  slide_mode_v0,x    ; $1407
;     →pitch_no_slide_path when zero (no-slide path).
                           beq  pitch_no_slide_path    ; $140A  slide_mode_v0,X was zero?
;     →pitch_portamento_path when positive (portamento path, $01..$7F).
                           bpl  pitch_portamento_path    ; $140C  slide_mode_v0,X had bit 7 clear?
;     asl A / Y←A / →pitch_oscillator_voice_loop_body when positive (clamp-check).
                           asl  a    ; $140E
                           tay    ; $140F
                           bpl  l_1    ; $1410  (slide_mode_v0,X << 1) had bit 7 clear?
                           lda  voice_record_v0,x    ; $1412
;     A-=slide_dec_lut_lo,Y subtractive integration → pitch_oscillator_voice_loop_body merge.
                           sbc  slide_dec_lut_lo,y    ; $1415
                           sta  voice_record_v0,x    ; $1418
                           lda  v0_slide_acc,x    ; $141B
                           sbc  slide_dec_lut_hi,y    ; $141E
                           sta  v0_slide_acc,x    ; $1421
                           jmp  l_2    ; $1424
l_1:                       lda  pitch_lut_band,y    ; $1427
                           clc    ; $142A
                           adc  voice_record_v0,x    ; $142B
                           sta  voice_record_v0,x    ; $142E
                           lda  slide_inc_lut_hi,y    ; $1431
                           adc  v0_slide_acc,x    ; $1434
                           sta  v0_slide_acc,x    ; $1437
l_2:                       clc    ; $143A
                           ldy  current_note_v0,x    ; $143B
                           lda  voice_record_v0,x    ; $143E
                           adc  note_pitch_lut_lo,y    ; $1441
                           sta  slide_acc_commit_lo,x    ; $1444
                           lda  note_pitch_lut_hi,y    ; $1447
                           adc  v0_slide_acc,x    ; $144A
                           sta  slide_acc_commit_hi,x    ; $144D
                           jmp  ps_sweep_entry    ; $1450
.bend

; ──────────────────────────────────────────────────────────────────────
; $1453  pitch_no_slide_path
; ──────────────────────────────────────────────────────────────────────
; slide_mode == 0 branch (→pitch_no_slide_path when zero from pitch_oscillator_voice_loop_body).
;
;   callers:             1 code sites: $140A
;
;   Looks up the 16-bit pitch for current_note from note_pitch_lut_lo/note_pitch_lut_hi, adds pitch_base (per-voice detune: V0=$00 / V1=$01 / V2=$02 — pre-loaded into voice_record_v0/ps_depth_v1/voice_record_v2 at offset +6), and writes the result into the per-voice freq-patch slots. Without the per-voice detune all three voices producing the same NOTE phase-lock into a static pitched click.
pitch_no_slide_path .block
                           ldy  current_note_v0,x    ; $1453
                           lda  note_pitch_lut_lo,y    ; $1456
                           clc    ; $1459
                           adc  pitch_base_v0,x    ; $145A
                           sta  slide_acc_commit_lo,x    ; $145D
                           lda  note_pitch_lut_hi,y    ; $1460
                           sta  slide_acc_commit_hi,x    ; $1463
                           jmp  ps_sweep_entry    ; $1466
.bend

; ──────────────────────────────────────────────────────────────────────
; $1469  pitch_portamento_path
; ──────────────────────────────────────────────────────────────────────
; slide_mode $01..$7F branch (→pitch_portamento_path when positive from pitch_oscillator_voice_loop_body).
;
;   callers:             1 code sites: $140C
;
;   Computes target NOTE = current_note + slide_mode (positive interval). The
;   adjacent-semitone interval LUTs (interval_lut_lo_a/b, interval_lut_hi_a/b)
;   give the per-frame step (= LUT_b[target] − LUT_a[target] for each byte),
;   which is patched into the self-modifying ADC operands inside this path.
;   The 16-bit pitch for current_note is then read from note_pitch_lut_lo/hi
;   and the patched step is added to it before writing the result to the
;   per-voice freq-patch slots.
;
;   This is NOT the active-slide integration path — it's a one-shot pitch
;   interpolation, not a per-frame integrator. The accumulator in
;   v0_slide_acc,X is not updated here, so re-entering this path each frame
;   re-computes the SAME interpolation from the SAME current_note. Portamento
;   therefore only animates when current_note changes (e.g. a GATE_N row
;   sidTAB-TR-shifts the note mid-portamento). Unverified.
pitch_portamento_path .block
                           clc    ; $1469
                           adc  current_note_v0,x    ; $146A
                           tay    ; $146D
                           lda  interval_lut_lo_b,y    ; $146E
                           sec    ; $1471
                           sbc  interval_lut_lo_a,y    ; $1472
                           sta  pitch_portamento_path + $20    ; $1475
                           lda  interval_lut_hi_b,y    ; $1478
                           sbc  interval_lut_hi_a,y    ; $147B
                           sta  pitch_portamento_path + $28    ; $147E
                           ldy  current_note_v0,x    ; $1481
                           lda  note_pitch_lut_lo,y    ; $1484
                           clc    ; $1487
                           adc  #$FF    ; $1488  ; ← (SMC operand at $1489, no name)
                           sta  slide_acc_commit_lo,x    ; $148A
                           lda  note_pitch_lut_hi,y    ; $148D
                           adc  #$FF    ; $1490  ; ← (SMC operand at $1491, no name)
                           sta  slide_acc_commit_hi,x    ; $1492
.bend

; ──────────────────────────────────────────────────────────────────────
; $1495  ps_sweep_entry
; ──────────────────────────────────────────────────────────────────────
; pulse-width sweep loop, called from BOTH pitch_oscillator_voice_loop_body (active-slide tail) and pitch_no_slide_path (no-slide tail).
;
;   callers:             2 code sites: $1450, $1466
;
;   Y←ps_depth_v0,X (signed depth+direction byte). →pitch_oscillator_loop_tail when zero (depth 0 → exit to loop tail, no PW change this frame). →ps_sweep_sub_path when positive (positive depth → SUB path); else fall through to ADD path at ps_sweep_add_path_smc-ps_sweep_anc_imm_smc. ps_sweep_hi_clamp/ps_sweep_lo_clamp are the clamp branches; ps_sweep_sub_path is the SUB path; pitch_oscillator_loop_tail is the X-loop tail. Note that ADD/SUB direction here is *inverted* relative to typical convention: depth bit 7 SET (negative) → ADC (ADD); bit 7 CLEAR (positive) → SBC (SUB).
ps_sweep_entry .block
                           ldy  ps_depth_v0,x    ; $1495
                           beq  pitch_oscillator_loop_tail    ; $1498  ps_depth_v0,X was zero?
                           bpl  ps_sweep_sub_path    ; $149A  ps_depth_v0,X had bit 7 clear?
ps_sweep_add_path_smc:     tya    ; $149C
.bend

; ──────────────────────────────────────────────────────────────────────
; $149D  ps_sweep_anc_imm_smc
; ──────────────────────────────────────────────────────────────────────
; Undocumented opcode $2B (immediate): masks A with #$7F and copies bit 7 into carry, in the PS-sweep add path; rendered as .byte because 64tass emits the $0B encoding for that mnemonic.
;
;   code edges:          fall-through from $149C ps_sweep_add_path_smc (1 bytes earlier)
;
;   Continues the ps_sweep_add_path_smc instruction stream; the $2B byte is one of two ANC encodings (the other is $0B).
ps_sweep_anc_imm_smc .block
                           .byte $2B, $7F    ; $149D  ; anc #$7F (undocumented opcode $2B)
                           adc  pw_lo_patch_v0,x    ; $149F
                           sta  pw_lo_patch_v0,x    ; $14A2
                           bcc  pitch_oscillator_loop_tail    ; $14A5  pw_lo_patch_v0 no carry
                           lda  pw_hi_patch_v0,x    ; $14A7
                           cmp  #$0F    ; $14AA
                           beq  ps_sweep_hi_clamp    ; $14AC  pw_hi_patch_v0,X was $0F?
                           inc  pw_hi_patch_v0,x    ; $14AE
                           jmp  pitch_oscillator_loop_tail    ; $14B1
.bend

; ──────────────────────────────────────────────────────────────────────
; $14B4  ps_sweep_hi_clamp
; ──────────────────────────────────────────────────────────────────────
; pulse-width high clamp at $0F.
;
;   callers:             1 code sites: $14AC
;
;   Reached after the ADD path's PW-lo overflow. If PW hi has reached $0F (max), flip the direction bit in ps_depth_v0,X (EOR $80) and clamp PW lo to $F8 — the sweep reverses on the way back down. Otherwise just bump PW hi. Implements the top end of the triangle PW sweep (ps_sweep_lo_clamp mirrors at the bottom).
ps_sweep_hi_clamp .block
                           lda  #$F8    ; $14B4
                           sta  pw_lo_patch_v0,x    ; $14B6
                           tya    ; $14B9
                           eor  #$80    ; $14BA
                           sta  ps_depth_v0,x    ; $14BC
                           jmp  pitch_oscillator_loop_tail    ; $14BF
.bend

; ──────────────────────────────────────────────────────────────────────
; $14C2  ps_sweep_lo_clamp
; ──────────────────────────────────────────────────────────────────────
; pulse-width low clamp at $00 (mirrors ps_sweep_hi_clamp hi clamp).
;
;   callers:             1 code sites: $14DE
;
;   Reached on PW-lo underflow during the SUB path. If PW hi has hit 0, clamp PW lo to $01 and flip the direction bit in ps_depth_v0,X (EOR $80) so the sweep reverses upward. Otherwise just decrement PW hi. Together with ps_sweep_hi_clamp produces the triangle-wave PW sweep that audibly modulates filter-less tunes.
ps_sweep_lo_clamp .block
                           lda  #$01    ; $14C2
                           sta  pw_lo_patch_v0,x    ; $14C4
                           tya    ; $14C7
                           eor  #$80    ; $14C8
                           sta  ps_depth_v0,x    ; $14CA
                           jmp  pitch_oscillator_loop_tail    ; $14CD
.bend

; ──────────────────────────────────────────────────────────────────────
; $14D0  ps_sweep_sub_path
; ──────────────────────────────────────────────────────────────────────
; PW depth positive branch (entered from →ps_sweep_sub_path when positive at ps_sweep_entry).
;
;   callers:             1 code sites: $149A
;
;   Subtracts ps_depth from the per-voice PW lo (carry-in is uncontrolled — see PS_sweep_sbc_c_in_uncontrolled). No underflow → exit. On underflow: if PW hi is already 0, jump to ps_sweep_lo_clamp to flip direction; otherwise decrement PW hi and exit.
ps_sweep_sub_path .block
                           lda  pw_lo_patch_v0,x    ; $14D0
.bend

; ──────────────────────────────────────────────────────────────────────
; $14D3  PS_sweep_sbc_c_in_uncontrolled
; ──────────────────────────────────────────────────────────────────────
; operand of the A-=ps_depth_v0,X at PS_sweep_sbc_c_in_uncontrolled.
;
;   code edges:          fall-through from $14D0 ps_sweep_sub_path (3 bytes earlier)
;
;   Carry-in is NOT explicitly set — the set-carry was issued at pitch_portamento_path (portamento path) or implicitly from pitch_oscillator_voice_loop_body (active slide). In practice this means A-=may behave as 'sbc - 1' if a prior carry-clearing operation happened.
PS_sweep_sbc_c_in_uncontrolled .block
                           sbc  ps_depth_v0,x    ; $14D3
                           sta  pw_lo_patch_v0,x    ; $14D6
                           bcs  pitch_oscillator_loop_tail    ; $14D9  ps_depth_v0 no borrow
                           lda  pw_hi_patch_v0,x    ; $14DB
                           beq  ps_sweep_lo_clamp    ; $14DE  pw_hi_patch_v0,X was zero?
                           dec  pw_hi_patch_v0,x    ; $14E0
.bend

; ──────────────────────────────────────────────────────────────────────
; $14E3  pitch_oscillator_loop_tail
; ──────────────────────────────────────────────────────────────────────
; A←X (A := X = $62/$31/$00); SBX #$31 ($CB $31 — undocumented AXS opcode: X := (A and X) - #$31, sets carry as for sbc); →groove_song_position when negative if result negative (X went below $00 = wrapped from $00); else jump pitch_oscillator_voice_loop_body (re-enter loop with X = X - $31).
;
;   callers:             6 code sites: $1498, $14A5, $14B1, $14BF, $14CD, $14D9
;
;   At entry X=$62 → X-$31 = $31 (V1 next); X=$31 → X-$31 = $00 (V0 next); X=$00 → wrap (→fires) when negative → return at groove_song_position. The AXS opcode is unusual — `X := (A and X) - #imm` in a single 2-byte instruction without clobbering A. Reading defmon.s, expect to see the `.byte $CB, $31` block in place of an `axs` mnemonic.
pitch_oscillator_loop_tail .block
                           txa    ; $14E3
.bend

; ──────────────────────────────────────────────────────────────────────
; $14E4  pitch_oscillator_loop_tail_smc
; ──────────────────────────────────────────────────────────────────────
; Undocumented opcode $CB (immediate): X is set to (A & X) minus #$31, at the tail of pitch_slide_oscillator.
;
;   code edges:          fall-through from $14E3 pitch_oscillator_loop_tail (1 bytes earlier)
;
;   Subtracts the $31 per-voice record stride as the loop walks voices.
pitch_oscillator_loop_tail_smc .block
                           axs  #$31    ; $14E4
                           bmi  pitch_oscillator_voice_loop_tail.groove_song_position    ; $14E6  X had bit 7 set?
.bend

; ──────────────────────────────────────────────────────────────────────
; $14E8  pitch_oscillator_voice_loop_tail
; ──────────────────────────────────────────────────────────────────────
; Per-voice X-loop tail inside pitch_slide_oscillator.
;
;   code edges:          fall-through from $14E6 in pitch_oscillator_loop_tail_smc (2 bytes earlier)
;
;   After PS sweep / clamps / slide-accumulator commit, →groove_song_position when negative merges into a tail block at groove_song_position-raster_sync_random that decrements X (A←X/A-=$31/X←A) and jump pitch_oscillator_voice_loop_body to walk to the next voice (V2→V1→V0). Exits when X underflows after V0. Not a separate function — see pitch_slide_oscillator.
pitch_oscillator_voice_loop_tail .block
                           jmp  pitch_oscillator_voice_loop_body    ; $14E8
groove_song_position:      rts    ; $14EB
        .byte $00, $00    ; $14EC
.bend

; ──────────────────────────────────────────────────────────────────────
; $14EE  raster_sync_random
; ──────────────────────────────────────────────────────────────────────
; push flags/IRQ-off, busy-wait for raster line VIC_RASTER=$FC, then read SID#1 voice-3 oscillator output SID_OSC3 for entropy.
;
;   callers:             1 code sites: $1544
;   registers clobbered: A
;
;   Reads bit 0 of the V3 oscillator entropy byte and uses it to randomly bias the cutoff-slide path. Bit 0 clear → filter_cutoff_slide_threshold_reload = $02 + filter_slide_output_opcode = $EA (NOP, output passes through). Bit 0 set → filter_cutoff_slide_threshold_reload = $00 + filter_slide_output_opcode = $0A (ASL A, doubles the cutoff-slide output). Called once from player_init_body; the patched bytes stay for the lifetime of the loaded tune. This is how defMON gets tune-startup-randomized swing without rerolling per frame.
raster_sync_random .block
                           php    ; $14EE
                           sei    ; $14EF
                           lda  #$FC    ; $14F0
l_1:                       cmp  VIC_RASTER    ; $14F2
                           bne  l_1    ; $14F5  $FC was not VIC_RASTER?
                           lda  #$FF    ; $14F7  ; ← slide_dec_lut_lo
                           sta  SID_V3_CTRL    ; $14F9  ; SID_V3_CTRL := TRI+SAW+PUL+NOI GATE SYNC RING TEST
                           sta  load_decoder_pat_base_walk.SID_V3_FREQ_LO    ; $14FC
                           sta  load_decoder_pat_base_walk.SID_V3_FREQ_HI    ; $14FF
                           lda  #$20    ; $1502
                           sta  SID_V3_CTRL    ; $1504  ; SID_V3_CTRL := SAW
                           lda  SID_OSC3    ; $1507
                           lsr  a    ; $150A
                           bcc  l_2    ; $150B  (SID_OSC3 >> 1) shifted-out bit was 0?
                           lda  #$00    ; $150D
                           sta  filter_cutoff_slide_threshold_reload    ; $150F
                           lda  #$0A    ; $1512
                           bne  l_3    ; $1514  raster_sync_random_$25 was non-zero?
l_2:                       lda  #$02    ; $1516
                           sta  filter_cutoff_slide_threshold_reload    ; $1518
                           lda  #$EA    ; $151B
l_3:                       sta  filter_slide_output_opcode    ; $151D
                           plp    ; $1520
                           rts    ; $1521
.bend

; ──────────────────────────────────────────────────────────────────────
; $1522  player_init_body
; ──────────────────────────────────────────────────────────────────────
; A=tune index → current_arranger_row.
;
;   callers:             1 code sites: $1000 player_init
;   inputs:              A
;   registers clobbered: A, X, Y
;
;   Clears all 24 SID #1 regs (SID_V1_FREQ_LO-SID_FILTER_RES) via the dey loop at player_init_body; zeros filter/slide globals filter_cutoff_acc_lo/filter_cutoff_slide_acc_hi/filter_cutoff_slide_accumulator/filter_cutoff_slide_acc_hi/filter_cutoff_slide_saturation_step/filter_resonance_routing/filter_volume_or_mode; JSRs raster_sync_random for raster sync + RNG. Then for each voice (X = $62, $31, $00) zeros per-voice runtime state (v0_sc1_row_idx/v0_sc2_row_idx sidcall row indices; pw_hi_patch_v0 SID-write patch slots; slide_mode_v0/ps_depth_v0 mode flags; current_note_v0 current note) and sets sidcall step counters v0_sc1_counter,X / v0_sc2_counter,X = SILENCE_FLAG_EOS so the cascade re-fetches a row on the first tick. Sets silence_or_endsong_flag = SILENCE_FLAG_QUIET (silence) so playback stays muted until the next pattern row promotes the voice.
player_init_body .block
                           sta  current_arranger_row    ; $1522
                           ldy  #$17    ; $1525
                           lda  #$00    ; $1527
l_1:                       sta  load_decoder_pat_base_walk.SID_V1_FREQ_LO,y    ; $1529
                           dey    ; $152C
                           bpl  l_1    ; $152D  $17 walked back 1 and had bit 7 clear?
                           sta  filter_cutoff_acc_lo    ; $152F
                           sta  filter_cutoff_slide_acc_hi    ; $1532
                           sta  filter_cutoff_slide_step_lo_smc    ; $1535
                           sta  filter_cutoff_slide_step_hi_smc    ; $1538
                           sta  filter_cutoff_slide_saturation_step    ; $153B
                           sta  filter_resonance_routing    ; $153E
                           sta  filter_volume_or_mode    ; $1541
                           jsr  raster_sync_random    ; $1544
                           ldx  #$62    ; $1547
l_2:                       lda  #$00    ; $1549
                           sta  v0_sc1_row_idx,x    ; $154B
                           sta  v0_sc2_row_idx,x    ; $154E
                           sta  v0_sid_patch_b,x    ; $1551
                           sta  v0_sid_patch_a,x    ; $1554
                           sta  v0_sid_patch_c,x    ; $1557
                           sta  v0_sid_patch_d,x    ; $155A
                           sta  slide_mode_v0,x    ; $155D
                           sta  ps_depth_v0,x    ; $1560
                           sta  current_note_v0,x    ; $1563
                           lda  #$FF    ; $1566
                           sta  v0_sc1_counter,x    ; $1568
                           sta  v0_sc2_counter,x    ; $156B
.bend

; ──────────────────────────────────────────────────────────────────────
; $156E  pitch_oscillator_anc_smc_mirror
; ──────────────────────────────────────────────────────────────────────
; Undocumented opcode $CB (immediate): X is set to (A & X) minus #$31, a parallel-branch mirror of pitch_oscillator_loop_tail_smc.
;
;   code edges:          fall-through from $156B in player_init_body_2 (3 bytes earlier)
;
;   Same $31 stride-subtract semantics.
pitch_oscillator_anc_smc_mirror .block
                           axs  #$31    ; $156E
                           bpl  player_init_body.l_2    ; $1570  X had bit 7 clear?
                           lda  #SILENCE_FLAG_QUIET    ; $1572
                           sta  silence_or_endsong_flag    ; $1574
                           rts    ; $1577
        .byte $00, $00, $01, $01, $02, $02, $04, $04, $08, $08, $0C, $0C, $11, $12, $14, $15    ; $1578
        .byte $16, $17, $19, $1A, $1C, $1D, $1F, $21, $23, $25, $27, $29, $2C, $2E, $31, $34    ; $1588
        .byte $37, $3B, $3E, $42, $46, $4A, $4E, $53, $58, $5D, $62, $68, $6E, $75, $7C, $83    ; $1598
        .byte $8B, $93, $9C, $A6, $AF, $BA, $C5, $D1, $DD, $EA, $F8, $07, $16, $27, $39, $4B    ; $15A8
        .byte $5F, $74, $8A, $A1, $BA, $D4, $F0, $0E, $2D, $4E, $71, $96, $BE, $E7, $14, $42    ; $15B8
        .byte $74, $A9, $E0, $1B, $5A, $9C, $E2, $2D, $7B, $CF, $27, $85, $E8, $51, $C1, $37    ; $15C8
        .byte $B4, $38, $C4, $59, $F7, $9D, $4E, $0A, $D0, $A2, $81, $6D, $67, $70, $89, $B2    ; $15D8
        .byte $ED, $3B, $9C, $13, $A0, $45, $02, $DA, $CE, $E0, $11, $64, $DA, $76, $39, $26    ; $15E8
        .byte $40, $89, $04, $B4, $9C, $C0, $23, $C8, $B4, $EB, $72, $4C, $80, $12, $08, $68    ; $15F8
        .byte $39, $80, $45, $90, $68, $D6, $E3, $99, $00, $24, $10, $FF    ; $1608
        .fill 59, $00    ; $1614-$164E
        .byte $01, $01, $01, $01, $01, $01, $01, $01, $01, $01, $01, $01, $02, $02, $02, $02    ; $164F
        .byte $02, $02, $02, $03, $03, $03, $03, $03, $04, $04, $04, $04, $05, $05, $05, $06    ; $165F
        .byte $06, $06, $07, $07, $08, $08, $09, $09, $0A, $0A, $0B, $0C, $0D, $0D, $0E, $0F    ; $166F
        .byte $10, $11, $12, $13, $14, $15, $17, $18, $1A, $1B, $1D, $1F, $20, $22, $24, $27    ; $167F
        .byte $29, $2B, $2E, $31, $34, $37, $3A, $3E, $41, $45, $49, $4E, $52, $57, $5C, $62    ; $168F
        .byte $68, $6E, $75, $7C, $83, $8B, $93, $9C, $A5, $AF, $B9, $C4, $D0, $DD, $EA, $F8    ; $169F
        .byte $FF    ; $16AF
.bend

; ──────────────────────────────────────────────────────────────────────
; $16B0  sidtab_row_apply
; ──────────────────────────────────────────────────────────────────────
; apply one sidTAB row to voice X (X = $00 / $31 / $62).
;
;   callers:             6 code sites: $130D, $133E, $136F, $13A0, $13D1, $1402
;   inputs:              A, X
;   registers clobbered: A, X, Y
;
;   A = row low byte; sets ($FB) = full row pointer. Reads the row's first bitmap byte and dispatches per bit (MSB to LSB):
;     - bit 7 → pw_hi_patch_v0,X (ctrl eor mask, WGl column applied each frame).
;     - bit 6 → pw_hi_patch_v0,X (ctrl_main = SID waveform/gate, WGh column).
;     - bit 5 → pw_hi_patch_v0,X (attack/decay, AD column).
;     - bit 4 → pw_hi_patch_v0,X (sustain/release, SR column).
;     - bit 3 → current_note_v0,X (current_note + optional transpose from v0_transpose_buffer,X; TR column).
;     - bit 2 → slide_mode_v0,X (slide mode, AF column).
;     - bit 1 → pw_hi_patch_v0 / pw_lo_patch_v0,X (PULSE-WIDTH pair: byte → pw_hi_patch_v0, byte & $F0 → pw_lo_patch_v0; 12-bit `$YX` PW encoding writes SID_V1_PW_HI = full byte, SID_V1_PW_LO = byte & $F0).
;
;   Reads second bitmap byte and dispatches further fields:
;     - filter resonance/routing (filter_resonance_routing / filter_volume_or_mode).
;     - filter cutoff slide (filter_cutoff_acc_lo / filter_cutoff_slide_accumulator / filter_cutoff_slide_acc_hi opcode patches).
;     - instrument-load slots (filter_cutoff_slide_saturation_step).
;
;   Returns via one of three RTSs at pitch_lut_tail_smc / player_irq_tail_anc_smc.
;
;   Called 6× from the sidTAB cascade tail at JP_redirect_reread/v1_cascade_slot_triple/v2_cascade_slot_triple (sidcall1
;   V0/V1/V2) and v0_sc2_cascade_slot_triple/v1_sc2_cascade_slot_triple/v2_sc2_cascade_slot_triple (sidcall2 V0/V1/V2). The per-row
;   bitmap byte encodes which fields the row writes; absent bits leave the
;   slot at its previous value, so a sidTAB row only needs to carry the
;   bytes it actually changes.
;
;   Bit ordering: bit 6 = WGh, bit 7 = WGl, bit 5 = AD, bit 4 = SR,
;   bit 3 = TR, bit 2 = AF, bit 1 = PW. The PW pair at pw_lo_patch_v0/pw_hi_patch_v0 are the
;   operand bytes of LDX/LDA immediates inside the V0 SID-write band at
;   player_play_body that get STX'd into SID_V1_PW_LO / STA'd into SID_V1_PW_HI; freq lo/hi slots
;   are separately at pw_hi_patch_v0 (one LDX/LDA pair later in the band).
;
;   The filter-cutoff slide path (pitch_lut_tail_smc-player_irq_tail_anc_smc) is the only branch that can
;   take more than one RTS — it patches the opcode at filter_cutoff_slide_accumulator/filter_cutoff_slide_acc_hi
;   ($69 = ADC immediate, $E9 = SBC immediate) so the per-frame cutoff
;   update at filter_cutoff_slide_accumulator-filter_cutoff_block_end walks the cutoff up or down.
sidtab_row_apply .block
                           sta  zp_sidtab_row_lo    ; $16B0
                           ldy  #$00    ; $16B2
                           lda  (zp_sidtab_row_lo),y    ; $16B4
                           beq  sidtab_row_apply_tr_tail.l_3    ; $16B6  (zp_sidtab_row_lo),Y was zero?
                           asl  a    ; $16B8
                           sta  zp_scratch_96    ; $16B9
                           bpl  l_1    ; $16BB  (zp_sidtab_row_lo),Y had bit 7 clear?
                           iny    ; $16BD
                           lda  (zp_sidtab_row_lo),y    ; $16BE
                           sta  v0_sid_patch_c,x    ; $16C0
l_1:                       bcc  l_2    ; $16C3  (zp_sidtab_row_lo),Y shifted-out bit was 0?
                           iny    ; $16C5
                           lda  (zp_sidtab_row_lo),y    ; $16C6
                           sta  v0_sid_patch_d,x    ; $16C8
l_2:                       bit  zp_scratch_96    ; $16CB
                           bvc  l_3    ; $16CD  zp_scratch_96 had bit 6 clear?
                           iny    ; $16CF
                           lda  (zp_sidtab_row_lo),y    ; $16D0
                           sta  v0_sid_patch_b,x    ; $16D2
l_3:                       lda  zp_scratch_96    ; $16D5
                           and  #$20    ; $16D7
                           beq  l_4    ; $16D9  (zp_scratch_96 & $20) was zero?
                           iny    ; $16DB
                           lda  (zp_sidtab_row_lo),y    ; $16DC
                           sta  v0_sid_patch_a,x    ; $16DE
l_4:                       lda  zp_scratch_96    ; $16E1
                           and  #$10    ; $16E3
                           beq  sidtab_row_apply_tr_tail.l_1    ; $16E5  (zp_scratch_96 & $10) was zero?
.bend

; ──────────────────────────────────────────────────────────────────────
; $16E7  sidtab_row_apply_tr_handler
; ──────────────────────────────────────────────────────────────────────
; TR column entry inside sidtab_row_apply.
;
;   code edges:          fall-through from $16E5 in sidtab_row_apply_4 (2 bytes earlier)
;
;   Bit 3 of the low bitmap selects the TR branch: read row_byte + clear-carry + A+=v0_transpose_buffer,X (V0 transpose buffer = raw NOTE from last GATE_N). Result is current_note + row.tr_offset → write current_note_v0,X. Per-voice v0_transpose_buffer,X is the transpose base; for V1 the analog lives at v1_cascade_slot_triple (mirror written by row_read_body_v1 row-read), for V2 at v2_cascade_slot_triple.
sidtab_row_apply_tr_handler .block
                           iny    ; $16E7
                           lda  (zp_sidtab_row_lo),y    ; $16E8
                           bmi  l_1    ; $16EA  (zp_sidtab_row_lo),Y had bit 7 set?
                           clc    ; $16EC
                           adc  v0_transpose_buffer,x    ; $16ED
l_1:                       and  #$7F    ; $16F0
.bend

; ──────────────────────────────────────────────────────────────────────
; $16F2  sidtab_row_apply_tr_tail
; ──────────────────────────────────────────────────────────────────────
; TR handler tail — final write current_note_v0,X (current_note write) inside sidtab_row_apply_tr_handler's branch.
;
;   code edges:          fall-through from $16F0 sidtab_row_apply_tr_handler_1 (2 bytes earlier)
;
;   Falls through to the bit-2 (AF / slide_mode) dispatch at sidtab_row_apply_tr_tail+. End of TR-column body.
sidtab_row_apply_tr_tail .block
                           sta  current_note_v0,x    ; $16F2
l_1:                       lda  zp_scratch_96    ; $16F5
                           and  #$08    ; $16F7
                           beq  l_2    ; $16F9  (zp_scratch_96 & $08) was zero?
                           iny    ; $16FB
                           lda  (zp_sidtab_row_lo),y    ; $16FC
                           sta  slide_mode_v0,x    ; $16FE
l_2:                       lda  zp_scratch_96    ; $1701
                           and  #$04    ; $1703
                           beq  l_3    ; $1705  (zp_scratch_96 & $04) was zero?
                           iny    ; $1707
                           lda  (zp_sidtab_row_lo),y    ; $1708
                           sta  pw_hi_patch_v0,x    ; $170A
                           and  #$F0    ; $170D
                           sta  pw_lo_patch_v0,x    ; $170F
l_3:                       iny    ; $1712
                           lda  (zp_sidtab_row_lo),y    ; $1713
                           beq  pitch_lut_tail_smc.l_4    ; $1715  (zp_sidtab_row_lo),Y was zero?
                           asl  a    ; $1717
