; ──────────────────────────────────────────────────────────────────────
; $73F0  raster_wait
; ──────────────────────────────────────────────────────────────────────
; wait one full VBL frame.
;
;   callers:             irq_banking_setup (player NMI body — raster sync before paint), raster_wait BPL self-loop, global_pre_dispatch_statusline_epilogue (status-line paint epilogue inside global_pre_dispatch's global_pre_dispatch_statusline_epilogue region).
;   inputs:              A
;   registers clobbered: none (preserves A/X/Y)
;
;   bit-test VIC_CR1 / →raster_wait when positive (busy-wait until raster is in the upper half) / bit-test VIC_CR1 / →raster_wait when negative (busy-wait until raster crosses into the lower half) / return. Guarantees the caller sees exactly one VIC_CR1 bit-7 transition per call (≈ half a PAL frame = ~8.3 ms).
raster_wait .block
                           bit  VIC_CR1    ; $73F0
                           bpl  raster_wait    ; $73F3  VIC_CR1 had bit 7 clear?
l_1:                       bit  VIC_CR1    ; $73F5
                           bmi  l_1    ; $73F8  VIC_CR1 had bit 7 set?
                           rts    ; $73FA
.bend

; ──────────────────────────────────────────────────────────────────────
; $73FB  screen_clear_space
; ──────────────────────────────────────────────────────────────────────
; Screen-clear with A=#$20.
;
;   callers:             disk_menu_drive_info_paint JSR (disk-menu open paint preamble inside save_ui_entry chain).
;   inputs:              A
;   registers clobbered: A, X
;
;   A←$20 / fall through to screen_fill_body. Fills the four screen-RAM pages screen_ram-SCREEN_RAM_END with the SPACE glyph (X = $00..$FF wraps via the →loop when nonzero at screen_ram_zero_fill). Used by the disk-menu open to blank the editor backdrop before the menu paint. Adjacent to screen_fill_body which is the same loop without the A preload — callers that want a non-space fill go through screen_fill_body directly.
screen_clear_space .block
                           lda  #$20    ; $73FB
.bend

; ──────────────────────────────────────────────────────────────────────
; $73FD  screen_fill_body
; ──────────────────────────────────────────────────────────────────────
; Screen-fill body — write screen_ram,X / SCREEN_RAM_P2,X / SCREEN_RAM_P3,X / SCREEN_RAM_P4,X / decrement X / →stereo_state_band_end when nonzero / return.
;
;   callers:             disk_menu_screen_init JSR (disk-menu inner paint after directory fetch), filename_prompt_paint JSR (SAVE-completed status banner).
;   inputs:              A
;   registers clobbered: X
;
;   Caller-supplied A picks the fill glyph; uses X as 256-byte loop counter touching all 4 screen-RAM pages (1000 visible cells + 24 padding). Reached by fall-through from screen_clear_space (fill with SPACE) or directly when caller pre-loads A.
screen_fill_body .block
                           ldx  #$00    ; $73FD
.bend

; ──────────────────────────────────────────────────────────────────────
; $73FF  stereo_state_band_end
; ──────────────────────────────────────────────────────────────────────
; End of the arranger_v5_sid2-stereo_state_band_end state-vars region (stereo / sid2 / chip-view + cursor cluster + seqLIST counters).
;
;   callers:             1 code sites: $740C
stereo_state_band_end .block
                           sta  screen_ram,x    ; $73FF
.bend

; ──────────────────────────────────────────────────────────────────────
; $7402  screen_ram_zero_fill
; ──────────────────────────────────────────────────────────────────────
; Screen-RAM zero-fill helper.
;
;   inputs:              A, X
;   registers clobbered: X
;
;   code edges:          fall-through from $73FF stereo_state_band_end (3 bytes earlier)
;
;   Clears 3×256 bytes of screen text RAM. Called by the directory-listing entry at disk_menu_screen_init (via call color_ram_fill sibling) to wipe the menu area before re-paint.
screen_ram_zero_fill .block
                           sta  SCREEN_RAM_P2,x    ; $7402
                           sta  SCREEN_RAM_P3,x    ; $7405
                           sta  SCREEN_RAM_P4,x    ; $7408
                           dex    ; $740B
                           bne  stereo_state_band_end    ; $740C  ($00 − 1) was non-zero?
                           rts    ; $740E
        .byte $A9, $00    ; $740F
.bend

; ──────────────────────────────────────────────────────────────────────
; $7411  color_ram_fill
; ──────────────────────────────────────────────────────────────────────
; Color-RAM fill.
;
;   callers:             disk_menu_screen_init (disk_menu_screen_init paints green color RAM); disk_menu_drive_info_paint (save-overwrite path repaint)
;   inputs:              A = palette index (e.g. $05 = green for the disk-menu repaint)
;   registers clobbered: X
;
;   X←$00; write COLOR_RAM,X / load_decoder_tail_jump,X / load_decoder_tail_jump,X / load_decoder_tail_jump,X; decrement X; bne — writes A into all 1000 color-RAM bytes (COLOR_RAM-load_decoder_tail_jump). Companion to screen_ram_zero_fill's screen-RAM zero-fill.
color_ram_fill .block
                           ldx  #$00    ; $7411
l_1:                       sta  COLOR_RAM,x    ; $7413
                           sta  COLOR_RAM + $100,x    ; $7416
                           sta  COLOR_RAM + $200,x    ; $7419
                           sta  COLOR_RAM + $300,x    ; $741C
                           dex    ; $741F
                           bne  l_1    ; $7420  ($00 − 1) was non-zero?
                           rts    ; $7422
.bend

; ──────────────────────────────────────────────────────────────────────
; $7423  save_ui_entry
; ──────────────────────────────────────────────────────────────────────
; Save/disk-menu UI entry.
;
;   callers:             1 code sites: $8244 shift_x_disk_menu_chord
;
;   Sets up screen, calls IEC quiesce (iec_bus_quiesce), then enters the disk_menu_input_loop which runs nested under the main loop.
save_ui_entry .block
                           jsr  irq_banking_setup    ; $7423
                           lda  save_ui_saved_state    ; $7426
                           sta  disk_menu_close_tail + $11    ; $7429
                           jsr  vic_cia_quiesce    ; $742C
                           jsr  stop_playback    ; $742F
                           jsr  sid_silence_and_reinit    ; $7432
                           jsr  iec_bus_quiesce    ; $7435
                           lda  #$00    ; $7438
                           sta  VIC_BORDER    ; $743A
                           sta  VIC_SP2_X.VIC_BG0    ; $743D
                           lda  #$05    ; $7440
                           sta  TEXT_COLOR    ; $7442
                           jsr  disk_menu_input_loop    ; $7445
.bend

; ──────────────────────────────────────────────────────────────────────
; $7448  disk_menu_close_tail
; ──────────────────────────────────────────────────────────────────────
; Disk-menu close tail.
;
;   callers:             save_ui_entry (fallthrough after JSR disk_menu_input_loop returns via disk_menu_exit_arm LEFTARROW arm)
;   registers clobbered: A, X, Y
;
;   Spins polling the keyboard until all keys are released ($FF == no key), then quiesces the IEC bus, re-installs the defMON IRQ vectors, clears save_ui_saved_state, and returns to save_ui_entry's caller.
disk_menu_close_tail .block
                           jsr  kbd_scan    ; $7448
                           lda  kbd_decoded_key    ; $744B
                           cmp  #KEY_NONE    ; $744E
                           bne  disk_menu_close_tail    ; $7450  kbd_decoded_key was not KEY_NONE?
                           jsr  iec_bus_quiesce    ; $7452
                           jsr  irq_banking_setup    ; $7455
                           lda  #$FF    ; $7458  ; ← (SMC operand at $7459, no name)
                           sta  save_ui_saved_state    ; $745A
                           rts    ; $745D
        .byte $24, $00    ; $745E
.bend

; ──────────────────────────────────────────────────────────────────────
; $7460  disk_menu_screen_init
; ──────────────────────────────────────────────────────────────────────
; Disk-menu screen init.
;
;   callers:             dir_read_open (disk_directory_open prologue); disk_confirm_prompt_loop (RUN/STOP-cancel branch in disk_menu_input_loop input loop, repaints the directory screen)
;   inputs:              (none; uses fixed cursor base addresses)
;   outputs:             dir_line_counter = 0, dir_paint_blocks_col_smc/dir_paint_blocks_col_smc_hi = screen_ram_row0_col19, dir_paint_name_col_smc/dir_paint_name_col_smc_hi = SCREEN_RAM_ROW0_COL1, dir_paint_cell_offset = 0
;   registers clobbered: A, X, Y
;
;   Sequence:
;     - Paint border via call screen_fill_body (A←$A0 = inverse SPACE).
;     - Color-fill green via call color_ram_fill (A=$05).
;     - Walk 25 rows × $12 bytes clearing a region using self-modifying disk_clear_loop_smc row-base pointer (+$28 stride/row).
;     - Pre-load paint cursors:
;         dir_paint_blocks_col_smc / dir_paint_blocks_col_smc_hi := screen_ram_row0_col19 (blocks column at row 0 col 19).
;         dir_paint_name_col_smc   / dir_paint_name_col_smc_hi   := SCREEN_RAM_ROW0_COL1 (name column at row 0 col 1).
;     - dir_line_counter := 0 (line counter).
;     - call dir_paint_reset_cell (reset dir_paint_cell_offset cell-offset).
;
;   Single caller: dir_read_open.
disk_menu_screen_init .block
                           lda  #$A0    ; $7460
                           jsr  screen_fill_body    ; $7462
                           lda  #$05    ; $7465
                           jsr  color_ram_fill    ; $7467
                           ldy  #$19    ; $746A
                           lda  #$15    ; $746C
                           sta  disk_clear_loop_smc    ; $746E
                           lda  #$D8    ; $7471
                           sta  disk_clear_loop_smc + $01    ; $7473
l_1:                       lda  #$00    ; $7476
                           ldx  #$12    ; $7478
l_2:                       sta  VEC_IRQ_HI,x    ; $747A
                           dex    ; $747D
                           bne  l_2    ; $747E  ($12 − 1) was non-zero?
                           lda  disk_clear_loop_smc    ; $7480
                           clc    ; $7483
                           adc  #$28    ; $7484
                           sta  disk_clear_loop_smc    ; $7486
                           bcc  l_3    ; $7489  (disk_clear_loop_smc + $28) shifted-out bit was 0?
                           inc  disk_clear_loop_smc + $01    ; $748B
l_3:                       dey    ; $748E
                           bne  l_1    ; $748F  ($19 − 1) was non-zero?
                           lda  #$01    ; $7491
                           sta  dir_paint_name_col_smc    ; $7493
                           lda  #$13    ; $7496
                           sta  dir_paint_blocks_col_smc    ; $7498
                           lda  #$04    ; $749B
                           sta  dir_paint_name_col_smc_hi    ; $749D
                           sta  dir_paint_blocks_col_smc_hi    ; $74A0
                           lda  #$00    ; $74A3
                           sta  dir_line_counter    ; $74A5
                           jsr  dir_paint_reset_cell    ; $74A8
                           rts    ; $74AB
.bend

; ──────────────────────────────────────────────────────────────────────
; $74AC  dir_read_open
; ──────────────────────────────────────────────────────────────────────
; Open + read 1541 directory.
;
;   callers:             disk_clear_loop_smc indirect via dir_paint_reset_cell / call-chain rooted at save_ui_entry (disk-menu open) and the `D` reload commands.
;   inputs:              disk_dir_bit_imm_operand = current drive's directory-selector char ($24 = '$', the standard '$0' wildcard for directory listing)
;   outputs:             Directory text painted into screen RAM via dir_paint_blocks_glyph/dir_paint_glyph cursor; dir_line_counter counts lines emitted (caps at $18 = 24 lines).
;   registers clobbered: A, X, Y
;
;   Sequence:
;     - call disk_menu_screen_init (screen init).
;     - KERNAL setup:
;         SETLFS lfn=1 / drive=$BA / sa=0.
;         SETNAM len=1 / name=disk_dir_bit_imm_operand (current drive's directory selector char).
;         OPEN, CHKIN(1).
;         bcs → dir_read_close_tail on error.
;     - Skip 4 BAM header bytes via 4× call KERNAL_CHRIN.
;     - call kbd_scan (key-poll for user abort) / read kbd_decoded_key / compare =KEY_STOP (CLR) → dir_read_close_tail abort.
;     - Falls through to the directory-entry loop at dir_entry_inner_loop.
;
;   The byte at disk_dir_bit_imm_operand (single-char directory selector) defaults to '$'
;   ($24 = ASCII dollar sign). defMON's disk-menu lets the user override
;   this with a custom pattern (e.g. '$0' for all files including
;   deletions, or '$:NAME' for a name match) by typing into the menu's
;   filename slot.
;
;   dir_read_open and the loop body at dir_entry_inner_loop-disk_menu_B_handler are conceptually a single
;   'list directory' routine; the split is just where the directory entry
;   header reading ends and the per-entry inner loop begins.
dir_read_open .block
                           jsr  disk_menu_screen_init    ; $74AC
                           lda  #$01    ; $74AF
                           ldx  cbm_drive_num    ; $74B1
                           ldy  #$00    ; $74B3
                           jsr  KERNAL_SETLFS    ; $74B5
                           lda  #$01    ; $74B8
                           ldx  #$5E    ; $74BA
                           ldy  #$74    ; $74BC
                           jsr  KERNAL_SETNAM    ; $74BE
                           jsr  KERNAL_OPEN    ; $74C1
                           bcc  l_1    ; $74C4  KERNAL_OPEN returned carry clear?
                           jmp  dir_read_close_tail    ; $74C6
l_1:                       ldx  #$01    ; $74C9
                           jsr  KERNAL_CHKIN    ; $74CB
                           bcc  l_2    ; $74CE  KERNAL_CHKIN returned carry clear?
                           jmp  dir_read_close_tail    ; $74D0
l_2:                       jsr  KERNAL_CHRIN    ; $74D3
                           jsr  KERNAL_CHRIN    ; $74D6
.bend

; ──────────────────────────────────────────────────────────────────────
; $74D9  dir_entry_inner_loop
; ──────────────────────────────────────────────────────────────────────
; Directory-entry inner loop (continuation of dir_read_open).
;
;   callers:             dir_read_open (fall-through after BAM-skip); dir_chrin_drain (loop-back JMP after dir_chrin_drain drain); dir_entry_inner_loop (BEQ back to entry header on null byte)
;   registers clobbered: A, X, Y
;
;   For each directory entry:
;     - 4× CHRIN to skip the entry preamble + call kbd_scan / compare =$93 abort check.
;     - CHRIN block-count lo → X → paint via dir_paint_glyph using hex_digit_hi_lut,X (hi nibble glyph) then hex_digit_lo_lut,X (lo nibble glyph).
;     - Skip spaces; read until $22 (") starts the filename.
;     - Paint chars via dir_paint_glyph until closing $22.
;     - Skip trailing chars until $00 entry-terminator.
;     - Fall through to dir_line_advance line-advance + jump dir_entry_inner_loop for next entry.
;
;   Three flow-control branches exit the loop:
;    dir_entry_inner_loop CMP #$93 (CLR pressed during read) → JMP dir_read_close_tail (abort)
;    dir_entry_inner_loop CMP #$12 (RVS-on flag on entry) → JMP disk_menu_R_handler (locked-file
;    variant: JSR dir_paint_reset_cell → JMP dir_chrin_drain → drain rest of line)
;    dir_entry_inner_loop CMP #$42 ('B' = block-allocation header) → JMP disk_menu_B_handler
;    (terminate listing — last 'blocks free' line)
;
;   The hex-digit LUTs at hex_digit_lo_lut / hex_digit_hi_lut are data tables. dir_entry_inner_loop LDA hex_digit_hi_lut,X
;   = lo-nibble glyph; dir_entry_inner_loop LDA hex_digit_lo_lut,X = hi-nibble glyph. The blocks-count
;   is displayed at column 19 of each row via dir_paint_blocks_glyph (which uses cursor
;   dir_paint_blocks_col_smc/dir_paint_blocks_col_smc_hi).
dir_entry_inner_loop .block
                           jsr  KERNAL_CHRIN    ; $74D9
                           jsr  KERNAL_CHRIN    ; $74DC
                           jsr  kbd_scan    ; $74DF
                           lda  kbd_decoded_key    ; $74E2
                           cmp  #KEY_STOP    ; $74E5
                           bne  l_1    ; $74E7  kbd_decoded_key was not KEY_STOP?
                           jmp  dir_read_close_tail    ; $74E9
l_1:                       jsr  KERNAL_CHRIN    ; $74EC
                           tax    ; $74EF
                           lda  hex_digit_hi_lut,x    ; $74F0
                           jsr  dir_paint_glyph    ; $74F3
                           lda  hex_digit_lo_lut,x    ; $74F6
                           jsr  dir_paint_glyph    ; $74F9
                           jsr  KERNAL_CHRIN    ; $74FC
                           jsr  KERNAL_READST    ; $74FF
                           bne  dir_read_close_tail    ; $7502  KERNAL_READST returned non-zero?
l_2:                       jsr  KERNAL_CHRIN    ; $7504
                           tax    ; $7507
                           beq  dir_entry_inner_loop    ; $7508  KERNAL_CHRIN->A was zero?
                           cmp  #KEY_SPACE    ; $750A
                           beq  l_2    ; $750C  KERNAL_CHRIN->A was $20?
                           cmp  #KEY_R    ; $750E
                           beq  disk_menu_R_handler    ; $7510  KERNAL_CHRIN->A was $12?
                           cmp  #$42    ; $7512
                           beq  disk_menu_B_handler    ; $7514  KERNAL_CHRIN->A was $42?
                           lda  #$22    ; $7516
                           jsr  dir_paint_glyph    ; $7518
l_3:                       jsr  KERNAL_CHRIN    ; $751B
                           tax    ; $751E
                           beq  dir_entry_inner_loop    ; $751F  KERNAL_CHRIN->A was zero?
                           jsr  dir_paint_blocks_glyph    ; $7521
                           cmp  #$22    ; $7524
                           bne  l_3    ; $7526  dir_paint_blocks_glyph->A was not $22?
l_4:                       jsr  KERNAL_CHRIN    ; $7528
                           tax    ; $752B
                           beq  dir_entry_inner_loop    ; $752C  KERNAL_CHRIN->A was zero?
                           cmp  #$20    ; $752E
                           beq  l_4    ; $7530  KERNAL_CHRIN->A was $20?
                           jsr  dir_paint_glyph    ; $7532
.bend

; ──────────────────────────────────────────────────────────────────────
; $7535  dir_line_advance
; ──────────────────────────────────────────────────────────────────────
; Directory-line advance.
;
;   callers:             dir_entry_inner_loop inner loop (fall-through from name-paint), disk_menu_B_handler (dir_entry_inner_loop's 'B'-arm = blocks-free entry hits dir_line_advance directly)
;   registers clobbered: A, X, Y
;
;   Bumps both paint cursors (name column and blocks column) by $28 = one screen row, resets the within-row cell offset, and increments the line counter. After 24 lines (dir_line_counter == $18) it jumps to disk_confirm_prompt_template to paint the final 'blocks free' line; otherwise it falls through into dir_chrin_drain to drain the remaining entry chars before continuing the directory loop.
dir_line_advance .block
                           lda  dir_paint_name_col_smc    ; $7535
                           clc    ; $7538
                           adc  #$28    ; $7539
                           sta  dir_paint_name_col_smc    ; $753B
                           bcc  l_1    ; $753E  (dir_paint_name_col_smc + $28) shifted-out bit was 0?
                           lda  dir_paint_name_col_smc_hi    ; $7540
                           inc  dir_paint_name_col_smc_hi    ; $7543
l_1:                       lda  dir_paint_blocks_col_smc    ; $7546
                           clc    ; $7549
                           adc  #$28    ; $754A
                           sta  dir_paint_blocks_col_smc    ; $754C
                           bcc  l_2    ; $754F  (dir_paint_blocks_col_smc + $28) shifted-out bit was 0?
                           lda  dir_paint_blocks_col_smc_hi    ; $7551
                           inc  dir_paint_blocks_col_smc_hi    ; $7554
l_2:                       jsr  dir_paint_reset_cell    ; $7557
                           inc  dir_line_counter    ; $755A
                           lda  dir_line_counter    ; $755D
                           cmp  #$18    ; $7560
                           beq  disk_menu_B_handler.l_1    ; $7562  dir_line_counter was $18?
.bend

; ──────────────────────────────────────────────────────────────────────
; $7564  dir_chrin_drain
; ──────────────────────────────────────────────────────────────────────
; CHRIN-drain helper.
;
;   callers:             3 code sites: $7568, $7579, $75B6
;   inputs:              (none — reads from KERNAL active input channel, opened against the 1541 directory by the disk-menu open path)
;   registers clobbered: A, X, Y
;
;   Reads characters from the active input channel (KERNAL CHRIN) until a $00 byte arrives, then jumps to dir_entry_inner_loop to paint the next row.
;
;   The directory-fetch inner loop. Each call drains one logical line from
;   the 1541's directory channel — the loop body discards the chars after
;   they've been processed upstream (the actual directory text lands in
;   screen RAM via the paint helpers at dir_paint_blocks_glyph/dir_paint_glyph before this drain
;   fires).
dir_chrin_drain .block
                           jsr  KERNAL_CHRIN    ; $7564
                           tax    ; $7567
                           bne  dir_chrin_drain    ; $7568  KERNAL_CHRIN->A was non-zero?
                           jmp  dir_entry_inner_loop    ; $756A
.bend

; ──────────────────────────────────────────────────────────────────────
; $756D  dir_read_close_tail
; ──────────────────────────────────────────────────────────────────────
; Directory-read close tail.
;
;   callers:             dir_read_open (CHKOUT error); dir_read_open (CHKIN error); dir_entry_inner_loop (CLR-abort); dir_entry_inner_loop (KERNAL_READST STATUS-error); disk_confirm_prompt_loop (RUN/STOP cancel branch from input loop); fall-through from disk_confirm_prompt_template (24-line cap)
;   registers clobbered: A, X, Y
;
;   Reached from any error path in dir_read_open/dir_entry_inner_loop (4 jump sites) plus the natural disk_clear_loop_smc → dir_read_open return — every directory-listing path funnels back here to release the IEC channel (CLOSE 1 + CLRCHN).
dir_read_close_tail .block
                           lda  #$01    ; $756D
                           jsr  KERNAL_CLOSE    ; $756F
                           jsr  KERNAL_CLRCHN    ; $7572
                           rts    ; $7575
.bend

; ──────────────────────────────────────────────────────────────────────
; $7576  disk_menu_R_handler
; ──────────────────────────────────────────────────────────────────────
; Disk-menu directory-fetch 'R' (read-error retry) handler.
;
;   callers:             dir_entry_inner_loop BEQ (in save_ui_entry disk-menu input cascade, CMP #$12 / BEQ disk_menu_R_handler arm).
;   registers clobbered: A, X, Y
;
;   call dir_paint_reset_cell (re-attempt file open with current cursor selection) / jump dir_chrin_drain (CHRIN-drain + cleanup). Reached when the user holds an 'R' key ($12 screen code) on a stalled directory fetch. Same shape as disk_menu_B_handler but with a retry pre-step.
disk_menu_R_handler .block
                           jsr  dir_paint_reset_cell    ; $7576
                           jmp  dir_chrin_drain    ; $7579
.bend

; ──────────────────────────────────────────────────────────────────────
; $757C  disk_menu_B_handler
; ──────────────────────────────────────────────────────────────────────
; Disk-menu directory-fetch 'B' (back) handler.
;
;   callers:             dir_entry_inner_loop BEQ (in save_ui_entry disk-menu input cascade, CMP #$42 / BEQ disk_menu_B_handler arm).
;   registers clobbered: A, X, Y
;
;   jump dir_line_advance (back to the directory-display top). Reached when the user types 'B' ($42 screen code) at the directory prompt — restarts directory listing from page 0.
disk_menu_B_handler .block
                           jmp  dir_line_advance    ; $757C
        .text "READ MORE? Y/N"    ; $757F
l_1:                       ldx  #$0D    ; $758D
l_2:                       lda  disk_confirm_prompt_template,x    ; $758F
                           sta  SCREEN_RAM + $3C3,x    ; $7592
                           dex    ; $7595
                           bpl  l_2    ; $7596  $0D walked back 1 and had bit 7 clear?
.bend

; ──────────────────────────────────────────────────────────────────────
; $7598  disk_confirm_prompt_loop
; ──────────────────────────────────────────────────────────────────────
; Disk-band confirm-prompt input loop ('overwrite Y/N?').
;
;   callers:             Only reached as JMP disk_confirm_prompt_jmp_trampoline → disk_confirm_prompt_loop fall-through from the prompt-paint at disk_confirm_prompt_template (paints the prompt string disk_confirm_prompt_template = '\x12\x05\x01\x04 \x0f\x0f\x12\x05\x3f ' = REV-ON 'READ OR?' style banner). 1 references (disk_confirm_prompt_jmp_trampoline JMP disk_confirm_prompt_loop).
;   inputs:              kbd_decoded_key = decoded key (set by kbd_scan); VIC_BORDER = border color (used as flash buffer).
;   outputs:             On confirm: JSR disk_menu_screen_init fires the staged action. On decline: file 1 closed via dir_read_close_tail. Border restored to $00 on either decision.
;   registers clobbered: A, X, Y
;
;   Polls kbd_scan and dispatches on the decoded key. 'N' (screen code $0E) takes the decline path — clears the border and jumps to dir_read_close_tail (close file 1 + CLRCHN). 'Y' ($19) takes the confirm path — clears the border, calls disk_menu_screen_init to run the gated action, then drains the CHRIN channel via dir_chrin_drain. Any other key flashes the border (EOR with $07) and re-polls — purely cosmetic feedback that the input was seen but rejected.
disk_confirm_prompt_loop .block
                           jsr  kbd_scan    ; $7598
                           lda  kbd_decoded_key    ; $759B
                           cmp  #KEY_N    ; $759E
                           bne  l_1    ; $75A0  kbd_decoded_key was not KEY_N?
                           lda  #$00    ; $75A2
                           sta  VIC_BORDER    ; $75A4
                           jmp  dir_read_close_tail    ; $75A7
l_1:                       cmp  #KEY_Y    ; $75AA
                           bne  l_2    ; $75AC  kbd_decoded_key was not KEY_Y?
                           lda  #$00    ; $75AE
                           sta  VIC_BORDER    ; $75B0
                           jsr  disk_menu_screen_init    ; $75B3
                           jmp  dir_chrin_drain    ; $75B6
l_2:                       lda  VIC_BORDER    ; $75B9
                           eor  #$07    ; $75BC
                           sta  VIC_BORDER    ; $75BE
.bend

; ──────────────────────────────────────────────────────────────────────
; $75C1  disk_confirm_prompt_jmp_trampoline
; ──────────────────────────────────────────────────────────────────────
; Fall-through-only jump disk_confirm_prompt_loop trampoline at the tail of the confirm-prompt paint (disk_confirm_prompt_template).
;
;   code edges:          fall-through from $75BE in disk_confirm_prompt_loop_2 (3 bytes earlier)
;
;   Sets border color via write VIC_BORDER from disk_confirm_prompt_loop then JMPs into disk_confirm_prompt_loop's input-poll loop. Not a separate function — see disk_confirm_prompt_loop.
disk_confirm_prompt_jmp_trampoline .block
                           jmp  disk_confirm_prompt_loop    ; $75C1
.bend

; ──────────────────────────────────────────────────────────────────────
; $75C4  dir_paint_blocks_glyph
; ──────────────────────────────────────────────────────────────────────
; Paint glyph into directory blocks-count column.
;
;   callers:             dir_entry_inner_loop (directory entry blocks-count second digit)
;   inputs:              A = glyph (screen-code); dir_paint_cell_offset = per-line cell index (0..1 for 2-digit block count); dir_paint_blocks_col_smc/dir_paint_blocks_col_smc_hi = current row's blocks-column base (self-modify STA operand)
;   outputs:             Screen RAM byte at (dir_paint_blocks_col_smc/dir_paint_blocks_col_smc_hi) + Y := A (high bit not masked, so reverse-video stays intact)
;   registers clobbered: A, Y
;
;   Y←dir_paint_cell_offset (per-cell offset); write screen_ram_row0_col19,Y where the screen_ram_row0_col19 operand bytes at dir_paint_blocks_col_smc/dir_paint_blocks_col_smc_hi are SELF-MODIFIED by the line-advance at dir_line_advance (`+= $28` per row). Used by dir_entry_inner_loop to emit the 2-digit hex blocks-count at column 19 of each row. dir_paint_cell_offset is bumped by sibling dir_paint_glyph, not by dir_paint_blocks_glyph itself — so dir_paint_blocks_glyph and dir_paint_glyph can be intermixed in the same row to paint to two different columns sharing the per-line cell index.
dir_paint_blocks_glyph .block
                           ldy  dir_paint_cell_offset    ; $75C4
                           sta  SCREEN_RAM + $FF,y    ; $75C7
.bend

; ──────────────────────────────────────────────────────────────────────
; $75CA  dir_paint_glyph
; ──────────────────────────────────────────────────────────────────────
; Paint glyph into directory name column + advance cell offset.
;
;   callers:             dir_entry_inner_loop (paint blocks-count hi-nibble glyph), dir_entry_inner_loop (lo-nibble), dir_entry_inner_loop (open-quote $22 glyph), dir_entry_inner_loop (filename char), disk_confirm_prompt_template (locked-file/special glyph)
;   inputs:              A = glyph; dir_paint_name_col_smc/dir_paint_name_col_smc_hi = current row's name-column base (self-modify STA operand)
;   outputs:             Screen RAM byte := A & $BF; dir_paint_cell_offset := dir_paint_cell_offset + 1
;   registers clobbered: A, Y
;
;   Y←$00; A&=$BF (clear bit 6 → strip the reverse-video flag); write SCREEN_RAM_ROW0_COL1,Y where SCREEN_RAM_ROW0_COL1 operand bytes at dir_paint_name_col_smc/dir_paint_name_col_smc_hi are SELF-MODIFIED by dir_line_advance (`+= $28` per row); increment dir_paint_cell_offset (next cell across the row). The AND #$BF mask is the inverse of dir_paint_blocks_glyph's behaviour — dir_paint_glyph is for filename text where the reverse-video bit must be stripped, while dir_paint_blocks_glyph preserves it for the block-count digits (so the count can be highlighted).
dir_paint_glyph .block
                           ldy  #$00    ; $75CA  ; ← dir_paint_cell_offset
                           and  #$BF    ; $75CC
                           sta  SCREEN_RAM + $FF,y    ; $75CE
                           inc  dir_paint_cell_offset    ; $75D1
                           rts    ; $75D4
.bend

; ──────────────────────────────────────────────────────────────────────
; $75D5  dir_paint_reset_cell
; ──────────────────────────────────────────────────────────────────────
; Reset directory per-line cell-offset.
;
;   callers:             disk_clear_loop_smc (disk_menu_screen_init epilogue, initial paint cursor reset); dir_line_advance (dir_line_advance line-advance, resets between rows); disk_menu_R_handler (dir_entry_inner_loop's RVS-flag entry — locked-file branch)
;   registers clobbered: A
;
;   Called at the start of each new directory line (and at disk_menu_screen_init initial setup) to rewind the within-column cursor to byte 0.
dir_paint_reset_cell .block
                           lda  #$00    ; $75D5
                           sta  dir_paint_cell_offset    ; $75D7
                           rts    ; $75DA
.bend

; ──────────────────────────────────────────────────────────────────────
; $75DB  disk_menu_input_loop
; ──────────────────────────────────────────────────────────────────────
; Disk menu's own input loop.
;
;   callers:             8 code sites: $7445, $7637, $7647, $76ED, $77E6, $781F, $782B, $7833
;
;   Self-contained: own keyboard scanner (disk_menu_kbd_scan), own dispatcher at disk_menu_prev_drive_arm+. Suspends mode_dispatch mode dispatch — ui_mode stays at UI_MODE_SEQED (seqED) while menu is open.
;
;   Bare-key dispatch (no modifier needed):
;    $20 SPACE → disk_menu_refresh_arm — refresh directory listing
;    $2E PERIOD → disk_menu_next_drive_arm — INC $BA (next drive 8..11 wrap)
;    $2C COMMA → disk_menu_prev_drive_arm — DEC $BA (prev drive)
;    $1F LEFTARROW → disk_menu_exit_arm — exit menu (RTS back through save_ui_entry)
;    $13 'S' → disk_menu_save_arm — save action
;    $0D RETURN → disk_menu_return_handler — load tune at cursor row (see LOAD path)
disk_menu_input_loop .block
                           lda  #$00    ; $75DB
                           sta  VIC_BORDER    ; $75DD
                           jsr  dir_read_open    ; $75E0
                           lda  dir_line_counter    ; $75E3
                           sta  screen_ram    ; $75E6
                           bne  l_1    ; $75E9  dir_line_counter was non-zero?
                           lda  #$02    ; $75EB
                           sta  border_color_state_a    ; $75ED
                           sta  VIC_BORDER    ; $75F0
l_1:                       lda  #$00    ; $75F3
                           sta  zp_ptr1_lo    ; $75F5
                           lda  #$04    ; $75F7
                           sta  zp_ptr1_hi    ; $75F9
                           clc    ; $75FB
                           ldx  #$00    ; $75FC
                           ldy  #$00    ; $75FE
                           jsr  KERNAL_PLOT    ; $7600
                           ldx  cbm_drive_num    ; $7603
                           lda  hex_digit_rvs_screencode,x    ; $7605
                           sta  screen_ram_row24    ; $7608
.bend

; ──────────────────────────────────────────────────────────────────────
; $760B  disk_menu_input_wait
; ──────────────────────────────────────────────────────────────────────
; Disk-menu input wait loop body (heart of disk_menu_input_loop).
;
;   callers:             12 code sites: $761D, $7651, $7673, $767D, $7697, $76A2, $76B3 disk_menu_shift_dispatch_5, $76BC, +4 more
;
;   Per-iter: raster-syncs at line $60 (cursor blink), paints the $BE cursor glyph at the cursor position, then polls the keyboard. If no key is pressed it loops; otherwise loads the decoded key + modifier bytes and falls through to the modifier check at disk_menu_kbd_scan. Hit on every menu re-entry.
disk_menu_input_wait .block
                           lda  #$60    ; $760B
l_1:                       cmp  VIC_RASTER    ; $760D
                           bne  l_1    ; $7610  $60 was not VIC_RASTER?
                           lda  #$BE    ; $7612
                           ldy  #$00    ; $7614
                           sta  (zp_ptr1_lo),y    ; $7616
.bend

; ──────────────────────────────────────────────────────────────────────
; $7618  disk_menu_kbd_scan
; ──────────────────────────────────────────────────────────────────────
; Disk-menu keyboard scan.
;
;   callers:             disk_menu_input_loop
;
;   code edges:          fall-through from $7616 in disk_menu_input_wait_1 (2 bytes earlier)
;
;   Polls the keyboard. When no key is pressed (kbd_decoded_key == KEY_NONE) it loops back into the cursor-blink wait at disk_menu_input_wait; otherwise it falls through to the bare-key dispatch at disk_menu_prev_drive_arm with the decoded key and modifier byte ready.
disk_menu_kbd_scan .block
                           jsr  kbd_scan    ; $7618
                           cmp  #$FF    ; $761B
                           beq  disk_menu_input_wait    ; $761D  kbd_scan->A was $FF?
                           lda  kbd_decoded_key    ; $761F
                           ldx  kbd_modifiers    ; $7622
                           cpx  #$00    ; $7625
                           bne  disk_menu_shift_dispatch    ; $7627  kbd_modifiers was not $00?
.bend

; ──────────────────────────────────────────────────────────────────────
; $7629  disk_menu_prev_drive_arm
; ──────────────────────────────────────────────────────────────────────
; Disk-menu arm: bare COMMA ($2C) → decrement $BA, A&=$0B, A|=$08 (wrap to 8..11), write $BA.
;
;   code edges:          fall-through from $7627 in disk_menu_kbd_scan (2 bytes earlier)
;
;   Decrements current drive number. jump disk_menu_input_loop for next iteration.
disk_menu_prev_drive_arm .block
; ─── switch (kbd_decoded_key) — 3 cases ───
;     case KEY_COMMA              → $762D
;     case KEY_PERIOD             → $763E
;     case KEY_SPACE              → $7647
;     default                   → $764A
                           cmp  #KEY_COMMA    ; $7629
                           bne  disk_menu_next_drive_arm    ; $762B  kbd_decoded_key was not KEY_COMMA?
                           dec  cbm_drive_num    ; $762D
.bend

; ──────────────────────────────────────────────────────────────────────
; $762F  wrap_drive_number_redraw
; ──────────────────────────────────────────────────────────────────────
; Wrap-drive-number-and-redraw.
;
;   callers:             disk_menu_next_drive_arm (`.` key handler `INC $BA; JMP wrap_drive_number_redraw`)
;   inputs:              $BA = caller-incremented drive byte
;   outputs:             $BA = wrapped drive number ($08..$0B); enters disk_menu_input_loop
;   registers clobbered: A, X, Y
;
;   `read $BA; A&=$0B; A|=$08; write $BA; jump disk_menu_input_loop`. Masks the KERNAL active-drive byte $BA so bits 1,3 stay and bit 3 is forced on — produces the cycle $08 → $09 → $0A → $0B → $08 as $BA is INCed by callers. Tail-jumps into disk_menu_input_loop (disk-menu input loop) to redraw with the new drive number.
wrap_drive_number_redraw .block
                           lda  cbm_drive_num    ; $762F
                           and  #$0B    ; $7631
                           ora  #$08    ; $7633
                           sta  cbm_drive_num    ; $7635
                           jmp  disk_menu_input_loop    ; $7637
.bend

; ──────────────────────────────────────────────────────────────────────
; $763A  disk_menu_next_drive_arm
; ──────────────────────────────────────────────────────────────────────
; Disk-menu arm: bare PERIOD ($2E) → increment $BA, then jump wrap_drive_number_redraw to share the wrap clamp + sta.
;
;   callers:             1 code sites: $762B
;
;   Increments current drive number.
disk_menu_next_drive_arm .block
                           cmp  #KEY_PERIOD    ; $763A
                           bne  disk_menu_refresh_arm    ; $763C  kbd_decoded_key was not KEY_PERIOD?
                           inc  cbm_drive_num    ; $763E
                           jmp  wrap_drive_number_redraw    ; $7640
.bend

; ──────────────────────────────────────────────────────────────────────
; $7643  disk_menu_refresh_arm
; ──────────────────────────────────────────────────────────────────────
; Disk-menu arm: bare SPACE ($20) → jump disk_menu_input_loop.
;
;   callers:             1 code sites: $763C
;
;   No-op except for redrawing the directory listing (the loop re-paints on each iteration).
disk_menu_refresh_arm .block
                           cmp  #KEY_SPACE    ; $7643
                           bne  l_1    ; $7645  kbd_decoded_key was not KEY_SPACE?
                           jmp  disk_menu_input_loop    ; $7647
l_1:                       cmp  #KEY_LEFTARROW    ; $764A
                           beq  disk_menu_exit_arm    ; $764C  kbd_decoded_key was KEY_LEFTARROW?
                           ldy  dir_line_counter    ; $764E
                           beq  disk_menu_input_wait    ; $7651  dir_line_counter was zero?
                           cmp  #KEY_RETURN    ; $7653
                           beq  disk_menu_exit_arm.l_1    ; $7655  kbd_decoded_key was KEY_RETURN?
                           cmp  #KEY_L    ; $7657
                           beq  disk_menu_exit_arm.l_1    ; $7659  kbd_decoded_key was KEY_L?
                           cmp  #KEY_S    ; $765B
                           bne  l_2    ; $765D  kbd_decoded_key was not KEY_S?
                           jmp  disk_menu_save_arm    ; $765F
l_2:                       cmp  #KEY_CRSRUD    ; $7662
                           bne  disk_menu_shift_dispatch    ; $7664  kbd_decoded_key was not KEY_CRSRUD?
                           lda  #$A0    ; $7666
                           ldy  #$00    ; $7668
                           sta  (zp_ptr1_lo),y    ; $766A
l_3:                       lda  zp_ptr1_lo    ; $766C
                           clc    ; $766E
                           adc  #$28    ; $766F
                           sta  zp_ptr1_lo    ; $7671
                           bcc  disk_menu_input_wait    ; $7673  (zp_ptr1_lo + $28) shifted-out bit was 0?
                           inc  zp_ptr1_hi    ; $7675
                           lda  zp_ptr1_hi    ; $7677
                           cmp  #$08    ; $7679
                           beq  disk_menu_shift_dispatch.l_1    ; $767B  zp_ptr1_hi was $08?
                           jmp  disk_menu_input_wait    ; $767D
.bend

; ──────────────────────────────────────────────────────────────────────
; $7680  disk_menu_shift_dispatch
; ──────────────────────────────────────────────────────────────────────
; SHIFT-modified disk-menu command dispatch.
;
;   callers:             2 code sites: $7627, $7664
;
;   compare X=$10 (SHIFT mod); per-key cascade: $6F → screen-row-decrement helper at disk_menu_shift_dispatch (paint $A0 at ($02), A-=$28 from ($02) pointer); 'S' ($13) → jump save_overwrite_tail (save-overwrite branch); $10 → jump disk_menu_drive_info_paint (other action); fallback jump disk_menu_input_wait.
disk_menu_shift_dispatch .block
                           cpx  #KBD_MOD_SHIFT    ; $7680
                           bne  l_5    ; $7682  kbd_modifiers was not KBD_MOD_SHIFT?
                           cmp  #KEY_CRSRUD    ; $7684
                           bne  l_3    ; $7686  kbd_decoded_key was not KEY_CRSRUD?
                           lda  #$A0    ; $7688
                           ldy  #$00    ; $768A
                           sta  (zp_ptr1_lo),y    ; $768C
l_1:                       lda  zp_ptr1_lo    ; $768E
                           sec    ; $7690
                           sbc  #$28    ; $7691
                           sta  zp_ptr1_lo    ; $7693
                           bcc  l_2    ; $7695  (zp_ptr1_lo − $28) shifted-out bit was 0?
                           jmp  disk_menu_input_wait    ; $7697
l_2:                       dec  zp_ptr1_hi    ; $769A
                           lda  zp_ptr1_hi    ; $769C
                           cmp  #$03    ; $769E
                           beq  disk_menu_refresh_arm.l_3    ; $76A0  zp_ptr1_hi was $03?
                           jmp  disk_menu_input_wait    ; $76A2
l_3:                       cmp  #KEY_S    ; $76A5
                           bne  l_4    ; $76A7  kbd_decoded_key was not KEY_S?
                           jmp  save_overwrite_tail    ; $76A9
l_4:                       cmp  #KEY_P    ; $76AC
                           bne  l_5    ; $76AE  kbd_decoded_key was not KEY_P?
                           jmp  disk_menu_drive_info_paint    ; $76B0
l_5:                       jmp  disk_menu_input_wait    ; $76B3
.bend

; ──────────────────────────────────────────────────────────────────────
; $76B6  disk_menu_exit_arm
; ──────────────────────────────────────────────────────────────────────
; Disk-menu arm: bare LEFTARROW ($1F) → return (exits the nested disk_menu_input_loop loop back through save_ui_entry to the main editor loop).
;
;   callers:             2 code sites: $764C, $7924
;   registers clobbered: none (preserves A/X/Y)
disk_menu_exit_arm .block
                           rts    ; $76B6
l_1:                       jsr  save_prg_loadaddr_msb.l_1    ; $76B7
                           bcc  l_2    ; $76BA  save_prg_loadaddr_msb_1 returned carry clear?
                           jmp  disk_menu_input_wait    ; $76BC
l_2:                       lda  save_name_buf_marker    ; $76BF
                           cmp  #$2E    ; $76C2
                           beq  disk_menu_return_handler    ; $76C4  save_name_buf_marker was $2E?
                           jmp  disk_menu_input_wait    ; $76C6
.bend

; ──────────────────────────────────────────────────────────────────────
; $76C9  disk_menu_return_handler
; ──────────────────────────────────────────────────────────────────────
; Disk-menu RETURN handler: load-tune-by-cursor-row.
;
;   callers:             1 code sites: $76C4
;
;   Chain entry into the LOAD path.
;
;   Sequence:
;    JSR tune_load_entry -- KERNAL LOAD into sidtab_row_lo verbatim (4060-17327 B body)
;    BCS load_failure_panic_loop -- load-error → flash border infinite loop
;    JSR disk_status_read -- read 1541 command channel (drive status), not a decoder
;    JSR jsr_with_ram_helper (X=$B2,Y=$CE) -- print status message
;    JSR irq_banking_setup -- enable defMON's IRQ (NMI vector nmi_irq_entry, $01=#$35)
;    JMP post_load_init_decoder -- post-load decoder of the saved RLE-packed body into the live pitch_lut_band_alt_base..super_cmd_staged RAM block (not just state-reset)
disk_menu_return_handler .block
                           jsr  tune_load_entry    ; $76C9
                           bcs  load_failure_panic_loop    ; $76CC  tune_load_entry returned carry set?
                           jsr  disk_status_read    ; $76CE
                           ldx  #$B2    ; $76D1
                           ldy  #$CE    ; $76D3
                           jsr  jsr_with_ram_helper    ; $76D5
                           jsr  irq_banking_setup    ; $76D8
                           jmp  post_load_init_decoder    ; $76DB
.bend

; ──────────────────────────────────────────────────────────────────────
; $76DE  load_failure_panic_loop
; ──────────────────────────────────────────────────────────────────────
; LOAD-failure border-flash panic loop.
;
;   callers:             disk_menu_return_handler (BCS load_failure_panic_loop = post-KERNAL-LOAD failure; the JSR tune_load_entry → kernal_load_call_site JSR KERNAL_LOAD returned with carry set), load_failure_panic_loop (JMP load_failure_panic_loop = post-OPEN failure in the secondary chain at disk_menu_save_arm).
;   inputs:              (none — terminal loop)
;   registers clobbered: none (preserves A/X/Y)
;
;   increment VIC_BORDER / jump load_failure_panic_loop — fast colour-cycle on screen until reset. Same shape as panic_color_loop, border_flash_panic, save_failure_panic_loop. Reached only on KERNAL LOAD/OPEN errors during tune load.
load_failure_panic_loop .block
                           inc  VIC_BORDER    ; $76DE
                           jmp  load_failure_panic_loop    ; $76E1
.bend

; ──────────────────────────────────────────────────────────────────────
; $76E4  disk_menu_save_arm
; ──────────────────────────────────────────────────────────────────────
; Disk-menu arm: bare 'S' ($13) → save action.
;
;   callers:             1 code sites: $765F
;
;   Prompts for the filename via filename_prompt_paint. If the user cancels (BCS exit), control jumps back to the menu input loop. Otherwise it clears the overwrite-confirmation flag at save_overwrite_body, runs the save, and reads the drive status afterwards.
disk_menu_save_arm .block
                           ldy  #$10    ; $76E4
                           ldx  #$01    ; $76E6
                           jsr  filename_prompt_paint    ; $76E8
                           bcc  l_1    ; $76EB  filename_prompt_paint returned carry clear?
                           jmp  disk_menu_input_loop    ; $76ED
l_1:                       lda  #$00    ; $76F0
                           sta  save_overwrite_state_byte    ; $76F2
                           jsr  save_overwrite_body    ; $76F5
                           jsr  disk_status_read    ; $76F8
                           rts    ; $76FB
.bend

; ──────────────────────────────────────────────────────────────────────
; $76FC  save_overwrite_tail
; ──────────────────────────────────────────────────────────────────────
; Save-overwrite tail.
;
;   callers:             1 code sites: $76A9
;
;   Reached from disk_menu_shift_dispatch's SHIFT+'S' arm. Sub-routines that write the file body under the current filename (without re-prompting). Body extends past save_overwrite_tail.
save_overwrite_tail .block
                           jsr  save_prg_loadaddr_msb.l_1    ; $76FC
                           bcc  l_1    ; $76FF  save_prg_loadaddr_msb_1 returned carry clear?
                           jmp  disk_menu_input_wait    ; $7701
l_1:                       lda  #$01    ; $7704
                           sta  save_overwrite_state_byte    ; $7706
.bend

; ──────────────────────────────────────────────────────────────────────
; $7709  save_overwrite_body
; ──────────────────────────────────────────────────────────────────────
; Save-overwrite body.
;
;   callers:             disk_menu_save_arm (save-overwrite entry from save_overwrite_tail + SHIFT+S input)
;
;   Validates filename buffer at save_name_input_state (compare =$2E '.' = name has extension marker, else abort to disk_menu_input_wait) and save_name_input_state (non-zero = name length set, else abort), then sets up source pointer at (save_prep_orchestrator)/ldx,ldy=$81/$CE and call jsr_with_ram_helper (string-copy helper), reads target name from song_end_pointer, call save_name_input_state_init (filename-store), then jsr's into the binary-stream save chain starting in the save-side disk band.
save_overwrite_body .block
                           lda  save_name_buf_marker    ; $7709
                           cmp  #$2E    ; $770C
                           beq  l_1    ; $770E  save_name_buf_marker was $2E?
                           jmp  disk_menu_input_wait    ; $7710
l_1:                       lda  save_name_buf_len    ; $7713
                           bne  l_2    ; $7716  save_name_buf_len was non-zero?
