                           sta  screen_ram_row03,x    ; $77CB
                           dex    ; $77CE
                           bpl  l_3    ; $77CF  $23 walked back 1 and had bit 7 clear?
.bend

; ──────────────────────────────────────────────────────────────────────
; $77D1  disk_menu_save_banner_dismiss
