; ──────────────────────────────────────────────────────────────────────
; $7F02  iec_tx_byte
; ──────────────────────────────────────────────────────────────────────
; IEC fast-save TX-byte primitive (custom bit-bang, not KERNAL).
;
;   callers:             supercmd_cbm_shift_fallthrough (CTRL+F1 / CTRL+F3 stop-playback super-cmd arms in the CBM+F-key parser).
;   inputs:              encoder_state_flag — must be non-zero (the BEQ at iec_tx_byte abandons the TX otherwise, jumping to the iec_tx_byte abort/cleanup tail with SEC).
;   outputs:             CIA2 PA (CIA2_PRA) driven through ATN+CLK toggles to clock one byte out to the drive. Border (VIC_BORDER) flashed CYAN ($03) during the TX as a visual debug indicator. Returns CLC on success, SEC on abort.
;   registers clobbered: A
;
;   Sends one byte to the 1541 via the serial bus's ATN/CLK/DATA handshake
;   protocol. Asserts ATN (CIA2_PRA bit 5), flashes the border CYAN as a
;   visual debug indicator, then waits on the drive-ready handshake
;   (CIA2_PRA BVS loop = poll until DATA line goes high).
;
;   User-cancel: while waiting on the drive, the routine also polls keyboard
;   row 7 (LSHIFT row) via CIA1_PRB. Any key down on that row aborts the TX —
;   the abort path restores the border, idles the CIA ports, debounces the
;   key release with a doubled CIA1_PRB read, and returns SEC. Success path
;   returns CLC.
iec_tx_byte .block
                           lda  encoder_state_flag    ; $7F02
                           beq  l_2    ; $7F05  encoder_state_flag was zero?
                           lda  CIA2_PRA    ; $7F07
                           ora  #$20    ; $7F0A
                           sta  CIA2_PRA    ; $7F0C
                           lda  VIC_BORDER    ; $7F0F
                           pha    ; $7F12
                           lda  #$03    ; $7F13
                           sta  VIC_BORDER    ; $7F15
                           lda  #$7F    ; $7F18
                           sta  CIA1_PRA    ; $7F1A
l_1:                       bit  CIA1_PRB    ; $7F1D
                           bpl  l_2    ; $7F20  CIA1_PRB had bit 7 clear?
                           bit  CIA2_PRA    ; $7F22
                           bvs  l_1    ; $7F25  CIA2_PRA had bit 6 set?
                           pla    ; $7F27
                           sta  VIC_BORDER    ; $7F28
                           lda  #$C7    ; $7F2B
                           sta  CIA2_PRA    ; $7F2D
                           clc    ; $7F30
                           rts    ; $7F31
l_2:                       pla    ; $7F32
                           sta  VIC_BORDER    ; $7F33
                           lda  #$C7    ; $7F36
                           sta  CIA2_PRA    ; $7F38
                           lda  #$00    ; $7F3B
                           sta  CIA1_PRA    ; $7F3D
l_3:                       lda  CIA1_PRB    ; $7F40
                           cmp  CIA1_PRB    ; $7F43
                           bne  l_3    ; $7F46  CIA1_PRB was not CIA1_PRB?
                           cmp  #$FF    ; $7F48
                           bne  l_3    ; $7F4A  CIA1_PRB was not $FF?
                           sec    ; $7F4C
                           rts    ; $7F4D
.bend

; ──────────────────────────────────────────────────────────────────────
; $7F4E  iec_clk_pulse
; ──────────────────────────────────────────────────────────────────────
; IEC fast-save sync-pulse primitive — pulse CLK line and return.
;
;   callers:             nmi_post_player_tail (player IRQ tail — called after each player_play main tick to maintain a heartbeat for any listening drive-side code).
;   inputs:              encoder_state_flag — must be non-zero (BEQ at iec_clk_pulse short-circuits to bare-RTS at iec_clk_pulse otherwise).
;   outputs:             CIA2 PA pulsed; no return value (always RTSes plain).
;   registers clobbered: A
;
;   When the DATA line is being asserted by the drive (MSB of CIA2_PRA clear), drives the CLK line high (bit 4) for ~12 NOPs (~12-24 cycles) and then idles the port back to $C7. Used by the player to keep the drive-side code synchronised when the editor is paused. Same encoder_state_flag gate as iec_tx_byte; symmetric with the cassette-toggle helpers border_flash_debug_a / border_flash_debug_b which mutate encoder_state_flag only on encoder error paths.
iec_clk_pulse .block
                           lda  encoder_state_flag    ; $7F4E
                           beq  l_1    ; $7F51  encoder_state_flag was zero?
                           lda  CIA2_PRA    ; $7F53
                           bmi  l_1    ; $7F56  CIA2_PRA had bit 7 set?
                           ora  #$10    ; $7F58
                           sta  CIA2_PRA    ; $7F5A
                           nop    ; $7F5D
                           nop    ; $7F5E
                           nop    ; $7F5F
                           nop    ; $7F60
                           nop    ; $7F61
                           nop    ; $7F62
                           nop    ; $7F63
                           nop    ; $7F64
                           nop    ; $7F65
                           nop    ; $7F66
                           nop    ; $7F67
                           nop    ; $7F68
                           lda  #$C7    ; $7F69
                           sta  CIA2_PRA    ; $7F6B
l_1:                       rts    ; $7F6E
.bend

; ──────────────────────────────────────────────────────────────────────
; $7F6F  vic_display_on
; ──────────────────────────────────────────────────────────────────────
; VIC raster-IRQ-enable bit setter.
;
;   callers:             player_helper_band (post-iec_bus_quiesce quiesce tail, restores screen after a save session).
;   registers clobbered: A
;
;   Sets bit 4 of VIC_CR1 (VIC control register 1), which on a real C64 enables the 24-row text display (not raster IRQ per se; the raster IRQ enable is on VIC_IRQ_MASK). Used as a 'show screen' helper after the IEC quiesce path blanks the display.
vic_display_on .block
                           lda  VIC_CR1    ; $7F6F
                           ora  #$10    ; $7F72
                           sta  VIC_CR1    ; $7F74
                           rts    ; $7F77
.bend

; ──────────────────────────────────────────────────────────────────────
; $7F78  vic_display_off
; ──────────────────────────────────────────────────────────────────────
; VIC display-blank helper.
;
;   callers:             iec_bus_quiesce (inside iec_bus_quiesce quiesce prologue).
;   registers clobbered: A
;
;   Clears bit 4 of VIC_CR1, blanking the 24-row text display. Paired with vic_display_on (set). Used to blank the screen during the IEC bit-bang loop at iec_bus_quiesce so VIC bus contention doesn't disturb the timing-critical CIA2 PA toggles.
vic_display_off .block
                           lda  VIC_CR1    ; $7F78
                           and  #$EF    ; $7F7B
                           sta  VIC_CR1    ; $7F7D
                           rts    ; $7F80
.bend

; ──────────────────────────────────────────────────────────────────────
; $7F81  iec_bus_quiesce
; ──────────────────────────────────────────────────────────────────────
; IEC bus init / quiesce.
;
;   callers:             save_ui_entry (inside save_ui_entry prologue), disk_menu_close_tail (inside disk_menu_close_tail save_ui_entry cleanup tail).
;   outputs:             CIA2_PRA = $C7 (IEC idle), VIC_CR1 bit 4 = 0 (display blanked), I-flag set (interrupts off — caller must CLI). 256 full toggle cycles burned to settle the bus.
;   registers clobbered: A, X, Y
;
;   Called from save_ui_entry prologue and disk_menu_close_tail cleanup tail, also from supercmd_cbm_shift_fallthrough (CTRL+F-key stop-playback paths). Disables interrupts (IRQ-off), blanks the VIC display (call vic_display_off), then runs a 256-iteration loop (iec_bus_quiesce) of alternating sta/X→CIA2_PRA writes — bit-banging the IEC CLK+DATA lines into a known idle state via paired transitions. Finishes with the canonical idle byte (CIA2_PRA = $C7).
;
;   The body is a hand-unrolled inner loop (16 paired STA/STX writes per
;   iteration × 256 outer iterations = 4096 paired writes, ~32K cycles =
;   ~32 raster lines on PAL). The pattern A=(idle byte | $30) / X=idle
;   byte interleaves CLK-high and CLK-low states on the bus.
;
;   Callers chain JSR iec_bus_quiesce (quiesce) → other IEC operations → JSR iec_bus_quiesce
;   (re-quiesce) as a 'reset to known state' bookend around each save.
;   Display-blanked-and-irq-disabled regime ensures bus timing isn't
;   disrupted by raster IRQs or VIC bus stealing during the save.
iec_bus_quiesce .block
                           sei    ; $7F81
                           jsr  vic_display_off    ; $7F82
                           lda  CIA2_PRA    ; $7F85
                           and  #$C7    ; $7F88
                           tax    ; $7F8A
                           ora  #$30    ; $7F8B
                           ldy  #$00    ; $7F8D
l_1:                       sta  CIA2_PRA    ; $7F8F
                           stx  CIA2_PRA    ; $7F92
                           sta  CIA2_PRA    ; $7F95
                           stx  CIA2_PRA    ; $7F98
                           sta  CIA2_PRA    ; $7F9B
                           stx  CIA2_PRA    ; $7F9E
                           sta  CIA2_PRA    ; $7FA1
                           stx  CIA2_PRA    ; $7FA4
                           sta  CIA2_PRA    ; $7FA7
                           stx  CIA2_PRA    ; $7FAA
                           sta  CIA2_PRA    ; $7FAD
                           stx  CIA2_PRA    ; $7FB0
                           sta  CIA2_PRA    ; $7FB3
                           stx  CIA2_PRA    ; $7FB6
                           sta  CIA2_PRA    ; $7FB9
                           stx  CIA2_PRA    ; $7FBC
                           sta  CIA2_PRA    ; $7FBF
                           stx  CIA2_PRA    ; $7FC2
                           sta  CIA2_PRA    ; $7FC5
                           stx  CIA2_PRA    ; $7FC8
                           sta  CIA2_PRA    ; $7FCB
                           stx  CIA2_PRA    ; $7FCE
                           sta  CIA2_PRA    ; $7FD1
                           stx  CIA2_PRA    ; $7FD4
                           sta  CIA2_PRA    ; $7FD7
                           stx  CIA2_PRA    ; $7FDA
                           sta  CIA2_PRA    ; $7FDD
                           stx  CIA2_PRA    ; $7FE0
                           sta  CIA2_PRA    ; $7FE3
                           stx  CIA2_PRA    ; $7FE6
                           sta  CIA2_PRA    ; $7FE9
                           stx  CIA2_PRA    ; $7FEC
                           sta  CIA2_PRA    ; $7FEF
                           stx  CIA2_PRA    ; $7FF2
                           sta  CIA2_PRA    ; $7FF5
                           stx  CIA2_PRA    ; $7FF8
                           dey    ; $7FFB
                           bne  l_1    ; $7FFC  ($00 − 1) was non-zero?
                           lda  #$C7    ; $7FFE
.bend

; ──────────────────────────────────────────────────────────────────────
; $8000  player_helper_band
; ──────────────────────────────────────────────────────────────────────
; Start of the player-band support helpers (player_helper_band-player_helper_band_end, ~2KB).
;
;   code edges:          fall-through from $7FFE in iec_bus_quiesce_1 (2 bytes earlier)
;   apparent (from data): $19FF in sidtab_decoder_buffer_end
;
;   Hand-coded helpers called from the main loop, mode dispatchers, and the player IRQ — status-line print family (print_char_to_statusline/print_byte_as_hex/statusline_clear/statusline_tick/print_zstring), super-command parser (hex_digit_validate/super_arg_buffer_init/super_flag_or/super_arg_extract/super_cmd_resolve_target/super_cmd_dispatch/super_enter_status/super_set_active/super_init_full), global pre-dispatch (global_pre_dispatch), VIC sprite init (vic_sprite_init), and helpers indexed by JSRs from the editor/dispatch bands (main_loop_postscan-main_loop_close). Distinct from the seqED_paint_unroll-seqED_paint_unroll_end unrolled paint block (which has its own seqED_paint_unroll). The player_helper_band-player_helper_band_end band has 13 first-pass annotations covering the highest-call-frequency entries; remaining ~50-80 helpers in player_helper_band-player_helper_band_end still need writeups.
player_helper_band .block
                           sta  CIA2_PRA    ; $8000
                           jsr  vic_display_on    ; $8003
                           cli    ; $8006
                           rts    ; $8007
.bend

; ──────────────────────────────────────────────────────────────────────
; $8008  iec_recv_primitive_a
; ──────────────────────────────────────────────────────────────────────
; IEC receive primitive (4-byte input via CIA2_PRA reads).
;
;   callers:             1 code sites: $0B97
;   registers clobbered: A, X, Y
;
;   Identified by CHECK_LOAD on CIA2_PRA firing 1620 times during disk-menu
;   directory read. Contains the LDA/LDX/LDY/BIT CIA2_PRA 4-byte-receive
;   sequence. NOT a generic load — used by directory-read path only as
;   of current understanding.
iec_recv_primitive_a .block
                           ldx  data_band_no_op_tail    ; $8008
                           bne  border_flash_debug_b.l_2    ; $800B  data_band_no_op_tail was non-zero?
                           lda  CIA2_PRA    ; $800D
                           ldx  CIA2_PRA    ; $8010
                           ldy  CIA2_PRA    ; $8013
                           bit  CIA2_PRA    ; $8016
                           bmi  l_1    ; $8019  CIA2_PRA had bit 7 set?
                           cpy  #$80    ; $801B
                           bcc  iec_recv_primitive_b    ; $801D  CIA2_PRA was below $80?
                           cpx  #$80    ; $801F
                           bcs  iec_recv_primitive_b    ; $8021  CIA2_PRA was $80 or above?
                           cmp  #$80    ; $8023
                           bcc  iec_recv_primitive_b    ; $8025  CIA2_PRA was below $80?
                           jmp  border_flash_debug_a    ; $8027
l_1:                       cpy  #$80    ; $802A
                           bcs  iec_recv_primitive_b    ; $802C  CIA2_PRA was $80 or above?
                           cpx  #$80    ; $802E
                           bcc  iec_recv_primitive_b    ; $8030  CIA2_PRA was below $80?
                           cmp  #$80    ; $8032
                           bcs  iec_recv_primitive_b    ; $8034  CIA2_PRA was $80 or above?
.bend

; ──────────────────────────────────────────────────────────────────────
; $8036  border_flash_debug_a
; ──────────────────────────────────────────────────────────────────────
; Border-flash debug toggle helper #1 (cassette-area scratch).
;
;   callers:             iec_recv_primitive_a JMP (encoder error-path band).
;   registers clobbered: A
;
;   Leaves a one-bit-toggle trace in cassette RAM (encoder_state_flag bit 0) after each encoder pass. Identical body shape to border_flash_debug_b. Cassette-area scratch (encoder_state_flag/data_band_no_op_tail) is used as 'unused RAM playground' since defMON disables KERNAL tape I/O.
border_flash_debug_a .block
                           lda  #$0A    ; $8036
                           sta  data_band_no_op_tail    ; $8038
                           lda  encoder_state_flag    ; $803B
                           eor  #$01    ; $803E
                           sta  encoder_state_flag    ; $8040
                           rts    ; $8043
.bend

; ──────────────────────────────────────────────────────────────────────
; $8044  iec_recv_primitive_b
; ──────────────────────────────────────────────────────────────────────
; Second IEC receive primitive (paired with iec_recv_primitive_a).
;
;   callers:             6 code sites: $801D, $8021, $8025, $802C, $8030, $8034
;   registers clobbered: A, X, Y
iec_recv_primitive_b .block
                           lda  CIA2_PRA    ; $8044
                           ldx  CIA2_PRA    ; $8047
                           ldy  CIA2_PRA    ; $804A
                           bit  CIA2_PRA    ; $804D
                           bmi  l_1    ; $8050  CIA2_PRA had bit 7 set?
                           cpy  #$80    ; $8052
                           bcc  border_flash_debug_b.l_1    ; $8054  CIA2_PRA was below $80?
                           cpx  #$80    ; $8056
                           bcs  border_flash_debug_b.l_1    ; $8058  CIA2_PRA was $80 or above?
                           cmp  #$80    ; $805A
                           bcc  border_flash_debug_b.l_1    ; $805C  CIA2_PRA was below $80?
                           jmp  border_flash_debug_b    ; $805E
l_1:                       cpy  #$80    ; $8061
                           bcs  border_flash_debug_b.l_1    ; $8063  CIA2_PRA was $80 or above?
                           cpx  #$80    ; $8065
                           bcc  border_flash_debug_b.l_1    ; $8067  CIA2_PRA was below $80?
                           cmp  #$80    ; $8069
                           bcs  border_flash_debug_b.l_1    ; $806B  CIA2_PRA was $80 or above?
.bend

; ──────────────────────────────────────────────────────────────────────
; $806D  border_flash_debug_b
; ──────────────────────────────────────────────────────────────────────
; Border-flash debug toggle helper #2 — identical body shape to border_flash_debug_a (write data_band_no_op_tail := #$0A / eor-toggle encoder_state_flag bit 0 / return).
;
;   callers:             iec_recv_primitive_b JMP.
;   registers clobbered: A
;
;   Called from iec_recv_primitive_b jump inside an adjacent encoder error-path band; the duplication is intentional (per-pass tracing slot in cassette RAM).
border_flash_debug_b .block
                           lda  #$0A    ; $806D
                           sta  data_band_no_op_tail    ; $806F
                           lda  encoder_state_flag    ; $8072
                           eor  #$01    ; $8075
                           sta  encoder_state_flag    ; $8077
                           rts    ; $807A
l_1:                       rts    ; $807B
l_2:                       dec  data_band_no_op_tail    ; $807C
                           rts    ; $807F
.bend

; ──────────────────────────────────────────────────────────────────────
; $8080  disk_status_read
; ──────────────────────────────────────────────────────────────────────
; 1541 command-channel reader (drive status check).
;
;   callers:             2 code sites: $76CE, $76F8
;   registers clobbered: A, X, Y
;
;   NOT the decoder.
;
;   SETNAM with empty name, SETLFS secondary=$0F (command channel), OPEN,
;   CHKIN, CHRIN loop, CHROUT — reads error status after LOAD/SAVE. NOT
;   involved in byte-stream encoding or decoding (despite the proximity
;   to the encoder band at encoder_state_flag+).
;
;   Body layout:
;    disk_status_read SETNAM(CPU_DDR) / SETLFS(LFN=$0F, dev=$08-or-$BA, secondary
;    =$0F) / OPEN; BCS border_flash_panic on error (border-flash panic).
;    disk_status_read LDX #$0F / CHKIN (KERNAL_CHKIN) — point default input at file
;    $0F (the command channel).
;    disk_status_inner_top-disk_status_inner_trampoline Stream-read inner loop:
;    LDY #$00; JSR READST (KERNAL_READST); BNE disk_status_cleanup_tail (EOF/error);
;    JSR CHRIN (KERNAL_CHRIN); JSR CHROUT (KERNAL_CHROUT); JMP disk_status_inner_top.
;    Prints the drive error string to screen one char at a
;    time until READST goes non-zero.
;    disk_status_cleanup_tail Tail / cleanup: LDA #$0F / JSR CLOSE (KERNAL_CLOSE); LDX #$00
;    / JSR CHKIN (KERNAL_CHKIN) — restore default input (keyboard);
;    RTS.
;
;   Internal labels (NOT separate functions):
;    disk_status_inner_top inner-loop top. Reached by JMP disk_status_inner_trampoline (next iter) only.
;    disk_status_cleanup_tail tail entry. Reached on stream-EOF/error (BNE from disk_status_inner_top) AND
;    via JMP disk_status_alt_cleanup_trampoline (alternate cleanup path from the post-RTS dead
;    bytes at border_flash_panic-disk_status_alt_cleanup_trampoline — an orphan branch; the
;    border_flash_panic infinite-INC-VIC_BORDER sequence is the same border-flash
;    panic shape as panic_color_loop).
disk_status_read .block
                           lda  #$00    ; $8080
                           ldx  #$00    ; $8082
                           ldy  #$00    ; $8084
                           jsr  KERNAL_SETNAM    ; $8086
                           lda  #$0F    ; $8089
                           ldx  cbm_drive_num    ; $808B
                           bne  l_1    ; $808D  cbm_drive_num was non-zero?
                           ldx  #$08    ; $808F
l_1:                       ldy  #$0F    ; $8091
                           jsr  KERNAL_SETLFS    ; $8093
                           jsr  KERNAL_OPEN    ; $8096
                           bcs  border_flash_panic    ; $8099  KERNAL_OPEN returned carry set?
                           ldx  #$0F    ; $809B
                           jsr  KERNAL_CHKIN    ; $809D
                           ldy  #$00    ; $80A0
.bend

; ──────────────────────────────────────────────────────────────────────
; $80A2  disk_status_inner_top
; ──────────────────────────────────────────────────────────────────────
; Inner-loop top inside disk_status_read command-channel reader.
;
;   callers:             1 code sites: $80AD disk_status_inner_trampoline
;
;   Reached only by jump disk_status_inner_trampoline (next iter). Not a separate function — see disk_status_read.
disk_status_inner_top .block
                           jsr  KERNAL_READST    ; $80A2
                           bne  disk_status_cleanup_tail    ; $80A5  KERNAL_READST returned non-zero?
                           jsr  KERNAL_CHRIN    ; $80A7
                           jsr  KERNAL_CHROUT    ; $80AA
.bend

; ──────────────────────────────────────────────────────────────────────
; $80AD  disk_status_inner_trampoline
; ──────────────────────────────────────────────────────────────────────
; 1-byte jump disk_status_inner_top trampoline (loop next-iter) inside disk_status_read command-channel reader.
;
;   code edges:          fall-through from $80AA in disk_status_inner_top (3 bytes earlier)
;
;   Fall-through-only landing for the inner-loop CHRIN/CHROUT body. Not a separate function — see disk_status_read.
disk_status_inner_trampoline .block
                           jmp  disk_status_inner_top    ; $80AD
.bend

; ──────────────────────────────────────────────────────────────────────
; $80B0  disk_status_cleanup_tail
; ──────────────────────────────────────────────────────────────────────
; Tail/cleanup label inside disk_status_read command-channel reader (CLOSE LFN $0F + restore CHKIN to keyboard).
;
;   callers:             1 code sites: $80A5
;
;   Reached on stream-EOF/error and via jump disk_status_alt_cleanup_trampoline. Not a separate function — see disk_status_read.
disk_status_cleanup_tail .block
                           lda  #$0F    ; $80B0
                           jsr  KERNAL_CLOSE    ; $80B2
                           ldx  #$00    ; $80B5
                           jsr  KERNAL_CHKIN    ; $80B7
                           rts    ; $80BA
.bend

; ──────────────────────────────────────────────────────────────────────
; $80BB  border_flash_panic
; ──────────────────────────────────────────────────────────────────────
; Border-flash panic loop (`increment VIC_BORDER / jump border_flash_panic`).
;
;   callers:             2 code sites: $8099, $80BE
;
;   Reached on disk_status_read KERNAL OPEN failure (disk_status_read →border_flash_panic) when carry and from border_flash_panic jump (alternate path). Visually freezes the screen with rapidly cycling border colors — only escape is RESET. Same shape as panic_color_loop boot panic. Not a separate function — see disk_status_read.
border_flash_panic .block
                           inc  VIC_BORDER    ; $80BB
                           jmp  border_flash_panic    ; $80BE
        .byte $4C, $B0, $80    ; $80C1
.bend

; ──────────────────────────────────────────────────────────────────────
; $80C4  global_pre_dispatch
; ──────────────────────────────────────────────────────────────────────
; Global pre-dispatch.
;
;   callers:             main_loop (every iteration)
;
;   Inspects kbd_voice_mute, dispatches to per-voice mute toggles via cursor_state_cluster nibble swap (one nibble per voice 0..2; high nibble for SID#2 V3..V5 when chip view = SID#2).
;
;   Body global_pre_dispatch..global_pre_dispatch_statusline_epilogue walks voice 0..2 then voice 3..5 (gated on sid_chip_view). Each per-voice arm EORs the mute bit at cursor_state_cluster,X. Falls through to global_shift_modifier_arm.
global_pre_dispatch .block
                           lda  kbd_voice_mute    ; $80C4
                           ldx  sid_chip_view    ; $80C7
                           beq  l_4    ; $80CA  sid_chip_view was SID_VIEW_1?
                           and  #$01    ; $80CC
