;
;   Self-mod the writer loop's operand slots:
;     - write super_cmd_write_dispatch (step-byte increment, operand of lda #$xx at super_cmd_write_dispatch).
;     - read writer_loop_count → write super_cmd_write_dispatch (count operand of A ← $FF at super_cmd_write_dispatch).
;     - read super_arg_count → write super_cmd_write_dispatch (src-pat staging at A ← $FF).
;     - read super_arg → write super_cmd_write_dispatch (dst-pat staging at A ← $FF).
;
;   Per-Y mode dispatch:
;     - Y = $01 (seqED): A += step_cursor + page_offset / asl×2 / A &= $7F at field_writer_high_bit_shim / jump super_cmd_write_iter.
;     - Y = $02 (seqLIST): A += step_cursor + page_offset / decrement an unidentified target / jump super_cmd_write_iter.
;     - Y = $04 (sidTAB): A += sidtab_scroll + chip_view_cursor_y / jump super_cmd_write_iter.
;
;   Mid-body inline field_writer_high_bit_shim (AND #$7F) is the seqED ASL-result mask — clamps the post-ASL step byte into $00..$7F before falling into super_cmd_write_iter.
super_cmd_write_setup .block
                           sta  super_cmd_writer_step_byte_smc    ; $8480
                           lda  writer_loop_count    ; $8483
                           sta  super_cmd_write_dispatch + $0B    ; $8486
                           lda  super_arg_count    ; $8489
                           sta  super_cmd_write_dispatch + $01    ; $848C
                           lda  super_arg    ; $848F
                           sta  super_cmd_write_dispatch + $06    ; $8492
; ─── switch (ui_mode) — 3 cases ───
;     case UI_MODE_SEQED          → $8499
;     case UI_MODE_SEQLIST        → $84AB
;     case UI_MODE_SIDTAB         → $84B9
;     default                   → super_cmd_write_iter
                           cpy  #UI_MODE_SEQED    ; $8495
                           bne  field_writer_high_bit_shim.l_1    ; $8497  ui_mode was not UI_MODE_SEQED?
                           lda  step_cursor    ; $8499
                           clc    ; $849C
                           adc  page_offset    ; $849D
                           asl  a    ; $84A0
                           asl  a    ; $84A1
.bend

; ──────────────────────────────────────────────────────────────────────
; $84A2  field_writer_high_bit_shim
; ──────────────────────────────────────────────────────────────────────
; 2-byte shim inside the field_writer_dispatcher field-writer dispatch chain: A&=$7F (mask hi bit off the step byte) / jump super_cmd_write_iter.
;
;   code edges:          fall-through from $84A1 in super_cmd_write_setup (1 bytes earlier)
;
;   Reached on fall-through from super_cmd_write_setup (→over when no-carry a per-mode dispatch). Not a separate function — see super_cmd_write_setup.
field_writer_high_bit_shim .block
                           and  #$7F    ; $84A2
                           jmp  super_cmd_write_iter    ; $84A4
l_1:                       cpy  #UI_MODE_SEQLIST    ; $84A7
                           bne  l_2    ; $84A9  ui_mode was not UI_MODE_SEQLIST?
                           lda  step_cursor    ; $84AB
                           clc    ; $84AE
                           adc  page_offset    ; $84AF
                           jmp  super_cmd_write_iter    ; $84B2
l_2:                       cpy  #UI_MODE_SIDTAB    ; $84B5
                           bne  super_cmd_write_iter    ; $84B7  ui_mode was not UI_MODE_SIDTAB?
                           lda  sidtab_scroll    ; $84B9
                           clc    ; $84BC
                           adc  chip_view_cursor_y    ; $84BD
                           jmp  super_cmd_write_iter    ; $84C0
.bend

; ──────────────────────────────────────────────────────────────────────
; $84C3  super_cmd_write_iter
; ──────────────────────────────────────────────────────────────────────
; per-iteration setup for the super-command write loop.
;
;   callers:             field_writer_high_bit_shim (Y==1 seqED arm), field_writer_high_bit_shim (Y==2 seqLIST arm), field_writer_high_bit_shim (Y==4 sidTAB), field_writer_high_bit_shim (Y==4 with seqLIST add-mode).
;   inputs:              A = step byte (from super_cmd_write_setup); writer_range_fill_mode = mode flag ($01 = range-fill, else single-cell); super_cmd_status_mirror = pattern-number working slot.
;   outputs:             super_cmd_writer_step_smc (counter), field_writer_offset_smc (writer ADC operand), cursor_state_cluster (current step) self-modified; either super_cmd_resolve_target dispatches once or loops $7F times in range-fill mode.
;   registers clobbered: A, X, Y
;
;   Setup:
;     - write cursor_state_cluster (current step).
;     - write super_cmd_writer_step_smc (self-mod operand: walking step counter).
;     - write field_writer_offset_smc (self-mod operand: writer's adc #$xx within super_cmd_resolve_target's seqED-arm).
;
;   Mode select:
;     - read writer_range_fill_mode / compare =$01 / →super_cmd_writer_abort_trampoline when zero:
;         range-fill mode walks super_cmd_status_mirror from $7F downward calling super_cmd_resolve_target each iter, decrementing super_cmd_status_mirror until →exits when positive.
;     - else (single-cell):
;         compare Y=$01 / →direct-write when nonzero.
;         call seqED_voice_selector_check (pat_base resolve for seqED voice) / →super_cmd_writer_bare_return when negative (exit if invalid).
;         write super_cmd_status_mirror / call super_cmd_resolve_target / jump super_cmd_writer_bare_return.
;
;   super_cmd_writer_bare_return is the shared RTS exit reached by direct-write success (super_cmd_writer_abort_trampoline JMP super_cmd_writer_bare_return), pat_base resolve failure (super_cmd_write_iter BMI super_cmd_writer_bare_return), and range-fill completion (super_cmd_writer_abort_trampoline BPL fall-through).
;
;   Self-modify slots super_cmd_writer_loop_count_smc (loop counter, init by super_cmd_write_dispatch) and super_cmd_writer_step_smc are STORAGE bytes — disasm shows them as BRK because they're operand slots, not opcodes.
super_cmd_write_iter .block
                           sta  super_cmd_current_step    ; $84C3
                           sta  super_cmd_writer_step_smc    ; $84C6
                           sta  field_writer_offset_smc    ; $84C9
                           lda  writer_range_fill    ; $84CC
                           cmp  #$01    ; $84CF
                           beq  super_cmd_writer_abort_trampoline.l_1    ; $84D1  writer_range_fill was $01?
                           cpy  #UI_MODE_SEQED    ; $84D3
                           bne  l_1    ; $84D5  ui_mode was not UI_MODE_SEQED?
                           jsr  seqED_voice_selector_check    ; $84D7
                           bmi  super_cmd_writer_bare_return    ; $84DA  seqED_voice_selector_check result had bit 7 set?
                           sta  super_cmd_status_mirror    ; $84DC
l_1:                       jsr  super_cmd_resolve_target    ; $84DF
.bend

; ──────────────────────────────────────────────────────────────────────
; $84E2  super_cmd_writer_abort_trampoline
; ──────────────────────────────────────────────────────────────────────
; 1-byte jump super_cmd_writer_bare_return trampoline (range-fill seed-only abort path) inside super_cmd_write_iter super-cmd writer setup.
;
;   code edges:          fall-through from $84DF super_cmd_write_iter_1 (3 bytes earlier)
;
;   Reached by fall-through from the super_cmd_write_iter arm when the seed-only flag is set but the range count is zero. Not a separate function — see super_cmd_resolve_target.
super_cmd_writer_abort_trampoline .block
                           jmp  super_cmd_writer_bare_return    ; $84E2
l_1:                       lda  #$7F    ; $84E5
                           sta  super_cmd_status_mirror    ; $84E7
l_2:                       jsr  super_cmd_resolve_target    ; $84EA
                           dec  super_cmd_status_mirror    ; $84ED
;   step-idiom: source = super_cmd_status_mirror  (= $71BE)
;               decremented 1× via DEX/DEY/DEC     ; final step @ $84ED
;               test     = BPL "had bit 7 clear?"
                           bpl  l_2    ; $84F0  super_cmd_status_mirror walked back 1 and had bit 7 clear?
.bend

; ──────────────────────────────────────────────────────────────────────
; $84F2  super_cmd_writer_bare_return
; ──────────────────────────────────────────────────────────────────────
; Shared bare-return inside super_cmd_write_iter super-cmd writer setup.
;
;   callers:             2 code sites: $84DA, $84E2 super_cmd_writer_abort_trampoline
;
;   Reached by →super_cmd_writer_bare_return when negative from super_cmd_write_iter (cap check) and jump super_cmd_writer_abort_trampoline (range-fill seed-only abort). Not a separate function.
super_cmd_writer_bare_return .block
                           rts    ; $84F2
        .byte $00, $00    ; $84F3
.bend

; ──────────────────────────────────────────────────────────────────────
; $84F5  super_cmd_resolve_target
; ──────────────────────────────────────────────────────────────────────
; mode-aware pointer resolver for the super-command writer.
;
;   callers:             2 code sites: $84DF super_cmd_write_iter_1, $84EA super_cmd_writer_abort_trampoline_2
;   inputs:              ui_mode = mode; super_cmd_status_mirror = pattern-num slot (seqED); field_writer_offset_smc = step-byte (self-mod from super_cmd_write_iter); X = step index for sidTAB indirect.
;   outputs:             $02/$03 zp pointer = target cell address; JMP super_cmd_write_dispatch dispatches the actual writer.
;   registers clobbered: A, X, Y
;
;   Shared seqED / seqLIST / sidTAB cursor-cell address resolver. Reads ui_mode and dispatches:
;     - seqED ($01):
;         X ← super_cmd_status_mirror.
;         read pat_base_lo,X / A += $FF (self-mod operand at field_writer_offset_smc set by caller) / write $02.
;         read pat_base_hi,X / write $03.
;         jump super_cmd_write_dispatch — yields pat_base[71BE] minus the per-step offset into the pattern bank.
;     - seqLIST ($02):
;         write $03 := $6F (V0 arr) or $70 (V1/V2 arr) per voice check, fall into super_cmd_write_dispatch.
;     - sidTAB ($04):
;         X ← field_writer_offset_smc.
;         read sidtab_row_lo,X → $02.
;         read sidtab_row_hi,X → $03.
;         jump super_cmd_write_dispatch.
;
;   Falls through to super_cmd_write_dispatch once $02/$03 are populated. Called from super_cmd_write_iter (seqED arm) and super_cmd_writer_abort_trampoline (range-fill mode loop).
super_cmd_resolve_target .block
                           lda  ui_mode    ; $84F5
                           cmp  #UI_MODE_SEQED    ; $84F8
                           bne  l_1    ; $84FA  ui_mode was not UI_MODE_SEQED?
                           ldx  super_cmd_status_mirror    ; $84FC
                           lda  pat_base_lo,x    ; $84FF
                           clc    ; $8502
                           adc  #$FF    ; $8503  ; ← field_writer_offset_smc
                           sta  zp_ptr1_lo    ; $8505
                           lda  pat_base_hi,x    ; $8507
                           sta  zp_ptr1_hi    ; $850A
                           jmp  super_cmd_write_dispatch    ; $850C
l_1:                       cmp  #UI_MODE_SEQLIST    ; $850F
                           bne  super_cmd_resolve_target_tail.l_1    ; $8511  ui_mode was not UI_MODE_SEQLIST?
                           jsr  seqLIST_helper    ; $8513
                           sta  zp_ptr1_lo    ; $8516
                           ldx  seqlist_col_cursor    ; $8518
                           lda  sid_chip_view    ; $851B
                           bne  l_4    ; $851E  sid_chip_view was not SID_VIEW_1?
                           cpx  #$02    ; $8520
                           bcs  l_2    ; $8522  seqlist_col_cursor was $02 or above?
                           lda  #$1B    ; $8524
                           jmp  super_cmd_resolve_target_tail    ; $8526
l_2:                       cpx  #$04    ; $8529
                           bcs  l_3    ; $852B  seqlist_col_cursor was $04 or above?
                           lda  #$1C    ; $852D
                           jmp  super_cmd_resolve_target_tail    ; $852F
l_3:                       lda  #$1D    ; $8532
                           jmp  super_cmd_resolve_target_tail    ; $8534
l_4:                       cpx  #$02    ; $8537
                           bcs  l_5    ; $8539  seqlist_col_cursor was $02 or above?
                           lda  #$6E    ; $853B
                           jmp  super_cmd_resolve_target_tail    ; $853D
l_5:                       cpx  #$04    ; $8540
                           bcs  l_6    ; $8542  seqlist_col_cursor was $04 or above?
                           lda  #$6F    ; $8544
                           jmp  super_cmd_resolve_target_tail    ; $8546
l_6:                       lda  #$70    ; $8549
.bend

; ──────────────────────────────────────────────────────────────────────
; $854B  super_cmd_resolve_target_tail
; ──────────────────────────────────────────────────────────────────────
; Shared 2-byte tail inside super_cmd_resolve_target: write $03 / jump super_cmd_write_dispatch.
;
;   callers:             5 code sites: $8526, $852F, $8534, $853D, $8546
;
;   Reached by 5 jump sites in the seqED/seqLIST/sidTAB mode arms that set $03 := $6F/$70 (V0/V1/V2 arranger high byte) or write the resolved high byte before falling into the writer. Not a separate function — see super_cmd_resolve_target.
super_cmd_resolve_target_tail .block
                           sta  zp_ptr1_hi    ; $854B
                           jmp  super_cmd_write_dispatch    ; $854D
l_1:                       cmp  #UI_MODE_SIDTAB    ; $8550
                           bne  super_cmd_write_dispatch    ; $8552  ui_mode was not UI_MODE_SIDTAB?
                           ldx  field_writer_offset_smc    ; $8554
                           lda  song_position_arrays_lo,x    ; $8557
                           sta  zp_ptr1_lo    ; $855A
                           lda  song_position_arrays_hi,x    ; $855C
                           sta  zp_ptr1_hi    ; $855F
                           jmp  super_cmd_write_dispatch    ; $8561
.bend

; ──────────────────────────────────────────────────────────────────────
; $8564  super_cmd_write_dispatch
; ──────────────────────────────────────────────────────────────────────
; final writer fan-in after super_cmd_resolve_target resolved $02/$03 zp pointer to the target cell.
;
;   callers:             super_cmd_resolve_target_adc_smc, super_cmd_resolve_target_tail, super_cmd_resolve_target_tail (per-mode fan-in from super_cmd_resolve_target).
;   inputs:              $02/$03 = resolved writer target (from super_cmd_resolve_target); writer_loop_stride = per-iter stride (signed); super_cmd_write_dispatch = step-increment byte (from super_cmd_write_setup); Y = mode.
;   outputs:             Calls the writer 1..writer_loop_count times, walking through $02/$03 + stride per iteration, with mode-specific overflow / ceiling checks.
;   registers clobbered: A, X, Y
;
;   Setup:
;     - A←$FF → write super_arg_count / write super_arg (mark super-write 'fresh').
;     - A←$FF / →super_cmd_write_dispatch_bare_return when zero (abort path — only taken if writer_loop_count was pre-zeroed).
;     - write super_cmd_writer_loop_count_smc (loop counter init).
;     - call VEC_IRQ_HI (writer call; operand super_cmd_write_dispatch self-modded by field_writer_dispatcher from caller's X,Y).
;
;   After writer returns:
;     - read super_cmd_writer_step_smc + A+=writer_loop_stride → write super_cmd_writer_step_smc (walk current_step by the per-iter stride from writer_loop_stride).
;     - per-mode cascade on Y:
;         - Y == 1 (seqED): A+=$FF / →super_cmd_write_dispatch when no-overflow / write $02 / decrement super_cmd_writer_loop_count_smc / →field_writer_jsr_smc when nonzero (next iter).
;         - Y == 2 (seqLIST): A+=super_cmd_write_dispatch / →super_cmd_write_dispatch_bare_return when carry / write $02 / decrement loop / →field_writer_jsr_smc when nonzero.
;         - Y == 4 (sidTAB): A+=super_cmd_write_dispatch / →super_cmd_write_dispatch when no-carry (continue) else increment Y $03 / compare Y=$6E (sidTAB ceiling) / →super_cmd_write_dispatch_bare_return when zero / Y→$03 / decrement loop / →field_writer_jsr_smc when nonzero.
;
;   super_cmd_write_dispatch_bare_return is a bare RTS reached on every overflow/abort path. The JSR VEC_IRQ_HI at field_writer_jsr_smc is self-modified by field_writer_dispatcher's caller chain — the writer call dispatches to one of the per-field writers.
super_cmd_write_dispatch .block
                           lda  #$FF    ; $8564  ; ← (SMC operand at $8565, no name)
                           sta  super_arg_count    ; $8566
                           lda  #$FF    ; $8569  ; ← (SMC operand at $856A, no name)
                           sta  super_arg    ; $856B
                           lda  #$FF    ; $856E  ; ← (SMC operand at $856F, no name)
                           beq  super_cmd_write_dispatch_bare_return    ; $8570  super_cmd_write_dispatch_$B was zero?
                           sta  super_cmd_writer_loop_count_smc    ; $8572
; ──── SMC-patched JSR (22 catalogued targets) ────
;   Patched at: $844F, $8452
;   SMC dispatch: per-field writer chosen by (ui_mode, kbd_modifiers,
;   kbd_decoded_key). Operand bytes are patched at $844F / $8452 by
;   field_writer_dispatcher's caller chain.
;   Targets:
;     $B396  writer_sidcall                    [seqED]
;     $B3DF  writer_note                       [seqED]
;     $B3F6  writer_clear_note                 [seqED]
;     $B3FF  writer_speed                      [seqED]
;     $C146  writer_sidtab_toggle              [sidTAB]
;     $C15F  writer_sidtab_digit               [sidTAB]
;     $C199  writer_sidtab_clear_advance       [sidTAB]
;     $C1AB  writer_sidtab_inc                 [sidTAB]
;     $C1CE  writer_sidtab_dec                 [sidTAB]
;     $C211  writer_sidtab_supercmd            [sidTAB]
;     $C352  writer_sidtab_cbm_shift_a         [sidTAB]
;     $C36A  writer_sidtab_inst_row            [sidTAB]
;     $C406  writer_sidtab_cbm_shift_b         [sidTAB]
;     $C4FA  writer_disk_filename              [sidTAB]
;     $E149  writer_seqlist_advance            [seqLIST]
;     $E211  writer_seqlist_digit              [seqLIST]
;     $E233  writer_seqlist_clear              [seqLIST]
;     $E23C  writer_seqlist_supercmd           [seqLIST]
;     $E41E  writer_seqlist_row_clone          [seqLIST]
;     $E444  writer_seqlist_row_insert         [seqLIST]
;     $E52C  writer_seqlist_dec                [seqLIST]
;     $E53E  writer_seqlist_inc                [seqLIST]
field_writer_jsr_smc:      jsr  VEC_IRQ_HI    ; $8575
                           lda  super_cmd_writer_step_smc    ; $8578
                           clc    ; $857B
                           adc  writer_stride    ; $857C
                           sta  super_cmd_writer_step_smc    ; $857F
                           ldy  ui_mode    ; $8582
                           cpy  #UI_MODE_SEQED    ; $8585
                           bne  l_3    ; $8587  ui_mode was not UI_MODE_SEQED?
                           lda  #$FF    ; $8589  ; ← super_cmd_writer_step_byte_smc
                           clc    ; $858B
                           adc  zp_ptr1_lo    ; $858C
                           bcs  l_1    ; $858E  zp_ptr1_lo carry
                           bvc  l_2    ; $8590
l_1:                       jmp  super_cmd_write_dispatch_bare_return    ; $8592
l_2:                       sta  zp_ptr1_lo    ; $8595
                           dec  super_cmd_writer_loop_count_smc    ; $8597
                           bne  field_writer_jsr_smc    ; $859A  (super_cmd_writer_loop_count_smc − 1) was non-zero?
                           jmp  super_cmd_write_dispatch_bare_return    ; $859C
l_3:                       cpy  #UI_MODE_SEQLIST    ; $859F
                           bne  l_4    ; $85A1  ui_mode was not UI_MODE_SEQLIST?
                           lda  super_cmd_writer_step_byte_smc    ; $85A3
                           clc    ; $85A6
                           adc  zp_ptr1_lo    ; $85A7
                           sta  zp_ptr1_lo    ; $85A9
                           bcs  super_cmd_write_dispatch_bare_return    ; $85AB  zp_ptr1_lo carry
                           dec  super_cmd_writer_loop_count_smc    ; $85AD
                           bne  field_writer_jsr_smc    ; $85B0  (super_cmd_writer_loop_count_smc − 1) was non-zero?
                           jmp  super_cmd_write_dispatch_bare_return    ; $85B2
l_4:                       cpy  #UI_MODE_SIDTAB    ; $85B5
                           bne  super_cmd_write_dispatch_bare_return    ; $85B7  ui_mode was not UI_MODE_SIDTAB?
                           lda  super_cmd_writer_step_byte_smc    ; $85B9
                           clc    ; $85BC
                           adc  zp_ptr1_lo    ; $85BD
                           sta  zp_ptr1_lo    ; $85BF
                           bcc  l_5    ; $85C1  zp_ptr1_lo no carry
                           ldy  zp_ptr1_hi    ; $85C3
                           iny    ; $85C5
                           cpy  #$6E    ; $85C6
                           beq  super_cmd_write_dispatch_bare_return    ; $85C8  (zp_ptr1_hi + 1) was $6E?
                           sty  zp_ptr1_hi    ; $85CA
l_5:                       dec  super_cmd_writer_loop_count_smc    ; $85CC
                           bne  field_writer_jsr_smc    ; $85CF  (super_cmd_writer_loop_count_smc − 1) was non-zero?
                           jmp  super_cmd_write_dispatch_bare_return    ; $85D1
.bend

; ──────────────────────────────────────────────────────────────────────
; $85D4  super_cmd_write_dispatch_bare_return
; ──────────────────────────────────────────────────────────────────────
; Bare return at the tail of super_cmd_write_dispatch.
;
;   callers:             8 code sites: $8570, $8592 super_cmd_write_dispatch_1, $859C, $85AB, $85B2, $85B7, $85C8, $85D1
;
;   Reached on every overflow/abort path: super_cmd_write_dispatch →(loop_count when zero), super_cmd_write_dispatch jump (seqED/seqLIST wrap), super_cmd_write_dispatch →(seq when carryED step overflow), super_cmd_write_dispatch jmp, super_cmd_write_dispatch →(sid when nonzeroTAB ceiling), super_cmd_write_dispatch →(loop when zero done). Not a separate function — see super_cmd_write_dispatch.
super_cmd_write_dispatch_bare_return .block
                           rts    ; $85D4
.bend

; ──────────────────────────────────────────────────────────────────────
; $85D5  super_init_full
; ──────────────────────────────────────────────────────────────────────
; clear supercmd_flag_mask super flags; call border_set_a; call super_enter_status; clear supercmd_flag_mask / writer_loop_count.
;
;   callers:             2 code sites: $082B, $8656
;   inputs:              X
;   registers clobbered: A, X
;
;   Full super-command state reset.
super_init_full .block
                           lda  #$00    ; $85D5
                           sta  super_cmd_extra    ; $85D7
                           lda  #$00    ; $85DA
                           jsr  border_set_a    ; $85DC
.bend

; ──────────────────────────────────────────────────────────────────────
; $85DF  super_cmd_state_init
; ──────────────────────────────────────────────────────────────────────
; boot/mode-change reset of super-command typed-arg slots.
;
;   callers:             mode_transition_wrapper_tail JMP (the mode-change wrapper inside mode_transition_wrapper — runs on every UI mode transition).
;   inputs:              (none — pure init)
;   outputs:             super_arg_count..writer_range_fill_mode initialised with sentinel defaults
;   registers clobbered: A, X
;
;   call super_enter_status (clear super_arg_count/page_pair_counter) / X←$00 / X→supercmd_flag_mask / X←$01 / X→super_arg, writer_loop_count, writer_loop_stride / X←$0C / X→writer_range_fill_mode / return. Leaves slot tracking in a 'pending super-command, default count=1, default page=$0C' state.
super_cmd_state_init .block
                           jsr  super_enter_status    ; $85DF
                           ldx  #$00    ; $85E2
                           stx  super_cmd_state_71c9    ; $85E4
                           ldx  #$01    ; $85E7
                           stx  super_arg    ; $85E9
                           stx  writer_loop_count    ; $85EC
                           stx  writer_stride    ; $85EF
                           ldx  #$0C    ; $85F2
                           stx  writer_range_fill    ; $85F4
                           rts    ; $85F7
.bend

; ──────────────────────────────────────────────────────────────────────
; $85F8  super_set_active
; ──────────────────────────────────────────────────────────────────────
; A←SUPERCMD_S_DIG1 / write super_cmd_flags / return.
;
;   callers:             1 code sites: $85FE super_enter_status
;   outputs:             A
;   registers clobbered: A
;
;   Marks super-command mode active.
super_set_active .block
                           lda  #SUPERCMD_S_DIG1    ; $85F8
                           sta  super_cmd_flags    ; $85FA
                           rts    ; $85FD
.bend

; ──────────────────────────────────────────────────────────────────────
; $85FE  super_enter_status
; ──────────────────────────────────────────────────────────────────────
; call super_set_active (set super_cmd_flags=SUPERCMD_S_DIG1 super-active flag) / jump statusline_clear (clear status line).
;
;   callers:             2 code sites: $85DF super_cmd_state_init, $8650
;   inputs:              X
;   registers clobbered: A, X
;
;   Combined 'enter super mode' init.
super_enter_status .block
                           jsr  super_set_active    ; $85FE
                           jmp  statusline_clear    ; $8601
.bend

; ──────────────────────────────────────────────────────────────────────
; $8604  hex_digit_validate
; ──────────────────────────────────────────────────────────────────────
; A is a typed key's screen code; validate for hex range.
;
;   callers:             7 code sites: $86BE super_cmd_s_lo_nibble, $86DB super_cmd_s_hi_nibble, $86FB super_cmd_w_lo_nibble, $8717 super_cmd_r_lo_nibble, $8734 super_cmd_wr_hi_nibble, $8751 super_cmd_q_lo_nibble, $876E super_cmd_q_hi_nibble
;   inputs:              A = screen code.
;   outputs:             A = nibble 0-15 if valid; C=1 valid / C=0 invalid.
;   registers clobbered: A
;
;   compare =$3A / →error when carry; compare =$30 / bcs = '0'-'9'; compare =$00 / →error when zero; compare =$07 / →error when carry; else 'A'-'F' (screen codes $01-$06). Returns C=1 valid, C=0 invalid. The valid 'A'-'F' branch ADCs the screen code to convert to nibble value.
hex_digit_validate .block
                           cmp  #$3A    ; $8604
                           bcs  l_2    ; $8606  A was $3A or above?
                           cmp  #$30    ; $8608
                           bcs  l_1    ; $860A  A was $30 or above?
                           cmp  #$00    ; $860C
                           beq  l_2    ; $860E  A was $00?
                           cmp  #$07    ; $8610
                           bcs  l_2    ; $8612  A was $07 or above?
                           clc    ; $8614
                           adc  #$09    ; $8615
l_1:                       and  #$0F    ; $8617
                           sec    ; $8619
                           rts    ; $861A
l_2:                       clc    ; $861B
                           rts    ; $861C
.bend

; ──────────────────────────────────────────────────────────────────────
; $861D  super_flag_or
; ──────────────────────────────────────────────────────────────────────
; ora supercmd_flag_mask / write supercmd_flag_mask / return.
;
;   callers:             5 code sites: $86D7, $8711, $8730, $876A, $87AB
;   inputs:              A = bit mask to OR into supercmd_flag_mask.
;   registers clobbered: A
;
;   Sets bits in the super-command flags register at supercmd_flag_mask.
super_flag_or .block
                           ora  super_cmd_extra    ; $861D
                           sta  super_cmd_extra    ; $8620
                           rts    ; $8623
.bend

; ──────────────────────────────────────────────────────────────────────
; $8624  super_arg_buffer_init
; ──────────────────────────────────────────────────────────────────────
; start of super-command argument typing.
;
;   callers:             5 code sites: $86C9, $8706, $8722, $875C, $8794
;   inputs:              A, X
;   outputs:             X
;   registers clobbered: A, X, Y
;
;   Sets up the status line to echo the user's typed super-command arg digits. Patches print_ff_helper's dispatch address with A (so the next $FF print routes to the caller's wanted target), sets statusline_color_mirror = $FF (the 'persistent' sentinel so statusline_tick doesn't auto-clear), and prints a leading space if the cursor isn't already at column 0. Called by super-command entry chords.
super_arg_buffer_init .block
                           sta  print_ff_helper + $01    ; $8624
                           lda  #$FF    ; $8627
                           sta  statusline_color_mirror    ; $8629
                           lda  statusline_scratch    ; $862C
                           beq  l_1    ; $862F  statusline_scratch was zero?
                           lda  #$20    ; $8631
                           jsr  statusline_print_char    ; $8633
                           jmp  print_ff_helper    ; $8636
l_1:                       jsr  statusline_clear    ; $8639
.bend

; ──────────────────────────────────────────────────────────────────────
; $863C  print_ff_helper
; ──────────────────────────────────────────────────────────────────────
; Print-$FF helper: A←$FF / jump print_char_to_statusline (status-line print one screen-code).
;
;   callers:             super_arg_buffer_init JMP (1 site inside super_arg_buffer_init body).
;   inputs:              X
;   outputs:             X
;   registers clobbered: A, X, Y
;
;   Used as a tail jump from super_arg_buffer_init inside super_arg_buffer_init to emit the $FF sentinel that marks 'super-arg typing in progress' on the status line.
print_ff_helper .block
                           lda  #$FF    ; $863C  ; ← (SMC operand at $863D, no name)
                           jmp  statusline_print_char    ; $863E
.bend

; ──────────────────────────────────────────────────────────────────────
; $8641  super_cmd_dispatch
; ──────────────────────────────────────────────────────────────────────
; CTRL+key typed super-command state machine.
;
;   callers:             main_loop_postscan JSR (inside main_loop, after global_pre_dispatch).
;   inputs:              kbd_modifiers (must be $04 = CTRL only — non-CTRL paths JMP super_cmd_dispatch_bare_return bare-RTS); kbd_decoded_key decoded key; super_cmd_flags (current parser state).
;   outputs:             super_cmd_flags advanced through prefix → lo-nibble → hi-nibble states; super_arg_slot_r-super_arg_slot_w typed-arg slots; status line repainted via print_char_to_statusline / print_zstring / super_arg_buffer_init.
;   registers clobbered: A, X, Y
;
;   Read every main-loop iteration (main_loop_postscan call super_cmd_dispatch before mode_dispatch). Two-phase: PREFIX (set super_cmd_flags from CTRL+letter) → DIGIT (consume typed hex digit, dispatch to per-prefix lo/hi-nibble arm based on super_cmd_flags).
;
;   PREFIX-recognition cascade (super_cmd_dispatch) — when the decoded key matches
;   a known super-cmd letter, sets super_cmd_flags to that prefix's bit and RTSes:
;
;    Key | kbd_decoded_key | super_cmd_flags set to | Super-command
;    ----+-----------------+------------------------+------------------------------------------
;    F1  | $88             | —                       | calls super_enter_status (special entry)
;    F5  | $92             | —                       | calls super_init_full (special entry)
;    S   | $13             | $01                     | step-jump (S lo-nibble → $02 hi-nibble)
;    W   | $17             | $04                     | width set
;    R   | $12             | $10                     | timer/rate set
;    Z   | $11             | $40                     | zone set
;    G   | $1A             | $08                     | page-jump
;
;   DIGIT-input cascade (super_cmd_dispatch) — when no prefix matches, reads super_cmd_flags
;   and dispatches to the lo-nibble / hi-nibble arm by current state:
;
;    super_cmd_flags | Arm | Stores into | Disp tag | Transitions to
;    ----------------+-----------------------+---------------------------------+----------+------------------------------------------------
;    $01 | super_cmd_s_lo_nibble  | super_arg_slot_swr_hi           | #$13 | $02 (S hi)
;    $02 | super_cmd_s_hi_nibble  | super_arg_slot_swr_hi (shifted) | —    | super_cmd_terminate terminate
;    $04 | super_cmd_w_lo_nibble  | super_arg_slot_w                | #$17 | $20 (shared hi-nibble)
;    $08 | super_cmd_z_arm        | super_arg_slot_z                | #$1A | super_cmd_terminate terminate (G is 1-digit)
;    $10 | super_cmd_r_lo_nibble  | super_arg_slot_r                | #$12 | $20 (shared hi-nibble)
;    $20 | super_cmd_wr_hi_nibble | super_arg_slot_swr_hi (shifted) | —    | super_cmd_terminate terminate (shared W+R hi)
;    $40 | super_cmd_q_lo_nibble  | super_arg_slot_q                | #$11 | $80 (Z hi)
;    $80 | super_cmd_q_hi_nibble  | super_arg_slot_q (shifted)      | —    | super_cmd_terminate terminate
;
;   Notable structural quirks:
;    - $20 (shared hi-nibble) is reached from BOTH $04 (W lo) AND $10
;    (R lo). super_cmd_wr_hi_nibble thus serves both W and R super-commands.
;    - The G arm ($08) is single-digit; super_cmd_z_arm terminates directly.
;    - Each lo-nibble arm uses a distinct slot (super_arg_slot_r/super_arg_slot_q/super_arg_slot_swr_hi/super_arg_slot_w)
;    but the slots are not exclusively per-command — super_arg_slot_swr_hi is shared
;    between S-pair (super_cmd_s_lo_nibble/super_cmd_s_hi_nibble) and W/R-hi (super_cmd_wr_hi_nibble).
super_cmd_dispatch .block
                           lda  kbd_modifiers    ; $8641
                           cmp  #KBD_MOD_CTRL    ; $8644
                           beq  l_1    ; $8646  kbd_modifiers was KBD_MOD_CTRL?
                           jmp  super_cmd_dispatch_bare_return    ; $8648
l_1:                       lda  kbd_decoded_key    ; $864B
                           cmp  #KEY_HOME    ; $864E
                           beq  super_enter_status    ; $8650  kbd_decoded_key was KEY_HOME?
; ─── switch (kbd_decoded_key) — 6 cases ───
;     case KEY_RETURN             → $8656
;     case KEY_S                  → $865D
;     case KEY_W                  → $8667
;     case KEY_R                  → $8671
;     case KEY_Q                  → $867B
;     case KEY_Z                  → $8685
;     default                   → $868B
                           cmp  #KEY_RETURN    ; $8652
                           bne  l_2    ; $8654  kbd_decoded_key was not KEY_RETURN?
                           jmp  super_init_full    ; $8656
l_2:                       cmp  #KEY_S    ; $8659
                           bne  l_3    ; $865B  kbd_decoded_key was not KEY_S?
                           lda  #SUPERCMD_S_DIG1    ; $865D
                           sta  super_cmd_flags    ; $865F
                           rts    ; $8662
l_3:                       cmp  #KEY_W    ; $8663
                           bne  l_4    ; $8665  kbd_decoded_key was not KEY_W?
                           lda  #SUPERCMD_W_DIG1    ; $8667
                           sta  super_cmd_flags    ; $8669
                           rts    ; $866C
l_4:                       cmp  #KEY_R    ; $866D
                           bne  l_5    ; $866F  kbd_decoded_key was not KEY_R?
                           lda  #SUPERCMD_R_DIG1    ; $8671
                           sta  super_cmd_flags    ; $8673
                           rts    ; $8676
l_5:                       cmp  #KEY_Q    ; $8677
                           bne  l_6    ; $8679  kbd_decoded_key was not KEY_Q?
                           lda  #SUPERCMD_Q_DIG1    ; $867B
                           sta  super_cmd_flags    ; $867D
                           rts    ; $8680
l_6:                       cmp  #KEY_Z    ; $8681
                           bne  l_7    ; $8683  kbd_decoded_key was not KEY_Z?
                           lda  #SUPERCMD_Z    ; $8685
                           sta  super_cmd_flags    ; $8687
                           rts    ; $868A
l_7:                       ldx  super_cmd_flags    ; $868B
; ─── switch (super_cmd_flags) — 3 cases ───
;     case SUPERCMD_S_DIG1        → super_cmd_s_lo_nibble
;     case SUPERCMD_S_DIG2        → super_cmd_s_hi_nibble
;     case SUPERCMD_W_DIG1        → super_cmd_w_lo_nibble
;     default                   → $869A
                           cpx  #SUPERCMD_S_DIG1    ; $868E
                           beq  super_cmd_s_lo_nibble    ; $8690  super_cmd_flags was SUPERCMD_S_DIG1?
                           cpx  #SUPERCMD_S_DIG2    ; $8692
                           beq  super_cmd_s_hi_nibble    ; $8694  super_cmd_flags was SUPERCMD_S_DIG2?
                           cpx  #SUPERCMD_W_DIG1    ; $8696
                           beq  super_cmd_w_lo_nibble    ; $8698  super_cmd_flags was SUPERCMD_W_DIG1?
; ─── switch (super_cmd_flags) — 5 cases ───
;     case SUPERCMD_R_DIG1        → $869E
;     case SUPERCMD_WR_DIG2       → $86A5
;     case SUPERCMD_Q_DIG1        → $86AC
;     case SUPERCMD_Q_DIG2        → $86B3
;     case SUPERCMD_Z             → $86BA
;     default                   → super_cmd_dispatch_bare_return
                           cpx  #SUPERCMD_R_DIG1    ; $869A
                           bne  l_8    ; $869C  super_cmd_flags was not SUPERCMD_R_DIG1?
                           jmp  super_cmd_r_lo_nibble    ; $869E
l_8:                       cpx  #SUPERCMD_WR_DIG2    ; $86A1
                           bne  l_9    ; $86A3  super_cmd_flags was not SUPERCMD_WR_DIG2?
                           jmp  super_cmd_wr_hi_nibble    ; $86A5
l_9:                       cpx  #SUPERCMD_Q_DIG1    ; $86A8
                           bne  l_10    ; $86AA  super_cmd_flags was not SUPERCMD_Q_DIG1?
                           jmp  super_cmd_q_lo_nibble    ; $86AC
l_10:                      cpx  #SUPERCMD_Q_DIG2    ; $86AF
                           bne  l_11    ; $86B1  super_cmd_flags was not SUPERCMD_Q_DIG2?
                           jmp  super_cmd_q_hi_nibble    ; $86B3
l_11:                      cpx  #SUPERCMD_Z    ; $86B6
                           bne  super_cmd_dispatch_bare_return    ; $86B8  super_cmd_flags was not SUPERCMD_Z?
                           jmp  super_cmd_z_arm    ; $86BA
.bend

; ──────────────────────────────────────────────────────────────────────
; $86BD  super_cmd_dispatch_bare_return
; ──────────────────────────────────────────────────────────────────────
; Shared bare-return landing pad inside the super_cmd_dispatch typed-digit cascade (super_cmd_dispatch).
;
;   callers:             2 code sites: $8648, $86B8
;
;   Reached on every CTRL+key path that doesn't match a super_cmd_flags arm — super_cmd_dispatch jump super_cmd_dispatch_bare_return (non-CTRL fall-through) and super_cmd_dispatch →super_cmd_dispatch_bare_return when nonzero (last-arm miss). Not a separate function.
super_cmd_dispatch_bare_return .block
                           rts    ; $86BD
.bend

; ──────────────────────────────────────────────────────────────────────
; $86BE  super_cmd_s_lo_nibble
; ──────────────────────────────────────────────────────────────────────
; Super-cmd 'S' (step-jump) typed-digit LO-NIBBLE arm.
;
;   callers:             super_cmd_dispatch BEQ (from super_cmd_dispatch cascade; CPX #$01 BEQ at super_cmd_dispatch).
;   inputs:              A
;   registers clobbered: A, X, Y
;
;   Fires when super_cmd_flags == SUPERCMD_S_DIG1 (set by CTRL+S prefix at super_cmd_dispatch). Sequence:
;     - call hex_digit_validate / →super_cmd_terminate when no-carry.
;     - write super_arg_slot_swr_hi.
;     - X←A / A←$13 / call super_arg_buffer_init (super_arg_buffer_init dispatch #$13).
;     - read hex_digit_lo_lut,X / call print_char_to_statusline.
;     - A←SUPERCMD_S_DIG2 / write super_cmd_flags (transition to S hi-nibble at super_cmd_s_hi_nibble).
