super_cmd_s_lo_nibble .block
                           jsr  hex_digit_validate    ; $86BE
                           bcc  super_cmd_terminate    ; $86C1  hex_digit_validate returned carry clear?
                           sta  super_arg_slot_swr_hi    ; $86C3
                           tax    ; $86C6
                           lda  #$13    ; $86C7
                           jsr  super_arg_buffer_init    ; $86C9
                           lda  hex_digit_lo_lut,x    ; $86CC
                           jsr  statusline_print_char    ; $86CF
                           lda  #SUPERCMD_S_DIG2    ; $86D2
                           sta  super_cmd_flags    ; $86D4
                           jsr  super_flag_or    ; $86D7
                           rts    ; $86DA
.bend

; ──────────────────────────────────────────────────────────────────────
; $86DB  super_cmd_s_hi_nibble
; ──────────────────────────────────────────────────────────────────────
; Super-cmd 'S' typed-digit HI-NIBBLE accumulator.
;
;   callers:             super_cmd_dispatch BEQ (from super_cmd_dispatch cascade; CPX #$02 BEQ at super_cmd_dispatch).
;   inputs:              A
;   registers clobbered: A, X, Y
;
;   Fires when super_cmd_flags == SUPERCMD_S_DIG2 (set by super_cmd_s_lo_nibble S lo-nibble). Sequence:
;     - call hex_digit_validate / →super_cmd_terminate when no-carry.
;     - X←$04 / 4× shift loop:
;         shift super_arg_slot_swr_hi left / decrement X / bne.
;     - ora super_arg_slot_swr_hi / write super_arg_slot_swr_hi.
;     - X←A / read hex_digit_lo_lut,X / call print_char_to_statusline.
;     - jump super_cmd_terminate.
;
;   Mirror of super_cmd_wr_hi_nibble but uses super_arg_slot_swr_hi slot exclusively.
super_cmd_s_hi_nibble .block
                           jsr  hex_digit_validate    ; $86DB
                           bcc  super_cmd_terminate    ; $86DE  hex_digit_validate returned carry clear?
                           ldx  #$04    ; $86E0
l_1:                       asl  super_arg_slot_swr_hi    ; $86E2
                           dex    ; $86E5
                           bne  l_1    ; $86E6  ($04 − 1) was non-zero?
                           ora  super_arg_slot_swr_hi    ; $86E8
                           sta  super_arg_slot_swr_hi    ; $86EB
                           tax    ; $86EE
                           lda  hex_digit_lo_lut,x    ; $86EF
                           jsr  statusline_print_char    ; $86F2
.bend

; ──────────────────────────────────────────────────────────────────────
; $86F5  super_cmd_terminate
; ──────────────────────────────────────────────────────────────────────
; common exit for super-command typed-digit arms.
;
;   callers:             12 sites in super-cmd typed-digit handlers: super_cmd_s_lo_nibble (W/R sub-arg invalid), super_cmd_s_hi_nibble (W lo-nibble fall-through), super_cmd_w_lo_nibble (Z/G sub-arg invalid), super_cmd_w_lo_nibble (G lo-nibble), super_cmd_r_lo_nibble/super_cmd_wr_hi_nibble/super_cmd_q_lo_nibble/super_cmd_q_hi_nibble (more sub-arg invalid), super_cmd_wr_hi_nibble (S lo-nibble), plus 2 jmp_abs paths.
;   inputs:              (none — pure flag write).
;   outputs:             super_cmd_flags := SUPERCMD_S_DIG1.
;   registers clobbered: A
