;   Fires when super_cmd_flags == SUPERCMD_W_DIG1 (set by CTRL+W prefix at super_cmd_dispatch). Sequence:
;     - call hex_digit_validate / →super_cmd_terminate when no-carry.
;     - write super_arg_slot_w.
;     - X←A / A←$17 / call super_arg_buffer_init (super_arg_buffer_init dispatch #$17).
;     - read hex_digit_lo_lut,X / call print_char_to_statusline.
;     - A←SUPERCMD_WR_DIG2 / write super_cmd_flags (transition to shared W+R hi-nibble at super_cmd_wr_hi_nibble).
;     - call super_flag_or / return.
super_cmd_w_lo_nibble .block
                           jsr  hex_digit_validate    ; $86FB
                           bcc  super_cmd_terminate    ; $86FE  hex_digit_validate returned carry clear?
                           sta  super_arg_slot_w    ; $8700
                           tax    ; $8703
                           lda  #$17    ; $8704
                           jsr  super_arg_buffer_init    ; $8706
                           lda  hex_digit_lo_lut,x    ; $8709
                           jsr  statusline_print_char    ; $870C
                           lda  #$04    ; $870F
                           jsr  super_flag_or    ; $8711
                           jmp  super_cmd_terminate    ; $8714
.bend

; ──────────────────────────────────────────────────────────────────────
; $8717  super_cmd_r_lo_nibble
; ──────────────────────────────────────────────────────────────────────
; Super-cmd 'R' (timer/rate-set) typed-digit LO-NIBBLE arm.
;
;   callers:             super_cmd_dispatch JMP (1 site in super_cmd_dispatch cascade).
;   inputs:              A
;   registers clobbered: A, X, Y
