;     - A←SUPERCMD_WR_DIG2 / write super_cmd_flags (transition to shared W+R hi-nibble state).
;     - call super_flag_or / return.
;
;   Dispatched via super_cmd_dispatch jump from super_cmd_dispatch cascade.
super_cmd_r_lo_nibble .block
                           jsr  hex_digit_validate    ; $8717
                           bcc  super_cmd_terminate    ; $871A  hex_digit_validate returned carry clear?
                           sta  super_arg_slot_r    ; $871C
                           tax    ; $871F
                           lda  #$12    ; $8720
                           jsr  super_arg_buffer_init    ; $8722
                           lda  hex_digit_lo_lut,x    ; $8725
                           jsr  statusline_print_char    ; $8728
                           lda  #SUPERCMD_WR_DIG2    ; $872B
                           sta  super_cmd_flags    ; $872D
                           jsr  super_flag_or    ; $8730
                           rts    ; $8733
.bend

; ──────────────────────────────────────────────────────────────────────
; $8734  super_cmd_wr_hi_nibble
; ──────────────────────────────────────────────────────────────────────
; Super-cmd shared W+R typed-digit HI-NIBBLE accumulator.
;
;   callers:             super_cmd_dispatch JMP (from super_cmd_dispatch cascade; CPX #$20 BEQ).
;   inputs:              A
;   registers clobbered: A, X, Y
;
;   Fires when super_cmd_flags == SUPERCMD_WR_DIG2 (set by either super_cmd_w_lo_nibble W lo-nibble OR super_cmd_r_lo_nibble R lo-nibble; both transition to this state). Sequence:
;     - call hex_digit_validate / →super_cmd_terminate when no-carry.
;     - X←$04 / 4× shift loop:
;         shift super_arg_slot_swr_hi left / decrement X / bne (shift prior lo-nibble into the hi-nibble position).
;     - ora super_arg_slot_swr_hi / write super_arg_slot_swr_hi.
;     - X←A / read hex_digit_lo_lut,X / call print_char_to_statusline.
;     - jump super_cmd_terminate (terminate).
;
;   Implements the second digit of W's or R's 2-digit hex pair.
super_cmd_wr_hi_nibble .block
                           jsr  hex_digit_validate    ; $8734
                           bcc  super_cmd_terminate    ; $8737  hex_digit_validate returned carry clear?
                           ldx  #$04    ; $8739
