; $8751  super_cmd_q_lo_nibble
; ──────────────────────────────────────────────────────────────────────
; Super-cmd typed-digit LO-NIBBLE arm reached when super_cmd_flags == SUPERCMD_Q_DIG1 (set by the super_cmd_dispatch prefix arm on compare =$11 — which fires for the Q key, NOT Z).
;
;   callers:             super_cmd_dispatch JMP (from super_cmd_dispatch cascade; CPX #$40 BEQ).
;   inputs:              A
;   registers clobbered: A, X, Y
;
;   Sequence:
;     - call hex_digit_validate / →super_cmd_terminate when no-carry (invalid).
;     - write super_arg_slot_q.
;     - X←A / A←$11 / call super_arg_buffer_init.
;     - read hex_digit_lo_lut,X / call print_char_to_statusline.
;     - A←SUPERCMD_Q_DIG2 / write super_cmd_flags (transition to super_cmd_q_hi_nibble hi-nibble).
;     - call super_flag_or / return.
super_cmd_q_lo_nibble .block
                           jsr  hex_digit_validate    ; $8751
                           bcc  super_cmd_terminate    ; $8754  hex_digit_validate returned carry clear?
                           sta  super_arg_slot_q    ; $8756
                           tax    ; $8759
                           lda  #$11    ; $875A
                           jsr  super_arg_buffer_init    ; $875C
                           lda  hex_digit_lo_lut,x    ; $875F
                           jsr  statusline_print_char    ; $8762
                           lda  #SUPERCMD_Q_DIG2    ; $8765
                           sta  super_cmd_flags    ; $8767
                           jsr  super_flag_or    ; $876A
                           rts    ; $876D
.bend

