                           lda  filter_cutoff_slide_acc_hi    ; $87F3
                           clc    ; $87F6
                           adc  filter_cutoff_slide_saturation_step    ; $87F7
                           tay    ; $87FA
                           jmp  l_2    ; $87FB
l_1:                       ldx  sid2_frame_state_c8b6    ; $87FE
                           lda  sid2_frame_state_c8be    ; $8801
                           clc    ; $8804
