; ──────────────────────────────────────────────────────────────────────
; $AA02  pat_base_resolve_v012
; ──────────────────────────────────────────────────────────────────────
; read sid_chip_view; if SID#1, walks arrangers arranger_v0_sid1/arranger_v1_sid1/arranger_v2_sid1,Y to get pat_num for each voice; looks up pat_base via pat_base_lo,X (lo) / pat_base_hi,X (hi); writes V0 base → $02/$03, V1 base → $FD/$FE, V2 base → $9E/$9F.
;
;   callers:             23 code sites: $8882, $8A0B, $8B8D, $8D0F, $8E91, $9013, $9195, $9317, +15 more
;   inputs:              Y = arranger row index. sid_chip_view selects SID#1 vs SID#2 view.
;   outputs:             $02/$03 = V0 pat_base, $FD/$FE = V1 pat_base, $9E/$9F = V2 pat_base.
;   registers clobbered: A, X
;
;   SID#2 (sid_chip_view=1) branch at pat_base_resolve_v012 handles the parallel SID#2 arranger lookup. return. 23 callers in static image — the most-JSR'd target in player_helper_band-seqED_paint_band_padding. Used as the entry-point setup for any code that needs to read all three voice patterns at an arranger row simultaneously (e.g. screen paint, playback advance, save-encoder).
pat_base_resolve_v012 .block
                           lda  sid_chip_view    ; $AA02
                           bne  l_1    ; $AA05  sid_chip_view was not SID_VIEW_1?
                           ldx  arranger_v0_sid1,y    ; $AA07
                           lda  pat_base_lo,x    ; $AA0A
                           sta  zp_ptr1_lo    ; $AA0D
                           lda  pat_base_hi,x    ; $AA0F
                           sta  zp_ptr1_hi    ; $AA12
                           ldx  arranger_v1_sid1,y    ; $AA14
                           lda  pat_base_lo,x    ; $AA17
                           sta  zp_decoder_dest_lo    ; $AA1A
                           lda  pat_base_hi,x    ; $AA1C
                           sta  zp_decoder_dest_hi    ; $AA1F
                           ldx  arranger_v2_sid1,y    ; $AA21
                           lda  pat_base_lo,x    ; $AA24
                           sta  zp_scratch_9e    ; $AA27
                           lda  pat_base_hi,x    ; $AA29
                           sta  zp_scratch_9f    ; $AA2C
                           rts    ; $AA2E
l_1:                       ldx  arranger_v3_sid2,y    ; $AA2F
                           lda  pat_base_lo,x    ; $AA32
                           sta  zp_ptr1_lo    ; $AA35
                           lda  pat_base_hi,x    ; $AA37
                           sta  zp_ptr1_hi    ; $AA3A
                           ldx  arranger_v4_sid2,y    ; $AA3C
