; ──────────────────────────────────────────────────────────────────────
; $AE78  seqED_handler
; ──────────────────────────────────────────────────────────────────────
; seqED handler (mode ui_mode=UI_MODE_SEQED).
;
;   callers:             1 code sites: $094A
;   inputs:              A
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Same shape as sidTAB: X←kbd_modifiers / Y←kbd_decoded_key / call seqED_dispatch dispatch / return.
seqED_handler .block
                           inc  editor_row_delta    ; $AE78
                           ldx  kbd_modifiers    ; $AE7B
                           ldy  kbd_decoded_key    ; $AE7E
                           jsr  seqED_dispatch    ; $AE81
                           rts    ; $AE84
.bend

; ──────────────────────────────────────────────────────────────────────
; $AE85  seqED_dispatch
; ──────────────────────────────────────────────────────────────────────
; seqED dispatch entry.
;
;   callers:             seqED_handler
;   inputs:              X = kbd_modifiers, Y = kbd_decoded_key
;   registers clobbered: A, X, Y
;
;   compare X=$00 (no modifier) / bne → seqED_clear_arm ctrl/cbm/shift dispatch; else cascade through bare-key arms (CRSR keys, note-keys, SPACE clear-advance, INSTDEL clear, etc.).
seqED_dispatch .block
                           cpx  #$00    ; $AE85
                           beq  l_1    ; $AE87  kbd_modifiers was $00?
                           jmp  seqED_clear_arm.l_5    ; $AE89
l_1:                       cpy  #KEY_CRSRUD    ; $AE8C
                           bne  seqED_CRSRUD_bare_arm.l_1    ; $AE8E  kbd_decoded_key was not KEY_CRSRUD?
.bend

; ──────────────────────────────────────────────────────────────────────
; $AE90  seqED_CRSRUD_bare_arm
; ──────────────────────────────────────────────────────────────────────
; seqED CRSRUD bare-arm dispatch — compare Y=$6F (CRSRUD keycode) → →next-arm when nonzero / jump note_arm_auto_writer (full cursor-walk via seqED_cursor_walk_dispatcher).
;
;   code edges:          fall-through from $AE8E in seqED_dispatch_1 (2 bytes earlier)
;
;   Not a separate function — this is the per-key arm inside seqED_dispatch seqED_dispatch_entry; the 1-byte fall-through pattern is the standard seqED bare-arm shape. See seqED_dispatch / note_arm_auto_writer.
seqED_CRSRUD_bare_arm .block
                           jmp  note_arm_auto_writer    ; $AE90
l_1:                       cpy  #KEY_CRSRLR    ; $AE93
                           bne  l_2    ; $AE95  Y was not $6A?
                           jmp  seqED_cursor_step_up_bare.l_1    ; $AE97
l_2:                       cpy  #KEY_LEFTARROW    ; $AE9A
                           bne  l_4    ; $AE9C  Y was not $1F?
l_3:                       lda  #$04    ; $AE9E
                           jsr  mode_transition_wrapper    ; $AEA0
                           jmp  super_cmd_page_commit.l_39    ; $AEA3
l_4:                       cpy  #KEY_STOP    ; $AEA6
                           bne  l_5    ; $AEA8  Y was not $93?
                           lda  #$02    ; $AEAA
                           jmp  mode_transition_wrapper    ; $AEAC
l_5:                       cpy  #KEY_CRSRLR    ; $AEAF
                           bcs  seqED_note_arm.l_1    ; $AEB1  Y was $6A or above?
.bend

; ──────────────────────────────────────────────────────────────────────
; $AEB3  seqED_note_arm
; ──────────────────────────────────────────────────────────────────────
; seqED note-key arm.
;
;   inputs:              Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   code edges:          fall-through from $AEB1 in seqED_CRSRUD_bare_arm_5 (2 bytes earlier)
;
;   Looks up the keycap pitch in key_pitch_lut (note keys carry the raw pitch; non-note keys are tagged with bit 7 set and exit immediately). For note keys: adds the current octave offset, dispatches to writer_note via field_writer_dispatcher (X/Y = lo/hi of writer_note), then jumps into seqED_auto_advance to roll the cursor.
seqED_note_arm .block
                           lda  key_pitch_lut,y    ; $AEB3
                           bmi  l_1    ; $AEB6  key_pitch_lut,Y had bit 7 set?
                           clc    ; $AEB8
                           adc  octave_offset    ; $AEB9
                           ldx  #$DF    ; $AEBC
                           ldy  #$B3    ; $AEBE
                           jsr  field_writer_dispatcher    ; $AEC0
                           jmp  seqED_auto_advance    ; $AEC3
l_1:                       cpy  #$20    ; $AEC6
                           bne  seqED_clear_advance_arm.l_1    ; $AEC8  Y was not $20?
.bend

; ──────────────────────────────────────────────────────────────────────
; $AECA  seqED_clear_advance_arm
; ──────────────────────────────────────────────────────────────────────
; seqED clear-and-advance arm (SPACE, $20).
;
;   inputs:              A
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   code edges:          fall-through from $AEC8 in seqED_note_arm_1 (2 bytes earlier)
;
;   Dispatches writer_clear_note via field_writer_dispatcher, then advances the cursor via seqED_auto_advance.
seqED_clear_advance_arm .block
                           ldx  #$F6    ; $AECA
                           ldy  #$B3    ; $AECC
                           jsr  field_writer_dispatcher    ; $AECE
                           jmp  seqED_auto_advance    ; $AED1
l_1:                       cpy  #KEY_INSTDEL    ; $AED4
