                           ldy  #$B4    ; $AEE5
                           jmp  field_writer_dispatcher    ; $AEE7
l_2:                       cpy  #KEY_COMMA    ; $AEEA
                           bne  l_3    ; $AEEC  kbd_decoded_key was not KEY_COMMA?
                           ldx  #$D7    ; $AEEE
