                           jmp  field_writer_dispatcher    ; $AEF2
l_3:                       cpy  #KEY_RETURN    ; $AEF5
                           bne  l_4    ; $AEF7  kbd_decoded_key was not KEY_RETURN?
                           ldx  #$13    ; $AEF9
                           ldy  #$B4    ; $AEFB
                           jmp  field_writer_dispatcher    ; $AEFD
l_4:                       jmp  seqED_auto_advance_bare_return    ; $AF00
l_5:                       cpx  #KBD_MOD_CBM    ; $AF03
                           beq  l_6    ; $AF05  kbd_modifiers was KBD_MOD_CBM?
                           jmp  seqED_sidcall_arm.l_13    ; $AF07
l_6:                       cpy  #KEY_CRSRUD    ; $AF0A
                           bne  l_7    ; $AF0C  kbd_decoded_key was not KEY_CRSRUD?
