                           jmp  seqED_auto_advance_via_b2c3.l_1    ; $AF11
l_7:                       cpy  #KEY_A    ; $AF14
                           bcc  seqED_sidcall_arm.l_2    ; $AF16  kbd_decoded_key was below KEY_A?
                           cpy  #KEY_G    ; $AF18
                           bcs  seqED_sidcall_arm.l_2    ; $AF1A  kbd_decoded_key was KEY_G or above?
.bend

; ──────────────────────────────────────────────────────────────────────
