;   $B234) loads an immediate (lo, hi) and stores it into this JSR's
;   operand at $B252/$B253 before falling through to the shared tail at
;   $B241. The four targets are therefore statically fixed (the
;   immediates), not runtime data: the step_cursor up/down and inc/dec
;   handlers below.
;   Targets:
;     $B2C3  seqED_cursor_step_up_bare         [step_cursor up ($B21A arm)]
;     $B2BC  seqED_cursor_step_down_bare       [step_cursor down ($B20D arm)]
;     $B36B  step_cursor_inc_wrap              [step_cursor +1 mod $20 ($B227 arm)]
;     $B380  step_cursor_dec_wrap              [step_cursor -1 ($B234 arm)]
l_2:                       jsr  VEC_IRQ_HI    ; $B251
                           dec  auto_advance_repeat    ; $B254
                           bne  l_2    ; $B257  (auto_advance_repeat − 1) was non-zero?
                           dec  auto_advance_count    ; $B259
                           bne  l_1    ; $B25C  (auto_advance_count − 1) was non-zero?
l_3:                       jmp  post_write_paint_tail    ; $B25E
.bend

; ──────────────────────────────────────────────────────────────────────
; $B261  seqED_step_cursor_increment
; ──────────────────────────────────────────────────────────────────────
; seqED step-cursor increment.
;
;   callers:             10 code sites: $8165, $8885, $B0CA, $B0F0, $B107, $B11E, $B1E3, $B27D seqED_voice_selector_check, +2 more
;   inputs:              page_offset/page_pair_counter/step_cursor = current cursor state; page_offset = page boundary.
;   outputs:             page_offset advanced; editor_col_delta INCed unless we just crossed a page boundary.
;   registers clobbered: A, Y
;
;   Walks one step forward in the seqED visible window.
seqED_step_cursor_increment .block
;     read page_offset (cursor x_offset within step).
                           lda  page_offset    ; $B261
;     Y ← page_pair_counter (page index).
                           ldy  page_pair_counter    ; $B264
;     clear-carry / A += step_cursor (step stride from caller).
                           clc    ; $B267
                           adc  step_cursor    ; $B268
;     compare = $20 → →skip when no-carry.
                           cmp  #$20    ; $B26B
                           bcc  l_1    ; $B26D  A was below $20?
;     increment Y (wrap to next page) / compare Y = page_offset (page limit) / →skip when zero-inc.
                           iny    ; $B26F
l_1:                       cpy  super_cmd_state_71d0    ; $B270
                           beq  l_2    ; $B273  page_pair_counter was super_cmd_state_71d0?
;     increment editor_col_delta (arranger row counter — only increment when we did not wrap at the page boundary).
                           inc  editor_col_delta    ; $B275
;     A ← Y / write page_offset / return.
l_2:                       tya    ; $B278
                           sta  super_cmd_state_71d0    ; $B279
                           rts    ; $B27C
.bend

; ──────────────────────────────────────────────────────────────────────
; $B27D  seqED_voice_selector_check
; ──────────────────────────────────────────────────────────────────────
; seqED voice-selector arm.
;
;   callers:             2 code sites: $84D7, $B646
;   outputs:             A, X, Y
;   registers clobbered: A, X, Y
;
;   Reads voice_selector, saves it, checks sid_chip_view; when SID#1: indexes arranger_v0/v1/v2_sid1 (arranger_v0_sid1/arranger_v1_sid1/arranger_v2_sid1). Resolves pat_num for the current voice and writes back to a temp slot used by the writer dispatch.
seqED_voice_selector_check .block
                           jsr  seqED_step_cursor_increment    ; $B27D
                           tax    ; $B280
                           lda  voice_selector    ; $B281
                           pha    ; $B284
                           lda  sid_chip_view    ; $B285
                           bne  l_4    ; $B288  sid_chip_view was not SID_VIEW_1?
                           pla    ; $B28A
                           cmp  #$09    ; $B28B
                           bcs  l_1    ; $B28D  voice_selector was $09 or above?
                           lda  arranger_v0_sid1,x    ; $B28F
                           jmp  l_3    ; $B292
l_1:                       cmp  #$12    ; $B295
                           bcs  l_2    ; $B297  voice_selector was $12 or above?
                           lda  arranger_v1_sid1,x    ; $B299
                           jmp  l_3    ; $B29C
l_2:                       lda  arranger_v2_sid1,x    ; $B29F
l_3:                       rts    ; $B2A2
l_4:                       pla    ; $B2A3
                           cmp  #$09    ; $B2A4
                           bcs  l_5    ; $B2A6  voice_selector was $09 or above?
                           lda  arranger_v3_sid2,x    ; $B2A8
                           jmp  l_3    ; $B2AB
l_5:                       cmp  #$12    ; $B2AE
                           bcs  l_6    ; $B2B0  voice_selector was $12 or above?
                           lda  arranger_v4_sid2,x    ; $B2B2
                           jmp  l_3    ; $B2B5
l_6:                       lda  arranger_v5_sid2,x    ; $B2B8
                           rts    ; $B2BB
.bend

; ──────────────────────────────────────────────────────────────────────
; $B2BC  note_arm_auto_writer
; ──────────────────────────────────────────────────────────────────────
; Note-arm auto-advance writer target — the call note_arm_auto_writer self-modded into auto_advance_loop_body by seqED_auto_advance.
;
;   callers:             1 code sites: $AE90 seqED_CRSRUD_bare_arm
;
;   X←$00 / Y←$01 / jump seqED_cursor_walk_dispatcher (the full cursor-walk dispatcher). Reached at runtime via the indirect call through auto_advance_loop_body's self-mod; also reachable directly via jump seqED_CRSRUD_bare_arm (the seqED entry-arm pre-advance that needs the walk without engaging auto_advance_loop_body's count-loop). Not a separate function — see seqED_auto_advance.
note_arm_auto_writer .block
                           ldx  #$00    ; $B2BC
                           ldy  #$01    ; $B2BE
                           jmp  seqED_cursor_walk_dispatcher    ; $B2C0
.bend

; ──────────────────────────────────────────────────────────────────────
; $B2C3  seqED_cursor_step_up_bare
; ──────────────────────────────────────────────────────────────────────
; seqED CRSRUD bare-arm — X-preload + cursor step.
;
;   callers:             seqED_cursor_step JMP (the CRSRUD branch of seqED_bare_arm seqED_cursor_step).
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   X←$00 / Y←$FF / jump seqED_cursor_walk_dispatcher (the full cursor-walk dispatcher that re-uses auto_advance_writer_smc_lo/auto_advance_writer_smc_hi self-mod slots). Walks the cursor one step upward (Y=$FF) without an active writer.
seqED_cursor_step_up_bare .block
                           ldx  #$00    ; $B2C3
                           ldy  #$FF    ; $B2C5
                           jmp  seqED_cursor_walk_dispatcher    ; $B2C7
l_1:                       lda  voice_selector    ; $B2CA
                           clc    ; $B2CD
                           adc  #$09    ; $B2CE
                           cmp  #$1D    ; $B2D0
                           bcs  post_write_paint_tail.l_1    ; $B2D2  A was $1D or above?
                           sta  voice_selector    ; $B2D4
                           inc  super_cmd_state_71cf    ; $B2D7
                           rts    ; $B2DA
.bend

; ──────────────────────────────────────────────────────────────────────
; $B2DB  seqED_CRSRLR_bare_arm
; ──────────────────────────────────────────────────────────────────────
; seqED CRSRLR bare-arm — decrement voice_selector by 9 (one full voice's worth of cursor columns).
;
;   callers:             seqED_cursor_wrap JMP (the CRSRLR branch of seqED_bare_arm seqED_cursor_step — see seqED_cursor_wrap).
;   registers clobbered: A
;
;   Subtract 9 from voice_selector; if that underflows the wrap exit returns without writing (cursor stays at column 0). On a successful step it decrements page_offset (the companion page index) so that the cursor and page counter stay in sync.
seqED_CRSRLR_bare_arm .block
                           lda  voice_selector    ; $B2DB
                           sec    ; $B2DE
                           sbc  #$09    ; $B2DF
                           bcc  l_1    ; $B2E1  (voice_selector − $09) shifted-out bit was 0?
                           sta  voice_selector    ; $B2E3
                           dec  super_cmd_state_71cf    ; $B2E6
l_1:                       rts    ; $B2E9
        .byte $01, $01, $02, $02, $04, $03, $03, $00, $00, $01, $01, $02, $02, $04, $03, $03    ; $B2EA
        .byte $00, $00, $01, $01, $02, $02, $04, $03, $03, $00, $00, $00, $00, $00    ; $B2FA
.bend

; ──────────────────────────────────────────────────────────────────────
; $B308  seqED_cursor_walk_dispatcher
; ──────────────────────────────────────────────────────────────────────
; Full cursor-walk dispatcher inside the seqED cursor-step band.
;
;   callers:             2 code sites: $B2C0, $B2C7
;
;   Setup:
;     - Y→cursor_walk_y_delta_smc (self-mod the loop's Y delta).
;     - read page_offset → cursor_walk_x_offset_smc (latch current x-offset).
;
;   Loop:
;     - A += step_cursor (step stride) → cursor_walk_x_offset_smc.
;     - A += page_offset / wrap on overflow → next page.
;     - commit back to page_offset / page_pair_counter.
;
;   Reached from note_arm_auto_writer jump (the CRSRUD bare-arm entry note_arm_auto_writer) and seqED_cursor_step_up_bare jump (the CRSRUD pre-loaded entry seqED_cursor_step_up_bare). Not a separate function — see seqED_cursor_step_up_bare.
seqED_cursor_walk_dispatcher .block
                           sty  cursor_walk_y_delta_smc    ; $B308
                           lda  page_offset    ; $B30B
                           sta  cursor_walk_x_offset_smc    ; $B30E
                           lda  cursor_walk_x_offset_smc    ; $B311
                           clc    ; $B314
                           adc  cursor_walk_y_delta_smc    ; $B315
                           sta  cursor_walk_x_offset_smc    ; $B318
                           clc    ; $B31B
                           adc  step_cursor    ; $B31C
                           ldy  page_pair_counter    ; $B31F
                           cmp  #$20    ; $B322
                           bcc  l_1    ; $B324  A was below $20?
                           iny    ; $B326
l_1:                       cpy  #$FF    ; $B327
                           bne  l_2    ; $B329  page_pair_counter was not $FF?
                           cmp  #$1F    ; $B32B
                           bne  l_2    ; $B32D  A was not $1F?
                           jsr  post_write_paint_tail.l_2    ; $B32F
l_2:                       lda  cursor_walk_x_offset_smc    ; $B332
                           cmp  #$08    ; $B335
                           bcc  post_write_paint_tail.l_4    ; $B337  cursor_walk_x_offset_smc was below $08?
                           cmp  #$09    ; $B339
                           bcs  post_write_paint_tail.l_2    ; $B33B  cursor_walk_x_offset_smc was $09 or above?
                           lda  cursor_walk_x_offset_smc    ; $B33D
                           sta  page_offset    ; $B340
                           jmp  post_write_paint_tail    ; $B343
        .byte $60, $00, $00    ; $B346
.bend

; ──────────────────────────────────────────────────────────────────────
; $B349  post_write_paint_tail
; ──────────────────────────────────────────────────────────────────────
; Post-write paint tail — shared by every seqED auto-advance flow.
;
;   callers:             8 code sites: $B092, $B1EB, $B1FD, $B25E auto_advance_loop_body_3, $B343, $B37D, $B393, $C077
;
;   call seqLIST_step_auto_advance (seqLIST step auto-advance / arranger-row counter bump) / A←UI_MODE_SIDTAB / write ui_mode_range_bound (cursor-redraw flag) / return. Reached from 8 jump sites in seqED arms and auto_advance_loop_body (auto_advance_loop_body's loop-done exit). Not a separate function — see seqED_auto_advance.
post_write_paint_tail .block
                           jsr  seqLIST_step_auto_advance    ; $B349
                           lda  #$04    ; $B34C
                           sta  cursor_redraw_flag    ; $B34E
                           rts    ; $B351
l_1:                       lda  page_offset    ; $B352
                           sec    ; $B355
                           sbc  #$00    ; $B356
                           sta  seqed_col_cursor    ; $B358
                           lda  #$00    ; $B35B
                           sta  seqlist_col_cursor    ; $B35D
                           inc  editor_row_delta    ; $B360
                           inc  editor_col_delta    ; $B363
                           lda  #$02    ; $B366
                           jmp  mode_transition_wrapper    ; $B368
l_2:                       lda  step_cursor    ; $B36B
                           clc    ; $B36E
                           adc  #$01    ; $B36F
                           cmp  #$20    ; $B371
                           bne  l_3    ; $B373  A was not $20?
                           inc  page_pair_counter    ; $B375
                           lda  #$00    ; $B378
l_3:                       sta  step_cursor    ; $B37A
                           jmp  post_write_paint_tail    ; $B37D
l_4:                       lda  step_cursor    ; $B380
                           sec    ; $B383
                           sbc  #$01    ; $B384
                           bcs  l_5    ; $B386  (step_cursor − $01) shifted-out bit was 1?
                           lda  page_pair_counter    ; $B388
                           dec  page_pair_counter    ; $B38B
                           lda  #$1F    ; $B38E
l_5:                       sta  step_cursor    ; $B390
                           jmp  post_write_paint_tail    ; $B393
.bend

; ──────────────────────────────────────────────────────────────────────
; $B396  writer_sidcall
; ──────────────────────────────────────────────────────────────────────
; writes a sidCALL nibble.
;
;   inputs:              ($02) = pattern step row base; A from caller = nibble value; kbd_modifiers selects slot 1 vs slot 2
;   outputs:             X
;   registers clobbered: A, X, Y
;
;   Reads kbd_modifiers; CBM-only → X=$01 (sidCALL1 slot, +1 byte offset); CBM+SHIFT → X=$02 (sidCALL2 slot, +2 byte offset). read ($02),y / ora octave_offset,X to merge new nibble with the cell's existing high nibble. Caller (seqED_sidcall_arm) increments digit_phase after the call to flip to the second nibble next time.
writer_sidcall .block
                           ldx  #$01    ; $B396
                           lda  kbd_modifiers    ; $B398
                           cmp  #KBD_MOD_CBM    ; $B39B
                           beq  l_1    ; $B39D  kbd_modifiers was KBD_MOD_CBM?
                           ldx  #$02    ; $B39F
l_1:                       ldy  #$00    ; $B3A1
                           lda  (zp_ptr1_lo),y    ; $B3A3
                           ora  voice_selector_lut_modifier_class,x    ; $B3A5
                           sta  (zp_ptr1_lo),y    ; $B3A8
                           txa    ; $B3AA
                           tay    ; $B3AB
                           lda  digit_phase    ; $B3AC
                           and  #$01    ; $B3AF
                           beq  l_2    ; $B3B1  (digit_phase & $01) was DIGIT_PHASE_HIGH?
                           lda  super_arg_count    ; $B3B3
                           sta  (zp_ptr1_lo),y    ; $B3B6
                           rts    ; $B3B8
l_2:                       lda  (zp_ptr1_lo),y    ; $B3B9
                           asl  a    ; $B3BB
                           asl  a    ; $B3BC
                           asl  a    ; $B3BD
                           asl  a    ; $B3BE
                           ora  super_arg_count    ; $B3BF
                           sta  (zp_ptr1_lo),y    ; $B3C2
                           sta  super_cmd_writer_arm_state    ; $B3C4
                           rts    ; $B3C7
.bend

; ──────────────────────────────────────────────────────────────────────
; $B3C8  writer_seqED_speed_or_value
; ──────────────────────────────────────────────────────────────────────
; Speed/value writer-arm dispatch (23 bytes).
;
;   registers clobbered: A, X, Y
;
;   code edges:          none
;   apparent (from data): $C70F in seqED_disk_key_lut
;
;   X←$01 / read kbd_modifiers / compare =KBD_MOD_CBM / beq +2 / X←$02 / Y←$00 / read octave_offset,X (look up the per-modifier value class) / write ($02),Y / return. Reached via indirect call through the field_writer_dispatcher field-writer dispatcher for the speed and similar single-byte writer arms.
writer_seqED_speed_or_value .block
                           ldx  #$01    ; $B3C8
                           lda  kbd_modifiers    ; $B3CA
                           cmp  #KBD_MOD_CBM    ; $B3CD
                           beq  l_1    ; $B3CF  kbd_modifiers was KBD_MOD_CBM?
                           ldx  #$02    ; $B3D1
l_1:                       ldy  #$00    ; $B3D3
                           lda  voice_selector_lut_modifier_class,x    ; $B3D5
                           eor  #$FF    ; $B3D8
                           and  (zp_ptr1_lo),y    ; $B3DA
                           sta  (zp_ptr1_lo),y    ; $B3DC
                           rts    ; $B3DE
.bend

; ──────────────────────────────────────────────────────────────────────
; $B3DF  writer_note
; ──────────────────────────────────────────────────────────────────────
; writes pattern note + sets GATE_N bit ($10) on the step flag.
;
;   inputs:              ($02) = pattern step row base; super_arg_count = note byte to write
;   registers clobbered: A, Y
;
;   ORs $10 into the flag byte at ($02),0 (sets the GATE_N bit so the note will play), then writes the staged note byte from super_arg_count into ($02),3.
;
;   Note row offset +3 = step's note byte per pattern_bank layout (flag, slot_a, slot_b, note). Bit 4 in flag = GATE_N = 'apply note'; ungated notes get zeroed by the player IRQ.
writer_note .block
                           ldy  #$00    ; $B3DF
                           lda  (zp_ptr1_lo),y    ; $B3E1
                           ora  #$10    ; $B3E3
                           sta  (zp_ptr1_lo),y    ; $B3E5
                           ldy  #$03    ; $B3E7
                           lda  super_arg_count    ; $B3E9
                           sta  (zp_ptr1_lo),y    ; $B3EC
                           clc    ; $B3EE
                           adc  super_cmd_state_71c9    ; $B3EF
                           sta  super_arg_count    ; $B3F2
                           rts    ; $B3F5
.bend

; ──────────────────────────────────────────────────────────────────────
; $B3F6  writer_clear_note
; ──────────────────────────────────────────────────────────────────────
; masks bit 4 (GATE_N) out of the step flag.
;
;   registers clobbered: A, Y
;
;   A←$EF / Y←$00 / and ($02),y / write ($02),y / return. Leaves the note byte at offset +3 intact (player just stops triggering it).
writer_clear_note .block
                           lda  #$EF    ; $B3F6
                           ldy  #$00    ; $B3F8
                           and  (zp_ptr1_lo),y    ; $B3FA
                           sta  (zp_ptr1_lo),y    ; $B3FC
                           rts    ; $B3FE
.bend

; ──────────────────────────────────────────────────────────────────────
; $B3FF  writer_speed
; ──────────────────────────────────────────────────────────────────────
; writes duration nibble (low 4 bits of the step flag).
;
;   registers clobbered: A, Y
;
;   Reads super_arg_count - 1 → self-modifies the immediate at writer_speed; then read ($02),y / A&=$F0 / ora #(stored nibble) / write ($02),y. Preserves the high-nibble GATE bits. The 'speed' name is legacy; the low 4 bits of the flag byte are the inter-event duration.
writer_speed .block
                           lda  super_arg_count    ; $B3FF
                           sec    ; $B402
                           sbc  #$01    ; $B403
                           sta  writer_speed + $10    ; $B405
                           ldy  #$00    ; $B408
                           lda  (zp_ptr1_lo),y    ; $B40A
                           and  #$F0    ; $B40C
                           ora  #$FF    ; $B40E  ; ← (SMC operand at $B40F, no name)
                           sta  (zp_ptr1_lo),y    ; $B410
                           rts    ; $B412
        .byte $AE, $C8, $71, $F0, $4A, $A5, $02, $29, $7F, $C9, $7C, $F0, $37, $A5, $02, $18    ; $B413
        .byte $69, $04, $85, $FD, $A5, $03, $85, $FE, $A9, $78, $38, $E5, $02, $29, $7F, $A8    ; $B423
        .byte $B1, $FD, $29, $8F, $91, $FD, $B1, $02, $29, $70, $11, $FD, $91, $FD, $C8, $B1    ; $B433
        .byte $02, $91, $FD, $C8, $B1, $02, $91, $FD, $C8, $B1, $02, $91, $FD, $98, $38, $E9    ; $B443
        .byte $07, $A8, $10, $DC, $A0, $00, $B1, $02, $29, $8F, $91, $02, $CA, $D0, $B6, $60    ; $B453
        .byte $AE, $C8, $71, $F0, $4F, $A5, $02, $29, $7F, $C9, $7C, $F0, $3C, $A5, $02, $18    ; $B463
        .byte $69, $04, $85, $FD, $A5, $03, $85, $FE, $A9, $7C, $38, $E5, $02, $29, $7F, $8D    ; $B473
        .byte $A9, $B4, $8D, $AD, $B4, $A0, $00, $B1, $02, $29, $8F, $91, $02, $B1, $FD, $29    ; $B483
        .byte $70, $11, $02, $91, $02, $C8, $B1, $FD, $91, $02, $C8, $B1, $FD, $91, $02, $C8    ; $B493
        .byte $B1, $FD, $91, $02, $C8, $C0, $FF, $D0, $DE, $A0, $FF, $B1, $02, $29, $8F, $91    ; $B4A3
        .byte $02, $CA, $D0, $B1, $60, $A9, $8F, $A0, $00, $31, $02, $91, $02, $60, $AE, $C8    ; $B4B3
        .byte $71, $F0, $10, $A0, $03, $B1, $02, $18, $69, $01, $C9, $78, $B0, $02, $91, $02    ; $B4C3
        .byte $CA, $D0, $F0, $60, $AE, $C8, $71, $F0, $0E, $A0, $03, $B1, $02, $38, $E9, $01    ; $B4D3
        .byte $30, $02, $91, $02, $CA, $D0, $F2, $60, $A0, $01, $AD, $41, $0E, $C9, $20, $F0    ; $B4E3
        .byte $02, $A0, $02, $AE, $C8, $71, $F0, $0A, $B1, $02, $18, $69, $01, $91, $02, $CA    ; $B4F3
        .byte $D0, $F6, $60, $A0, $01, $AD, $41, $0E, $C9, $20, $F0, $02, $A0, $02, $AE, $C8    ; $B503
        .byte $71, $F0, $0A, $B1, $02, $38, $E9, $01, $91, $02, $CA, $D0, $F6, $60, $A0, $01    ; $B513
        .byte $AD, $41, $0E, $C9, $20, $F0, $02, $A0, $02, $8C, $3D, $B5, $AE, $C8, $71, $F0    ; $B523
