                           beq  l_7    ; $BB8E  kbd_voice_mute_mirror,X was zero?
                           lda  #$A0    ; $BB90
                           jmp  l_8    ; $BB92
l_7:                       lda  #$D1    ; $BB95
l_8:                       sta  SCREEN_RAM_SIDTAB_GLYPH,x    ; $BB97
                           dex    ; $BB9A
                           bpl  l_6    ; $BB9B  $02 walked back 1 and had bit 7 clear?
                           jmp  l_13    ; $BB9D
l_9:                       ldx  #$02    ; $BBA0
l_10:                      lda  cursor_state_cluster,x    ; $BBA2
                           beq  l_11    ; $BBA5  cursor_state_cluster,X was zero?
                           lda  #$A0    ; $BBA7
                           jmp  l_12    ; $BBA9
l_11:                      lda  #$D1    ; $BBAC
l_12:                      sta  SCREEN_RAM_SIDTAB_GLYPH,x    ; $BBAE
                           dex    ; $BBB1
                           bpl  l_10    ; $BBB2  $02 walked back 1 and had bit 7 clear?
l_13:                      rts    ; $BBB4
.bend

; ──────────────────────────────────────────────────────────────────────
; $BBB5  sidTAB_handler
; ──────────────────────────────────────────────────────────────────────
; sidTAB handler (mode ui_mode=UI_MODE_SIDTAB).
;
;   callers:             1 code sites: $095E
;   inputs:              A
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   X←kbd_modifiers / Y←kbd_decoded_key, cascade dispatch on (mod, key) → call field_writer_dispatcher with writer (X,Y).
sidTAB_handler .block
                           inc  editor_aux_counter    ; $BBB5
                           ldx  kbd_modifiers    ; $BBB8
                           ldy  kbd_decoded_key    ; $BBBB
                           jsr  sidtab_cascade    ; $BBBE
                           rts    ; $BBC1
.bend

; ──────────────────────────────────────────────────────────────────────
; $BBC2  sidtab_cascade
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade entry.
;
;   callers:             1 code sites: $BBBE
;   inputs:              A, X, Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Branches on modifier byte X: no-mod (X=$00) takes the hex-letter arm; otherwise (any modifier) falls into the CBM/LSHIFT cascade. Reached from sidTAB_handler via jsr.
sidtab_cascade .block
                           cpx  #$00    ; $BBC2
                           beq  sidtab_cascade_nomod_hex_letter_arm    ; $BBC4  kbd_modifiers was $00?
                           jmp  sidtab_cascade_cbm_entry    ; $BBC6
.bend

; ──────────────────────────────────────────────────────────────────────
; $BBC9  sidtab_cascade_nomod_hex_letter_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade no-mod arm — A..F hex-letter range.
;
;   callers:             1 code sites: $BBC4
;   inputs:              A, Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Decoded keys Y=$01..$06 are letters A-F (per kbd_scancode_lut LUT); fall outside that range and the digit-arm at sidtab_cascade_nomod_hex_digit_arm handles 0-9 instead. On a hex-letter hit, biases Y by +9 to reach nibble values $0A..$0F, then dispatches via field_writer_dispatcher and advances the cursor right.
sidtab_cascade_nomod_hex_letter_arm .block
                           cpy  #KEY_A    ; $BBC9
                           bcc  sidtab_cascade_nomod_hex_digit_arm    ; $BBCB  kbd_decoded_key was below KEY_A?
                           cpy  #KEY_G    ; $BBCD
                           bcs  sidtab_cascade_nomod_hex_digit_arm    ; $BBCF  kbd_decoded_key was KEY_G or above?
                           tya    ; $BBD1
                           clc    ; $BBD2
                           adc  #$09    ; $BBD3
l_1:                       ldx  #$5F    ; $BBD5
                           ldy  #$C1    ; $BBD7
                           jsr  field_writer_dispatcher    ; $BBD9
                           jmp  chipview_step_right    ; $BBDC
.bend

; ──────────────────────────────────────────────────────────────────────
; $BBDF  sidtab_cascade_nomod_hex_digit_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade no-mod arm — hex digit 0..9.
;
;   callers:             2 code sites: $BBCB, $BBCF
;   inputs:              A, Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Decoded keys Y=$30..$39 are the hex digits '0'..'9'. Strips the top nibble (A &= $0F) to extract the digit value and shares the writer entry with the hex-letter arm at sidtab_cascade_nomod_hex_letter_arm.
sidtab_cascade_nomod_hex_digit_arm .block
                           cpy  #KEY_0    ; $BBDF
                           bcc  sidtab_cascade_nomod_instdel_arm    ; $BBE1  kbd_decoded_key was below KEY_0?
                           cpy  #KEY_POUND    ; $BBE3
                           bcs  sidtab_cascade_nomod_instdel_arm    ; $BBE5  kbd_decoded_key was KEY_POUND or above?
                           tya    ; $BBE7
                           and  #$0F    ; $BBE8
                           jmp  sidtab_cascade_nomod_hex_letter_arm.l_1    ; $BBEA
.bend

; ──────────────────────────────────────────────────────────────────────
; $BBED  sidtab_cascade_nomod_instdel_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade no-mod arm — bare INSTDEL key ($6F → jump chipview_step_down chip-view DOWN).
;
;   callers:             2 code sites: $BBE1, $BBE5
;   inputs:              A, Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Decoded $6F per kbd_scancode_lut LUT row-0 bit-0.
sidtab_cascade_nomod_instdel_arm .block
                           cpy  #KEY_CRSRUD    ; $BBED
                           bne  sidtab_cascade_nomod_f3_arm    ; $BBEF  kbd_decoded_key was not KEY_CRSRUD?
                           jmp  chipview_step_down    ; $BBF1
.bend

; ──────────────────────────────────────────────────────────────────────
; $BBF4  sidtab_cascade_nomod_f3_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade no-mod arm — bare F3 key ($6A → jump chipview_step_right chip-view RIGHT).
;
;   callers:             1 code sites: $BBEF
;   inputs:              A, Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Decoded $6A per kbd_scancode_lut row-0 bit-5.
sidtab_cascade_nomod_f3_arm .block
                           cpy  #KEY_CRSRLR    ; $BBF4
                           bne  sidtab_cascade_nomod_leftarrow_arm    ; $BBF6  kbd_decoded_key was not KEY_CRSRLR?
                           jmp  chipview_step_right    ; $BBF8
.bend

; ──────────────────────────────────────────────────────────────────────
; $BBFB  sidtab_cascade_nomod_leftarrow_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade no-mod arm — bare LEFTARROW ($1F → read ui_mode_prev / call mode_transition_wrapper / jump vic_sprite_init: exit sidTAB to prior mode).
;
;   callers:             1 code sites: $BBF6
;   inputs:              A, Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
sidtab_cascade_nomod_leftarrow_arm .block
                           cpy  #KEY_LEFTARROW    ; $BBFB
                           bne  sidtab_cascade_nomod_space_arm    ; $BBFD  kbd_decoded_key was not KEY_LEFTARROW?
                           lda  ui_mode_prev    ; $BBFF
.bend

; ──────────────────────────────────────────────────────────────────────
; $BC02  sidtab_cascade_nomod_entry
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade entry point (compare X=$00 no-mod arm).
;
;   code edges:          fall-through from $BBFF in sidtab_cascade_nomod_leftarrow_arm (3 bytes earlier)
;
;   Reached from sidTAB_handler sidTAB dispatcher's first modifier branch. The cascade body below (sidtab_cascade_nomod_space_arm-sidtab_cascade_nomod_slash_arm) handles bare-key arms (SPACE/PERIOD/COMMA/etc.); higher-modifier branches at sidtab_cascade_cbm_entry (CBM) / sidtab_cascade_lshift_entry (LSHIFT) / sidtab_cascade_cbmlshift_entry (CBM+LSHIFT) / sidtab_cascade_ctrl_entry (CTRL) / sidtab_cascade_ctrl_lshift_entry (CTRL+LSHIFT).
sidtab_cascade_nomod_entry .block
                           jsr  mode_transition_wrapper    ; $BC02
                           jmp  vic_sprite_init    ; $BC05
.bend

; ──────────────────────────────────────────────────────────────────────
; $BC08  sidtab_cascade_nomod_space_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade no-mod arm — bare SPACE ($20 → writer C199 with X=$99 Y=$C1, then chip-view RIGHT).
;
;   callers:             1 code sites: $BBFD
;   inputs:              A, Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
sidtab_cascade_nomod_space_arm .block
                           cpy  #KEY_SPACE    ; $BC08
                           bne  sidtab_cascade_nomod_period_arm    ; $BC0A  kbd_decoded_key was not KEY_SPACE?
                           ldx  #$99    ; $BC0C
                           ldy  #$C1    ; $BC0E
                           jsr  field_writer_dispatcher    ; $BC10
                           jmp  chipview_step_right    ; $BC13
.bend

; ──────────────────────────────────────────────────────────────────────
; $BC16  sidtab_cascade_nomod_period_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade no-mod arm — bare PERIOD ($2E → writer C1AB with X=$AB Y=$C1).
;
;   callers:             1 code sites: $BC0A
;   inputs:              A, Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
sidtab_cascade_nomod_period_arm .block
                           cpy  #KEY_PERIOD    ; $BC16
                           bne  sidtab_cascade_nomod_comma_arm    ; $BC18  kbd_decoded_key was not KEY_PERIOD?
                           ldx  #$AB    ; $BC1A
                           ldy  #$C1    ; $BC1C
                           jmp  field_writer_dispatcher    ; $BC1E
.bend

; ──────────────────────────────────────────────────────────────────────
; $BC21  sidtab_cascade_nomod_comma_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade no-mod arm — bare COMMA ($2C → writer C1CE with X=$CE Y=$C1).
;
;   callers:             1 code sites: $BC18
;   inputs:              A, Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
sidtab_cascade_nomod_comma_arm .block
                           cpy  #KEY_COMMA    ; $BC21
                           bne  sidtab_cascade_nomod_f5_arm    ; $BC23  kbd_decoded_key was not KEY_COMMA?
                           ldx  #$CE    ; $BC25
                           ldy  #$C1    ; $BC27
                           jmp  field_writer_dispatcher    ; $BC29
.bend

; ──────────────────────────────────────────────────────────────────────
; $BC2C  sidtab_cascade_nomod_f5_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade no-mod arm — bare F5 key ($92 → set writer_sidtab_supercmd=$F0, writer C211 with X=$11 Y=$C2).
;
;   callers:             1 code sites: $BC23
;   inputs:              A, Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Decoded $92 = F5 via kbd_scancode_lut.
sidtab_cascade_nomod_f5_arm .block
                           cpy  #KEY_RETURN    ; $BC2C
                           bne  sidtab_cascade_nomod_clrhome_arm    ; $BC2E  kbd_decoded_key was not KEY_RETURN?
                           lda  #$F0    ; $BC30
                           sta  writer_sidtab_supercmd.l_6    ; $BC32
                           ldx  #$11    ; $BC35
                           ldy  #$C2    ; $BC37
                           jmp  field_writer_dispatcher    ; $BC39
.bend

; ──────────────────────────────────────────────────────────────────────
; $BC3C  sidtab_cascade_nomod_clrhome_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade no-mod arm — bare CLR/HOME ($93 → A←$02 / call mode_transition_wrapper / jump vic_sprite_init: exit to seqLIST).
;
;   callers:             1 code sites: $BC2E
;   inputs:              A, Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
sidtab_cascade_nomod_clrhome_arm .block
                           cpy  #KEY_STOP    ; $BC3C
                           bne  sidtab_cascade_nomod_slash_arm    ; $BC3E  kbd_decoded_key was not KEY_STOP?
                           lda  #$02    ; $BC40
                           jsr  mode_transition_wrapper    ; $BC42
                           jmp  vic_sprite_init    ; $BC45
.bend

; ──────────────────────────────────────────────────────────────────────
; $BC48  sidtab_cascade_nomod_slash_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade no-mod arm — bare SLASH ($2F → writer C146 with X=$46 Y=$C1 = sidTAB toggle).
;
;   callers:             1 code sites: $BC3E
;   inputs:              A, Y
;   registers clobbered: A, X, Y
sidtab_cascade_nomod_slash_arm .block
                           cpy  #KEY_SLASH    ; $BC48
                           bne  l_1    ; $BC4A  kbd_decoded_key was not KEY_SLASH?
                           ldx  #$46    ; $BC4C
                           ldy  #$C1    ; $BC4E
                           jmp  field_writer_dispatcher    ; $BC50
l_1:                       jmp  sidtab_dispatch_bare_return    ; $BC53
.bend

; ──────────────────────────────────────────────────────────────────────
; $BC56  sidtab_cascade_cbm_entry
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade CBM entry (compare X=$20).
;
;   callers:             1 code sites: $BBC6
;   inputs:              X, Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   kbd_modifiers modifier KBD_MOD_CBM = CBM (per modifier_extract). Mirrors sidtab_cascade_nomod_hex_letter_arm's no-mod shape but selects CBM-modified writer targets.
sidtab_cascade_cbm_entry .block
                           cpx  #KBD_MOD_CBM    ; $BC56
                           bne  sidtab_cascade_lshift_entry    ; $BC58  kbd_modifiers was not KBD_MOD_CBM?
                           cpy  #KEY_A    ; $BC5A
                           bcc  sidtab_cascade_cbm_hex_digit_arm    ; $BC5C  kbd_decoded_key was below KEY_A?
                           cpy  #KEY_G    ; $BC5E
                           bcs  sidtab_cascade_cbm_hex_digit_arm    ; $BC60  kbd_decoded_key was KEY_G or above?
                           tya    ; $BC62
                           clc    ; $BC63
                           adc  #$09    ; $BC64
l_1:                       ldx  #$5F    ; $BC66
                           ldy  #$C1    ; $BC68
                           jsr  field_writer_dispatcher    ; $BC6A
                           jmp  chipview_step_down    ; $BC6D
.bend

; ──────────────────────────────────────────────────────────────────────
; $BC70  sidtab_cascade_cbm_hex_digit_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade CBM arm — hex digit range ($30-$39).
;
;   callers:             2 code sites: $BC5C, $BC60
;   inputs:              Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   A&=$0F → jump sidtab_cascade_cbm_entry (writer X=$5F Y=$C1, post-jump chipview_step_down chip-view DOWN).
sidtab_cascade_cbm_hex_digit_arm .block
                           cpy  #KEY_0    ; $BC70
                           bcc  sidtab_cascade_cbm_instdel_arm    ; $BC72  kbd_decoded_key was below KEY_0?
                           cpy  #KEY_POUND    ; $BC74
                           bcs  sidtab_cascade_cbm_instdel_arm    ; $BC76  kbd_decoded_key was KEY_POUND or above?
                           tya    ; $BC78
                           and  #$0F    ; $BC79
                           jmp  sidtab_cascade_cbm_entry.l_1    ; $BC7B
.bend

; ──────────────────────────────────────────────────────────────────────
; $BC7E  sidtab_cascade_cbm_instdel_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade CBM arm — CBM+INSTDEL ($6F → jump cursor_redraw_request sidtab_scroll +1 + cursor redraw).
;
;   callers:             2 code sites: $BC72, $BC76
;   inputs:              Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
sidtab_cascade_cbm_instdel_arm .block
                           cpy  #KEY_CRSRUD    ; $BC7E
                           bne  sidtab_cascade_cbm_space_arm    ; $BC80  kbd_decoded_key was not KEY_CRSRUD?
                           jmp  cursor_redraw_request.l_1    ; $BC82
.bend

; ──────────────────────────────────────────────────────────────────────
; $BC85  sidtab_cascade_cbm_space_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade CBM arm — CBM+SPACE ($20 → writer C199 with X=$99 Y=$C1, post-write chip-view DOWN).
;
;   callers:             1 code sites: $BC80
;   inputs:              Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
sidtab_cascade_cbm_space_arm .block
                           cpy  #KEY_SPACE    ; $BC85
                           bne  sidtab_cascade_cbm_leftarrow_arm    ; $BC87  kbd_decoded_key was not KEY_SPACE?
                           ldx  #$99    ; $BC89
                           ldy  #$C1    ; $BC8B
                           jsr  field_writer_dispatcher    ; $BC8D
                           jmp  chipview_step_down    ; $BC90
.bend

; ──────────────────────────────────────────────────────────────────────
; $BC93  sidtab_cascade_cbm_leftarrow_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade CBM arm — CBM+LEFTARROW ($1F → A←$01 / call mode_transition_wrapper / jump vic_sprite_init: exit to seqED).
;
;   callers:             1 code sites: $BC87
;   inputs:              Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
sidtab_cascade_cbm_leftarrow_arm .block
                           cpy  #KEY_LEFTARROW    ; $BC93
                           bne  sidtab_cascade_cbm_f5_arm    ; $BC95  kbd_decoded_key was not KEY_LEFTARROW?
l_1:                       lda  #$01    ; $BC97
                           jsr  mode_transition_wrapper    ; $BC99
                           jmp  vic_sprite_init    ; $BC9C
.bend

; ──────────────────────────────────────────────────────────────────────
; $BC9F  sidtab_cascade_cbm_f5_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade CBM arm — CBM+F5 ($92 → writer C36A with X=$6A Y=$C3 = JP/DL field writer).
;
;   callers:             1 code sites: $BC95
;   inputs:              Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
sidtab_cascade_cbm_f5_arm .block
                           cpy  #KEY_RETURN    ; $BC9F
                           bne  sidtab_cascade_cbm_slash_arm    ; $BCA1  kbd_decoded_key was not KEY_RETURN?
                           ldx  #$6A    ; $BCA3
                           ldy  #$C3    ; $BCA5
                           jmp  field_writer_dispatcher    ; $BCA7
.bend

; ──────────────────────────────────────────────────────────────────────
; $BCAA  sidtab_cascade_cbm_slash_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade CBM arm — CBM+SLASH ($2F → jump writer_sidtab_dec: ACID-column writer).
;
;   callers:             1 code sites: $BCA1
;   inputs:              Y
;   registers clobbered: A
sidtab_cascade_cbm_slash_arm .block
                           cpy  #KEY_SLASH    ; $BCAA
                           bne  l_1    ; $BCAC  kbd_decoded_key was not KEY_SLASH?
                           jmp  writer_sidtab_dec.l_3    ; $BCAE
l_1:                       jmp  sidtab_dispatch_bare_return    ; $BCB1
.bend

; ──────────────────────────────────────────────────────────────────────
; $BCB4  sidtab_cascade_lshift_entry
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade LSHIFT entry (compare X=$10).
;
;   callers:             1 code sites: $BC58
;   inputs:              X, Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   kbd_modifiers modifier KBD_MOD_SHIFT = LSHIFT per modifier_extract. Selects LSHIFT-modified writer targets; same range-then-key-cascade shape.
sidtab_cascade_lshift_entry .block
                           cpx  #KBD_MOD_SHIFT    ; $BCB4
                           beq  sidtab_cascade_lshift_hex_letter_arm    ; $BCB6  kbd_modifiers was KBD_MOD_SHIFT?
                           jmp  sidtab_cascade_cbmlshift_entry    ; $BCB8
.bend

; ──────────────────────────────────────────────────────────────────────
; $BCBB  sidtab_cascade_lshift_hex_letter_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade LSHIFT arm — A..F hex letter ($01-$06): tya+9 → writer X=$5F Y=$C1, then call sidTAB_shifted_helper (shifted-helper) + →test when negative to chain into chipview_step_left chip-view LEFT or fall to chipview_step_right RIGHT.
;
;   callers:             1 code sites: $BCB6
;   inputs:              Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
sidtab_cascade_lshift_hex_letter_arm .block
                           cpy  #KEY_A    ; $BCBB
                           bcc  sidtab_cascade_lshift_hex_digit_arm    ; $BCBD  kbd_decoded_key was below KEY_A?
                           cpy  #KEY_G    ; $BCBF
                           bcs  sidtab_cascade_lshift_hex_digit_arm    ; $BCC1  kbd_decoded_key was KEY_G or above?
                           tya    ; $BCC3
                           clc    ; $BCC4
                           adc  #$09    ; $BCC5
l_1:                       ldx  #$5F    ; $BCC7
                           ldy  #$C1    ; $BCC9
                           jsr  field_writer_dispatcher    ; $BCCB
                           jsr  sidTAB_shifted_helper    ; $BCCE
                           bmi  l_2    ; $BCD1  sidTAB_shifted_helper result had bit 7 set?
                           jmp  chipview_step_right    ; $BCD3
l_2:                       jsr  chipview_step_left    ; $BCD6
                           jmp  chipview_step_down    ; $BCD9
.bend

; ──────────────────────────────────────────────────────────────────────
; $BCDC  sidtab_cascade_lshift_hex_digit_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade LSHIFT arm — hex digit ($30-$39): A&=$0F → jump sidtab_cascade_lshift_hex_letter_arm (writer X=$5F Y=$C1).
;
;   callers:             2 code sites: $BCBD, $BCC1
;   inputs:              Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
sidtab_cascade_lshift_hex_digit_arm .block
                           cpy  #KEY_0    ; $BCDC
                           bcc  sidtab_cascade_lshift_instdel_arm    ; $BCDE  kbd_decoded_key was below KEY_0?
                           cpy  #KEY_POUND    ; $BCE0
                           bcs  sidtab_cascade_lshift_instdel_arm    ; $BCE2  kbd_decoded_key was KEY_POUND or above?
                           tya    ; $BCE4
                           and  #$0F    ; $BCE5
                           jmp  sidtab_cascade_lshift_hex_letter_arm.l_1    ; $BCE7
.bend

; ──────────────────────────────────────────────────────────────────────
; $BCEA  sidtab_cascade_lshift_instdel_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade LSHIFT arm — LSHIFT+INSTDEL ($6F → jump chipview_step_up chip-view UP).
;
;   callers:             2 code sites: $BCDE, $BCE2
;   inputs:              Y
;   outputs:             X, Y
;   registers clobbered: A, X, Y
sidtab_cascade_lshift_instdel_arm .block
                           cpy  #KEY_CRSRUD    ; $BCEA
                           bne  sidtab_cascade_lshift_f3_arm    ; $BCEC  kbd_decoded_key was not KEY_CRSRUD?
                           jmp  chipview_step_up    ; $BCEE
.bend

; ──────────────────────────────────────────────────────────────────────
; $BCF1  sidtab_cascade_lshift_f3_arm
; ──────────────────────────────────────────────────────────────────────
; sidTAB cascade LSHIFT arm — LSHIFT+F3 ($6A → jump chipview_step_left chip-view LEFT).
;
