l_2:                       ldy  #$01    ; $CA8F
                           lda  #$FF    ; $CA91  ; ← (SMC operand at $CA92, no name)
                           bpl  l_3    ; $CA93  sid2_row_advance_ldy_smc_$3E had bit 7 clear?
                           lda  VEC_IRQ_HI,y    ; $CA95
                           sta  sid2_cascade_v1_silence_counter    ; $CA98
