sid2_silence_latch_arm .block
;     A ← $FF.
                           lda  #$FF    ; $CB41  ; ← sid2_v1_sc1_counter
;     →sid2_v1_cascade_slot_triple when zero (never — A=$FF).
                           beq  l_1    ; $CB43  sid2_v1_sc1_counter was zero?
