                           dec  sid2_v1_sc1_counter    ; $CB47
;     jump sid2_cascade_inner_gate.
                           jmp  sid2_cascade_inner_gate    ; $CB4A
        .byte $00, $00, $00    ; $CB4D
l_1:                       ldy  #$FF    ; $CB50  ; ← sid2_cascade_v1_silence_counter
                           lda  song_position_arrays_hi,y    ; $CB52
                           bne  l_2    ; $CB55  song_position_arrays_hi,Y was non-zero?
                           lda  song_position_arrays_lo,y    ; $CB57
                           tay    ; $CB5A
                           lda  song_position_arrays_hi,y    ; $CB5B
l_2:                       sta  zp_sidtab_row_hi    ; $CB5E
                           lda  dl_per_step_counters,y    ; $CB60
                           sta  sid2_v1_sc1_counter    ; $CB63
                           lda  song_position_arrays_lo,y    ; $CB66
                           iny    ; $CB69
                           sty  sid2_cascade_v1_silence_counter    ; $CB6A
                           ldx  #$62    ; $CB6D
                           jsr  sid2_sidtab_row_apply    ; $CB6F
.bend

; ──────────────────────────────────────────────────────────────────────
; $CB72  sid2_cascade_inner_gate
; ──────────────────────────────────────────────────────────────────────
; Inner per-voice gate inside the SID#2 cascade tail at sid2_v1_cascade_slot_triple-sid2_voice_fanout_next_gate (the V0/V1/V2 fan-out that JSRs sid2_sidtab_row_apply sidtab_row_apply for each SID#2 voice).
;
;   callers:             2 code sites: $CB45, $CB4A
;
;   Same shape as sid2_silence_latch_path / sid2_silence_latch_arm — each SID#2 voice has its own gate slot. Not a separate function — see sid2_sidtab_row_apply / sid2_silence_latch_path.
sid2_cascade_inner_gate .block
;     A ← $FF.
                           lda  #$FF    ; $CB72  ; ← sid2_cascade_inner_gate_counter
;     →sid2_v2_cascade_slot_triple when zero (never).
                           beq  l_1    ; $CB74  sid2_cascade_inner_gate_counter was zero?
;     →sid2_voice_fanout_next_gate when negative (always — wraps to next-voice tail).
                           bmi  sid2_voice_fanout_next_gate    ; $CB76  sid2_cascade_inner_gate_counter had bit 7 set?
;     decrement sid2_cascade_inner_gate (self-mod counter byte).
                           dec  sid2_cascade_inner_gate_counter    ; $CB78
;     jump sid2_voice_fanout_next_gate.
                           jmp  sid2_voice_fanout_next_gate    ; $CB7B
        .byte $00, $00, $00    ; $CB7E
l_1:                       ldy  #$FF    ; $CB81  ; ← sid2_v2_sc2_counter
                           lda  song_position_arrays_hi,y    ; $CB83
                           bne  l_2    ; $CB86  song_position_arrays_hi,Y was non-zero?
                           lda  song_position_arrays_lo,y    ; $CB88
                           tay    ; $CB8B
                           lda  song_position_arrays_hi,y    ; $CB8C
l_2:                       sta  zp_sidtab_row_hi    ; $CB8F
                           lda  dl_per_step_counters,y    ; $CB91
                           sta  sid2_cascade_inner_gate_counter    ; $CB94
                           lda  song_position_arrays_lo,y    ; $CB97
                           iny    ; $CB9A
                           sty  sid2_v2_sc2_counter    ; $CB9B
                           ldx  #$00    ; $CB9E
                           jsr  sid2_sidtab_row_apply    ; $CBA0
.bend

; ──────────────────────────────────────────────────────────────────────
; $CBA3  sid2_voice_fanout_next_gate
; ──────────────────────────────────────────────────────────────────────
; Next SID#2 voice gate in the sid2_v1_cascade_slot_triple-sid2_v0_sc2_cascade_slot_triple fan-out — same shape as sid2_silence_latch_path / sid2_silence_latch_arm / sid2_cascade_inner_gate (A←$FF / →never when zero / →always-taken when negative / decrement self-mod counter / jmp).
