        .byte $00, $00, $00    ; $CBAF
l_1:                       ldy  #$FF    ; $CBB2  ; ← sid2_cascade_v0_sc2_silence_counter
                           lda  song_position_arrays_hi,y    ; $CBB4
                           bne  l_2    ; $CBB7  song_position_arrays_hi,Y was non-zero?
                           lda  song_position_arrays_lo,y    ; $CBB9
                           tay    ; $CBBC
                           lda  song_position_arrays_hi,y    ; $CBBD
l_2:                       sta  zp_sidtab_row_hi    ; $CBC0
                           lda  dl_per_step_counters,y    ; $CBC2
                           sta  sid2_v0_sc2_counter    ; $CBC5
                           lda  song_position_arrays_lo,y    ; $CBC8
                           iny    ; $CBCB
                           sty  sid2_cascade_v0_sc2_silence_counter    ; $CBCC
                           ldx  #$31    ; $CBCF
                           jsr  sid2_sidtab_row_apply    ; $CBD1
l_3:                       lda  #$FF    ; $CBD4  ; ← sid2_v1_sc2_counter
                           beq  l_4    ; $CBD6  sid2_v1_sc2_counter was zero?
                           bmi  l_6    ; $CBD8  sid2_v1_sc2_counter had bit 7 set?
                           dec  sid2_v1_sc2_counter    ; $CBDA
