        .byte $00, $00, $00    ; $CBE0
l_4:                       ldy  #$FF    ; $CBE3  ; ← sid2_cascade_v1_sc2_silence_counter
                           lda  song_position_arrays_hi,y    ; $CBE5
                           bne  l_5    ; $CBE8  song_position_arrays_hi,Y was non-zero?
                           lda  song_position_arrays_lo,y    ; $CBEA
                           tay    ; $CBED
