                           iny    ; $CBFC
                           sty  sid2_cascade_v1_sc2_silence_counter    ; $CBFD
                           ldx  #$62    ; $CC00
                           jsr  sid2_sidtab_row_apply    ; $CC02
l_6:                       ldx  #$62    ; $CC05
