; ──────────────────────────────────────────────────────────────────────
; $CC07  sid2_pitch_oscillator
; ──────────────────────────────────────────────────────────────────────
; SID#2 pitch_slide_oscillator — direct mirror of pitch_oscillator_voice_loop_body (the per-voice X-loop body of pitch_slide_oscillator).
;
;   callers:             sid2_pitch_oscillator_wrap_tail JMP (the SID#2 cascade re-dispatch loop tail).
;   inputs:              X
;   outputs:             A, X, Y
;   registers clobbered: A, X, Y
;
;   Per-voice dispatch on slide mode (sid2_subframe_forced_variant,X = SID#2 mirror of slide_mode_v0,X):
;     - == 0     → sid2_pitch_oscillator_post_tail (no-slide).
;     - $01..$7F → sid2_pitch_oscillator_post_tail (portamento).
;     - else (active slide):
;         asl A / Y←A / →sid2_pitch_oscillator when positive.
;         A -= slide_dec_lut_lo,Y (SUB path — SHARES the SID#1 slide-decrement LUT).
;         writes integrate into sid2_voice_record,X / sid2_subframe_forced_variant,X (SID#2 mirror of voice_record_v0/v0_slide_acc slide-accumulator).
;
;   jump sid2_pitch_oscillator_post_tail merges to the post-integration tail. Aliases SID#1's slide LUTs:
;     - slide_dec_lut_lo / pitch_lut_band / slide_dec_lut_hi / slide_inc_lut_hi
;     - note_pitch_lut_lo / note_pitch_lut_hi
;     - interval_lut_lo_a / interval_lut_lo_b / interval_lut_hi_a / interval_lut_hi_b
;
;   SID#2 doesn't get its own pitch LUTs because the table is large (576 B) and the pitch semantics are chip-identical.
sid2_pitch_oscillator .block
                           lda  sid2_v0_voice_record_slot_c,x    ; $CC07
                           beq  sid2_pitch_oscillator_post_tail.l_1    ; $CC0A  sid2_v0_voice_record_slot_c,X was zero?
                           bpl  sid2_pitch_oscillator_post_tail.l_2    ; $CC0C  sid2_v0_voice_record_slot_c,X had bit 7 clear?
                           asl  a    ; $CC0E
                           tay    ; $CC0F
                           bpl  l_1    ; $CC10  (sid2_v0_voice_record_slot_c,X << 1) had bit 7 clear?
                           lda  sid2_voice_record_v0,x    ; $CC12
                           sbc  slide_dec_lut_lo,y    ; $CC15
                           sta  sid2_voice_record_v0,x    ; $CC18
                           lda  sid2_v0_voice_record_slot_a,x    ; $CC1B
                           sbc  slide_dec_lut_hi,y    ; $CC1E
                           sta  sid2_v0_voice_record_slot_a,x    ; $CC21
                           jmp  sid2_pitch_oscillator_post_tail    ; $CC24
l_1:                       lda  pitch_lut_band,y    ; $CC27
                           clc    ; $CC2A
                           adc  sid2_voice_record_v0,x    ; $CC2B
                           sta  sid2_voice_record_v0,x    ; $CC2E
                           lda  slide_inc_lut_hi,y    ; $CC31
                           adc  sid2_v0_voice_record_slot_a,x    ; $CC34
                           sta  sid2_v0_voice_record_slot_a,x    ; $CC37
.bend

; ──────────────────────────────────────────────────────────────────────
; $CC3A  sid2_pitch_oscillator_post_tail
; ──────────────────────────────────────────────────────────────────────
; SID#2 pitch-oscillator post-integration tail — mirror of pitch_oscillator_voice_loop_body in SID#1.
