;   callers:             1 code sites: $CC24
;
;   clear-carry / Y←sid2_v2_cascade_slot_triple,X (SID#2 current-note mirror of current_note_v0,X) / read sid2_voice_record,X / A+=note_pitch_lut_lo,Y (note→pitch LUT lo — shared with SID#1) → sid2_register_write_body,X (SID#2 voice freq lo) / read note_pitch_lut_hi,Y (note→pitch LUT hi — shared) → sid2_register_write_body,X. Reached from sid2_pitch_oscillator jump inside sid2_pitch_oscillator. Not a separate function — see sid2_pitch_oscillator.
sid2_pitch_oscillator_post_tail .block
                           clc    ; $CC3A
                           ldy  sid2_cascade_inner_counter,x    ; $CC3B
                           lda  sid2_voice_record_v0,x    ; $CC3E
                           adc  note_pitch_lut_lo,y    ; $CC41
                           sta  sid2_v0_voice_record_slide_lo,x    ; $CC44
                           lda  note_pitch_lut_hi,y    ; $CC47
                           adc  sid2_v0_voice_record_slot_a,x    ; $CC4A
                           sta  sid2_v0_voice_record_slide_hi,x    ; $CC4D
                           jmp  sid2_cascade_step_dispatcher    ; $CC50
l_1:                       ldy  sid2_cascade_inner_counter,x    ; $CC53
                           lda  note_pitch_lut_lo,y    ; $CC56
                           clc    ; $CC59
                           adc  sid2_voice_record_v0.pitch_base,x    ; $CC5A
                           sta  sid2_v0_voice_record_slide_lo,x    ; $CC5D
                           lda  note_pitch_lut_hi,y    ; $CC60
                           sta  sid2_v0_voice_record_slide_hi,x    ; $CC63
                           jmp  sid2_cascade_step_dispatcher    ; $CC66
l_2:                       clc    ; $CC69
                           adc  sid2_cascade_inner_counter,x    ; $CC6A
                           tay    ; $CC6D
                           lda  interval_lut_lo_b,y    ; $CC6E
                           sec    ; $CC71
                           sbc  interval_lut_lo_a,y    ; $CC72
                           sta  sid2_pitch_oscillator_post_tail + $4F    ; $CC75
                           lda  interval_lut_hi_b,y    ; $CC78
                           sbc  interval_lut_hi_a,y    ; $CC7B
                           sta  sid2_pitch_oscillator_post_tail + $57    ; $CC7E
                           ldy  sid2_cascade_inner_counter,x    ; $CC81
                           lda  note_pitch_lut_lo,y    ; $CC84
                           clc    ; $CC87
                           adc  #$FF    ; $CC88  ; ← (SMC operand at $CC89, no name)
                           sta  sid2_v0_voice_record_slide_lo,x    ; $CC8A
                           lda  note_pitch_lut_hi,y    ; $CC8D
                           adc  #$FF    ; $CC90  ; ← (SMC operand at $CC91, no name)
                           sta  sid2_v0_voice_record_slide_hi,x    ; $CC92
.bend

; ──────────────────────────────────────────────────────────────────────
; $CC95  sid2_cascade_step_dispatcher
; ──────────────────────────────────────────────────────────────────────
; SID#2 per-voice cascade step-byte read & dispatcher.
;
;   callers:             2 code sites: $CC50, $CC66
;   inputs:              X
;   outputs:             A, X, Y
;   registers clobbered: A, X, Y
;
;   Per-voice dispatch on step-byte:
;     - Y ← sid2_subframe_forced_variant,X (per-voice step-byte slot — SID#2 mirror of SID#1's row_advance_band_end area).
;     - →sid2_pitch_pw_clamp_commit when zero (refetch — counter zero, advance to next row).
;     - →sid2_pitch_pw_clamp_commit when positive (hold — counter $01..$7F, decrement and stay).
;     - else (counter $80..$FF):
;         A ← Y / ANC #$7F / A += sid2_register_write_body,X / write sid2_register_write_body,X — accumulate step-byte (mod $80) into the per-voice step-accumulator slot.
;
;   Branches into the sid2_pitch_pw_clamp_commit arms that update sid2_subframe_forced_variant,X / sid2_register_write_body,X / sid2_register_write_body,X and jump sid2_cascade_dispatch_wrap_guard (cascade re-dispatch wrap). Mirror of the SID#1 step-dispatch at row_advance_band_end / v0_sc1_counter / v0_sc1_row_idx area.
;
;   sid2_subframe_forced_variant (step-byte), sid2_register_write_body (step-accum), sid2_register_write_body (row counter) are the SID#2 per-voice cascade state slots (per-voice offset by X = 0/8/16 for V3/V4/V5).
sid2_cascade_step_dispatcher .block
                           ldy  sid2_v0_voice_record_slot_b,x    ; $CC95
                           beq  sid2_cascade_dispatch_wrap_guard    ; $CC98  sid2_v0_voice_record_slot_b,X was zero?
                           bpl  sid2_pitch_pw_clamp_commit.l_3    ; $CC9A  sid2_v0_voice_record_slot_b,X had bit 7 clear?
                           tya    ; $CC9C
.bend

; ──────────────────────────────────────────────────────────────────────
; $CC9D  sid2_pitch_pw_clamp_commit
; ──────────────────────────────────────────────────────────────────────
; SID#2 PS-sweep clamp + commit (37 bytes, sid2_pitch_pw_clamp_commit).
;
;   inputs:              A, X
;   outputs:             A, X, Y
;   registers clobbered: A, X, Y
;
;   code edges:          fall-through from $CC9C in sid2_cascade_step_dispatcher (1 bytes earlier)
;
;   Body reads sid2_register_write_body,X (SID#2 PS slot), ANDs with #$7F, indexes sid2_cascade_inner_gate, writes back to sid2_register_write_body,X (SID#2 PW lo slot), and applies a sid2_voice_record_v2 overflow check. The PS-sweep counterpart of SID#1's clamp logic at the same offsets in the ps_sweep_entry-ps_sweep_tail band.
sid2_pitch_pw_clamp_commit .block
                           .byte $2B, $7F    ; $CC9D  ; anc #$7F (undocumented opcode $2B)
                           adc  sid2_v0_step_accumulator,x    ; $CC9F
                           sta  sid2_v0_step_accumulator,x    ; $CCA2
                           bcc  sid2_cascade_dispatch_wrap_guard    ; $CCA5  sid2_v0_step_accumulator no carry
                           lda  sid2_v0_voice_record_pw_slot,x    ; $CCA7
                           cmp  #$0F    ; $CCAA
                           beq  l_1    ; $CCAC  sid2_v0_voice_record_pw_slot,X was $0F?
                           inc  sid2_v0_voice_record_pw_slot,x    ; $CCAE
                           jmp  sid2_cascade_dispatch_wrap_guard    ; $CCB1
l_1:                       lda  #$F8    ; $CCB4
                           sta  sid2_v0_step_accumulator,x    ; $CCB6
                           tya    ; $CCB9
                           eor  #$80    ; $CCBA
                           sta  sid2_v0_voice_record_slot_b,x    ; $CCBC
                           jmp  sid2_cascade_dispatch_wrap_guard    ; $CCBF
l_2:                       lda  #$01    ; $CCC2
                           sta  sid2_v0_step_accumulator,x    ; $CCC4
                           tya    ; $CCC7
                           eor  #$80    ; $CCC8
                           sta  sid2_v0_voice_record_slot_b,x    ; $CCCA
                           jmp  sid2_cascade_dispatch_wrap_guard    ; $CCCD
l_3:                       lda  sid2_v0_step_accumulator,x    ; $CCD0
                           sbc  sid2_v0_voice_record_slot_b,x    ; $CCD3
                           sta  sid2_v0_step_accumulator,x    ; $CCD6
                           bcs  sid2_cascade_dispatch_wrap_guard    ; $CCD9  sid2_v0_voice_record_slot_b no borrow
                           lda  sid2_v0_voice_record_pw_slot,x    ; $CCDB
                           beq  l_2    ; $CCDE  sid2_v0_voice_record_pw_slot,X was zero?
                           dec  sid2_v0_voice_record_pw_slot,x    ; $CCE0
.bend

; ──────────────────────────────────────────────────────────────────────
; $CCE3  sid2_cascade_dispatch_wrap_guard
; ──────────────────────────────────────────────────────────────────────
; SID#2 cascade re-dispatch wrap guard.
;
;   callers:             6 code sites: $CC98, $CCA5, $CCB1, $CCBF, $CCCD, $CCD9
;   inputs:              X
;   outputs:             A, X
;   registers clobbered: A, X, Y
;
;   A←X / SBX #$31 (illegal opcode — X := (A & X) - $31 = X - $31, flags from result) / →sid2_pitch_oscillator_wrap_tail when negative (X was < $31 → return, end of cascade chain) / jump sid2_pitch_oscillator (X >= $31 → continue cascade with X reduced by $31). The $31 = 49 = #SID#2 cascade row-table size. Reached by 3 jump callers from the sid2_cascade_step_dispatcher dispatch arms (sid2_pitch_pw_clamp_commit) after they update per-voice cascade state slots. SBX is an undocumented 6502 opcode (CB imm). After TXA the accumulator equals X, so (A & X) = X, and SBX effectively does X := X - $31 + flag-set. Used here as a 'reduce X by $31 with underflow branch' primitive.
sid2_cascade_dispatch_wrap_guard .block
                           txa    ; $CCE3
.bend

; ──────────────────────────────────────────────────────────────────────
; $CCE4  sid2_pitch_oscillator_wrap_tail
; ──────────────────────────────────────────────────────────────────────
; SID#2 pitch oscillator wrap tail (10 bytes, sid2_pitch_oscillator_wrap_tail).
;
;   code edges:          fall-through from $CCE3 sid2_cascade_dispatch_wrap_guard (1 bytes earlier)
;
;   Reads the SID#2 stride/wrap state, branches back to sid2_pitch_oscillator if more voices to process. Companion to sid2_pitch_oscillator's body.
sid2_pitch_oscillator_wrap_tail .block
                           axs  #$31    ; $CCE4
                           bmi  l_1    ; $CCE6  X had bit 7 set?
                           jmp  sid2_pitch_oscillator    ; $CCE8
l_1:                       rts    ; $CCEB
        .byte $00, $00    ; $CCEC
.bend

; ──────────────────────────────────────────────────────────────────────
; $CCEE  sid2_player_init_body
; ──────────────────────────────────────────────────────────────────────
; SID#2 player_init body inside sid2_main_tick.
;
;   callers:             1 code sites: $CD44
;
;   Clears SID#2 state slots and installs SID#2 IRQ entry. Mirror of player_init_body for SID#2. Reached from sid2_main_tick call inside sid2_main_tick's startup sequence. Not a separate function — see sid2_main_tick.
sid2_player_init_body .block
;     push flags / IRQ-off.
                           php    ; $CCEE
                           sei    ; $CCEF
;     A ← $FC / compare VIC_RASTER / →(raster when nonzero) — sync to line $FC.
                           lda  #$FC    ; $CCF0
l_1:                       cmp  VIC_RASTER    ; $CCF2
                           bne  l_1    ; $CCF5  $FC was not VIC_RASTER?
;     A ← $FF / ...
                           lda  #$FF    ; $CCF7
                           sta  save_encoder_jp_chain_walker.decoder_state_d512    ; $CCF9  ; decoder_state_d512 := TRI+SAW+PUL+NOI GATE SYNC RING TEST
                           sta  sid2_alias_d50e    ; $CCFC
                           sta  save_encoder_jp_chain_walker.sid2_alias_d50f    ; $CCFF
                           lda  #$20    ; $CD02
                           sta  save_encoder_jp_chain_walker.decoder_state_d512    ; $CD04  ; decoder_state_d512 := SAW
                           lda  save_encoder_jp_chain_walker.l_3    ; $CD07
                           lsr  a    ; $CD0A
                           bcc  l_2    ; $CD0B  (save_encoder_jp_chain_walker_3 >> 1) shifted-out bit was 0?
                           lda  #$00    ; $CD0D
                           sta  sid2_v1_voice_record_slot_a    ; $CD0F
                           lda  #$0A    ; $CD12
                           bne  l_3    ; $CD14  sid2_player_init_body_$25 was non-zero?
l_2:                       lda  #$02    ; $CD16
                           sta  sid2_v1_voice_record_slot_a    ; $CD18
                           lda  #$EA    ; $CD1B
l_3:                       sta  sid2_register_write_body.l_10    ; $CD1D
                           plp    ; $CD20
                           rts    ; $CD21
.bend

; ──────────────────────────────────────────────────────────────────────
; $CD22  sid2_main_tick
; ──────────────────────────────────────────────────────────────────────
; SID#2 main_tick body — direct mirror of player_play SID#1 main_tick.
;
;   callers:             sid2_main_tick_entry JMP (the SID#2 main_tick entry — see sid2_main_tick_entry).
;   inputs:              A
;   outputs:             X
;   registers clobbered: A, X, Y
;
;   write sid2_base_default,Y / decrement Y / bpl — clears the 24 SID#2 voice/filter registers (sid2_base_default-save_encoder_jp_chain_walker).
;     - write sid2_voice_record_v2 / sid2_silence_latch_acc / sid2_voice_record_v2 (zero the SID#2 filter-cutoff accumulator + voice control slots).
;     - call sid2_player_init_body (SID#2 player_init).
;     - X←$62 / A←$00 / loop:
;         write sid2_v0_cascade_step_bytes,X / write sid2_v2_cascade_slot_triple,X (clear SID#2 cascade step-counter + row-idx tables).
;         decrement X / →loop when positive.
;
;   Mirror of player_init_body for chip #2.
sid2_main_tick .block
;     write sid2_voice_record_v2 (latch entry-A into SID#2 frame-state slot).
                           sta  sid2_frame_state_slot    ; $CD22
;     Y←$17 / A←$00 / loop: write sid2_base_default,Y / decrement Y / bpl — clears the 24 SID#2 voice/filter registers (sid2_base_default-save_encoder_jp_chain_walker).
                           ldy  #$17    ; $CD25
                           lda  #$00    ; $CD27
;     write sid2_voice_record_v2 / sid2_silence_latch_acc / sid2_voice_record_v2 (zero the SID#2 filter-cutoff accumulator + voice control slots).
l_1:                       sta  sid2_base_default,y    ; $CD29
                           dey    ; $CD2C
                           bpl  l_1    ; $CD2D  $17 walked back 1 and had bit 7 clear?
                           sta  sid2_frame_state_c8b6    ; $CD2F
                           sta  sid2_frame_state_c8be    ; $CD32
                           sta  sid2_voice_record_v2 + $3E    ; $CD35
                           sta  sid2_voice_record_v2 + $45    ; $CD38
                           sta  sid2_cascade_pre_counter    ; $CD3B
                           sta  sid2_silence_latch_acc    ; $CD3E
                           sta  sid2_voice_record_v2 + $34    ; $CD41
;     call sid2_player_init_body (SID#2 player_init).
                           jsr  sid2_player_init_body    ; $CD44
;     X←$62 / A←$00 / loop: write sid2_v0_cascade_step_bytes,X / write sid2_v2_cascade_slot_triple,X (clear SID#2 cascade step-counter + row-idx tables). decrement X / →loop when positive.
                           ldx  #$62    ; $CD47
l_2:                       lda  #$00    ; $CD49
                           sta  sid2_cascade_step_counter,x    ; $CD4B
                           sta  sid2_v2_sc2_counter,x    ; $CD4E
                           sta  sid2_v0_sid_patch_b,x    ; $CD51
                           sta  sid2_v0_sid_patch_a,x    ; $CD54
                           sta  sid2_v0_sid_patch_c,x    ; $CD57
                           sta  sid2_v0_sid_patch_d,x    ; $CD5A
                           sta  sid2_v0_voice_record_slot_c,x    ; $CD5D
                           sta  sid2_v0_voice_record_slot_b,x    ; $CD60
                           sta  sid2_cascade_inner_counter,x    ; $CD63
                           lda  #$FF    ; $CD66
                           sta  sid2_filter_slot_cae0,x    ; $CD68
                           sta  sid2_cascade_inner_gate_counter,x    ; $CD6B
.bend

; ──────────────────────────────────────────────────────────────────────
; $CD6E  sid2_player_init_tail
; ──────────────────────────────────────────────────────────────────────
; SID#2 player_init tail (10 bytes, sid2_player_init_tail) — reads the SID#2 stride byte and writes $80 to sid2_voice_record_v2 (SID#2 silence flag).
;
;   code edges:          fall-through from $CD6B in sid2_main_tick_2 (3 bytes earlier)
;
;   Companion to sid2_player_init_body.
sid2_player_init_tail .block
                           axs  #$31    ; $CD6E
                           bpl  sid2_main_tick.l_2    ; $CD70  X had bit 7 clear?
                           lda  #$80    ; $CD72
                           sta  sid2_v1_voice_record_slot_b    ; $CD74
                           rts    ; $CD77
.bend

; ──────────────────────────────────────────────────────────────────────
; $CD78  sid2_sidtab_row_apply
; ──────────────────────────────────────────────────────────────────────
; SID#2 sidtab_row_apply body (sister of sidtab_row_apply SID#1).
;
;   callers:             6 code sites: $CB0D, $CB3E, $CB6F, $CBA0, $CBD1, $CC02
;   inputs:              A, X
;   registers clobbered: A, X, Y
;
;   write $FB / Y←$00 / read ($FB),Y bitmap byte; shift stores left low/high split into ZP $96; bit-dispatched into per-field handlers at sid2_sidtab_row_apply+. Writes go to sid2_register_write_body+X (SID#2 staging mirror of current_note_v0 for current_note). Called 6× from the SID#2 cascade tail at sid2_v0_cascade_step_bytes/sid2_v0_cascade_slot_triple/sid2_v1_cascade_slot_triple/sid2_v2_cascade_slot_triple/sid2_v0_sc2_cascade_slot_triple/sid2_v1_sc2_cascade_slot_triple.
sid2_sidtab_row_apply .block
                           sta  zp_sidtab_row_lo    ; $CD78
                           ldy  #$00    ; $CD7A
                           lda  (zp_sidtab_row_lo),y    ; $CD7C
                           beq  l_8    ; $CD7E  (zp_sidtab_row_lo),Y was zero?
                           asl  a    ; $CD80
                           sta  zp_scratch_96    ; $CD81
                           bpl  l_1    ; $CD83  (zp_sidtab_row_lo),Y had bit 7 clear?
                           iny    ; $CD85
                           lda  (zp_sidtab_row_lo),y    ; $CD86
                           sta  sid2_v0_sid_patch_c,x    ; $CD88
l_1:                       bcc  l_2    ; $CD8B  (zp_sidtab_row_lo),Y shifted-out bit was 0?
                           iny    ; $CD8D
                           lda  (zp_sidtab_row_lo),y    ; $CD8E
                           sta  sid2_v0_sid_patch_d,x    ; $CD90
l_2:                       bit  zp_scratch_96    ; $CD93
                           bvc  l_3    ; $CD95  zp_scratch_96 had bit 6 clear?
                           iny    ; $CD97
                           lda  (zp_sidtab_row_lo),y    ; $CD98
                           sta  sid2_v0_sid_patch_b,x    ; $CD9A
l_3:                       lda  zp_scratch_96    ; $CD9D
                           and  #$20    ; $CD9F
                           beq  l_4    ; $CDA1  (zp_scratch_96 & $20) was zero?
                           iny    ; $CDA3
                           lda  (zp_sidtab_row_lo),y    ; $CDA4
                           sta  sid2_v0_sid_patch_a,x    ; $CDA6
l_4:                       lda  zp_scratch_96    ; $CDA9
                           and  #$10    ; $CDAB
                           beq  l_6    ; $CDAD  (zp_scratch_96 & $10) was zero?
                           iny    ; $CDAF
                           lda  (zp_sidtab_row_lo),y    ; $CDB0
                           bmi  l_5    ; $CDB2  (zp_sidtab_row_lo),Y had bit 7 set?
                           clc    ; $CDB4
                           adc  sid2_v2_sc2_step_counter,x    ; $CDB5
l_5:                       and  #$7F    ; $CDB8
                           sta  sid2_cascade_inner_counter,x    ; $CDBA
l_6:                       lda  zp_scratch_96    ; $CDBD
                           and  #$08    ; $CDBF
                           beq  l_7    ; $CDC1  (zp_scratch_96 & $08) was zero?
                           iny    ; $CDC3
                           lda  (zp_sidtab_row_lo),y    ; $CDC4
                           sta  sid2_v0_voice_record_slot_c,x    ; $CDC6
l_7:                       lda  zp_scratch_96    ; $CDC9
                           and  #$04    ; $CDCB
                           beq  l_8    ; $CDCD  (zp_scratch_96 & $04) was zero?
                           iny    ; $CDCF
                           lda  (zp_sidtab_row_lo),y    ; $CDD0
                           sta  sid2_v0_voice_record_pw_slot,x    ; $CDD2
                           and  #$F0    ; $CDD5
                           sta  sid2_v0_step_accumulator,x    ; $CDD7
l_8:                       iny    ; $CDDA
                           lda  (zp_sidtab_row_lo),y    ; $CDDB
                           beq  sid2_sidtab_ctrl_accumulator.l_4    ; $CDDD  (zp_sidtab_row_lo),Y was zero?
                           asl  a    ; $CDDF
                           sta  zp_scratch_96    ; $CDE0
                           bcc  l_9    ; $CDE2  (zp_sidtab_row_lo),Y shifted-out bit was 0?
                           iny    ; $CDE4
                           lda  (zp_sidtab_row_lo),y    ; $CDE5
                           sta  sid2_v0_voice_record_slot_b,x    ; $CDE7
l_9:                       lda  zp_scratch_96    ; $CDEA
                           beq  sid2_sidtab_ctrl_accumulator.l_4    ; $CDEC  zp_scratch_96 was zero?
                           and  #$80    ; $CDEE
                           beq  sid2_sidtab_ctrl_accumulator    ; $CDF0  (zp_scratch_96 & $80) was zero?
                           iny    ; $CDF2
                           lda  (zp_sidtab_row_lo),y    ; $CDF3
                           beq  l_10    ; $CDF5  (zp_sidtab_row_lo),Y was zero?
                           and  #$08    ; $CDF7
                           bne  l_11    ; $CDF9  ((zp_sidtab_row_lo),Y & $08) was non-zero?
                           lda  (zp_sidtab_row_lo),y    ; $CDFB
                           jmp  sid2_sidtab_row_apply_ctrl_write    ; $CDFD
l_10:                      lda  sid2_silence_latch_acc    ; $CE00
                           and  sid2_voice_record_v0.voice_bit_complement,x    ; $CE03
                           jmp  sid2_sidtab_row_apply_ctrl_write    ; $CE06
l_11:                      lda  sid2_silence_latch_acc    ; $CE09
                           and  #$0F    ; $CE0C
                           ora  (zp_sidtab_row_lo),y    ; $CE0E
                           ora  sid2_voice_record_v0.voice_bit_mask,x    ; $CE10
.bend

; ──────────────────────────────────────────────────────────────────────
; $CE13  sid2_sidtab_row_apply_ctrl_write
; ──────────────────────────────────────────────────────────────────────
; SID#2 sidtab_row_apply CTRL accumulator write.
;
;   callers:             2 code sites: $CDFD, $CE06
;   inputs:              A, Y
;   outputs:             X
;   registers clobbered: A, X, Y
;
;   Confluence point for SID#2's CTRL row-apply: three mutation modes (replace, AND-with-mask, OR-with-mask) all converge on the STA sid2_silence_latch_acc here. The two non-fall-through arms (single-source replace, AND-mask) jump in from sid2_sidtab_row_apply; the OR-mask fall-through arrives directly. sid2_silence_latch_acc is the single-byte CTRL combiner slot mirroring the equivalent area in SID#1's sidtab_row_apply body.
sid2_sidtab_row_apply_ctrl_write .block
                           sta  sid2_silence_latch_acc    ; $CE13
.bend

; ──────────────────────────────────────────────────────────────────────
; $CE16  sid2_sidtab_ctrl_accumulator
; ──────────────────────────────────────────────────────────────────────
; SID#2 sidtab_row_apply CTRL accumulator (71 bytes, sid2_sidtab_ctrl_accumulator).
;
;   callers:             1 code sites: $CDF0
;   inputs:              Y
;   outputs:             X
;   registers clobbered: A, X, Y
;
;   Y←$96 / beq +43 / A&=$40 / beq +6 / increment Y / read ($FB),Y / write sid2_voice_record_v2 / A←X / and … — CTRL-accumulator merge logic feeding the sid2_sidtab_row_apply_ctrl_write write sid2_silence_latch_acc write. Mirror of SID#1's sidtab_row_apply cascade CTRL handling.
sid2_sidtab_ctrl_accumulator .block
                           lax  zp_scratch_96    ; $CE16
                           beq  l_4    ; $CE18  zp_scratch_96 was zero?
                           and  #$40    ; $CE1A
                           beq  l_1    ; $CE1C  (zp_scratch_96 & $40) was zero?
                           iny    ; $CE1E
                           lda  (zp_sidtab_row_lo),y    ; $CE1F
                           sta  sid2_voice_record_v2 + $34    ; $CE21
l_1:                       txa    ; $CE24
                           and  #$20    ; $CE25
                           beq  l_2    ; $CE27  (zp_scratch_96 & $20) was zero?
                           iny    ; $CE29
                           lda  (zp_sidtab_row_lo),y    ; $CE2A
                           sta  sid2_cascade_pre_counter    ; $CE2C
l_2:                       txa    ; $CE2F
                           and  #$10    ; $CE30
                           beq  l_4    ; $CE32  (zp_scratch_96 & $10) was zero?
                           iny    ; $CE34
                           lax  (zp_sidtab_row_lo),y    ; $CE35
                           iny    ; $CE37
                           lda  (zp_sidtab_row_lo),y    ; $CE38
                           bmi  l_3    ; $CE3A  (zp_sidtab_row_lo),Y had bit 7 set?
                           stx  sid2_frame_state_c8b6    ; $CE3C
                           sta  sid2_frame_state_c8be    ; $CE3F
                           lda  #$00    ; $CE42
                           sta  sid2_voice_record_v2 + $3E    ; $CE44
                           sta  sid2_voice_record_v2 + $45    ; $CE47
                           rts    ; $CE4A
l_3:                       asl  a    ; $CE4B
                           bmi  sid2_self_modifier_setup    ; $CE4C  (zp_sidtab_row_lo),Y had bit 7 set?
                           stx  sid2_voice_record_v2 + $3E    ; $CE4E
                           lsr  a    ; $CE51
                           sta  sid2_voice_record_v2 + $45    ; $CE52
                           lda  #$69    ; $CE55
                           sta  sid2_register_write_body.l_6    ; $CE57
                           sta  sid2_register_write_body.l_7    ; $CE5A
l_4:                       rts    ; $CE5D
.bend

; ──────────────────────────────────────────────────────────────────────
; $CE5E  sid2_self_modifier_setup
; ──────────────────────────────────────────────────────────────────────
; Self-modifier-setup.
;
;   callers:             1 code sites: $CE4C
;   inputs:              A, X
;   registers clobbered: A
;
;   Sequence:
;     - X→sid2_voice_record_v2.
;     - .byte $4B $7F (= ALR #$7F, undocumented AND-then-LSR-A on the 6510).
;     - write sid2_voice_record_v2.
;     - A←$E9 / write sid2_voice_record_v2 / write sid2_voice_record_v2.
;     - return.
;
;   Patches 4 sites in the sid2_voice_record_v2 region (inside secondary_disk_mode_handler) with X and #$E9. Reached from sid2_sidtab_ctrl_accumulator (bmi). Body ends at sid2_self_modifier_setup; sid2_self_modifier_padding..save_prep_arranger_scan beyond is mixed break/data padding. sid2_voice_record_v2 sits inside the secondary_disk_mode_handler band — this routine seeds it with caller-X + a stride constant.
sid2_self_modifier_setup .block
                           stx  sid2_voice_record_v2 + $3E    ; $CE5E
                           alr  #$7F    ; $CE61
                           sta  sid2_voice_record_v2 + $45    ; $CE63
                           lda  #$E9    ; $CE66
                           sta  sid2_register_write_body.l_6    ; $CE68
                           sta  sid2_register_write_body.l_7    ; $CE6B
                           rts    ; $CE6E
        .byte $00, $40, $00, $1F, $00, $1F, $00, $00, $0F, $00, $5F, $00, $5F, $FF, $00, $71    ; $CE6F
        .byte $00, $00    ; $CE7F
.bend

; ──────────────────────────────────────────────────────────────────────
; $CE81  save_prep_orchestrator
; ──────────────────────────────────────────────────────────────────────
; pre-save preparation chain.
;
;   registers clobbered: A, X, Y
;
;   Calls save_prep_markers (write $11 markers into empty song-position slots), save_prep_arranger_scan (arranger pat-num scan), save_prep_zero_pat_base (zero pat_base_lo/hi tables), then continues with the SAVE setup beyond save_prep_orchestrator.
;
;   Inverse of the LOAD-side secondary_pat_base_init/secondary_song_position_transform passes: clear pat_base because secondary_pat_base_init rebuilds it on load; write $11 markers because secondary_song_position_transform rewrites them to runtime pointers on load.
save_prep_orchestrator .block
                           jsr  save_prep_markers    ; $CE81
                           jsr  save_prep_arranger_scan    ; $CE84
                           jsr  save_prep_zero_pat_base    ; $CE87
                           lda  #$66    ; $CE8A
                           sta  decoder_save_state_d64b    ; $CE8C
                           lda  #$71    ; $CE8F
                           sta  decoder_save_state_d65c    ; $CE91
                           lda  #$00    ; $CE94
                           sta  decoder_byte_count_lo_smc    ; $CE96
                           sta  decoder_dest_init_lo_smc    ; $CE99
                           lda  #$18    ; $CE9C
                           sta  decoder_byte_count_hi_smc    ; $CE9E
                           sta  decoder_dest_init_hi_smc    ; $CEA1
                           jsr  decoder_pointer_init.l_1    ; $CEA4
                           lda  zp_decoder_dest_lo    ; $CEA7
                           sta  song_end_pointer    ; $CEA9
                           lda  zp_decoder_dest_hi    ; $CEAC
                           sta  song_end_pointer_hi    ; $CEAE
                           rts    ; $CEB1
.bend

; ──────────────────────────────────────────────────────────────────────
; $CEB2  decoder_load_setup
; ──────────────────────────────────────────────────────────────────────
; patches the decoder's end-of-stream bound from KERNAL_LOAD_END_LO/KERNAL_LOAD_END_HI (KERNAL LOAD's end-of-program pointer).
;
;   registers clobbered: A, X, Y
;
;   Sets $02/$03 src start to ($AE-3, $AF) so decoder_block_helper walks backward from there. Called immediately after KERNAL LOAD completes, before JMP decoder_block_helper to run the decoder. The SBC #$03 backs the pointer up by 3 bytes so the first read at offset +0/+1/+2 examines the last 3 bytes of the loaded body.
decoder_load_setup .block
;     read $AE / set-carry / A -= $03 / write decoder_byte_count / write $FD.
                           lda  KERNAL_LOAD_END_LO    ; $CEB2
                           sec    ; $CEB4
                           sbc  #$03    ; $CEB5
                           sta  decoder_byte_count_lo_smc    ; $CEB7
                           sta  zp_decoder_dest_lo    ; $CEBA
;     read $AF / A -= $00 / write decoder_byte_count.
                           lda  KERNAL_LOAD_END_HI    ; $CEBC
                           sbc  #$00    ; $CEBE
                           sta  decoder_byte_count_hi_smc    ; $CEC0
                           sta  zp_decoder_dest_hi    ; $CEC3
                           ldy  #$01    ; $CEC5
                           lda  (zp_decoder_dest_lo),y    ; $CEC7
                           clc    ; $CEC9
                           adc  #$00    ; $CECA
                           sta  decoder_dest_init_lo_smc    ; $CECC
                           iny    ; $CECF
                           lda  (zp_decoder_dest_lo),y    ; $CED0
                           adc  #$18    ; $CED2
                           sta  decoder_dest_init_hi_smc    ; $CED4
.bend

; ──────────────────────────────────────────────────────────────────────
; $CED7  load_decoder_src_floor_patch
; ──────────────────────────────────────────────────────────────────────
; LOAD-decoder src-floor patcher — sets the sbc-immediate operand bytes at decoder_term_lo_smc / decoder_term_hi_smc to lo/hi of the src_floor (typically $00 / $18 = sidtab_row_lo).
;
;   registers clobbered: A, X, Y
;
;   code edges:          fall-through from $CED4 in decoder_load_setup (3 bytes earlier)
;
;   Static image has $FF $FF at those operands (compares src against VEC_IRQ_HI, never matching). Patches the lo/hi pair to $00/$18 (= sidtab_row_lo) before the call to decoder_block_helper. Net effect: the termination check inside decoder_block_helper compares src against sidtab_row_lo and terminates when src < sidtab_row_lo (NOT src < pitch_lut_band_alt_base).
load_decoder_src_floor_patch .block
                           lda  #$00    ; $CED7
                           sta  decoder_term_lo_smc    ; $CED9
                           lda  #$18    ; $CEDC
.bend

; ──────────────────────────────────────────────────────────────────────
; $CEDE  post_load_chain
; ──────────────────────────────────────────────────────────────────────
; called from post_load_init_decoder after KERNAL LOAD; runs decoder_block_helper then up to 3 gated secondary passes.
;
;   inputs:              sidtab_row_lo..super_cmd_staged (raw saved body in memory at load addr); flags post_load_xform_gate/post_load_pat_base_gate/post_load_pattern_marker_gate (set by main decoder's emit if present in trailer)
;   outputs:             live RAM load_decoder_dest_floor..super_cmd_staged fully populated; pat_base_lo/hi initialised by secondary_pat_base_init; per-pattern bit-7 marker set by secondary_pattern_marker; sidTAB rows transformed by secondary_song_position_transform
;   registers clobbered: A, X, Y
;
;   code edges:          fall-through from $CEDC in load_decoder_src_floor_patch (2 bytes earlier)
;
;   Sequence at post_load_chain..load_decoder_block_call_site:
;    STA decoder_term_hi_smc; JSR decoder_block_helper (main backward-RLE decoder, see [function.decoder_block_helper]).
;    LDA post_load_xform_gate / BEQ +3 / JSR secondary_song_position_transform (sidtab transform pass).
;    LDA post_load_pat_base_gate / BEQ +3 / JSR secondary_pat_base_init (pat_base table init).
;    LDA post_load_pattern_marker_gate / BEQ +3 / JSR secondary_pattern_marker (pattern bit-7 marker).
;    CLC; RTS.
post_load_chain .block
                           sta  decoder_term_hi_smc    ; $CEDE
.bend

; ──────────────────────────────────────────────────────────────────────
; $CEE1  load_decoder_block_call_site
; ──────────────────────────────────────────────────────────────────────
; call decoder_block_helper call site — the single invocation of the LOAD-time decoder.
;
;   code edges:          fall-through from $CEDE post_load_chain (3 bytes earlier)
;
;   Preceded at load_decoder_src_floor_patch-post_load_chain by self-mod patches that write src_floor lo/hi into the A-=operand bytes at decoder_term_lo_smc/decoder_term_hi_smc; the static image has $FF/$FF there. Without these patches the decoder would compare src against VEC_IRQ_HI and never terminate. See decoder_block_helper.
load_decoder_block_call_site .block
                           jsr  decoder_block_helper    ; $CEE1
                           lda  post_load_xform_gate    ; $CEE4
                           beq  l_1    ; $CEE7  post_load_xform_gate was zero?
                           jsr  secondary_song_position_transform    ; $CEE9
l_1:                       lda  post_load_pat_base_gate    ; $CEEC
                           beq  l_2    ; $CEEF  post_load_pat_base_gate was zero?
                           jsr  VIC_SP2_X    ; $CEF1
l_2:                       lda  post_load_pattern_marker_gate    ; $CEF4
                           beq  l_3    ; $CEF7  post_load_pattern_marker_gate was zero?
                           jsr  secondary_pattern_marker    ; $CEF9
l_3:                       clc    ; $CEFC
                           rts    ; $CEFD
.bend

; ──────────────────────────────────────────────────────────────────────
; $CEFE  sid2_jp_marker_walker
; ──────────────────────────────────────────────────────────────────────
; SID#2 JP-marker mirror walker (44 bytes, sid2_jp_marker_walker).
;
;   registers clobbered: A, X
;
;   Sequence:
;     - X ← $00.
;     - Loop:
;         read sidtab_row_lo,X / A += $00 / write sidtab_row_lo,X.
;         read sidtab_row_hi,X / A += $5F / write sidtab_row_hi,X.
;         increment X / →loop when nonzero.
;
;   Walks the JP-marker tables (sidtab_row_lo / sidtab_row_hi) shifting them so the SID#2 cascade can resolve them at a different base offset. Mirror of save_encoder_jp_chain_walker in shape but operating on the SID#2-side JP layout.
sid2_jp_marker_walker .block
                           ldx  #$00    ; $CEFE
l_1:                       lda  song_position_arrays_lo,x    ; $CF00
                           clc    ; $CF03
                           adc  #$00    ; $CF04
                           sta  song_position_arrays_lo,x    ; $CF06
                           lda  song_position_arrays_hi,x    ; $CF09
                           adc  #$5F    ; $CF0C
                           sta  song_position_arrays_hi,x    ; $CF0E
                           dex    ; $CF11
                           bne  l_1    ; $CF12  ($00 − 1) was non-zero?
l_2:                       lda  pat_base_lo,x    ; $CF14
                           clc    ; $CF17
                           adc  #$00    ; $CF18
                           sta  pat_base_lo,x    ; $CF1A
                           lda  pat_base_hi,x    ; $CF1D
                           adc  #$1F    ; $CF20
                           sta  pat_base_hi,x    ; $CF22
                           dex    ; $CF25
                           bne  l_2    ; $CF26  (($00 − 1) − 1) was non-zero?
                           clc    ; $CF28
                           rts    ; $CF29
.bend

; ──────────────────────────────────────────────────────────────────────
; $CF2A  save_prep_markers
; ──────────────────────────────────────────────────────────────────────
; walk X=0..255; for each X where sidtab_row_hi,X == $00, write $11 to both sidtab_row_lo,X and sidtab_row_hi,X.
;
;   callers:             1 code sites: $CE81 save_prep_orchestrator
;   registers clobbered: A, X
;
;   Fills empty song-position slots with the $11 marker that secondary_song_position_transform expects on LOAD.
;
;   defMON's on-disk form uses $11 markers in sidtab_row_lo/sidtab_row_hi wherever a song-position slot is active; secondary_song_position_transform rewrites those to runtime pointers `sidtab_data_base + X*$0F` after LOAD.
save_prep_markers .block
                           ldx  #$00    ; $CF2A
l_1:                       lda  song_position_arrays_hi,x    ; $CF2C
                           beq  l_2    ; $CF2F  song_position_arrays_hi,X was zero?
                           lda  #$11    ; $CF31
                           sta  song_position_arrays_lo,x    ; $CF33
                           sta  song_position_arrays_hi,x    ; $CF36
l_2:                       inx    ; $CF39
                           bne  l_1    ; $CF3A  ($00 + 1) was non-zero?
                           lda  #$01    ; $CF3C
                           sta  post_load_xform_gate    ; $CF3E
                           rts    ; $CF41
.bend

; ──────────────────────────────────────────────────────────────────────
; $CF42  secondary_song_position_transform
; ──────────────────────────────────────────────────────────────────────
; iterates X=0..255; for each non-zero sidtab_row_hi,X (song_position_arrays_hi $11-marker on disk) calls sidtab_row_decoder then writes ($02,$03) back to (sidtab_row_lo,X / sidtab_row_hi,X) as the runtime pointer sidtab_data_base + X*$0F.
;
;   callers:             1 code sites: $CEE9
;   inputs:              sidtab_row_lo/sidtab_row_hi song_position_arrays (decoder scratch), post_load_xform_gate gate
;   outputs:             sidtab_row_lo/sidtab_row_hi rewritten in-place to runtime row pointers
;   registers clobbered: A, X
;
;   Clears post_load_xform_gate gate flag.
;
;   Side-effect: post_load_xform_gate := 0 at end. Saves/restores sidTAB_staging_prefix across the call.
;   The actual sidTAB row DATA lives at sidtab_data_base..super_cmd_staged (15-byte stride); this
;   function only rewrites the per-index *pointer* arrays at sidtab_row_lo/sidtab_row_hi,
;   not the row bodies. The Tune class composes row bodies directly via
;   set_sidtab_row(row, 15 bytes raw).
secondary_song_position_transform .block
                           lda  sidTAB_staging_prefix    ; $CF42
                           pha    ; $CF45
                           ldx  #$00    ; $CF46
l_1:                       lda  song_position_arrays_hi,x    ; $CF48
                           beq  l_2    ; $CF4B  song_position_arrays_hi,X was zero?
                           stx  sidTAB_staging_prefix    ; $CF4D
                           jsr  sidtab_row_decoder    ; $CF50
                           lda  zp_ptr1_lo    ; $CF53
                           sta  song_position_arrays_lo,x    ; $CF55
                           lda  zp_ptr1_hi    ; $CF58
                           sta  song_position_arrays_hi,x    ; $CF5A
l_2:                       inx    ; $CF5D
                           bne  l_1    ; $CF5E  (sidtab_row_decoder->X + 1) was non-zero?
                           pla    ; $CF60
                           sta  sidTAB_staging_prefix    ; $CF61
                           lda  #$00    ; $CF64
                           sta  post_load_xform_gate    ; $CF66
                           rts    ; $CF69
.bend

; ──────────────────────────────────────────────────────────────────────
; $CF6A  save_prep_arranger_scan
; ──────────────────────────────────────────────────────────────────────
; walks A=0..N with Y=0..(arranger length) doing A←X / compare arranger_v0_sid1,Y / beq +57 / compare arranger_v1_sid1,Y / beq +52 / compare arranger_v2_sid1,Y /...
;
;   callers:             1 code sites: $CE84
;   registers clobbered: A, X, Y
;
;   Looks for whether each pattern number is referenced by any arranger column.
;
;   Find-unused-patterns scan used to trim the pattern bank before save — patterns referenced by no arranger row don't need to be encoded. Body extends to ~save_prep_arranger_scan just before secondary_pattern_marker.
save_prep_arranger_scan .block
                           ldx  #$00    ; $CF6A
l_1:                       ldy  #$00    ; $CF6C
l_2:                       txa    ; $CF6E
                           cmp  arranger_v0_sid1,y    ; $CF6F
                           beq  l_5    ; $CF72  $00 was arranger_v0_sid1,Y?
                           cmp  arranger_v1_sid1,y    ; $CF74
                           beq  l_5    ; $CF77  $00 was arranger_v1_sid1,Y?
                           cmp  arranger_v2_sid1,y    ; $CF79
                           beq  l_5    ; $CF7C  $00 was arranger_v2_sid1,Y?
                           lda  stereo_enable    ; $CF7E
                           beq  l_3    ; $CF81  stereo_enable was STEREO_OFF?
                           txa    ; $CF83
                           cmp  arranger_v3_sid2,y    ; $CF84
                           beq  l_5    ; $CF87  $00 was arranger_v3_sid2,Y?
                           cmp  arranger_v4_sid2,y    ; $CF89
                           beq  l_5    ; $CF8C  $00 was arranger_v4_sid2,Y?
                           cmp  arranger_v5_sid2,y    ; $CF8E
                           beq  l_5    ; $CF91  $00 was arranger_v5_sid2,Y?
l_3:                       iny    ; $CF93
                           cpy  #$00    ; $CF94
                           bne  l_2    ; $CF96  ($00 + 1) was not $00?
                           lda  pat_base_lo,x    ; $CF98
                           sta  zp_ptr1_lo    ; $CF9B
                           lda  pat_base_hi,x    ; $CF9D
                           sta  zp_ptr1_hi    ; $CFA0
                           ldy  #$00    ; $CFA2
                           lda  #$01    ; $CFA4
l_4:                       sta  (zp_ptr1_lo),y    ; $CFA6
                           iny    ; $CFA8
                           cpy  #$80    ; $CFA9
                           bne  l_4    ; $CFAB  ($00 + 1) was not $80?
l_5:                       inx    ; $CFAD
                           cpx  #$80    ; $CFAE
                           bne  l_1    ; $CFB0  ($00 + 1) was not $80?
                           lda  #$01    ; $CFB2
                           sta  post_load_pattern_marker_gate    ; $CFB4
                           rts    ; $CFB7
.bend

; ──────────────────────────────────────────────────────────────────────
; $CFB8  secondary_pattern_marker
; ──────────────────────────────────────────────────────────────────────
; walks 128 patterns and ORs $80 into each pattern's byte at offset $7C (step 31's speed byte).
;
;   callers:             1 code sites: $CEF9
;   inputs:              post_load_pattern_marker_gate gate; LIVE pattern bank starting at pattern_bank
;   outputs:             each pattern's V2 step-0 NOTE byte (pattern_bank_v2_step0_note, pat01_default_base, pat02_default_base, ...) has bit 7 set.
;   registers clobbered: A, X
;
;   Clears post_load_pattern_marker_gate gate.
;
;   Idempotent: re-running has no further effect (the OR keeps the bit
;   set). Compose-time implication: the Tune class can write step-31 speed
;   bytes WITHOUT bit 7; secondary_pattern_marker will set it post-LOAD as long as the
;   template's post_load_pattern_marker_gate flag is preserved.
secondary_pattern_marker .block
                           lda  #$7C    ; $CFB8
                           sta  save_prep_state_cfcb    ; $CFBA
                           sta  save_prep_state_cfd0    ; $CFBD
                           lda  #$1F    ; $CFC0
                           sta  save_prep_state_cfcc    ; $CFC2
                           sta  save_prep_state_cfd1    ; $CFC5
                           ldx  #$80    ; $CFC8
l_1:                       lda  VEC_IRQ_HI    ; $CFCA
                           ora  #$80    ; $CFCD
                           sta  pattern_bank + 31*PatternStep_size    ; $CFCF
                           lda  save_prep_state_cfcb    ; $CFD2
                           clc    ; $CFD5
                           adc  #$80    ; $CFD6
                           sta  save_prep_state_cfcb    ; $CFD8
                           sta  save_prep_state_cfd0    ; $CFDB
                           bcc  l_2    ; $CFDE  (save_prep_state_cfcb + $80) shifted-out bit was 0?
                           inc  save_prep_state_cfcc    ; $CFE0
                           inc  save_prep_state_cfd1    ; $CFE3
l_2:                       dex    ; $CFE6
                           bne  l_1    ; $CFE7  ($80 − 1) was non-zero?
                           lda  #$00    ; $CFE9
                           sta  post_load_pattern_marker_gate    ; $CFEB
                           rts    ; $CFEE
.bend

; ──────────────────────────────────────────────────────────────────────
; $CFEF  save_prep_zero_pat_base
; ──────────────────────────────────────────────────────────────────────
; A←$00 / X←$00 / write pat_base_lo,X / write pat_base_hi,X / increment X / compare X=$80 / bne -.
;
;   callers:             1 code sites: $CE87
;   registers clobbered: A, X
;
;   Zeros all 128 bytes of pat_base_lo and pat_base_hi.
;
;   Inverse of secondary_pat_base_init (which populates pat_base with the default pattern_bank + idx*$80 layout on LOAD). Saving with pat_base zeroed shrinks the encoded body since the RLE codec can express 256 zero bytes in 3 emitted bytes via Path D.
save_prep_zero_pat_base .block
                           lda  #$00    ; $CFEF
                           ldx  #$00    ; $CFF1
l_1:                       sta  pat_base_lo,x    ; $CFF3
                           sta  pat_base_hi,x    ; $CFF6
                           inx    ; $CFF9
                           cpx  #$80    ; $CFFA
                           bne  l_1    ; $CFFC  ($00 + 1) was not $80?
                           lda  #$01    ; $CFFE

; ──────────────────────────────────────────────────────────────────────
; SEGMENT  ram_under_io  ($D000-$DFFF, 4096 bytes, element_size=1)
;   RAM under I/O: defMON runs with $01=$35 to access this RAM region; static image preserves the boot-time bytes
; ──────────────────────────────────────────────────────────────────────
.bend

; ──────────────────────────────────────────────────────────────────────
; $D000  ram_under_io
; ──────────────────────────────────────────────────────────────────────
; Start of the RAM-under-I/O region (ram_under_io-ram_under_io_end).
;
;   callers:             1 code sites: $AA6C
