; ──────────────────────────────────────────────────────────────────────
; $D611  decoder_pointer_init
; ──────────────────────────────────────────────────────────────────────
; Decoder pointer init.
;
;   callers:             2 code sites: $D62B, $D6C9 decoder_block_helper
;   inputs:              decoder_byte_count (caller-prepared 4-byte block: src_lo, src_hi, dest_lo, dest_hi)
;   outputs:             $02/$03 = src start; $FD/$FE = dest start
;   registers clobbered: A
;
;   Copies decoder_byte_count → $02/$03 (src) and decoder_byte_count → $FD/$FE (dest). return.
decoder_pointer_init .block
                           lda  decoder_byte_count_lo_smc    ; $D611
                           sta  zp_ptr1_lo    ; $D614
                           lda  decoder_byte_count_hi_smc    ; $D616
                           sta  zp_ptr1_hi    ; $D619
                           lda  decoder_dest_init_lo_smc    ; $D61B
                           sta  zp_decoder_dest_lo    ; $D61E
                           lda  decoder_dest_init_hi_smc    ; $D620
                           sta  zp_decoder_dest_hi    ; $D623
                           rts    ; $D625
l_1:                       lda  #$00    ; $D626
                           sta  decoder_pointer_init + $90    ; $D628
                           jsr  decoder_pointer_init    ; $D62B
l_2:                       inc  SCREEN_RAM + $3C1    ; $D62E
                           ldy  #$00    ; $D631
                           lda  (zp_ptr1_lo),y    ; $D633
l_3:                       iny    ; $D635
                           beq  l_4    ; $D636  (($00 + 1) + 1) was zero?
                           cmp  (zp_ptr1_lo),y    ; $D638
                           beq  l_3    ; $D63A  (zp_ptr1_lo),Y was zero?
l_4:                       pha    ; $D63C
                           tya    ; $D63D
                           tax    ; $D63E
                           beq  l_5    ; $D63F  ($00 + 1) was zero?
                           clc    ; $D641
                           adc  zp_ptr1_lo    ; $D642
                           sta  zp_ptr1_lo    ; $D644
                           bcc  l_6    ; $D646  zp_ptr1_lo no carry
l_5:                       inc  zp_ptr1_hi    ; $D648
l_6:                       lda  #$FF    ; $D64A  ; ← decoder_save_state_d64b
                           sec    ; $D64C
                           sbc  zp_ptr1_lo    ; $D64D
                           eor  #$FF    ; $D64F
                           sta  decoder_pointer_init + $53    ; $D651
                           beq  l_7    ; $D654  (A ^ $FF) was zero?
                           dec  decoder_pointer_init + $53    ; $D656
l_7:                       bcs  l_8    ; $D659  zp_ptr1_lo no borrow
                           lda  #$FF    ; $D65B  ; ← decoder_save_state_d65c
                           sbc  zp_ptr1_hi    ; $D65D
                           bcs  l_8    ; $D65F  zp_ptr1_hi no borrow
                           txa    ; $D661
                           sec    ; $D662
                           sbc  #$FF    ; $D663  ; ← (SMC operand at $D664, no name)
                           tax    ; $D665
                           inc  decoder_pointer_init + $90    ; $D666
l_8:                       ldy  #$00    ; $D669
                           pla    ; $D66B
                           cpx  #$01    ; $D66C
                           beq  l_11    ; $D66E  A was $01?
                           cpx  #$02    ; $D670
                           beq  l_10    ; $D672  A was $02?
