                           cmp  #$FF    ; $D677
                           bne  l_9    ; $D679  decoder_emit_byte_inc->A was not $FF?
                           jsr  decoder_emit_byte_inc    ; $D67B
l_9:                       lda  #$FF    ; $D67E
                           jsr  decoder_emit_byte_inc    ; $D680
                           dex    ; $D683
                           dex    ; $D684
                           txa    ; $D685
                           jsr  decoder_emit_byte_inc    ; $D686
