; ──────────────────────────────────────────────────────────────────────
; $D6B8  decoder_emit_byte_inc
; ──────────────────────────────────────────────────────────────────────
; Decoder emit-byte (ascending).
;
;   callers:             10 code sites: $D674, $D67B, $D680, $D686, $D68C decoder_pointer_init_10, $D693, $D696 decoder_pointer_init_11, $D69D, +2 more
;   inputs:              A = byte to emit, Y = $00 (page offset for the store), $FD/$FE = dest pointer
;   outputs:             $FD/$FE += 1, decoder_byte_count += 1
;   registers clobbered: none (preserves A/X/Y)
;
;   write ($FD),Y; advance dest pointer; increment running count at decoder_byte_count; return.
;
;   Called from many sites in the RAM-with-I/O decoder band (≥10 JSR sites).
decoder_emit_byte_inc .block
                           sta  (zp_decoder_dest_lo),y    ; $D6B8
                           inc  zp_decoder_dest_lo    ; $D6BA
                           bne  l_1    ; $D6BC  (zp_decoder_dest_lo + 1) was non-zero?
                           inc  zp_decoder_dest_hi    ; $D6BE
l_1:                       inc  decoder_byte_count    ; $D6C0
                           bne  l_2    ; $D6C3  (decoder_byte_count + 1) was non-zero?
                           inc  decoder_byte_count + $01    ; $D6C5
l_2:                       rts    ; $D6C8
.bend

; ──────────────────────────────────────────────────────────────────────
; $D6C9  decoder_block_helper
; ──────────────────────────────────────────────────────────────────────
; LOAD-time decoder body (the actual byte-stream decompressor).
;
;   callers:             1 code sites: $CEE1 load_decoder_block_call_site
;   inputs:              decoder_byte_count caller-prepared; $02/$03 walks down file body; $FD/$FE walks down dest region
;   outputs:             Dest region filled with decoded bytes; decoder_byte_count running byte count
;   registers clobbered: A, X, Y
;
;   Reads file body BACKWARDS through src ($02/$03), writes LIVE form
;   BACKWARDS through dest ($FD/$FE). Both pointers walk DOWN, not up.
;
;   Decoder grammar (LAX (zp),Y at decoder_rle_lax_indy_site is the lone undocumented opcode):
;
;    Entry: 2× JSR decoder_src_decr decrements src so we examine bytes at
;    [src+0, src+1, src+2] each iteration.
;
;    Path A — single emit (src+1 != $FF):
;    emit byte at src+2; src -= 1 (consumes 1 byte)
;
;    Path B — FF byte-escape (src+1 == $FF AND src+2 == $FF):
;    emit $FF; src -= 2 (consumes 2 bytes)
;
;    Path C — single + redundant (src+1 == $FF AND src+2 != $FF
;    AND src+0 == $FF):
;    emit byte at src+2; src -= 1
;    (same observable output as Path A; falls through from decoder_term_gate)
;
;    Path D — RLE fill (src+1 == $FF AND src+2 != $FF
;    AND src+0 != $FF):
;    count_byte = byte at src+2
;    value = byte at src+0
;    emit (count_byte + 2) copies of value (descending fill via decoder_emit_byte_dec)
;    src -= 3 (consumes 3 bytes)
;    # LAX loads count_byte into X; INX makes X = count_byte + 1; the
;    # descending loop at decoder_emit_byte_dec writes X+1 bytes before X wraps from
;    # $00 → $FF and BNE exits. Total emitted = count_byte + 2.
;
;   End-of-stream: caller patches the SBC immediates at decoder_term_lo_smc / decoder_term_hi_smc to
;   encode the body-start address; when the src pointer walks below that
;   bound, BCC at decoder_term_gate takes the branch to RTS at decoder_emit_byte_dec. The
;   standard load setup at decoder_load_setup patches decoder_term_lo_smc = $00 and
;   decoder_term_hi_smc = $18, so the decoder stops when src high < $18 (i.e. the body
;   extends down to sidtab_row_lo = the start of the sidtab region).
;
;   The LAX (zp),Y at decoder_rle_lax_indy_site reads byte[src+2] simultaneously into A and X,
;   seeding the fill-loop counter. defMON uses LAX at ~40 other call sites
;   inside the field-writer dispatcher band as well.
decoder_block_helper .block
                           jsr  decoder_pointer_init    ; $D6C9
                           jsr  decoder_src_decr    ; $D6CC
                           jsr  decoder_src_decr    ; $D6CF
l_1:                       inc  SCREEN_RAM + $3C2    ; $D6D2
.bend

; ──────────────────────────────────────────────────────────────────────
; $D6D5  decoder_block_helper_term_check
; ──────────────────────────────────────────────────────────────────────
; Start of the decoder_block_helper iteration termination check.
;
;   code edges:          fall-through from $D6D2 decoder_block_helper_1 (3 bytes earlier)
;
;   decoder_block_helper_term_check read $02 (src_lo) + set-carry + decoder_block_helper_term_check A-=imm (self-modified operand byte at decoder_term_lo_smc = src_floor_lo, patched by load_decoder_src_floor_patch); decoder_term_lo_smc read $03 (src_hi) + decoder_term_lo_smc A-=imm (self-modified at decoder_term_hi_smc = src_floor_hi, patched by load_decoder_src_floor_patch). decoder_term_gate →decoder_term_gate when carry taken iff src >= src_floor (no borrow) — loop continues; →not when carry taken → fall to decoder_term_gate which does one optional FF-escape continuation (when src_lo offset >= $FE) before decoder_emit_byte_dec return terminates. See `load_decoder_src_floor_patch` for the patch.
decoder_block_helper_term_check .block
                           lda  zp_ptr1_lo    ; $D6D5
                           sec    ; $D6D7
                           sbc  #$FF    ; $D6D8  ; ← decoder_term_lo_smc
                           sta  decoder_term_gate + $03    ; $D6DA
                           lda  zp_ptr1_hi    ; $D6DD
                           sbc  #$FF    ; $D6DF  ; ← decoder_term_hi_smc
.bend

; ──────────────────────────────────────────────────────────────────────
; $D6E1  decoder_term_gate
; ──────────────────────────────────────────────────────────────────────
; →decoder_term_gate when carry — the LOAD-decoder's loop continuation gate.
;
;   code edges:          fall-through from $D6DF in decoder_term_lo_smc (2 bytes earlier)
;
;   Taken when src >= src_floor (no borrow from the decoder_block_helper_term_check-decoder_term_gate subtract); falls through to decoder_term_gate special-case (one more FF-escape) + decoder_emit_byte_dec return otherwise. Together with the patched operands at decoder_term_lo_smc / decoder_term_hi_smc (see `load_decoder_src_floor_patch`) this implements the `while src >= src_floor` termination.
decoder_term_gate .block
                           bcs  l_1    ; $D6E1  (zp_ptr1_hi − $FF) shifted-out bit was 1?
                           lda  #$FF    ; $D6E3  ; ← (SMC operand at $D6E4, no name)
                           cmp  #$FE    ; $D6E5
                           bcs  decoder_loop_entry    ; $D6E7  $FF was $FE or above?
                           bcc  decoder_emit_byte_dec_body.l_2    ; $D6E9  $FF was below $FE?
l_1:                       ldy  #$01    ; $D6EB
                           lda  (zp_ptr1_lo),y    ; $D6ED
                           cmp  #$FF    ; $D6EF
                           bne  decoder_loop_entry    ; $D6F1  (zp_ptr1_lo),Y was not $FF?
                           ldy  #$02    ; $D6F3
                           lda  (zp_ptr1_lo),y    ; $D6F5
                           cmp  #$FF    ; $D6F7
                           bne  l_2    ; $D6F9  (zp_ptr1_lo),Y was not $FF?
                           jsr  decoder_src_decr    ; $D6FB
                           jmp  decoder_loop_entry    ; $D6FE
l_2:                       ldy  #$00    ; $D701
                           lda  (zp_ptr1_lo),y    ; $D703
                           cmp  #$FF    ; $D705
                           bne  decoder_rle_fill_path    ; $D707  (zp_ptr1_lo),Y was not $FF?
.bend

; ──────────────────────────────────────────────────────────────────────
; $D709  decoder_loop_entry
; ──────────────────────────────────────────────────────────────────────
; Decoder Path A/C single-byte emit.
;
;   callers:             3 code sites: $D6E7, $D6F1, $D6FE
;   registers clobbered: A, X, Y
;
;   Reached after the path-selector at decoder_term_gate decides src+1 != $FF
;   (or the dual-$FF degenerate Path C). The write loop at decoder_emit_byte_dec is
;   entered with X=$00 so a single byte is emitted then the loop exits.
decoder_loop_entry .block
                           ldx  #$00    ; $D709
                           ldy  #$02    ; $D70B
                           lda  (zp_ptr1_lo),y    ; $D70D
                           jsr  decoder_src_decr    ; $D70F
.bend

; ──────────────────────────────────────────────────────────────────────
; $D712  decoder_fill_jump
; ──────────────────────────────────────────────────────────────────────
; Decoder fill-jump.
;
;   inputs:              A, X, Y
;   registers clobbered: A, X, Y
;
;   code edges:          fall-through from $D70F in decoder_loop_entry (3 bytes earlier)
;
;   jump decoder_emit_byte_dec = enter the descending fill loop. Reached from decoder_loop_entry (Path A single emit, X=$00 falls into one-byte fill) or from decoder_rle_fill_path (Path D RLE-fill, X = count_byte + 1).
decoder_fill_jump .block
                           jmp  decoder_emit_byte_dec    ; $D712
.bend

; ──────────────────────────────────────────────────────────────────────
; $D715  decoder_rle_fill_path
; ──────────────────────────────────────────────────────────────────────
; Decoder RLE-fill path.
;
;   callers:             1 code sites: $D707
;   registers clobbered: A, X, Y
;
;   Reads count via read A=X=($02),Y at decoder_rle_lax_indy_site; src -= 3; fall into decoder_emit_byte_dec descending fill.
;
;   Reached only via decoder_term_gate BNE decoder_rle_fill_path — i.e. when src+1==$FF AND src+2!=$FF
;   AND src+0!=$FF. The CMP #$FF at decoder_rle_lax_indy_site + JSR decoder_src_decr at decoder_rle_lax_indy_site is
;   dead-on-this-path (value is known != $FF). LAX is one of several
;   undocumented NMOS opcodes defMON uses — the field-writer dispatcher
;   band uses it heavily too (40+ sites).
decoder_rle_fill_path .block
                           ldy  #$02    ; $D715
.bend

; ──────────────────────────────────────────────────────────────────────
; $D717  decoder_rle_lax_indy_site
; ──────────────────────────────────────────────────────────────────────
; read A=X=($02),Y site inside the decoder_block_helper Path-D RLE fill (reached via decoder_rle_fill_path).
;
;   code edges:          fall-through from $D715 decoder_rle_fill_path (2 bytes earlier)
;
;   The lone undocumented opcode in the LOAD-decoder body; loads byte[src+2] simultaneously into A and X to seed the descending fill loop at decoder_emit_byte_dec.
decoder_rle_lax_indy_site .block
                           lax  (zp_ptr1_lo),y    ; $D717
                           inx    ; $D719
                           ldy  #$00    ; $D71A
                           lda  (zp_ptr1_lo),y    ; $D71C
                           cmp  #$FF    ; $D71E
                           bne  l_1    ; $D720  (zp_ptr1_lo),Y was not $FF?
                           jsr  decoder_src_decr    ; $D722
l_1:                       pha    ; $D725
                           lda  zp_ptr1_lo    ; $D726
                           sec    ; $D728
                           sbc  #$03    ; $D729
                           sta  zp_ptr1_lo    ; $D72B
                           bcs  l_2    ; $D72D  (zp_ptr1_lo − $03) shifted-out bit was 1?
                           dec  zp_ptr1_hi    ; $D72F
l_2:                       pla    ; $D731
.bend

; ──────────────────────────────────────────────────────────────────────
; $D732  decoder_emit_byte_dec
; ──────────────────────────────────────────────────────────────────────
; Decoder descending-fill entry (load Y=#$00).
;
;   callers:             2 code sites: $D712 decoder_fill_jump, $D746
;   inputs:              A, X, Y
;   registers clobbered: A, X, Y
;
;   Loops X+1 times, writing the next source byte through the ($FD/$FE) destination pointer and decrementing both src and dest after each write. Exits when X wraps past $FF. Entered by the path-A/C/RLE-fill decoder arms after they've loaded the count into X and the byte (or count) into the indirect pointers.
decoder_emit_byte_dec .block
                           ldy  #$00    ; $D732
.bend

; ──────────────────────────────────────────────────────────────────────
; $D734  decoder_emit_byte_dec_body
; ──────────────────────────────────────────────────────────────────────
; Decoder emit-byte loop body (descending fill).
;
;   inputs:              A = byte to fill, $FD/$FE = dest pointer (filled downward), X = byte-count - 1
;   outputs:             X bytes of value A written into [$FD-X, $FD] (descending), $FD/$FE = $FD - X.
;   registers clobbered: A, X, Y
;
;   code edges:          fall-through from $D732 decoder_emit_byte_dec (2 bytes earlier)
;
;   write ($FD),Y; decrement $FD; decrement X; loop while X != $FF. The decoder_emit_byte_dec entry sits 2 bytes earlier and pre-loads X.
;
;   Loop body at decoder_emit_byte_dec..decoder_emit_byte_dec. When X=0 at entry only a single-byte
;   write fires before the loop exits. Surrounding decoder code (at
;   decoder_loop_entry / decoder_fill_jump) sets X before falling into decoder_emit_byte_dec.
decoder_emit_byte_dec_body .block
                           sta  (zp_decoder_dest_lo),y    ; $D734
                           pha    ; $D736
                           lda  zp_decoder_dest_lo    ; $D737
                           sec    ; $D739
                           sbc  #$01    ; $D73A
                           sta  zp_decoder_dest_lo    ; $D73C
                           bcs  l_1    ; $D73E  (zp_decoder_dest_lo − $01) shifted-out bit was 1?
                           dec  zp_decoder_dest_hi    ; $D740
l_1:                       pla    ; $D742
                           dex    ; $D743
                           cpx  #$FF    ; $D744
