                           bne  l_5    ; $E38A  sid_chip_view was not SID_VIEW_1?
                           pla    ; $E38C
                           sta  arranger_v0_sid1,y    ; $E38D
                           jmp  post_load_decoder_internal_label.l_1    ; $E390
l_5:                       pla    ; $E393
.bend

