.bend

; ──────────────────────────────────────────────────────────────────────
; $E444  writer_seqlist_row_insert
; ──────────────────────────────────────────────────────────────────────
; `RETURN` in seqLIST (insert row).
;
;   callers:             1 code sites: $E4D6
;   registers clobbered: A, X, Y
;
;   read ($02),y / bmi +bail (FF jump marker means don't insert); else A+=$01 / bmi +bail; read arranger_v0_sid1,Y into X to shift the row block down.
writer_seqlist_row_insert .block
                           ldy  #$00    ; $E444
                           lda  (zp_ptr1_lo),y    ; $E446
                           bmi  l_5    ; $E448  (zp_ptr1_lo),Y had bit 7 set?
l_1:                       ldy  #$00    ; $E44A
                           clc    ; $E44C
                           adc  #$01    ; $E44D
                           bmi  l_5    ; $E44F  (A + $01) had bit 7 set?
l_2:                       ldx  arranger_v0_sid1,y    ; $E451
                           bmi  l_3    ; $E454  arranger_v0_sid1,Y had bit 7 set?
                           cmp  arranger_v0_sid1,y    ; $E456
                           beq  l_1    ; $E459  A was arranger_v0_sid1,Y?
                           cmp  arranger_v1_sid1,y    ; $E45B
                           beq  l_1    ; $E45E  A was arranger_v1_sid1,Y?
                           cmp  arranger_v2_sid1,y    ; $E460
                           beq  l_1    ; $E463  A was arranger_v2_sid1,Y?
l_3:                       ldx  stereo_enable    ; $E465
                           beq  l_4    ; $E468  stereo_enable was STEREO_OFF?
