; ──────────────────────────────────────────────────────────────────────
; $E550  seqLIST_handler
; ──────────────────────────────────────────────────────────────────────
; seqLIST handler (mode ui_mode=UI_MODE_SEQLIST).
;
;   callers:             1 code sites: $0954
;   inputs:              A
;   outputs:             X, Y
;   registers clobbered: A, X, Y
;
;   Mode-switch chords: LEFTARROW→sidTAB, RUNSTOP→seqED.
seqLIST_handler .block
                           inc  editor_col_delta    ; $E550
                           ldx  kbd_modifiers    ; $E553
                           ldy  kbd_decoded_key    ; $E556
                           cpx  #$00    ; $E559
                           beq  l_1    ; $E55B  kbd_modifiers was $00?
                           jmp  l_15    ; $E55D
; ─── switch (kbd_decoded_key) — 4 cases ───
;     case KEY_CRSRUD             → $E564
;     case KEY_CRSRLR             → $E56B
;     case KEY_LEFTARROW          → $E572
;     case KEY_STOP               → $E57E
;     default                   → $E583
l_1:                       cpy  #KEY_CRSRUD    ; $E560
                           bne  l_2    ; $E562  kbd_decoded_key was not KEY_CRSRUD?
                           jmp  writer_seqlist_advance    ; $E564
l_2:                       cpy  #KEY_CRSRLR    ; $E567
                           bne  l_3    ; $E569  kbd_decoded_key was not KEY_CRSRLR?
                           jmp  writer_seqlist_advance.l_2    ; $E56B
l_3:                       cpy  #KEY_LEFTARROW    ; $E56E
                           bne  l_4    ; $E570  kbd_decoded_key was not KEY_LEFTARROW?
                           lda  #$04    ; $E572
                           jsr  mode_transition_wrapper    ; $E574
                           jmp  super_cmd_page_commit.l_39    ; $E577
l_4:                       cpy  #KEY_STOP    ; $E57A
                           bne  l_5    ; $E57C  kbd_decoded_key was not KEY_STOP?
                           lda  #$01    ; $E57E
                           jmp  mode_transition_wrapper    ; $E580
l_5:                       cpy  #KEY_A    ; $E583
                           bcc  l_7    ; $E585  kbd_decoded_key was below KEY_A?
                           cpy  #KEY_G    ; $E587
                           bcs  l_7    ; $E589  kbd_decoded_key was KEY_G or above?
                           tya    ; $E58B
                           clc    ; $E58C
                           adc  #$09    ; $E58D
l_6:                       ldx  #$11    ; $E58F
                           ldy  #$E2    ; $E591
                           jsr  field_writer_dispatcher    ; $E593
                           jmp  writer_seqlist_advance.l_2    ; $E596
l_7:                       cpy  #KEY_0    ; $E599
                           bcc  l_8    ; $E59B  kbd_decoded_key was below KEY_0?
                           cpy  #KEY_POUND    ; $E59D
                           bcs  l_8    ; $E59F  kbd_decoded_key was KEY_POUND or above?
                           tya    ; $E5A1
                           and  #$0F    ; $E5A2
                           jmp  l_6    ; $E5A4
; ─── switch (kbd_decoded_key) — 6 cases ───
;     case KEY_U                  → $E5AB
;     case KEY_INSTDEL            → $E5B6
;     case KEY_SPACE              → $E5C1
;     case KEY_RETURN             → $E5CF
;     case KEY_COMMA              → $E5E1
;     case KEY_PERIOD             → $E5EC
;     default                   → $E5F3
l_8:                       cpy  #KEY_U    ; $E5A7
                           bne  l_9    ; $E5A9  kbd_decoded_key was not KEY_U?
                           ldx  #$44    ; $E5AB
                           ldy  #$E4    ; $E5AD
                           jmp  field_writer_dispatcher    ; $E5AF
l_9:                       cpy  #KEY_INSTDEL    ; $E5B2
                           bne  l_10    ; $E5B4  kbd_decoded_key was not KEY_INSTDEL?
                           ldx  #$33    ; $E5B6
